struct ReadFileIR {
    AllocaInst *buf = nullptr;
    Value *n = nullptr;
    ArrayType *bufTy = nullptr;
    BasicBlock *afterRead = nullptr;
    BasicBlock *ret0 = nullptr;
};

ReadFileIR emitReadSmallFile(IRBuilder<> &B, Module &M, Function *Fn,
                             StringRef Path, std::uint64_t BufBytes,
                             ir::IRRandom &rng, const Triple &TT) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;

    ReadFileIR out;
    out.bufTy = ArrayType::get(i8, BufBytes);
    out.buf = B.CreateAlloca(out.bufTy, nullptr, "morok.antidbg.buf");

    Value *path = ir::emitCloakedSymbol(B, M, Path, rng);
    Value *fd = nullptr;
    const bool hasLinuxSyscalls =
        linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr);
    if (hasLinuxSyscalls) {
        Value *fdLong = emitLinuxSyscall(B, M, TT, openatNr,
                                         {ConstantInt::getSigned(ip, -100),
                                          path, ConstantInt::get(ip, 0),
                                          ConstantInt::get(ip, 0)});
        fd = B.CreateTruncOrBitCast(fdLong, i32);
    } else {
        fd = B.CreateCall(openDecl(M), {path, ConstantInt::get(i32, 0)});
    }

    auto *readBB = BasicBlock::Create(ctx, "read", Fn);
    out.ret0 = BasicBlock::Create(ctx, "ret0", Fn);
    Value *badFd = B.CreateICmpSLT(fd, ConstantInt::getSigned(i32, 0));
    B.CreateCondBr(badFd, out.ret0, readBB);

    IRBuilder<> RB(readBB);
    Value *bufPtr = RB.CreateInBoundsGEP(
        out.bufTy, out.buf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)});
    if (hasLinuxSyscalls) {
        out.n =
            emitLinuxSyscall(RB, M, TT, readNr,
                             {fd, bufPtr, ConstantInt::get(ip, BufBytes - 1)});
        emitLinuxSyscall(RB, M, TT, closeNr, {fd});
    } else {
        out.n = RB.CreateCall(readDecl(M),
                              {fd, bufPtr, ConstantInt::get(ip, BufBytes - 1)});
        RB.CreateCall(closeDecl(M), {fd});
    }
    out.afterRead = readBB;
    return out;
}

ReadFileIR emitReadPathValue(IRBuilder<> &B, Module &M, Function *Fn,
                             Value *Path, std::uint64_t BufBytes,
                             const Triple &TT, StringRef Prefix) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;

    ReadFileIR out;
    out.bufTy = ArrayType::get(i8, BufBytes);
    out.buf = B.CreateAlloca(out.bufTy, nullptr, Twine(Prefix) + ".buf");

    Value *fd = nullptr;
    const bool hasLinuxSyscalls =
        linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr);
    if (hasLinuxSyscalls) {
        Value *fdLong = emitLinuxSyscall(B, M, TT, openatNr,
                                         {ConstantInt::getSigned(ip, -100),
                                          Path, ConstantInt::get(ip, 0),
                                          ConstantInt::get(ip, 0)});
        fdLong->setName(Twine(Prefix) + ".fd");
        fd = B.CreateTruncOrBitCast(fdLong, i32, Twine(Prefix) + ".fd.i32");
    } else {
        fd = B.CreateCall(openDecl(M), {Path, ConstantInt::get(i32, 0)},
                          Twine(Prefix) + ".fd");
    }

    auto *readBB = BasicBlock::Create(ctx, Twine(Prefix) + ".read", Fn);
    out.ret0 = BasicBlock::Create(ctx, Twine(Prefix) + ".miss", Fn);
    Value *badFd = B.CreateICmpSLT(fd, ConstantInt::getSigned(i32, 0),
                                   Twine(Prefix) + ".fd.bad");
    B.CreateCondBr(badFd, out.ret0, readBB);

    IRBuilder<> RB(readBB);
    Value *bufPtr = RB.CreateInBoundsGEP(
        out.bufTy, out.buf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        Twine(Prefix) + ".ptr");
    if (hasLinuxSyscalls) {
        out.n =
            emitLinuxSyscall(RB, M, TT, readNr,
                             {fd, bufPtr, ConstantInt::get(ip, BufBytes - 1)});
        out.n->setName(Twine(Prefix) + ".read.n");
        emitLinuxSyscall(RB, M, TT, closeNr, {fd});
    } else {
        out.n = RB.CreateCall(readDecl(M),
                              {fd, bufPtr, ConstantInt::get(ip, BufBytes - 1)},
                              Twine(Prefix) + ".read.n");
        RB.CreateCall(closeDecl(M), {fd});
    }
    out.afterRead = readBB;
    return out;
}

void emitLinuxMemfdReexecCtor(Module &M, ir::IRRandom &rng, const Triple &TT) {
    if (!useDirectLinuxSyscalls(M, TT) ||
        M.getFunction("morok.antidbg.memfd"))
        return;

    constexpr std::uint32_t kRead = 0;
    constexpr std::uint32_t kWrite = 1;
    constexpr std::uint32_t kClose = 3;
    constexpr std::uint32_t kExecve = 59;
    constexpr std::uint32_t kReadlink = 89;
    constexpr std::uint32_t kOpenAt = 257;
    constexpr std::uint32_t kDup3 = 292;
    constexpr std::uint32_t kMemfdCreate = 319;
    constexpr std::uint32_t kExecveat = 322;
    constexpr std::int64_t kAtFdcwd = -100;
    constexpr std::uint64_t kAtEmptyPath = 0x1000;
    constexpr std::uint64_t kOCloexec = 0x80000;
    constexpr std::uint64_t kMfdCloexec = 0x1;
    constexpr std::uint64_t kBufBytes = 4096;
    constexpr std::uint64_t kFallbackFd = 200;

    LLVMContext &ctx = M.getContext();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);

    Function *fn = makeLinuxArgCtorShell(M, "morok.antidbg.memfd");
    fn->getArg(0)->setName("argc");
    Argument *argv = fn->getArg(1);
    Argument *envp = fn->getArg(2);
    argv->setName("argv");
    envp->setName("envp");

    auto *entry = &fn->getEntryBlock();
    auto *prefixInitBB = BasicBlock::Create(ctx, "prefix.init", fn);
    auto *prefixBodyBB = BasicBlock::Create(ctx, "prefix.body", fn);
    auto *openBB = BasicBlock::Create(ctx, "open", fn);
    auto *memfdBB = BasicBlock::Create(ctx, "memfd", fn);
    auto *copyBB = BasicBlock::Create(ctx, "copy", fn);
    auto *readDoneBB = BasicBlock::Create(ctx, "read.done", fn);
    auto *writeBB = BasicBlock::Create(ctx, "write", fn);
    auto *writeContBB = BasicBlock::Create(ctx, "write.cont", fn);
    auto *execBB = BasicBlock::Create(ctx, "exec", fn);
    auto *execProcFdBB = BasicBlock::Create(ctx, "exec.procfd", fn);
    auto *closeSrcRetBB = BasicBlock::Create(ctx, "close.src.ret", fn);
    auto *closeBothRetBB = BasicBlock::Create(ctx, "close.both.ret", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    auto *pathTy = ArrayType::get(i8, kBufBytes);
    auto *bufTy = ArrayType::get(i8, kBufBytes);
    auto *emptyTy = ArrayType::get(i8, 1);
    auto *fallbackArgvTy = ArrayType::get(PointerType::getUnqual(ctx), 2);
    AllocaInst *path =
        B.CreateAlloca(pathTy, nullptr, "morok.antidbg.memfd.path");
    AllocaInst *buf = B.CreateAlloca(bufTy, nullptr,
                                     "morok.antidbg.memfd.copybuf");
    AllocaInst *empty =
        B.CreateAlloca(emptyTy, nullptr, "morok.antidbg.memfd.empty");
    AllocaInst *fallbackArgv = B.CreateAlloca(
        fallbackArgvTy, nullptr, "morok.antidbg.memfd.argv.fallback");
    Value *pathBuf = B.CreateInBoundsGEP(
        pathTy, path, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.memfd.path.buf");
    Value *copyBuf = B.CreateInBoundsGEP(
        bufTy, buf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.memfd.copy.buf");
    Value *emptyPath = B.CreateInBoundsGEP(
        emptyTy, empty, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.memfd.empty.path");
    B.CreateStore(ConstantInt::get(i8, 0), emptyPath);
    Value *fallbackArgv0 = B.CreateInBoundsGEP(
        fallbackArgvTy, fallbackArgv,
        {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.memfd.argv0.slot");
    Value *fallbackArgv1 = B.CreateInBoundsGEP(
        fallbackArgvTy, fallbackArgv,
        {ConstantInt::get(ip, 0), ConstantInt::get(ip, 1)},
        "morok.antidbg.memfd.argv1.slot");
    B.CreateStore(pathBuf, fallbackArgv0);
    B.CreateStore(ConstantPointerNull::get(PointerType::getUnqual(ctx)),
                  fallbackArgv1);

    Value *selfPath = ir::emitCloakedSymbol(B, M, "/proc/self/exe", rng);
    Value *pathLen = emitLinuxSyscall(
        B, M, TT, kReadlink,
        {selfPath, pathBuf, ConstantInt::get(ip, kBufBytes - 1)});
    pathLen->setName("morok.antidbg.memfd.readlink");
    Value *pathOk = B.CreateAnd(
        B.CreateICmpSGT(pathLen, ConstantInt::get(ip, 0)),
        B.CreateICmpULT(pathLen, ConstantInt::get(ip, kBufBytes - 1)),
        "morok.antidbg.memfd.path.ok");
    B.CreateCondBr(pathOk, prefixInitBB, retBB);

    IRBuilder<> PIB(prefixInitBB);
    constexpr std::array<unsigned char, 7> marker = {'/', 'm', 'e', 'm',
                                                     'f', 'd', ':'};
    Value *prefixEnough = PIB.CreateICmpUGE(
        pathLen, ConstantInt::get(ip, marker.size()),
        "morok.antidbg.memfd.prefix.enough");
    PIB.CreateCondBr(prefixEnough, prefixBodyBB, openBB);

    IRBuilder<> PBB(prefixBodyBB);
    Value *match = ConstantInt::get(i1, true);
    for (std::uint32_t i = 0; i < marker.size(); ++i) {
        Value *off = ConstantInt::get(ip, i);
        Value *ch = PBB.CreateLoad(i8, gepI8(PBB, M, pathBuf, off,
                                             "morok.antidbg.memfd.prefix.ch"));
        Value *eq = PBB.CreateICmpEQ(
            ch, ConstantInt::get(i8, marker[i]),
            "morok.antidbg.memfd.prefix.eq");
        match = PBB.CreateAnd(match, eq,
                              "morok.antidbg.memfd.prefix.match");
    }
    PBB.CreateCondBr(match, retBB, openBB);

    IRBuilder<> OB(openBB);
    OB.CreateStore(ConstantInt::get(i8, 0),
                   gepI8(OB, M, pathBuf, pathLen,
                         "morok.antidbg.memfd.path.nul"));
    Value *srcFd = emitLinuxSyscall(
        OB, M, TT, kOpenAt,
        {ConstantInt::getSigned(ip, kAtFdcwd), pathBuf,
         ConstantInt::get(ip, kOCloexec), ConstantInt::get(ip, 0)});
    srcFd->setName("morok.antidbg.memfd.open");
    Value *srcOk = OB.CreateICmpSGE(srcFd, ConstantInt::get(ip, 0),
                                    "morok.antidbg.memfd.open.ok");
    OB.CreateCondBr(srcOk, memfdBB, retBB);

    IRBuilder<> MB(memfdBB);
    Value *name = ir::emitCloakedSymbol(MB, M, ".nscd-cache", rng);
    Value *memFd = emitLinuxSyscall(
        MB, M, TT, kMemfdCreate, {name, ConstantInt::get(ip, kMfdCloexec)});
    memFd->setName("morok.antidbg.memfd.create");
    Value *memOk = MB.CreateICmpSGE(memFd, ConstantInt::get(ip, 0),
                                    "morok.antidbg.memfd.create.ok");
    MB.CreateCondBr(memOk, copyBB, closeSrcRetBB);

    IRBuilder<> CB(copyBB);
    Value *nread = emitLinuxSyscall(
        CB, M, TT, kRead, {srcFd, copyBuf, ConstantInt::get(ip, kBufBytes)});
    nread->setName("morok.antidbg.memfd.read");
    Value *readOk = CB.CreateICmpSGE(nread, ConstantInt::get(ip, 0),
                                     "morok.antidbg.memfd.read.ok");
    Value *readMore = CB.CreateICmpSGT(nread, ConstantInt::get(ip, 0),
                                       "morok.antidbg.memfd.read.more");
    CB.CreateCondBr(CB.CreateAnd(readOk, readMore), writeBB, readDoneBB);

    IRBuilder<> RDB(readDoneBB);
    RDB.CreateCondBr(readOk, execBB, closeBothRetBB);

    IRBuilder<> WB(writeBB);
    auto *written = WB.CreatePHI(ip, 2, "morok.antidbg.memfd.written");
    written->addIncoming(ConstantInt::get(ip, 0), copyBB);
    Value *remaining =
        WB.CreateSub(nread, written, "morok.antidbg.memfd.write.remaining");
    Value *writePtr = gepI8(WB, M, copyBuf, written,
                            "morok.antidbg.memfd.write.ptr");
    Value *nwrite =
        emitLinuxSyscall(WB, M, TT, kWrite, {memFd, writePtr, remaining});
    nwrite->setName("morok.antidbg.memfd.write");
    Value *writeOk = WB.CreateICmpSGT(nwrite, ConstantInt::get(ip, 0),
                                      "morok.antidbg.memfd.write.ok");
    WB.CreateCondBr(writeOk, writeContBB, closeBothRetBB);

    IRBuilder<> WCB(writeContBB);
    Value *writtenNext =
        WCB.CreateAdd(written, nwrite, "morok.antidbg.memfd.written.next");
    Value *chunkDone = WCB.CreateICmpUGE(
        writtenNext, nread, "morok.antidbg.memfd.chunk.done");
    WCB.CreateCondBr(chunkDone, copyBB, writeBB);
    written->addIncoming(writtenNext, writeContBB);

    IRBuilder<> EB(execBB);
    emitLinuxSyscall(EB, M, TT, kClose, {srcFd});
    Value *execRc =
        emitLinuxSyscall(EB, M, TT, kExecveat,
                         {memFd, emptyPath, argv, envp,
                          ConstantInt::get(ip, kAtEmptyPath)});
    execRc->setName("morok.antidbg.memfd.execveat");
    Value *fallbackArgvPtr = EB.CreateInBoundsGEP(
        fallbackArgvTy, fallbackArgv,
        {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.memfd.argv.fallback.ptr");
    Value *fallbackEnvp =
        EB.CreateLoad(PointerType::getUnqual(ctx), environGlobal(M),
                      "morok.antidbg.memfd.environ");
    Value *retryRc =
        emitLinuxSyscall(EB, M, TT, kExecveat,
                         {memFd, emptyPath, fallbackArgvPtr, fallbackEnvp,
                          ConstantInt::get(ip, kAtEmptyPath)});
    retryRc->setName("morok.antidbg.memfd.execveat.retry");
    Value *dupFd =
        emitLinuxSyscall(EB, M, TT, kDup3,
                         {memFd, ConstantInt::get(ip, kFallbackFd),
                          ConstantInt::get(ip, kOCloexec)});
    dupFd->setName("morok.antidbg.memfd.dup3");
    EB.CreateCondBr(
        EB.CreateICmpEQ(dupFd, ConstantInt::get(ip, kFallbackFd),
                        "morok.antidbg.memfd.dup3.ok"),
        execProcFdBB, closeBothRetBB);

    IRBuilder<> EPB(execProcFdBB);
    Value *procFdPath =
        ir::emitCloakedSymbol(EPB, M, "/proc/self/fd/200", rng);
    Value *execProcRc = emitLinuxSyscall(
        EPB, M, TT, kExecve, {procFdPath, fallbackArgvPtr, fallbackEnvp});
    execProcRc->setName("morok.antidbg.memfd.execve.procfd");
    EPB.CreateBr(closeBothRetBB);

    IRBuilder<> CSRB(closeSrcRetBB);
    emitLinuxSyscall(CSRB, M, TT, kClose, {srcFd});
    CSRB.CreateBr(retBB);

    IRBuilder<> CBRB(closeBothRetBB);
    emitLinuxSyscall(CBRB, M, TT, kClose, {memFd});
    emitLinuxSyscall(CBRB, M, TT, kClose, {srcFd});
    CBRB.CreateBr(retBB);

    IRBuilder<> RB(retBB);
    RB.CreateRetVoid();

    appendToGlobalCtors(M, fn, 0);
}

void finishI32Ret(BasicBlock *BB, std::uint32_t Value) {
    IRBuilder<> B(BB);
    B.CreateRet(ConstantInt::get(Type::getInt32Ty(BB->getContext()), Value));
}

void finishI64Ret(BasicBlock *BB, std::uint64_t Value) {
    IRBuilder<> B(BB);
    B.CreateRet(ConstantInt::get(Type::getInt64Ty(BB->getContext()), Value));
}

struct StatusHexFieldIR {
    Value *found = nullptr;
    Value *value = nullptr;
};

struct StatusDecimalFieldIR {
    Value *found = nullptr;
    Value *value = nullptr;
};

StatusDecimalFieldIR parseProcStatusDecimalField(
    IRBuilder<> &B, Module &M, AllocaInst *Buf, Value *N,
    std::initializer_list<unsigned char> Prefix, std::uint64_t MaxBytes,
    const Twine &Name);

Function *linuxStatusTracerCheck(Module &M, ir::IRRandom &rng,
                                 const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.status"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);

    auto *fn = Function::Create(FunctionType::get(i32, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.status", &M);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    ReadFileIR rf =
        emitReadSmallFile(B, M, fn, "/proc/self/status", 1024, rng, TT);

    constexpr std::array<unsigned char, 10> prefix = {'T', 'r', 'a', 'c', 'e',
                                                      'r', 'P', 'i', 'd', ':'};

    auto *loopBB = BasicBlock::Create(ctx, "scan", fn);
    auto *matchBB = BasicBlock::Create(ctx, "match", fn);
    auto *nextBB = BasicBlock::Create(ctx, "next", fn);
    auto *digitBB = BasicBlock::Create(ctx, "digit", fn);
    auto *digitCharBB = BasicBlock::Create(ctx, "digit.char", fn);
    auto *digitMaybeNlBB = BasicBlock::Create(ctx, "digit.nl", fn);
    auto *digitNextBB = BasicBlock::Create(ctx, "digit.next", fn);
    auto *ret1 = BasicBlock::Create(ctx, "ret1", fn);

    IRBuilder<> RB(rf.afterRead);
    Value *enough = RB.CreateICmpSGT(rf.n, ConstantInt::get(ip, prefix.size()));
    RB.CreateCondBr(enough, loopBB, rf.ret0);

    IRBuilder<> LB(loopBB);
    auto *idx = LB.CreatePHI(ip, 2, "morok.antidbg.idx");
    idx->addIncoming(ConstantInt::get(ip, 0), rf.afterRead);
    Value *last = LB.CreateSub(rf.n, ConstantInt::get(ip, prefix.size()));
    Value *inRange = LB.CreateICmpULE(idx, last);
    LB.CreateCondBr(inRange, matchBB, rf.ret0);

    IRBuilder<> MB(matchBB);
    Value *match = ConstantInt::get(i1, true);
    for (std::uint32_t j = 0; j < prefix.size(); ++j) {
        Value *off = MB.CreateAdd(idx, ConstantInt::get(ip, j));
        Value *ptr = arrayBytePtr(MB, rf.bufTy, rf.buf, off);
        Value *ch = MB.CreateLoad(i8, ptr);
        Value *eq = MB.CreateICmpEQ(ch, ConstantInt::get(i8, prefix[j]));
        match = MB.CreateAnd(match, eq);
    }
    Value *digitStart = MB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()));
    MB.CreateCondBr(match, digitBB, nextBB);

    IRBuilder<> NB(nextBB);
    Value *idxNext = NB.CreateAdd(idx, ConstantInt::get(ip, 1));
    NB.CreateBr(loopBB);
    idx->addIncoming(idxNext, nextBB);

    IRBuilder<> DB(digitBB);
    auto *digitIdx = DB.CreatePHI(ip, 2, "morok.antidbg.digit");
    digitIdx->addIncoming(digitStart, matchBB);
    Value *digitInRange = DB.CreateICmpULT(digitIdx, rf.n);
    DB.CreateCondBr(digitInRange, digitCharBB, rf.ret0);

    IRBuilder<> DCB(digitCharBB);
    Value *dptr = arrayBytePtr(DCB, rf.bufTy, rf.buf, digitIdx);
    Value *ch = DCB.CreateLoad(i8, dptr);
    Value *geOne =
        DCB.CreateICmpUGE(ch, ConstantInt::get(i8, static_cast<unsigned>('1')));
    Value *leNine =
        DCB.CreateICmpULE(ch, ConstantInt::get(i8, static_cast<unsigned>('9')));
    DCB.CreateCondBr(DCB.CreateAnd(geOne, leNine), ret1, digitMaybeNlBB);

    IRBuilder<> DNB(digitMaybeNlBB);
    DNB.CreateCondBr(DNB.CreateICmpEQ(ch, ConstantInt::get(i8, '\n')), rf.ret0,
                     digitNextBB);

    IRBuilder<> DXB(digitNextBB);
    Value *digitNext = DXB.CreateAdd(digitIdx, ConstantInt::get(ip, 1));
    DXB.CreateBr(digitBB);
    digitIdx->addIncoming(digitNext, digitNextBB);

    finishI32Ret(rf.ret0, 0);
    finishI32Ret(ret1, 1);
    return fn;
}

Function *linuxStatField4Check(Module &M, ir::IRRandom &rng, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.stat4"))
        return existing;

    std::uint32_t getppidNr = 0;
    switch (TT.getArch()) {
    case Triple::x86_64:
        getppidNr = 110;
        break;
    case Triple::aarch64:
        getppidNr = 173;
        break;
    case Triple::x86:
    case Triple::arm:
    case Triple::armeb:
    case Triple::thumb:
    case Triple::thumbeb:
        getppidNr = 64;
        break;
    default:
        return nullptr;
    }

    LLVMContext &ctx = M.getContext();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);

    auto *fn = Function::Create(FunctionType::get(i32, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.stat4", &M);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    ReadFileIR stat =
        emitReadSmallFile(B, M, fn, "/proc/self/stat", 1024, rng, TT);
    IRBuilder<> SB(stat.afterRead);
    ReadFileIR status =
        emitReadSmallFile(SB, M, fn, "/proc/self/status", 1024, rng, TT);

    auto *parseBB = BasicBlock::Create(ctx, "parse", fn);
    IRBuilder<> RB(status.afterRead);
    Value *statReadOk =
        RB.CreateICmpSGT(stat.n, ConstantInt::get(ip, 8),
                         "morok.antidbg.stat.read.ok");
    Value *statusReadOk =
        RB.CreateICmpSGT(status.n, ConstantInt::get(ip, 16),
                         "morok.antidbg.status.read.ok");
    RB.CreateCondBr(RB.CreateAnd(statReadOk, statusReadOk,
                                 "morok.antidbg.stat.reads.ok"),
                    parseBB, status.ret0);

    struct DecimalRangeIR {
        Value *found = nullptr;
        Value *value = nullptr;
    };
    struct HashRangeIR {
        Value *found = nullptr;
        Value *hash = nullptr;
        Value *length = nullptr;
    };

    auto hashRange = [&](IRBuilder<> &IB, AllocaInst *Buf, ArrayType *BufTy,
                         Value *Limit, Value *Start, Value *End,
                         const Twine &Name) -> HashRangeIR {
        Function *parent = IB.GetInsertBlock()->getParent();
        auto *foundSlot = IB.CreateAlloca(i1, nullptr, Name + ".found.slot");
        auto *hashSlot = IB.CreateAlloca(i64, nullptr, Name + ".hash.slot");
        auto *lenSlot = IB.CreateAlloca(i64, nullptr, Name + ".len.slot");
        auto *posSlot = IB.CreateAlloca(ip, nullptr, Name + ".pos.slot");
        IB.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(i64, 0xcbf29ce484222325ULL), hashSlot)
            ->setVolatile(true);
        IB.CreateStore(ConstantInt::get(i64, 0), lenSlot)->setVolatile(true);
        IB.CreateStore(Start, posSlot)->setVolatile(true);
        auto *loopBB = BasicBlock::Create(ctx, (Name + ".loop").str(), parent);
        auto *bodyBB = BasicBlock::Create(ctx, (Name + ".body").str(), parent);
        auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), parent);
        Value *nonEmpty = IB.CreateICmpULT(Start, End, Name + ".nonempty");
        IB.CreateCondBr(nonEmpty, loopBB, doneBB);

        IRBuilder<> LB(loopBB);
        auto *pos = LB.CreateLoad(ip, posSlot, Name + ".pos");
        pos->setVolatile(true);
        Value *inRange =
            LB.CreateAnd(LB.CreateICmpULT(pos, End, Name + ".before.end"),
                         LB.CreateICmpULT(pos, Limit, Name + ".in.buf"),
                         Name + ".range");
        LB.CreateCondBr(inRange, bodyBB, doneBB);

        IRBuilder<> HB(bodyBB);
        Value *ch =
            HB.CreateLoad(i8, arrayBytePtr(HB, BufTy, Buf, pos), Name + ".ch");
        Value *oldHash = HB.CreateLoad(i64, hashSlot, Name + ".hash.old");
        cast<LoadInst>(oldHash)->setVolatile(true);
        Value *mixed = HB.CreateMul(
            HB.CreateXor(oldHash, HB.CreateZExt(ch, i64), Name + ".hash.xor"),
            ConstantInt::get(i64, 0x100000001b3ULL), Name + ".hash.next");
        HB.CreateStore(mixed, hashSlot)->setVolatile(true);
        Value *oldLen = HB.CreateLoad(i64, lenSlot, Name + ".len.old");
        cast<LoadInst>(oldLen)->setVolatile(true);
        HB.CreateStore(HB.CreateAdd(oldLen, ConstantInt::get(i64, 1),
                                    Name + ".len.next"),
                       lenSlot)
            ->setVolatile(true);
        HB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
        HB.CreateStore(HB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                    Name + ".pos.next"),
                       posSlot)
            ->setVolatile(true);
        HB.CreateBr(loopBB);

        IB.SetInsertPoint(doneBB);
        HashRangeIR out;
        out.found = IB.CreateLoad(i1, foundSlot, Name + ".found");
        cast<LoadInst>(out.found)->setVolatile(true);
        out.hash = IB.CreateLoad(i64, hashSlot, Name + ".hash");
        cast<LoadInst>(out.hash)->setVolatile(true);
        out.length = IB.CreateLoad(i64, lenSlot, Name + ".len");
        cast<LoadInst>(out.length)->setVolatile(true);
        return out;
    };

    auto parseDecimalRange = [&](IRBuilder<> &IB, AllocaInst *Buf,
                                 ArrayType *BufTy, Value *Limit, Value *Start,
                                 const Twine &Name) -> DecimalRangeIR {
        Function *parent = IB.GetInsertBlock()->getParent();
        auto *foundSlot = IB.CreateAlloca(i1, nullptr, Name + ".found.slot");
        auto *valueSlot = IB.CreateAlloca(i64, nullptr, Name + ".value.slot");
        auto *posSlot = IB.CreateAlloca(ip, nullptr, Name + ".pos.slot");
        IB.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(i64, 0), valueSlot)->setVolatile(true);
        IB.CreateStore(Start, posSlot)->setVolatile(true);
        auto *loopBB = BasicBlock::Create(ctx, (Name + ".loop").str(), parent);
        auto *bodyBB = BasicBlock::Create(ctx, (Name + ".body").str(), parent);
        auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), parent);
        IB.CreateCondBr(IB.CreateICmpULT(Start, Limit, Name + ".start.in.buf"),
                        loopBB, doneBB);

        IRBuilder<> LB(loopBB);
        auto *pos = LB.CreateLoad(ip, posSlot, Name + ".pos");
        pos->setVolatile(true);
        LB.CreateCondBr(LB.CreateICmpULT(pos, Limit, Name + ".pos.in.buf"),
                        bodyBB, doneBB);

        IRBuilder<> DB(bodyBB);
        Value *ch =
            DB.CreateLoad(i8, arrayBytePtr(DB, BufTy, Buf, pos), Name + ".ch");
        Value *digit = DB.CreateAnd(
            DB.CreateICmpUGE(ch, ConstantInt::get(i8, '0'), Name + ".ge0"),
            DB.CreateICmpULE(ch, ConstantInt::get(i8, '9'), Name + ".le9"),
            Name + ".digit");
        Value *old = DB.CreateLoad(i64, valueSlot, Name + ".old");
        cast<LoadInst>(old)->setVolatile(true);
        Value *digitValue =
            DB.CreateSub(DB.CreateZExt(ch, i64, Name + ".zext"),
                         ConstantInt::get(i64, '0'), Name + ".digit.value");
        Value *next =
            DB.CreateAdd(DB.CreateMul(old, ConstantInt::get(i64, 10),
                                      Name + ".scale"),
                         digitValue, Name + ".next");
        auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), parent);
        DB.CreateCondBr(digit, nextBB, doneBB);

        IRBuilder<> NB(nextBB);
        NB.CreateStore(next, valueSlot)->setVolatile(true);
        NB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
        NB.CreateStore(NB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                    Name + ".pos.next"),
                       posSlot)
            ->setVolatile(true);
        NB.CreateBr(loopBB);

        IB.SetInsertPoint(doneBB);
        DecimalRangeIR out;
        out.found = IB.CreateLoad(i1, foundSlot, Name + ".found");
        cast<LoadInst>(out.found)->setVolatile(true);
        out.value = IB.CreateLoad(i64, valueSlot, Name + ".value");
        cast<LoadInst>(out.value)->setVolatile(true);
        return out;
    };

    auto parseStatusName = [&](IRBuilder<> &IB, Value *Limit) -> HashRangeIR {
        Function *parent = IB.GetInsertBlock()->getParent();
        constexpr std::array<unsigned char, 5> prefix = {'N', 'a', 'm', 'e',
                                                         ':'};
        auto *foundSlot =
            IB.CreateAlloca(i1, nullptr, "morok.antidbg.status.name.found.slot");
        auto *hashSlot =
            IB.CreateAlloca(i64, nullptr, "morok.antidbg.status.name.hash.slot");
        auto *lenSlot =
            IB.CreateAlloca(i64, nullptr, "morok.antidbg.status.name.len.slot");
        auto *startSlot =
            IB.CreateAlloca(ip, nullptr, "morok.antidbg.status.name.start.slot");
        auto *idxSlot =
            IB.CreateAlloca(ip, nullptr, "morok.antidbg.status.name.idx.slot");
        IB.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(i64, 0), hashSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(i64, 0), lenSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(ip, 0), startSlot)->setVolatile(true);
        IB.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);
        auto *scanBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.scan", parent);
        auto *matchBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.match", parent);
        auto *nextBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.next", parent);
        auto *skipBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.skip", parent);
        auto *hashPrepBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.hash.prep",
                               parent);
        auto *doneBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.result", parent);
        IB.CreateBr(scanBB);

        IRBuilder<> SCB(scanBB);
        auto *idx = SCB.CreateLoad(ip, idxSlot, "morok.antidbg.status.name.idx");
        idx->setVolatile(true);
        Value *prefixEnd = SCB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                                         "morok.antidbg.status.name.end");
        SCB.CreateCondBr(SCB.CreateICmpULE(prefixEnd, Limit,
                                           "morok.antidbg.status.name.in.buf"),
                         matchBB, doneBB);

        IRBuilder<> MB(matchBB);
        Value *match = ConstantInt::getTrue(ctx);
        for (std::uint64_t j = 0; j < prefix.size(); ++j) {
            Value *ch = loadAt(MB, M, i8, status.buf,
                               MB.CreateAdd(idx, ConstantInt::get(ip, j)),
                               "morok.antidbg.status.name.prefix.ch");
            match = MB.CreateAnd(
                match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, prefix[j])),
                "morok.antidbg.status.name.prefix.match");
        }
        Value *rawStart =
            MB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                         "morok.antidbg.status.name.raw.start");
        MB.CreateCondBr(match, skipBB, nextBB);

        IRBuilder<> NB(nextBB);
        NB.CreateStore(NB.CreateAdd(idx, ConstantInt::get(ip, 1),
                                    "morok.antidbg.status.name.idx.next"),
                       idxSlot)
            ->setVolatile(true);
        NB.CreateBr(scanBB);

        IRBuilder<> SKB(skipBB);
        auto *skipPos = SKB.CreatePHI(ip, 2, "morok.antidbg.status.name.skip.pos");
        skipPos->addIncoming(rawStart, matchBB);
        Value *skipInRange = SKB.CreateICmpULT(
            skipPos, Limit, "morok.antidbg.status.name.skip.in.buf");
        Value *skipCh = loadAt(SKB, M, i8, status.buf, skipPos,
                               "morok.antidbg.status.name.skip.ch");
        Value *skipWs = SKB.CreateOr(
            SKB.CreateICmpEQ(skipCh, ConstantInt::get(i8, ' '),
                             "morok.antidbg.status.name.skip.space"),
            SKB.CreateICmpEQ(skipCh, ConstantInt::get(i8, '\t'),
                             "morok.antidbg.status.name.skip.tab"),
            "morok.antidbg.status.name.skip.ws");
        auto *skipNextBB = BasicBlock::Create(
            ctx, "morok.antidbg.status.name.skip.next", parent);
        SKB.CreateCondBr(SKB.CreateAnd(skipInRange, skipWs,
                                       "morok.antidbg.status.name.skip.more"),
                         skipNextBB, hashPrepBB);

        IRBuilder<> SNB(skipNextBB);
        Value *skipNext = SNB.CreateAdd(skipPos, ConstantInt::get(ip, 1),
                                        "morok.antidbg.status.name.skip.next");
        SNB.CreateBr(skipBB);
        skipPos->addIncoming(skipNext, skipNextBB);

        IRBuilder<> HPB(hashPrepBB);
        HPB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
        HPB.CreateStore(skipPos, startSlot)->setVolatile(true);
        auto *endSlot =
            HPB.CreateAlloca(ip, nullptr, "morok.antidbg.status.name.end.slot");
        HPB.CreateStore(skipPos, endSlot)->setVolatile(true);
        auto *endLoopBB = BasicBlock::Create(
            ctx, "morok.antidbg.status.name.end.loop", parent);
        auto *endBodyBB = BasicBlock::Create(
            ctx, "morok.antidbg.status.name.end.body", parent);
        auto *hashBB =
            BasicBlock::Create(ctx, "morok.antidbg.status.name.hash", parent);
        HPB.CreateBr(endLoopBB);

        IRBuilder<> ELB(endLoopBB);
        auto *endPos =
            ELB.CreateLoad(ip, endSlot, "morok.antidbg.status.name.end.pos");
        endPos->setVolatile(true);
        ELB.CreateCondBr(ELB.CreateICmpULT(endPos, Limit,
                                           "morok.antidbg.status.name.end.range"),
                         endBodyBB, hashBB);

        IRBuilder<> EBB(endBodyBB);
        Value *endCh = loadAt(EBB, M, i8, status.buf, endPos,
                              "morok.antidbg.status.name.end.ch");
        Value *isNl = EBB.CreateICmpEQ(endCh, ConstantInt::get(i8, '\n'),
                                       "morok.antidbg.status.name.end.nl");
        auto *endNextBB = BasicBlock::Create(
            ctx, "morok.antidbg.status.name.end.next", parent);
        EBB.CreateCondBr(isNl, hashBB, endNextBB);

        IRBuilder<> ENB(endNextBB);
        ENB.CreateStore(ENB.CreateAdd(endPos, ConstantInt::get(ip, 1),
                                      "morok.antidbg.status.name.end.next"),
                        endSlot)
            ->setVolatile(true);
        ENB.CreateBr(endLoopBB);

        IRBuilder<> HB(hashBB);
        auto *start = HB.CreateLoad(ip, startSlot,
                                    "morok.antidbg.status.name.start");
        start->setVolatile(true);
        auto *end = HB.CreateLoad(ip, endSlot, "morok.antidbg.status.name.end.v");
        end->setVolatile(true);
        HashRangeIR out =
            hashRange(HB, status.buf, status.bufTy, Limit, start, end,
                      "morok.antidbg.status.name");
        Value *hasName =
            HB.CreateAnd(out.found,
                         HB.CreateICmpNE(out.length, ConstantInt::get(i64, 0),
                                         "morok.antidbg.status.name.nonempty"),
                         "morok.antidbg.status.name.found");
        HB.CreateStore(hasName, foundSlot)->setVolatile(true);
        HB.CreateStore(out.hash, hashSlot)->setVolatile(true);
        HB.CreateStore(out.length, lenSlot)->setVolatile(true);
        HB.CreateBr(doneBB);

        IRBuilder<> DB(doneBB);
        HashRangeIR result;
        result.found = DB.CreateLoad(i1, foundSlot,
                                     "morok.antidbg.status.name.found.value");
        cast<LoadInst>(result.found)->setVolatile(true);
        result.hash =
            DB.CreateLoad(i64, hashSlot, "morok.antidbg.status.name.hash.value");
        cast<LoadInst>(result.hash)->setVolatile(true);
        result.length =
            DB.CreateLoad(i64, lenSlot, "morok.antidbg.status.name.len.value");
        cast<LoadInst>(result.length)->setVolatile(true);
        IB.SetInsertPoint(doneBB);
        return result;
    };

    IRBuilder<> PB(parseBB);
    Value *statLimit = PB.CreateSelect(
        PB.CreateICmpULT(stat.n, ConstantInt::get(ip, 1024),
                         "morok.antidbg.stat.limit.raw"),
        stat.n, ConstantInt::get(ip, 1024), "morok.antidbg.stat.limit");
    Value *statusLimit = PB.CreateSelect(
        PB.CreateICmpULT(status.n, ConstantInt::get(ip, 1024),
                         "morok.antidbg.status.limit.raw"),
        status.n, ConstantInt::get(ip, 1024), "morok.antidbg.status.limit");

    auto *openSlot = PB.CreateAlloca(ip, nullptr, "morok.antidbg.stat.open.slot");
    auto *scanSlot = PB.CreateAlloca(ip, nullptr, "morok.antidbg.stat.idx.slot");
    PB.CreateStore(ConstantInt::get(ip, 0), openSlot)->setVolatile(true);
    PB.CreateStore(ConstantInt::get(ip, 0), scanSlot)->setVolatile(true);
    auto *openLoopBB = BasicBlock::Create(ctx, "morok.antidbg.stat.open.loop", fn);
    auto *openBodyBB = BasicBlock::Create(ctx, "morok.antidbg.stat.open.body", fn);
    auto *openNextBB = BasicBlock::Create(ctx, "morok.antidbg.stat.open.next", fn);
    auto *openDoneBB = BasicBlock::Create(ctx, "morok.antidbg.stat.open.done", fn);
    PB.CreateBr(openLoopBB);

    IRBuilder<> OLB(openLoopBB);
    auto *openIdx = OLB.CreateLoad(ip, scanSlot, "morok.antidbg.stat.open.idx");
    openIdx->setVolatile(true);
    OLB.CreateCondBr(OLB.CreateICmpULT(openIdx, statLimit,
                                       "morok.antidbg.stat.open.range"),
                     openBodyBB, openDoneBB);

    IRBuilder<> OBB(openBodyBB);
    Value *openCh = loadAt(OBB, M, i8, stat.buf, openIdx,
                           "morok.antidbg.stat.open.ch");
    OBB.CreateCondBr(OBB.CreateICmpEQ(openCh, ConstantInt::get(i8, '('),
                                      "morok.antidbg.stat.open.hit"),
                     openDoneBB, openNextBB);

    IRBuilder<> ONB(openNextBB);
    ONB.CreateStore(ONB.CreateAdd(openIdx, ConstantInt::get(ip, 1),
                                  "morok.antidbg.stat.open.next"),
                    scanSlot)
        ->setVolatile(true);
    ONB.CreateBr(openLoopBB);

    IRBuilder<> ODB(openDoneBB);
    Value *openHit =
        ODB.CreateICmpULT(openIdx, statLimit, "morok.antidbg.stat.open.found");
    ODB.CreateStore(ODB.CreateSelect(openHit, openIdx, ConstantInt::get(ip, 0)),
                    openSlot)
        ->setVolatile(true);

    auto *closeSlot =
        ODB.CreateAlloca(ip, nullptr, "morok.antidbg.stat.close.slot");
    auto *revSlot =
        ODB.CreateAlloca(ip, nullptr, "morok.antidbg.stat.close.idx.slot");
    Value *lastIdx = ODB.CreateSub(statLimit, ConstantInt::get(ip, 1),
                                   "morok.antidbg.stat.last.idx");
    ODB.CreateStore(ConstantInt::get(ip, 0), closeSlot)->setVolatile(true);
    ODB.CreateStore(lastIdx, revSlot)->setVolatile(true);
    auto *closeLoopBB =
        BasicBlock::Create(ctx, "morok.antidbg.stat.close.loop", fn);
    auto *closeBodyBB =
        BasicBlock::Create(ctx, "morok.antidbg.stat.close.body", fn);
    auto *closeNextBB =
        BasicBlock::Create(ctx, "morok.antidbg.stat.close.next", fn);
    auto *closeDoneBB =
        BasicBlock::Create(ctx, "morok.antidbg.stat.close.done", fn);
    ODB.CreateCondBr(openHit, closeLoopBB, closeDoneBB);

    IRBuilder<> CLB(closeLoopBB);
    auto *closeIdx =
        CLB.CreateLoad(ip, revSlot, "morok.antidbg.stat.close.idx");
    closeIdx->setVolatile(true);
    Value *afterOpen =
        CLB.CreateICmpUGT(closeIdx, openIdx, "morok.antidbg.stat.close.after.open");
    CLB.CreateCondBr(afterOpen, closeBodyBB, closeDoneBB);

    IRBuilder<> CBB(closeBodyBB);
    Value *closeCh = loadAt(CBB, M, i8, stat.buf, closeIdx,
                            "morok.antidbg.stat.close.ch");
    CBB.CreateCondBr(CBB.CreateICmpEQ(closeCh, ConstantInt::get(i8, ')'),
                                      "morok.antidbg.stat.close.hit"),
                     closeDoneBB, closeNextBB);

    IRBuilder<> CNB(closeNextBB);
    CNB.CreateStore(CNB.CreateSub(closeIdx, ConstantInt::get(ip, 1),
                                  "morok.antidbg.stat.close.prev"),
                    revSlot)
        ->setVolatile(true);
    CNB.CreateBr(closeLoopBB);

    IRBuilder<> CDB(closeDoneBB);
    auto *closeIdxFinal =
        CDB.CreateLoad(ip, revSlot, "morok.antidbg.stat.close.idx.final");
    closeIdxFinal->setVolatile(true);
    auto *openForClose =
        CDB.CreateLoad(ip, openSlot, "morok.antidbg.stat.open.for.close");
    openForClose->setVolatile(true);
    Value *closeAfterOpen =
        CDB.CreateICmpUGT(closeIdxFinal, openForClose,
                          "morok.antidbg.stat.close.after.open.final");
    Value *closeHit =
        CDB.CreateAnd(openHit, closeAfterOpen, "morok.antidbg.stat.close.found");
    CDB.CreateStore(CDB.CreateSelect(closeHit, closeIdxFinal,
                                     ConstantInt::get(ip, 0)),
                    closeSlot)
        ->setVolatile(true);

    auto *openFinal =
        CDB.CreateLoad(ip, openSlot, "morok.antidbg.stat.open.final");
    openFinal->setVolatile(true);
    auto *closeFinal =
        CDB.CreateLoad(ip, closeSlot, "morok.antidbg.stat.close.final");
    closeFinal->setVolatile(true);
    Value *stateIdx = CDB.CreateAdd(closeFinal, ConstantInt::get(ip, 2),
                                    "morok.antidbg.stat.state.idx");
    Value *ppidStart = CDB.CreateAdd(closeFinal, ConstantInt::get(ip, 4),
                                     "morok.antidbg.stat.ppid.start");
    Value *fieldsReady =
        CDB.CreateAnd(closeHit,
                      CDB.CreateICmpULT(ppidStart, statLimit,
                                        "morok.antidbg.stat.fields.in.buf"),
                      "morok.antidbg.stat.fields.ready");
    Value *safeStateIdx =
        CDB.CreateSelect(fieldsReady, stateIdx, ConstantInt::get(ip, 0),
                         "morok.antidbg.stat.state.safe.idx");
    Value *stateCh = loadAt(CDB, M, i8, stat.buf, safeStateIdx,
                            "morok.antidbg.stat.state.ch");
    Value *stateStop = CDB.CreateAnd(
        fieldsReady,
        CDB.CreateOr(CDB.CreateICmpEQ(stateCh, ConstantInt::get(i8, 'T'),
                                      "morok.antidbg.stat.state.T"),
                     CDB.CreateICmpEQ(stateCh, ConstantInt::get(i8, 't'),
                                      "morok.antidbg.stat.state.t")),
        "morok.antidbg.stat.state.stop");
    DecimalRangeIR statPpid =
        parseDecimalRange(CDB, stat.buf, stat.bufTy, statLimit, ppidStart,
                          "morok.antidbg.stat.ppid");
    Value *commStart = CDB.CreateAdd(openFinal, ConstantInt::get(ip, 1),
                                     "morok.antidbg.stat.comm.start");
    HashRangeIR statComm = hashRange(CDB, stat.buf, stat.bufTy, statLimit,
                                     commStart, closeFinal,
                                     "morok.antidbg.stat.comm");
    HashRangeIR statusName = parseStatusName(CDB, statusLimit);
    StatusDecimalFieldIR tracer = parseProcStatusDecimalField(
        CDB, M, status.buf, status.n,
        {'T', 'r', 'a', 'c', 'e', 'r', 'P', 'i', 'd', ':'}, 1024,
        "morok.antidbg.stat.tracer");

    Value *rawPpid = emitLinuxSyscall(CDB, M, TT, getppidNr, {});
    rawPpid->setName("morok.antidbg.stat.getppid");
    Value *rawPpidOk =
        CDB.CreateICmpSGE(rawPpid, ConstantInt::getSigned(ip, 0),
                          "morok.antidbg.stat.getppid.ok");
    Value *rawPpid64 =
        CDB.CreateZExtOrTrunc(rawPpid, i64, "morok.antidbg.stat.getppid.w");
    Value *ppidReady =
        CDB.CreateAnd(statPpid.found, rawPpidOk,
                      "morok.antidbg.stat.ppid.ready");
    Value *ppidMismatch = CDB.CreateAnd(
        ppidReady,
        CDB.CreateICmpNE(statPpid.value, rawPpid64,
                         "morok.antidbg.stat.ppid.delta"),
        "morok.antidbg.stat.ppid.mismatch");
    Value *nameReady =
        CDB.CreateAnd(statComm.found, statusName.found,
                      "morok.antidbg.stat.name.ready");
    Value *nameMismatchRaw = CDB.CreateOr(
        CDB.CreateICmpNE(statComm.length, statusName.length,
                         "morok.antidbg.stat.name.len.delta"),
        CDB.CreateICmpNE(statComm.hash, statusName.hash,
                         "morok.antidbg.stat.name.hash.delta"),
        "morok.antidbg.stat.name.delta");
    Value *nameMismatch =
        CDB.CreateAnd(nameReady, nameMismatchRaw,
                      "morok.antidbg.stat.name.mismatch");
    Value *tracerPresent = CDB.CreateAnd(
        tracer.found,
        CDB.CreateICmpNE(tracer.value, ConstantInt::get(i64, 0),
                         "morok.antidbg.stat.tracer.present.raw"),
        "morok.antidbg.stat.tracer.present");
    Value *tracedStopped =
        CDB.CreateAnd(tracerPresent, stateStop,
                      "morok.antidbg.stat.tracer.state");
    Value *anomaly = CDB.CreateOr(
        ppidMismatch, CDB.CreateOr(nameMismatch, tracedStopped,
                                   "morok.antidbg.stat.coherence.bits"),
        "morok.antidbg.stat.coherence.anomaly");
    Value *packed = CDB.CreateZExt(stateStop, i32,
                                   "morok.antidbg.stat.state.stop.bit");
    packed = CDB.CreateOr(
        packed,
        CDB.CreateShl(CDB.CreateZExt(ppidMismatch, i32),
                      ConstantInt::get(i32, 1),
                      "morok.antidbg.stat.ppid.mismatch.bit"),
        "morok.antidbg.stat.pack.ppid");
    packed = CDB.CreateOr(
        packed,
        CDB.CreateShl(CDB.CreateZExt(nameMismatch, i32),
                      ConstantInt::get(i32, 2),
                      "morok.antidbg.stat.name.mismatch.bit"),
        "morok.antidbg.stat.pack.name");
    packed = CDB.CreateOr(
        packed,
        CDB.CreateShl(CDB.CreateZExt(tracedStopped, i32),
                      ConstantInt::get(i32, 3),
                      "morok.antidbg.stat.tracer.state.bit"),
        "morok.antidbg.stat.pack.tracer");
    packed = CDB.CreateOr(
        packed,
        CDB.CreateShl(CDB.CreateZExt(anomaly, i32), ConstantInt::get(i32, 8),
                      "morok.antidbg.stat.coherence.bit"),
        "morok.antidbg.stat.pack");
    CDB.CreateRet(packed);

    finishI32Ret(stat.ret0, 0);
    finishI32Ret(status.ret0, 0);
    return fn;
}

StatusDecimalFieldIR parseProcStatusDecimalField(
    IRBuilder<> &B, Module &M, AllocaInst *Buf, Value *N,
    std::initializer_list<unsigned char> Prefix, std::uint64_t MaxBytes,
    const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    std::vector<unsigned char> prefix(Prefix.begin(), Prefix.end());

    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found.slot");
    auto *valueSlot = B.CreateAlloca(i64, nullptr, Name + ".value.slot");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), valueSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);

    auto *scanBB = BasicBlock::Create(ctx, (Name + ".scan").str(), fn);
    auto *matchBB = BasicBlock::Create(ctx, (Name + ".match").str(), fn);
    auto *parseBB = BasicBlock::Create(ctx, (Name + ".parse").str(), fn);
    auto *charBB = BasicBlock::Create(ctx, (Name + ".char").str(), fn);
    auto *digitBB = BasicBlock::Create(ctx, (Name + ".digit").str(), fn);
    auto *skipBB = BasicBlock::Create(ctx, (Name + ".skip").str(), fn);
    auto *stopBB = BasicBlock::Create(ctx, (Name + ".stop").str(), fn);
    auto *hitBB = BasicBlock::Create(ctx, (Name + ".hit").str(), fn);
    auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(scanBB);

    IRBuilder<> SB(scanBB);
    auto *found = SB.CreateLoad(i1, foundSlot, Name + ".found.v");
    found->setVolatile(true);
    auto *idx = SB.CreateLoad(ip, idxSlot, Name + ".idx");
    idx->setVolatile(true);
    Value *end = SB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                              Name + ".end");
    Value *withinRead = SB.CreateICmpSLE(end, N, Name + ".within.read");
    Value *withinBuf = SB.CreateICmpULE(end, ConstantInt::get(ip, MaxBytes),
                                        Name + ".within.buf");
    SB.CreateCondBr(SB.CreateAnd(SB.CreateAnd(withinRead, withinBuf),
                                 SB.CreateNot(found)),
                    matchBB, doneBB);

    IRBuilder<> MB(matchBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < prefix.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf,
                           MB.CreateAdd(idx, ConstantInt::get(ip, j)),
                           Name + ".prefix.ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, prefix[j])),
            Name + ".prefix.match");
    }
    MB.CreateCondBr(match, parseBB, nextBB);

    IRBuilder<> PB(parseBB);
    Value *start = PB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                                Name + ".value.start");
    PB.CreateBr(charBB);

    IRBuilder<> CB(charBB);
    auto *pos = CB.CreatePHI(ip, 3, Name + ".pos");
    auto *acc = CB.CreatePHI(i64, 3, Name + ".acc");
    auto *seen = CB.CreatePHI(i1, 3, Name + ".seen");
    pos->addIncoming(start, parseBB);
    acc->addIncoming(ConstantInt::get(i64, 0), parseBB);
    seen->addIncoming(ConstantInt::getFalse(ctx), parseBB);
    Value *posInRead = CB.CreateICmpSLT(pos, N, Name + ".pos.in.read");
    Value *posInBuf =
        CB.CreateICmpULT(pos, ConstantInt::get(ip, MaxBytes), Name + ".pos.in.buf");
    CB.CreateCondBr(CB.CreateAnd(posInRead, posInBuf), digitBB, stopBB);

    IRBuilder<> DB(digitBB);
    Value *ch = loadAt(DB, M, i8, Buf, pos, Name + ".ch");
    Value *dec = DB.CreateAnd(
        DB.CreateICmpUGE(ch, ConstantInt::get(i8, '0'), Name + ".dec.lo"),
        DB.CreateICmpULE(ch, ConstantInt::get(i8, '9'), Name + ".dec.hi"),
        Name + ".dec");
    Value *digit =
        DB.CreateSub(DB.CreateZExt(ch, i64, Name + ".zext"),
                     ConstantInt::get(i64, '0'), Name + ".digit.value");
    Value *nextAcc =
        DB.CreateAdd(DB.CreateMul(acc, ConstantInt::get(i64, 10),
                                  Name + ".acc.scale"),
                     digit, Name + ".next.acc");
    Value *nextPos = DB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                  Name + ".next.pos");
    DB.CreateCondBr(dec, charBB, skipBB);
    pos->addIncoming(nextPos, digitBB);
    acc->addIncoming(nextAcc, digitBB);
    seen->addIncoming(ConstantInt::getTrue(ctx), digitBB);

    IRBuilder<> SKB(skipBB);
    Value *ws = SKB.CreateOr(
        SKB.CreateICmpEQ(ch, ConstantInt::get(i8, ' '), Name + ".space"),
        SKB.CreateICmpEQ(ch, ConstantInt::get(i8, '\t'), Name + ".tab"),
        Name + ".ws");
    Value *skip = SKB.CreateAnd(SKB.CreateNot(seen), ws, Name + ".skip.ws");
    Value *skipPos = SKB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                   Name + ".skip.pos");
    SKB.CreateCondBr(skip, charBB, stopBB);
    pos->addIncoming(skipPos, skipBB);
    acc->addIncoming(acc, skipBB);
    seen->addIncoming(seen, skipBB);

    IRBuilder<> STB(stopBB);
    STB.CreateCondBr(seen, hitBB, doneBB);

    IRBuilder<> HTB(hitBB);
    HTB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    HTB.CreateStore(acc, valueSlot)->setVolatile(true);
    HTB.CreateBr(doneBB);

    IRBuilder<> NB(nextBB);
    NB.CreateStore(NB.CreateAdd(idx, ConstantInt::get(ip, 1),
                                Name + ".idx.next"),
                   idxSlot)
        ->setVolatile(true);
    NB.CreateBr(scanBB);

    B.SetInsertPoint(doneBB);
    StatusDecimalFieldIR out;
    out.found = B.CreateLoad(i1, foundSlot, Name + ".found");
    cast<LoadInst>(out.found)->setVolatile(true);
    out.value = B.CreateLoad(i64, valueSlot, Name + ".value");
    cast<LoadInst>(out.value)->setVolatile(true);
    return out;
}

StatusHexFieldIR parseProcStatusHexField(IRBuilder<> &B, Module &M,
                                         AllocaInst *Buf, Value *N,
                                         std::initializer_list<unsigned char> Prefix,
                                         std::uint64_t MaxBytes,
                                         const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    std::vector<unsigned char> prefix(Prefix.begin(), Prefix.end());

    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found.slot");
    auto *valueSlot = B.CreateAlloca(i64, nullptr, Name + ".value.slot");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), valueSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);

    auto *scanBB = BasicBlock::Create(ctx, (Name + ".scan").str(), fn);
    auto *matchBB = BasicBlock::Create(ctx, (Name + ".match").str(), fn);
    auto *parseBB = BasicBlock::Create(ctx, (Name + ".parse").str(), fn);
    auto *charBB = BasicBlock::Create(ctx, (Name + ".char").str(), fn);
    auto *digitBB = BasicBlock::Create(ctx, (Name + ".digit").str(), fn);
    auto *skipBB = BasicBlock::Create(ctx, (Name + ".skip").str(), fn);
    auto *stopBB = BasicBlock::Create(ctx, (Name + ".stop").str(), fn);
    auto *hitBB = BasicBlock::Create(ctx, (Name + ".hit").str(), fn);
    auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(scanBB);

    IRBuilder<> SB(scanBB);
    auto *found = SB.CreateLoad(i1, foundSlot, Name + ".found.v");
    found->setVolatile(true);
    auto *idx = SB.CreateLoad(ip, idxSlot, Name + ".idx");
    idx->setVolatile(true);
    Value *end = SB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                              Name + ".end");
    Value *withinRead = SB.CreateICmpSLE(end, N, Name + ".within.read");
    Value *withinBuf = SB.CreateICmpULE(end, ConstantInt::get(ip, MaxBytes),
                                        Name + ".within.buf");
    SB.CreateCondBr(SB.CreateAnd(SB.CreateAnd(withinRead, withinBuf),
                                 SB.CreateNot(found)),
                    matchBB, doneBB);

    IRBuilder<> MB(matchBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < prefix.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf,
                           MB.CreateAdd(idx, ConstantInt::get(ip, j)),
                           Name + ".prefix.ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, prefix[j])),
            Name + ".prefix.match");
    }
    MB.CreateCondBr(match, parseBB, nextBB);

    IRBuilder<> PB(parseBB);
    Value *start = PB.CreateAdd(idx, ConstantInt::get(ip, prefix.size()),
                                Name + ".value.start");
    PB.CreateBr(charBB);

    IRBuilder<> CB(charBB);
    auto *pos = CB.CreatePHI(ip, 3, Name + ".pos");
    auto *acc = CB.CreatePHI(i64, 3, Name + ".acc");
    auto *seen = CB.CreatePHI(i1, 3, Name + ".seen");
    pos->addIncoming(start, parseBB);
    acc->addIncoming(ConstantInt::get(i64, 0), parseBB);
    seen->addIncoming(ConstantInt::getFalse(ctx), parseBB);
    Value *posInRead = CB.CreateICmpSLT(pos, N, Name + ".pos.in.read");
    Value *posInBuf =
        CB.CreateICmpULT(pos, ConstantInt::get(ip, MaxBytes), Name + ".pos.in.buf");
    CB.CreateCondBr(CB.CreateAnd(posInRead, posInBuf), digitBB, stopBB);

    IRBuilder<> DB(digitBB);
    Value *ch = loadAt(DB, M, i8, Buf, pos, Name + ".ch");
    Value *dec = DB.CreateAnd(
        DB.CreateICmpUGE(ch, ConstantInt::get(i8, '0'), Name + ".dec.lo"),
        DB.CreateICmpULE(ch, ConstantInt::get(i8, '9'), Name + ".dec.hi"),
        Name + ".dec");
    Value *lower = DB.CreateAnd(
        DB.CreateICmpUGE(ch, ConstantInt::get(i8, 'a'), Name + ".lower.lo"),
        DB.CreateICmpULE(ch, ConstantInt::get(i8, 'f'), Name + ".lower.hi"),
        Name + ".lower");
    Value *upper = DB.CreateAnd(
        DB.CreateICmpUGE(ch, ConstantInt::get(i8, 'A'), Name + ".upper.lo"),
        DB.CreateICmpULE(ch, ConstantInt::get(i8, 'F'), Name + ".upper.hi"),
        Name + ".upper");
    Value *hex = DB.CreateOr(dec, DB.CreateOr(lower, upper), Name + ".is.hex");
    Value *decDigit =
        DB.CreateSub(DB.CreateZExt(ch, i64), ConstantInt::get(i64, '0'),
                     Name + ".digit.dec");
    Value *lowerDigit =
        DB.CreateAdd(DB.CreateSub(DB.CreateZExt(ch, i64),
                                  ConstantInt::get(i64, 'a')),
                     ConstantInt::get(i64, 10), Name + ".digit.lower");
    Value *upperDigit =
        DB.CreateAdd(DB.CreateSub(DB.CreateZExt(ch, i64),
                                  ConstantInt::get(i64, 'A')),
                     ConstantInt::get(i64, 10), Name + ".digit.upper");
    Value *alphaDigit =
        DB.CreateSelect(lower, lowerDigit, upperDigit, Name + ".digit.alpha");
    Value *digit = DB.CreateSelect(dec, decDigit, alphaDigit, Name + ".digit");
    Value *nextAcc =
        DB.CreateOr(DB.CreateShl(acc, ConstantInt::get(i64, 4),
                                 Name + ".shift"),
                    digit, Name + ".next.acc");
    Value *nextPos = DB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                  Name + ".next.pos");
    DB.CreateCondBr(hex, charBB, skipBB);
    pos->addIncoming(nextPos, digitBB);
    acc->addIncoming(nextAcc, digitBB);
    seen->addIncoming(ConstantInt::getTrue(ctx), digitBB);

    IRBuilder<> SKB(skipBB);
    Value *ws = SKB.CreateOr(
        SKB.CreateICmpEQ(ch, ConstantInt::get(i8, ' '), Name + ".space"),
        SKB.CreateICmpEQ(ch, ConstantInt::get(i8, '\t'), Name + ".tab"),
        Name + ".ws");
    Value *skip = SKB.CreateAnd(SKB.CreateNot(seen), ws, Name + ".skip.ws");
    Value *skipPos = SKB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                   Name + ".skip.pos");
    SKB.CreateCondBr(skip, charBB, stopBB);
    pos->addIncoming(skipPos, skipBB);
    acc->addIncoming(acc, skipBB);
    seen->addIncoming(seen, skipBB);

    IRBuilder<> STB(stopBB);
    STB.CreateCondBr(seen, hitBB, doneBB);

    IRBuilder<> HTB(hitBB);
    HTB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    HTB.CreateStore(acc, valueSlot)->setVolatile(true);
    HTB.CreateBr(doneBB);

    IRBuilder<> NB(nextBB);
    NB.CreateStore(NB.CreateAdd(idx, ConstantInt::get(ip, 1), Name + ".idx.next"),
                   idxSlot)
        ->setVolatile(true);
    NB.CreateBr(scanBB);

    B.SetInsertPoint(doneBB);
    StatusHexFieldIR out;
    out.found = B.CreateLoad(i1, foundSlot, Name + ".found");
    cast<LoadInst>(out.found)->setVolatile(true);
    out.value = B.CreateLoad(i64, valueSlot, Name + ".value");
    cast<LoadInst>(out.value)->setVolatile(true);
    return out;
}

bool linuxRtSigprocmaskSyscall(const Triple &TT, std::uint32_t &RtSigprocmask) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        RtSigprocmask = 14;
        return true;
    case Triple::aarch64:
        RtSigprocmask = 135;
        return true;
    case Triple::arm:
        RtSigprocmask = 175;
        return true;
    default:
        return false;
    }
}

Function *linuxSignalMaskThreadCheck(Module &M, ir::IRRandom &rng,
                                     const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.sigmask"))
        return existing;
    if (!TT.isOSLinux())
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    std::uint32_t rtSigprocmaskNr = 0;
    if (!linuxRtSigprocmaskSyscall(TT, rtSigprocmaskNr))
        return nullptr;

    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.sigmask", &M);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    ReadFileIR proc =
        emitReadSmallFile(B, M, fn, "/proc/self/status", 1024, rng, TT);

    IRBuilder<> PB(proc.afterRead);
    ReadFileIR thread = emitReadSmallFile(PB, M, fn, "/proc/thread-self/status",
                                          1024, rng, TT);

    IRBuilder<> TB(thread.afterRead);
    StatusHexFieldIR procBlk = parseProcStatusHexField(
        TB, M, proc.buf, proc.n,
        {'S', 'i', 'g', 'B', 'l', 'k', ':'}, 1024,
        "morok.antidbg.sigmask.proc.blk");
    StatusHexFieldIR procCgt = parseProcStatusHexField(
        TB, M, proc.buf, proc.n,
        {'S', 'i', 'g', 'C', 'g', 't', ':'}, 1024,
        "morok.antidbg.sigmask.proc.cgt");
    StatusHexFieldIR threadBlk = parseProcStatusHexField(
        TB, M, thread.buf, thread.n,
        {'S', 'i', 'g', 'B', 'l', 'k', ':'}, 1024,
        "morok.antidbg.sigmask.thread.blk");
    StatusHexFieldIR threadCgt = parseProcStatusHexField(
        TB, M, thread.buf, thread.n,
        {'S', 'i', 'g', 'C', 'g', 't', ':'}, 1024,
        "morok.antidbg.sigmask.thread.cgt");

    auto *liveMask = TB.CreateAlloca(i64, nullptr,
                                     "morok.antidbg.sigmask.live.mask");
    TB.CreateStore(ConstantInt::get(i64, 0), liveMask)->setVolatile(true);
    Value *sigRc = emitLinuxSyscall(
        TB, M, TT, rtSigprocmaskNr,
        {ConstantInt::get(ip, 0), ConstantPointerNull::get(ptr), liveMask,
         ConstantInt::get(ip, 8)});
    sigRc->setName("morok.antidbg.sigmask.rt_sigprocmask");
    Value *sigOk =
        TB.CreateICmpEQ(sigRc, ConstantInt::get(ip, 0),
                        "morok.antidbg.sigmask.rt_sigprocmask.ok");
    auto *live = TB.CreateLoad(i64, liveMask, "morok.antidbg.sigmask.live");
    live->setVolatile(true);

    constexpr std::uint64_t unblockableMask = (1ULL << 8) | (1ULL << 18);
    auto hasUnblockable = [&](StatusHexFieldIR Field, const Twine &Name) {
        Value *masked =
            TB.CreateAnd(Field.value, ConstantInt::get(i64, unblockableMask),
                         Name + ".bits");
        Value *set =
            TB.CreateICmpNE(masked, ConstantInt::get(i64, 0), Name);
        return TB.CreateAnd(Field.found, set, Name + ".found");
    };
    Value *procUnblockable =
        hasUnblockable(procBlk, "morok.antidbg.sigmask.proc.unblockable");
    Value *threadUnblockable =
        hasUnblockable(threadBlk, "morok.antidbg.sigmask.thread.unblockable");
    Value *statusUnblockable = TB.CreateOr(
        procUnblockable, threadUnblockable,
        "morok.antidbg.sigmask.status.unblockable");

    Value *cgtReady =
        TB.CreateAnd(procCgt.found, threadCgt.found,
                     "morok.antidbg.sigmask.cgt.ready");
    Value *cgtDelta =
        TB.CreateICmpNE(procCgt.value, threadCgt.value,
                        "morok.antidbg.sigmask.cgt.delta");
    Value *cgtDiverged =
        TB.CreateAnd(cgtReady, cgtDelta, "morok.antidbg.sigmask.cgt.diverged");

    Value *liveUnblockableRaw =
        TB.CreateICmpNE(TB.CreateAnd(live, ConstantInt::get(i64, unblockableMask),
                                     "morok.antidbg.sigmask.live.unblockable.bits"),
                        ConstantInt::get(i64, 0),
                        "morok.antidbg.sigmask.live.unblockable.raw");
    Value *liveUnblockable =
        TB.CreateAnd(sigOk, liveUnblockableRaw,
                     "morok.antidbg.sigmask.live.unblockable");
    Value *liveThreadDeltaRaw =
        TB.CreateICmpNE(TB.CreateXor(live, threadBlk.value,
                                     "morok.antidbg.sigmask.live.thread.xor"),
                        ConstantInt::get(i64, 0),
                        "morok.antidbg.sigmask.live.thread.delta.raw");
    Value *liveThreadDelta =
        TB.CreateAnd(TB.CreateAnd(sigOk, threadBlk.found),
                     liveThreadDeltaRaw,
                     "morok.antidbg.sigmask.live.thread.delta");

    Value *packed = TB.CreateOr(
        TB.CreateZExt(statusUnblockable, i64),
        TB.CreateShl(TB.CreateZExt(cgtDiverged, i64), ConstantInt::get(i64, 1)),
        "morok.antidbg.sigmask.pack.seal");
    packed = TB.CreateOr(
        packed,
        TB.CreateShl(TB.CreateZExt(liveUnblockable, i64),
                     ConstantInt::get(i64, 8),
                     "morok.antidbg.sigmask.live.unblockable.bit"),
        "morok.antidbg.sigmask.pack.live");
    packed = TB.CreateOr(
        packed,
        TB.CreateShl(TB.CreateZExt(liveThreadDelta, i64),
                     ConstantInt::get(i64, 9),
                     "morok.antidbg.sigmask.live.thread.bit"),
        "morok.antidbg.sigmask.pack");
    TB.CreateRet(packed);

    finishI64Ret(proc.ret0, 0);
    finishI64Ret(thread.ret0, 0);
    return fn;
}

bool linuxUnameSyscall(const Triple &TT, std::uint32_t &Uname);

Value *linuxKernelVersionAtLeast(IRBuilder<> &B, Module &M, const Triple &TT,
                                 std::uint32_t NeedMajor,
                                 std::uint32_t NeedMinor,
                                 const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t unameNr = 0;
    if (!linuxUnameSyscall(TT, unameNr))
        return ConstantInt::getFalse(ctx);

    auto *utsTy = ArrayType::get(i8, 390);
    AllocaInst *uts = B.CreateAlloca(utsTy, nullptr, Name + ".uts");
    Value *utsPtr = B.CreateInBoundsGEP(
        utsTy, uts, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        Name + ".uts.ptr");
    Value *rc = emitLinuxSyscall(B, M, TT, unameNr, {utsPtr});
    rc->setName(Name + ".uname");
    Value *ok = B.CreateICmpEQ(rc, ConstantInt::get(ip, 0), Name + ".uname.ok");
    auto loadRelease = [&](std::uint64_t Offset, const Twine &Field) {
        return loadAt(B, M, i8, uts, Offset, Name + "." + Field);
    };
    auto digitValue = [&](Value *Ch, const Twine &Field) {
        return B.CreateSub(B.CreateZExt(Ch, i32, Field + ".zext"),
                           ConstantInt::get(i32, '0'), Field);
    };

    Value *c0 = loadRelease(130, "c0");
    Value *c1 = loadRelease(131, "c1");
    Value *c2 = loadRelease(132, "c2");
    Value *c3 = loadRelease(133, "c3");
    Value *c4 = loadRelease(134, "c4");
    Value *c0Digit = B.CreateAnd(
        B.CreateICmpUGE(c0, ConstantInt::get(i8, '0'), Name + ".c0.ge0"),
        B.CreateICmpULE(c0, ConstantInt::get(i8, '9'), Name + ".c0.le9"),
        Name + ".c0.digit");
    Value *c1Digit = B.CreateAnd(
        B.CreateICmpUGE(c1, ConstantInt::get(i8, '0'), Name + ".c1.ge0"),
        B.CreateICmpULE(c1, ConstantInt::get(i8, '9'), Name + ".c1.le9"),
        Name + ".c1.digit");
    Value *oneDigitMajor =
        B.CreateAnd(c0Digit, B.CreateICmpEQ(c1, ConstantInt::get(i8, '.')),
                    Name + ".major.one");
    Value *twoDigitMajor = B.CreateAnd(
        B.CreateAnd(c0Digit, c1Digit),
        B.CreateICmpEQ(c2, ConstantInt::get(i8, '.')), Name + ".major.two");
    Value *d0 = digitValue(c0, Name + ".major.d0");
    Value *d1 = digitValue(c1, Name + ".major.d1");
    Value *major2 =
        B.CreateAdd(B.CreateMul(d0, ConstantInt::get(i32, 10)), d1,
                    Name + ".major.two.value");
    Value *major = B.CreateSelect(twoDigitMajor, major2, d0, Name + ".major");
    Value *m0 = B.CreateSelect(twoDigitMajor, c3, c2, Name + ".minor.c0");
    Value *m1 = B.CreateSelect(twoDigitMajor, c4, c3, Name + ".minor.c1");
    Value *m0Digit = B.CreateAnd(
        B.CreateICmpUGE(m0, ConstantInt::get(i8, '0'), Name + ".m0.ge0"),
        B.CreateICmpULE(m0, ConstantInt::get(i8, '9'), Name + ".m0.le9"),
        Name + ".m0.digit");
    Value *m1Digit = B.CreateAnd(
        B.CreateICmpUGE(m1, ConstantInt::get(i8, '0'), Name + ".m1.ge0"),
        B.CreateICmpULE(m1, ConstantInt::get(i8, '9'), Name + ".m1.le9"),
        Name + ".m1.digit");
    Value *minorOne =
        B.CreateAnd(m0Digit, B.CreateNot(m1Digit), Name + ".minor.one");
    Value *minorTwo =
        B.CreateAnd(m0Digit, m1Digit, Name + ".minor.two");
    Value *md0 = digitValue(m0, Name + ".minor.d0");
    Value *md1 = digitValue(m1, Name + ".minor.d1");
    Value *minor2 =
        B.CreateAdd(B.CreateMul(md0, ConstantInt::get(i32, 10)), md1,
                    Name + ".minor.two.value");
    Value *minor = B.CreateSelect(minorTwo, minor2, md0, Name + ".minor");
    Value *parsed =
        B.CreateAnd(B.CreateOr(oneDigitMajor, twoDigitMajor),
                    B.CreateOr(minorOne, minorTwo), Name + ".parsed");
    Value *newerMajor =
        B.CreateICmpUGT(major, ConstantInt::get(i32, NeedMajor),
                        Name + ".major.newer");
    Value *sameMajor =
        B.CreateICmpEQ(major, ConstantInt::get(i32, NeedMajor),
                       Name + ".major.same");
    Value *minorOk =
        B.CreateICmpUGE(minor, ConstantInt::get(i32, NeedMinor),
                        Name + ".minor.ok");
    return B.CreateAnd(
        B.CreateAnd(ok, parsed, Name + ".version.ok"),
        B.CreateOr(newerMajor, B.CreateAnd(sameMajor, minorOk),
                   Name + ".version.ge"),
        Name + ".kernel.ok");
}

Value *parseFixedBufferPrefix(IRBuilder<> &B, Module &M, AllocaInst *Buf,
                              Value *N,
                              std::initializer_list<unsigned char> Prefix,
                              std::uint64_t MaxBytes, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    std::vector<unsigned char> prefix(Prefix.begin(), Prefix.end());

    auto *matchSlot = B.CreateAlloca(i1, nullptr, Name + ".slot");
    B.CreateStore(ConstantInt::getFalse(ctx), matchSlot)->setVolatile(true);
    auto *checkBB = BasicBlock::Create(ctx, (Name + ".check").str(), fn);
    auto *matchBB = BasicBlock::Create(ctx, (Name + ".match").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(checkBB);

    IRBuilder<> CB(checkBB);
    Value *enough =
        CB.CreateICmpSGE(N, ConstantInt::get(ip, prefix.size()),
                         Name + ".enough");
    Value *withinBuf = ConstantInt::get(i1, prefix.size() <= MaxBytes);
    CB.CreateCondBr(CB.CreateAnd(enough, withinBuf), matchBB, doneBB);

    IRBuilder<> MB(matchBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < prefix.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf, j, Name + ".ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, prefix[j])),
            Name + ".prefix");
    }
    MB.CreateStore(match, matchSlot)->setVolatile(true);
    MB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreateLoad(i1, matchSlot, Name);
    out->setVolatile(true);
    return out;
}

struct StatStateIR {
    Value *found = nullptr;
    Value *state = nullptr;
    Value *stopped = nullptr;
    Value *traceStop = nullptr;
    Value *stopLike = nullptr;
};

StatStateIR parseLinuxStatState(IRBuilder<> &B, Module &M, AllocaInst *Buf,
                                Value *N, std::uint64_t MaxBytes,
                                const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found.slot");
    auto *stateSlot = B.CreateAlloca(i8, nullptr, Name + ".state.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i8, 0), stateSlot)->setVolatile(true);

    auto *loopBB = BasicBlock::Create(ctx, (Name + ".scan").str(), fn);
    auto *charBB = BasicBlock::Create(ctx, (Name + ".char").str(), fn);
    auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), fn);
    auto *foundBB = BasicBlock::Create(ctx, (Name + ".found").str(), fn);
    auto *readBB = BasicBlock::Create(ctx, (Name + ".read").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    BasicBlock *startBB = B.GetInsertBlock();
    Value *lastIdx = B.CreateSub(N, ConstantInt::get(ip, 1), Name + ".last");
    Value *hasAny = B.CreateICmpSGT(N, ConstantInt::get(ip, 3),
                                   Name + ".has.any");
    B.CreateCondBr(hasAny, loopBB, doneBB);

    IRBuilder<> LB(loopBB);
    auto *idx = LB.CreatePHI(ip, 2, Name + ".idx");
    idx->addIncoming(lastIdx, startBB);
    Value *valid =
        LB.CreateICmpSGE(idx, ConstantInt::getSigned(ip, 0), Name + ".valid");
    LB.CreateCondBr(valid, charBB, doneBB);

    IRBuilder<> CB(charBB);
    Value *ch = loadAt(CB, M, i8, Buf, idx, Name + ".ch");
    CB.CreateCondBr(CB.CreateICmpEQ(ch, ConstantInt::get(i8, ')'),
                                    Name + ".close"),
                    foundBB, nextBB);

    IRBuilder<> NB(nextBB);
    Value *prev = NB.CreateSub(idx, ConstantInt::get(ip, 1), Name + ".prev");
    NB.CreateBr(loopBB);
    idx->addIncoming(prev, nextBB);

    IRBuilder<> FB(foundBB);
    Value *stateIdx = FB.CreateAdd(idx, ConstantInt::get(ip, 2),
                                   Name + ".state.idx");
    Value *inRead = FB.CreateICmpSLT(stateIdx, N, Name + ".state.in.read");
    Value *inBuf =
        FB.CreateICmpULT(stateIdx, ConstantInt::get(ip, MaxBytes),
                         Name + ".state.in.buf");
    FB.CreateCondBr(FB.CreateAnd(inRead, inBuf), readBB, doneBB);

    IRBuilder<> RB(readBB);
    Value *state = loadAt(RB, M, i8, Buf, stateIdx, Name + ".state.raw");
    RB.CreateStore(state, stateSlot)->setVolatile(true);
    RB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    RB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    StatStateIR out;
    out.found = B.CreateLoad(i1, foundSlot, Name + ".found");
    cast<LoadInst>(out.found)->setVolatile(true);
    out.state = B.CreateLoad(i8, stateSlot, Name + ".state");
    cast<LoadInst>(out.state)->setVolatile(true);
    out.stopped = B.CreateAnd(
        out.found,
        B.CreateICmpEQ(out.state, ConstantInt::get(i8, 'T'), Name + ".stopped"),
        Name + ".stopped.found");
    out.traceStop = B.CreateAnd(
        out.found,
        B.CreateICmpEQ(out.state, ConstantInt::get(i8, 't'),
                       Name + ".trace.stop"),
        Name + ".trace.stop.found");
    out.stopLike =
        B.CreateOr(out.stopped, out.traceStop, Name + ".state.stop");
    return out;
}

Function *linuxPtraceStopCoherenceCheck(Module &M, ir::IRRandom &rng,
                                        const Triple &TT,
                                        Function *StatusFn) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.ptrace_stop"))
        return existing;
    if (!TT.isOSLinux() || !StatusFn)
        return nullptr;
    std::uint32_t unameNr = 0;
    if (!linuxUnameSyscall(TT, unameNr))
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.ptrace_stop", &M);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *probeBB = BasicBlock::Create(ctx, "probe", fn);
    auto *gateRetBB = BasicBlock::Create(ctx, "ret0.kernel", fn);
    IRBuilder<> B(entry);
    Value *kernelOk =
        linuxKernelVersionAtLeast(B, M, TT, 3, 4,
                                  "morok.antidbg.ptrace_stop.kernel");
    B.CreateCondBr(kernelOk, probeBB, gateRetBB);

    IRBuilder<> PB(probeBB);
    ReadFileIR wchan =
        emitReadSmallFile(PB, M, fn, "/proc/self/wchan", 64, rng, TT);
    IRBuilder<> WB(wchan.afterRead);
    ReadFileIR stat =
        emitReadSmallFile(WB, M, fn, "/proc/self/stat", 1024, rng, TT);

    IRBuilder<> SB(stat.afterRead);
    Value *wchanStop = parseFixedBufferPrefix(
        SB, M, wchan.buf, wchan.n,
        {'p', 't', 'r', 'a', 'c', 'e', '_', 's', 't', 'o', 'p'}, 64,
        "morok.antidbg.ptrace_stop.wchan.ptrace_stop");
    Value *wchanSignalStop = parseFixedBufferPrefix(
        SB, M, wchan.buf, wchan.n,
        {'d', 'o', '_', 's', 'i', 'g', 'n', 'a', 'l', '_', 's', 't', 'o', 'p'},
        64, "morok.antidbg.ptrace_stop.wchan.signal_stop");
    wchanStop =
        SB.CreateOr(wchanStop, wchanSignalStop,
                    "morok.antidbg.ptrace_stop.wchan.stop");
    StatStateIR statState = parseLinuxStatState(
        SB, M, stat.buf, stat.n, 1024, "morok.antidbg.ptrace_stop.stat");
    Value *status = SB.CreateCall(StatusFn->getFunctionType(), StatusFn, {},
                                  "morok.antidbg.ptrace_stop.status");
    Value *traced =
        SB.CreateICmpNE(status, ConstantInt::get(i32, 0),
                        "morok.antidbg.ptrace_stop.tracer");
    Value *stopPair = SB.CreateAnd(wchanStop, statState.stopLike,
                                   "morok.antidbg.ptrace_stop.stop.pair");
    Value *coherent =
        SB.CreateAnd(traced, stopPair, "morok.antidbg.ptrace_stop.coherent");
    Value *notTraced = SB.CreateNot(traced, "morok.antidbg.ptrace_stop.clean");
    Value *wchanNoTracer =
        SB.CreateAnd(wchanStop, notTraced,
                     "morok.antidbg.ptrace_stop.wchan.no_tracer");
    Value *statNoTracer =
        SB.CreateAnd(statState.stopLike, notTraced,
                     "morok.antidbg.ptrace_stop.stat.no_tracer");
    Value *wchanStatDelta =
        SB.CreateXor(wchanStop, statState.stopLike,
                     "morok.antidbg.ptrace_stop.wchan.stat.delta");

    Value *packed = SB.CreateZExt(coherent, i64,
                                  "morok.antidbg.ptrace_stop.pack.coherent");
    auto packBit = [&](Value *Flag, std::uint64_t Shift, const Twine &Name) {
        return SB.CreateShl(SB.CreateZExt(Flag, i64), ConstantInt::get(i64, Shift),
                            Name);
    };
    packed = SB.CreateOr(
        packed, packBit(traced, 1, "morok.antidbg.ptrace_stop.pack.tracer"),
        "morok.antidbg.ptrace_stop.pack.1");
    packed = SB.CreateOr(
        packed, packBit(wchanStop, 2, "morok.antidbg.ptrace_stop.pack.wchan"),
        "morok.antidbg.ptrace_stop.pack.2");
    packed = SB.CreateOr(
        packed,
        packBit(statState.stopLike, 3, "morok.antidbg.ptrace_stop.pack.stat"),
        "morok.antidbg.ptrace_stop.pack.3");
    packed = SB.CreateOr(
        packed,
        packBit(wchanStatDelta, 4, "morok.antidbg.ptrace_stop.pack.delta"),
        "morok.antidbg.ptrace_stop.pack.4");
    packed = SB.CreateOr(
        packed,
        packBit(wchanNoTracer, 5, "morok.antidbg.ptrace_stop.pack.wchan.clean"),
        "morok.antidbg.ptrace_stop.pack.5");
    packed = SB.CreateOr(
        packed,
        packBit(statNoTracer, 6, "morok.antidbg.ptrace_stop.pack.stat.clean"),
        "morok.antidbg.ptrace_stop.pack");
    SB.CreateRet(packed);

    finishI64Ret(gateRetBB, 0);
    finishI64Ret(wchan.ret0, 0);
    finishI64Ret(stat.ret0, 0);
    return fn;
}

bool linuxBuddyLivenessSyscalls(const Triple &TT, std::uint32_t &Kill,
                                std::uint32_t &Wait4);

Value *emitLinuxCoreLimitZero(IRBuilder<> &B, Module &M, const Triple &TT,
                              const Twine &Name) {
    std::uint32_t setrlimitNr = 0;
    auto *ip = intPtrTy(M);
    if (!linuxSetrlimitSyscall(TT, setrlimitNr))
        return ConstantInt::getSigned(ip, -38);

    LLVMContext &ctx = M.getContext();
    auto *limitTy = StructType::get(ctx, {ip, ip});
    auto *limit = B.CreateAlloca(limitTy, nullptr, Name + ".limit");
    limit->setAlignment(Align(ip->getBitWidth() / 8));
    auto *zero = ConstantInt::get(ip, 0);
    auto *cur = B.CreateStore(
        zero, B.CreateStructGEP(limitTy, limit, 0, Name + ".cur.ptr"));
    cur->setAlignment(Align(ip->getBitWidth() / 8));
    auto *max = B.CreateStore(
        zero, B.CreateStructGEP(limitTy, limit, 1, Name + ".max.ptr"));
    max->setAlignment(Align(ip->getBitWidth() / 8));

    constexpr std::uint32_t kRlimitCore = 4;
    return emitLinuxStaticRawSyscall(
        B, M, TT, setrlimitNr, {ConstantInt::get(ip, kRlimitCore), limit},
        Name);
}

void emitLinuxDumpableHardening(IRBuilder<> &B, Module &M,
                                GlobalVariable *State, const Triple &TT,
                                const Twine &Name, std::uint64_t Salt) {
    Value *setRc = emitLinuxPrctlDirect(B, M, TT, 4, 0, 0, 0, 0, Name);
    Value *limitRc = emitLinuxCoreLimitZero(B, M, TT, Name + ".rlimit_core");
    Value *getRc =
        emitLinuxPrctlDirect(B, M, TT, 3, 0, 0, 0, 0, Name + ".get");

    foldState(B, State, setRc, Salt ^ 0xA91E4C72D503B68FULL, Name + ".set");
    foldState(B, State, limitRc, Salt ^ 0x5E7B2186C49AD03FULL,
              Name + ".rlimit_core");
    foldState(B, State, getRc, Salt ^ 0xC38D6F10A2495BE7ULL, Name + ".get");
    Value *dumpable =
        B.CreateICmpNE(getRc, ConstantInt::get(getRc->getType(), 0),
                       Name + ".get.enabled");
    foldFlag(B, State, dumpable, Salt ^ 0x76D4A90E3B15C28FULL,
             Name + ".enabled");
}

Function *linuxWatchThread(Module &M, Function *StatusFn, Function *StatFn,
                           Function *SignalMaskFn, Function *PtraceStopFn,
                           GlobalVariable *State, GlobalVariable *BuddyPid,
                           GlobalVariable *SentinelActive, const Triple &TT,
                           bool AllowSelfTrace) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.watch"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    std::uint32_t killNr = 0;
    std::uint32_t wait4Nr = 0;
    const bool watchBuddy =
        BuddyPid && linuxBuddyLivenessSyscalls(TT, killNr, wait4Nr);

    auto *fn = Function::Create(FunctionType::get(ptr, {ptr}, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.watch", &M);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *loopBB = BasicBlock::Create(ctx, "loop", fn);
    auto *bodyBB = BasicBlock::Create(ctx, "body", fn);
    auto *buddyCheckBB =
        watchBuddy ? BasicBlock::Create(ctx, "buddy.check", fn) : nullptr;
    auto *buddyLiveBB =
        watchBuddy ? BasicBlock::Create(ctx, "buddy.live", fn) : nullptr;
    auto *buddyMissingBB =
        watchBuddy ? BasicBlock::Create(ctx, "buddy.missing", fn) : nullptr;
    auto *nextBB = watchBuddy ? BasicBlock::Create(ctx, "next", fn) : nullptr;
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> EB(entry);
    AllocaInst *buddyStatus =
        watchBuddy ? EB.CreateAlloca(i32, nullptr, "morok.antidbg.buddy.status")
                   : nullptr;
    EB.CreateBr(loopBB);

    IRBuilder<> LB(loopBB);
    auto *iter = LB.CreatePHI(i32, 2, "morok.antidbg.iter");
    iter->addIncoming(ConstantInt::get(i32, 0), entry);
    const std::uint32_t limit = watchBuddy ? kWatchdogMaxIterations : 8u;
    LB.CreateCondBr(
        LB.CreateICmpULT(iter, ConstantInt::get(i32, limit),
                         "morok.antidbg.watch.keep"),
        bodyBB, retBB);

    IRBuilder<> BB(bodyBB);
    FunctionCallee sleepFn =
        M.getOrInsertFunction("sleep", FunctionType::get(i32, {i32}, false));
    BB.CreateCall(sleepFn, {ConstantInt::get(i32, 1)});
    emitLinuxDumpableHardening(BB, M, State, TT,
                               "morok.antidbg.watch.dumpable",
                               0x4E6A1D93B827C05FULL);
    if (AllowSelfTrace)
        emitLinuxSelfTraceFallback(BB, M, State, SentinelActive, TT,
                                   "morok.antidbg.watch.ptrace",
                                   0x6FAE31D54B8C9721ULL);
    Value *status = BB.CreateCall(StatusFn);
    Value *stat4 = BB.CreateCall(StatFn);
    Value *statusTraced =
        BB.CreateICmpNE(status, ConstantInt::get(i32, 0),
                        "morok.antidbg.watch.status.traced");
    foldLinuxTracerPidVerdict(BB, State, statusTraced, AllowSelfTrace,
                              0x64C2D0B6D8F44A2DULL,
                              0xB9281F3D4E6C507AULL,
                              "morok.antidbg.watch.status");
    foldState(BB, State, stat4, 0x8CB92BA72F3D8DD7ULL,
              "morok.antidbg.watch.stat4");
    Value *statCoherence = packedI32Flag(
        BB, stat4, 1u << 8, "morok.antidbg.watch.stat.coherence.bits",
        "morok.antidbg.watch.stat.coherence.anomaly");
    foldEnforcedFlag(BB, State, statCoherence, 0x7F541C8E92AB6D03ULL,
                     "morok.antidbg.watch.stat.coherence");
    if (SignalMaskFn) {
        Value *sigmask = BB.CreateCall(SignalMaskFn->getFunctionType(),
                                       SignalMaskFn, {},
                                       "morok.antidbg.watch.sigmask");
        foldState(BB, State, sigmask, 0x5C36D8A19E4072BFULL,
                  "morok.antidbg.watch.sigmask");
        Value *unblockable =
            BB.CreateICmpNE(BB.CreateAnd(sigmask, ConstantInt::get(i64, 1),
                                         "morok.antidbg.watch.sigmask.unblockable.bit"),
                            ConstantInt::get(i64, 0),
                            "morok.antidbg.watch.sigmask.unblockable");
        Value *cgtDiverged =
            BB.CreateICmpNE(BB.CreateAnd(sigmask, ConstantInt::get(i64, 2),
                                         "morok.antidbg.watch.sigmask.cgt.bit"),
                            ConstantInt::get(i64, 0),
                            "morok.antidbg.watch.sigmask.cgt.diverged");
        sealFold(BB, unblockable, 0x8E7B1346D5A0C29FULL);
        sealFold(BB, cgtDiverged, 0x42F9C16B8D30A57EULL);
    }
    if (PtraceStopFn) {
        Value *ptraceStop = BB.CreateCall(PtraceStopFn->getFunctionType(),
                                          PtraceStopFn, {},
                                          "morok.antidbg.watch.stopcoh");
        foldState(BB, State, ptraceStop, 0xA63F5B4C91D207E8ULL,
                  "morok.antidbg.watch.stopcoh");
        Value *coherent =
            BB.CreateICmpNE(BB.CreateAnd(ptraceStop, ConstantInt::get(i64, 1),
                                         "morok.antidbg.watch.stopcoh.bit"),
                            ConstantInt::get(i64, 0),
                            "morok.antidbg.watch.stopcoh.coherent");
        sealFold(BB, coherent, 0xD5A127BC904E63F8ULL);
    }
    if (watchBuddy) {
        BB.CreateBr(buddyCheckBB);

        IRBuilder<> CB(buddyCheckBB);
        auto *pid = CB.CreateLoad(ip, BuddyPid, "morok.antidbg.buddy.pid.load");
        pid->setVolatile(true);
        CB.CreateCondBr(
            CB.CreateICmpSGT(pid, ConstantInt::get(ip, 1),
                             "morok.antidbg.buddy.pid.valid"),
            buddyLiveBB, buddyMissingBB);

        IRBuilder<> BuddyB(buddyLiveBB);
        Value *killRc =
            emitLinuxSyscall(BuddyB, M, TT, killNr,
                             {pid, ConstantInt::get(ip, 0)});
        killRc->setName("morok.antidbg.buddy.kill");
        Value *waitRc = emitLinuxSyscall(
            BuddyB, M, TT, wait4Nr,
            {pid, buddyStatus, ConstantInt::get(ip, 1),
             ConstantPointerNull::get(ptr)});
        waitRc->setName("morok.antidbg.buddy.wait");
        Value *missing = BuddyB.CreateOr(
            BuddyB.CreateICmpNE(killRc, ConstantInt::get(ip, 0)),
            BuddyB.CreateICmpEQ(waitRc, pid), "morok.antidbg.buddy.missing");
        foldState(BuddyB, State, waitRc, 0x5B47E91D2C806A3FULL,
                  "morok.antidbg.buddy.wait");
        BuddyB.CreateCondBr(missing, buddyMissingBB, nextBB);

        IRBuilder<> MissingB(buddyMissingBB);
        foldFlag(MissingB, State, ConstantInt::getTrue(ctx),
                 0xDF0E7318A649C2B5ULL, "morok.antidbg.buddy.missing");
        if (SentinelActive) {
            auto *inactive = MissingB.CreateStore(ConstantInt::getFalse(ctx),
                                                  SentinelActive);
            inactive->setVolatile(true);
            inactive->setAlignment(Align(1));
            if (AllowSelfTrace)
                emitLinuxSelfTraceFallback(MissingB, M, State, SentinelActive,
                                           TT,
                                           "morok.antidbg.buddy.ptrace",
                                           0x3E42A7168C9D50BFULL);
        }
        MissingB.CreateBr(nextBB);

        IRBuilder<> NB(nextBB);
        Value *next =
            NB.CreateAdd(iter, ConstantInt::get(i32, 1), "morok.antidbg.next");
        NB.CreateBr(loopBB);
        iter->addIncoming(next, nextBB);
    } else {
        Value *next = BB.CreateAdd(iter, ConstantInt::get(i32, 1));
        BB.CreateBr(loopBB);
        iter->addIncoming(next, bodyBB);
    }

    IRBuilder<> RB(retBB);
    RB.CreateRet(ConstantPointerNull::get(ptr));
    return fn;
}

bool linuxDrSentinelSyscalls(const Triple &TT, std::uint32_t &Fork,
                             std::uint32_t &Getppid, std::uint32_t &Getdents64,
                             std::uint32_t &Wait4, std::uint32_t &Nanosleep,
                             std::uint32_t &Exit) {
    if (TT.getArch() != Triple::x86_64)
        return false;
    Fork = 57;
    Getppid = 110;
    Getdents64 = 217;
    Wait4 = 61;
    Nanosleep = 35;
    Exit = 60;
    return true;
}

bool linuxBuddyLivenessSyscalls(const Triple &TT, std::uint32_t &Kill,
                                std::uint32_t &Wait4) {
    if (TT.getArch() != Triple::x86_64)
        return false;
    Kill = 62;
    Wait4 = 61;
    return true;
}

Value *emitLinuxPtraceRaw(IRBuilder<> &B, Module &M, const Triple &TT,
                          std::uint64_t Request, Value *Pid, Value *Addr,
                          Value *Data, const Twine &Name) {
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    auto *ip = intPtrTy(M);
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr))
        return ConstantInt::getSigned(ip, -1);
    Value *rc = emitLinuxSyscall(
        B, M, TT, ptraceNr, {ConstantInt::get(ip, Request), Pid, Addr, Data});
    rc->setName(Name);
    return rc;
}

struct LinuxYamaScopeSample {
    Value *value;
    Value *ready;
    Value *unreadable;
    Value *mode0;
    Value *mode1;
    Value *mode2;
    Value *mode3;
};

LinuxYamaScopeSample emitLinuxYamaPtraceScopeRead(IRBuilder<> &B, Module &M,
                                                  ir::IRRandom &rng,
                                                  const Triple &TT,
                                                  const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    constexpr std::uint64_t kBufBytes = 4;

    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr)) {
        Value *zero = ConstantInt::get(i32, 0);
        Value *falseV = ConstantInt::getFalse(ctx);
        Value *trueV = ConstantInt::getTrue(ctx);
        return {zero, falseV, trueV, falseV, falseV, falseV, falseV};
    }

    auto *bufTy = ArrayType::get(i8, kBufBytes);
    AllocaInst *buf = B.CreateAlloca(bufTy, nullptr, Name + ".buf");
    B.CreateMemSet(buf, ConstantInt::get(i8, 0),
                   ConstantInt::get(ip, kBufBytes), MaybeAlign(1));
    Value *path =
        ir::emitCloakedSymbol(B, M, "/proc/sys/kernel/yama/ptrace_scope", rng);
    Value *fd = emitLinuxSyscall(B, M, TT, openatNr,
                                 {ConstantInt::getSigned(ip, -100), path,
                                  ConstantInt::get(ip, 0),
                                  ConstantInt::get(ip, 0)});
    fd->setName(Name + ".fd");
    Value *bufPtr = B.CreateInBoundsGEP(
        bufTy, buf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        Name + ".ptr");
    Value *nread = emitLinuxSyscall(
        B, M, TT, readNr, {fd, bufPtr, ConstantInt::get(ip, kBufBytes - 1)});
    nread->setName(Name + ".read.n");
    emitLinuxSyscall(B, M, TT, closeNr, {fd});

    Value *ch = loadAt(B, M, i8, buf, 0ULL, Name + ".ch");
    Value *digit = B.CreateAnd(
        B.CreateICmpUGE(ch, ConstantInt::get(i8, '0'), Name + ".ge0"),
        B.CreateICmpULE(ch, ConstantInt::get(i8, '9'), Name + ".le9"),
        Name + ".digit");
    Value *fdOk =
        B.CreateICmpSGE(fd, ConstantInt::get(ip, 0), Name + ".fd.ok");
    Value *readOk =
        B.CreateICmpSGT(nread, ConstantInt::get(ip, 0), Name + ".read.ok");
    Value *ready = B.CreateAnd(fdOk, B.CreateAnd(readOk, digit),
                               Name + ".ready");
    Value *raw = B.CreateZExt(
        B.CreateSub(ch, ConstantInt::get(i8, '0'), Name + ".raw"), i32,
        Name + ".raw.i32");
    Value *value = B.CreateSelect(ready, raw, ConstantInt::get(i32, 0),
                                  Name + ".value");
    Value *unreadable = B.CreateNot(ready, Name + ".unreadable");
    Value *mode0 = B.CreateAnd(
        ready, B.CreateICmpEQ(value, ConstantInt::get(i32, 0), Name + ".is0"),
        Name + ".mode0");
    Value *mode1 = B.CreateAnd(
        ready, B.CreateICmpEQ(value, ConstantInt::get(i32, 1), Name + ".is1"),
        Name + ".mode1");
    Value *mode2 = B.CreateAnd(
        ready, B.CreateICmpEQ(value, ConstantInt::get(i32, 2), Name + ".is2"),
        Name + ".mode2");
    Value *mode3 = B.CreateAnd(
        ready, B.CreateICmpEQ(value, ConstantInt::get(i32, 3), Name + ".is3"),
        Name + ".mode3");
    return {value, ready, unreadable, mode0, mode1, mode2, mode3};
}

void foldLinuxYamaPtraceScope(IRBuilder<> &B, GlobalVariable *State,
                              const LinuxYamaScopeSample &Scope,
                              const Twine &Name) {
    foldState(B, State, Scope.value, 0x48A6C1D93E0572B4ULL, Name + ".value");
    foldFlag(B, State, Scope.unreadable, 0x75D2B849A13E6C0FULL,
             Name + ".unreadable");
    foldFlag(B, State, Scope.mode0, 0xD6438A1BE59C207FULL, Name + ".mode0");
    foldFlag(B, State, Scope.mode2, 0x2F9B51C84A60D37EULL, Name + ".mode2");
    foldFlag(B, State, Scope.mode3, 0xA91E2D7046B8C35FULL, Name + ".mode3");
}

Function *linuxDrScrubThread(Module &M, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.dr.scrub"))
        return existing;
    std::uint32_t forkNr = 0;
    std::uint32_t getppidNr = 0;
    std::uint32_t getdentsNr = 0;
    std::uint32_t wait4Nr = 0;
    std::uint32_t nanosleepNr = 0;
    std::uint32_t exitNr = 0;
    if (!linuxDrSentinelSyscalls(TT, forkNr, getppidNr, getdentsNr, wait4Nr,
                                 nanosleepNr, exitNr))
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, {ip, ip, ip}, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.dr.scrub", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *tid = fn->getArg(0);
    tid->setName("tid");
    Argument *leader = fn->getArg(1);
    leader->setName("leader");
    Argument *mirrorTarget = fn->getArg(2);
    mirrorTarget->setName("mirror.target");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *seizeBB = BasicBlock::Create(ctx, "seize", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);
    IRBuilder<> B(entry);
    B.CreateCondBr(B.CreateICmpSGT(tid, ConstantInt::get(ip, 1)), seizeBB,
                   retBB);

    IRBuilder<> SB(seizeBB);
    Value *seize =
        emitLinuxPtraceRaw(SB, M, TT, 0x4206, tid, ConstantInt::get(ip, 0),
                           ConstantInt::get(ip, 0), "morok.antidbg.dr.seize");
    Value *interrupt = emitLinuxPtraceRaw(SB, M, TT, 0x4207, tid,
                                          ConstantInt::get(ip, 0),
                                          ConstantInt::get(ip, 0),
                                          "morok.antidbg.dr.interrupt");
    auto *pokeBB = BasicBlock::Create(ctx, "poke", fn);
    SB.CreateCondBr(SB.CreateICmpEQ(interrupt, ConstantInt::get(ip, 0)), pokeBB,
                    retBB);

    IRBuilder<> PB(pokeBB);
    auto *status = PB.CreateAlloca(i32, nullptr, "morok.antidbg.dr.status");
    Value *waitRc = emitLinuxSyscall(
        PB, M, TT, wait4Nr,
        {tid, status, ConstantInt::get(ip, 0), ConstantPointerNull::get(ptr)});
    waitRc->setName("morok.antidbg.dr.wait");
    Value *acc = PB.CreateXor(PB.CreateZExtOrTrunc(waitRc, i64),
                              PB.CreateZExtOrTrunc(seize, i64),
                              "morok.antidbg.dr.acc");
    acc = PB.CreateXor(acc, PB.CreateZExtOrTrunc(interrupt, i64),
                       "morok.antidbg.dr.acc.interrupt");
    Value *canInspect = PB.CreateAnd(
        PB.CreateICmpEQ(waitRc, tid),
        PB.CreateICmpEQ(interrupt, ConstantInt::get(ip, 0)),
        "morok.antidbg.buddy.inspect");
    constexpr std::uint64_t kDebugReg0Offset = 848;
    Value *allZeroed = ConstantInt::getTrue(ctx);
    for (std::uint64_t i = 0; i < 8; ++i) {
        Value *rc = emitLinuxPtraceRaw(
            PB, M, TT, 6, tid, ConstantInt::get(ip, kDebugReg0Offset + i * 8),
            ConstantInt::get(ip, 0), "morok.antidbg.dr.poke");
        allZeroed = PB.CreateAnd(
            allZeroed, PB.CreateICmpEQ(rc, ConstantInt::get(ip, 0)),
            "morok.negative.dr.zero.acc");
        acc = PB.CreateXor(acc, PB.CreateZExtOrTrunc(rc, i64),
                           "morok.antidbg.dr.acc.poke");
    }
    Value *drNotZeroed =
        PB.CreateNot(allZeroed, "morok.negative.dr.notzero");
    acc = PB.CreateXor(acc, PB.CreateZExt(drNotZeroed, i64),
                       "morok.antidbg.dr.acc.negative");
    Value *mirrorDiff = ConstantInt::getFalse(ctx);
    for (std::uint64_t i = 0; i < 4; ++i) {
        Value *addr =
            PB.CreateAdd(mirrorTarget, ConstantInt::get(ip, i * 8),
                         "morok.antidbg.buddy.addr");
        Value *remote =
            emitLinuxPtraceRaw(PB, M, TT, 2, tid, addr, ConstantInt::get(ip, 0),
                               "morok.antidbg.buddy.peek");
        auto *local =
            loadUnaligned(PB, ip, PB.CreateIntToPtr(addr, ptr),
                          "morok.antidbg.buddy.local");
        local->setVolatile(true);
        mirrorDiff = PB.CreateOr(
            mirrorDiff, PB.CreateICmpNE(remote, local),
            "morok.antidbg.buddy.mirror.diff");
    }
    Value *mirrorBad = PB.CreateAnd(
        PB.CreateAnd(canInspect, PB.CreateICmpEQ(tid, leader)),
        mirrorDiff, "morok.antidbg.buddy.mirror.bad");
    Value *cont =
        emitLinuxPtraceRaw(PB, M, TT, 7, tid, ConstantInt::get(ip, 0),
                           ConstantInt::get(ip, 0), "morok.antidbg.dr.cont");
    acc = PB.CreateXor(acc, PB.CreateZExtOrTrunc(cont, i64),
                       "morok.antidbg.dr.acc.cont");
    Value *drBad =
        PB.CreateAnd(canInspect, drNotZeroed, "morok.antidbg.buddy.dr.bad");
    Value *bad = PB.CreateOr(drBad, mirrorBad, "morok.antidbg.buddy.bad");
    PB.CreateRet(PB.CreateZExt(bad, i64));

    IRBuilder<> RB(retBB);
    RB.CreateRet(ConstantInt::get(i64, 0));
    return fn;
}

Function *linuxDrSentinelProcess(Module &M, ir::IRRandom &rng,
                                 const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.linux.dr.sentinel"))
        return existing;
    std::uint32_t forkNr = 0;
    std::uint32_t getppidNr = 0;
    std::uint32_t getdentsNr = 0;
    std::uint32_t wait4Nr = 0;
    std::uint32_t nanosleepNr = 0;
    std::uint32_t exitNr = 0;
    if (!linuxDrSentinelSyscalls(TT, forkNr, getppidNr, getdentsNr, wait4Nr,
                                 nanosleepNr, exitNr))
        return nullptr;
    Function *scrub = linuxDrScrubThread(M, TT);
    if (!scrub)
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i16 = Type::getInt16Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.linux.dr.sentinel", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *loopBB = BasicBlock::Create(ctx, "loop", fn);
    auto *bodyBB = BasicBlock::Create(ctx, "body", fn);
    auto *openOkBB = BasicBlock::Create(ctx, "open.ok", fn);
    auto *readBB = BasicBlock::Create(ctx, "read", fn);
    auto *scanLoopBB = BasicBlock::Create(ctx, "scan.loop", fn);
    auto *scanBodyBB = BasicBlock::Create(ctx, "scan.body", fn);
    auto *scanNextBB = BasicBlock::Create(ctx, "scan.next", fn);
    auto *closeBB = BasicBlock::Create(ctx, "close", fn);
    auto *nextBB = BasicBlock::Create(ctx, "next", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    auto *pathTy = ArrayType::get(i8, 96);
    auto *dirTy = ArrayType::get(i8, 4096);
    auto *tsTy = StructType::get(ctx, {i64, i64});
    AllocaInst *path = B.CreateAlloca(pathTy, nullptr, "morok.antidbg.dr.path");
    AllocaInst *dirBuf =
        B.CreateAlloca(dirTy, nullptr, "morok.antidbg.dr.dirents");
    AllocaInst *ts = B.CreateAlloca(tsTy, nullptr, "morok.antidbg.dr.sleep");
    B.CreateStore(ConstantInt::get(i64, 0), B.CreateStructGEP(tsTy, ts, 0));
    B.CreateStore(ConstantInt::get(i64, 200000000),
                  B.CreateStructGEP(tsTy, ts, 1));
    Value *ppid = emitLinuxSyscall(B, M, TT, getppidNr, {});
    ppid->setName("morok.antidbg.dr.ppid");
    Function *mirrorFn = M.getFunction("main");
    if (!mirrorFn || mirrorFn->isDeclaration())
        mirrorFn = scrub;
    Value *mirrorTarget =
        B.CreatePtrToInt(mirrorFn, ip, "morok.antidbg.buddy.mirror");
    Value *pathPtr = B.CreateInBoundsGEP(
        pathTy, path, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)});
    Value *fmt = ir::emitCloakedSymbol(B, M, "/proc/%ld/task", rng);
    FunctionCallee snprintfFn = M.getOrInsertFunction(
        "snprintf", FunctionType::get(i32, {ptr, ip, ptr}, true));
    B.CreateCall(snprintfFn, {pathPtr, ConstantInt::get(ip, 96), fmt, ppid},
                 "morok.antidbg.dr.path.n");
    B.CreateBr(loopBB);

    IRBuilder<> LB(loopBB);
    auto *iter = LB.CreatePHI(i32, 2, "morok.antidbg.dr.iter");
    iter->addIncoming(ConstantInt::get(i32, 0), entry);
    LB.CreateCondBr(
        LB.CreateICmpULT(iter, ConstantInt::get(i32, kWatchdogMaxIterations),
                         "morok.antidbg.dr.keep"),
        bodyBB, retBB);

    IRBuilder<> BB(bodyBB);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr);
    Value *fdLong = emitLinuxSyscall(BB, M, TT, openatNr,
                                     {ConstantInt::getSigned(ip, -100), pathPtr,
                                      ConstantInt::get(ip, 0x10000),
                                      ConstantInt::get(ip, 0)});
    fdLong->setName("morok.antidbg.dr.fd");
    BB.CreateCondBr(BB.CreateICmpSGE(fdLong, ConstantInt::get(ip, 0)), openOkBB,
                    nextBB);

    IRBuilder<> OKB(openOkBB);
    OKB.CreateBr(readBB);

    IRBuilder<> RB(readBB);
    Value *bufPtr = RB.CreateInBoundsGEP(
        dirTy, dirBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)});
    Value *nread = emitLinuxSyscall(
        RB, M, TT, getdentsNr, {fdLong, bufPtr, ConstantInt::get(ip, 4096)});
    nread->setName("morok.antidbg.dr.getdents");
    RB.CreateCondBr(RB.CreateICmpSGT(nread, ConstantInt::get(ip, 0)),
                    scanLoopBB, closeBB);

    IRBuilder<> SLB(scanLoopBB);
    auto *off = SLB.CreatePHI(ip, 2, "morok.antidbg.dr.dir.off");
    off->addIncoming(ConstantInt::get(ip, 0), readBB);
    SLB.CreateCondBr(SLB.CreateICmpULT(off, nread), scanBodyBB, readBB);

    IRBuilder<> SB(scanBodyBB);
    Value *reclenOff = SB.CreateAdd(off, ConstantInt::get(ip, 16),
                                    "morok.antidbg.dr.reclen.off");
    Value *reclen =
        loadAt(SB, M, i16, dirBuf, reclenOff, "morok.antidbg.dr.reclen");
    Value *nameBase = SB.CreateAdd(off, ConstantInt::get(ip, 19),
                                   "morok.antidbg.dr.name.off");
    Value *tid = ConstantInt::get(ip, 0);
    Value *active = ConstantInt::getTrue(ctx);
    Value *any = ConstantInt::getFalse(ctx);
    for (std::uint64_t i = 0; i < 12; ++i) {
        Value *ch = loadAt(SB, M, i8, dirBuf,
                           SB.CreateAdd(nameBase, ConstantInt::get(ip, i)),
                           "morok.antidbg.dr.name.ch");
        Value *ge0 = SB.CreateICmpUGE(ch, ConstantInt::get(i8, '0'));
        Value *le9 = SB.CreateICmpULE(ch, ConstantInt::get(i8, '9'));
        Value *digit = SB.CreateAnd(active, SB.CreateAnd(ge0, le9),
                                    "morok.antidbg.dr.name.digit");
        Value *dval = SB.CreateZExt(SB.CreateSub(ch, ConstantInt::get(i8, '0')),
                                    ip, "morok.antidbg.dr.name.dval");
        Value *nextTid =
            SB.CreateAdd(SB.CreateMul(tid, ConstantInt::get(ip, 10)), dval,
                         "morok.antidbg.dr.name.tid.next");
        tid = SB.CreateSelect(digit, nextTid, tid, "morok.antidbg.dr.name.tid");
        any = SB.CreateOr(any, digit, "morok.antidbg.dr.name.any");
        active = digit;
    }
    Value *validTid = SB.CreateAnd(any, SB.CreateICmpUGE(tid, ppid),
                                   "morok.antidbg.dr.tid.valid");
    Value *scrubTid = SB.CreateSelect(validTid, tid, ConstantInt::get(ip, 0),
                                      "morok.antidbg.dr.tid");
    Value *scrubBad = SB.CreateCall(scrub->getFunctionType(), scrub,
                                    {scrubTid, ppid, mirrorTarget},
                                    "morok.antidbg.buddy.scrub");
    auto *badBB = BasicBlock::Create(ctx, "buddy.bad", fn);
    SB.CreateCondBr(SB.CreateICmpNE(scrubBad, ConstantInt::get(i64, 0)), badBB,
                    scanNextBB);

    IRBuilder<> BadB(badBB);
    emitLinuxSyscall(BadB, M, TT, exitNr, {ConstantInt::get(ip, 77)});
    BadB.CreateUnreachable();

    IRBuilder<> SNB(scanNextBB);
    Value *safeReclen = SNB.CreateSelect(
        SNB.CreateICmpUGT(reclen, ConstantInt::get(i16, 0)),
        SNB.CreateZExt(reclen, ip), nread, "morok.antidbg.dr.reclen.safe");
    Value *nextOff =
        SNB.CreateAdd(off, safeReclen, "morok.antidbg.dr.dir.next");
    SNB.CreateBr(scanLoopBB);
    off->addIncoming(nextOff, scanNextBB);

    IRBuilder<> CB(closeBB);
    emitLinuxSyscall(CB, M, TT, closeNr, {fdLong});
    CB.CreateBr(nextBB);

    IRBuilder<> NB(nextBB);
    emitLinuxSyscall(NB, M, TT, nanosleepNr,
                     {ts, ConstantPointerNull::get(ptr)});
    Value *livePpid = emitLinuxSyscall(NB, M, TT, getppidNr, {});
    livePpid->setName("morok.antidbg.buddy.ppid.live");
    auto *parentGoneBB = BasicBlock::Create(ctx, "parent.gone", fn);
    auto *parentLiveBB = BasicBlock::Create(ctx, "parent.live", fn);
    NB.CreateCondBr(NB.CreateICmpSLE(livePpid, ConstantInt::get(ip, 1)),
                    parentGoneBB, parentLiveBB);

    IRBuilder<> GoneB(parentGoneBB);
    emitLinuxSyscall(GoneB, M, TT, exitNr, {ConstantInt::get(ip, 0)});
    GoneB.CreateUnreachable();

    IRBuilder<> LiveB(parentLiveBB);
    Value *next =
        LiveB.CreateAdd(iter, ConstantInt::get(i32, 1), "morok.antidbg.dr.next");
    LiveB.CreateBr(loopBB);
    iter->addIncoming(next, parentLiveBB);

    IRBuilder<> RetB(retBB);
    RetB.CreateRetVoid();
    return fn;
}

bool emitLinuxDrSentinelStart(IRBuilder<> &B, Module &M, GlobalVariable *State,
                              GlobalVariable *BuddyPid,
                              GlobalVariable *SentinelActive,
                              ir::IRRandom &rng, const Triple &TT) {
    std::uint32_t forkNr = 0;
    std::uint32_t getppidNr = 0;
    std::uint32_t getdentsNr = 0;
    std::uint32_t wait4Nr = 0;
    std::uint32_t nanosleepNr = 0;
    std::uint32_t exitNr = 0;
    if (!linuxDrSentinelSyscalls(TT, forkNr, getppidNr, getdentsNr, wait4Nr,
                                 nanosleepNr, exitNr))
        return false;
    Function *helper = linuxDrSentinelProcess(M, rng, TT);
    if (!helper || !BuddyPid || !SentinelActive)
        return false;

    LLVMContext &ctx = M.getContext();
    auto *ip = intPtrTy(M);
    Function *ctor = B.GetInsertBlock()->getParent();
    LinuxYamaScopeSample yama =
        emitLinuxYamaPtraceScopeRead(B, M, rng, TT, "morok.antidbg.yama.dr");
    foldLinuxYamaPtraceScope(B, State, yama, "morok.antidbg.yama.dr");
    Value *pid = emitLinuxSyscall(B, M, TT, forkNr, {});
    pid->setName("morok.antidbg.dr.fork");
    foldState(B, State, pid, 0xD8A18F4C2E7B6A95ULL, "morok.antidbg.dr.fork");

    auto *childBB = BasicBlock::Create(ctx, "morok.antidbg.dr.child", ctor);
    auto *parentBB = BasicBlock::Create(ctx, "morok.antidbg.dr.parent", ctor);
    auto *setPtracerBB =
        BasicBlock::Create(ctx, "morok.antidbg.dr.ptracer", ctor);
    auto *contBB = BasicBlock::Create(ctx, "morok.antidbg.dr.cont", ctor);
    B.CreateCondBr(B.CreateICmpEQ(pid, ConstantInt::get(ip, 0)), childBB,
                   parentBB);

    IRBuilder<> ChildB(childBB);
    emitLinuxDumpableHardening(ChildB, M, State, TT,
                               "morok.antidbg.dr.child.dumpable",
                               0x2C5B81D6F407A39EULL);
    emitLinuxPrctlDirect(ChildB, M, TT, 0x59616D61, 0, 0, 0, 0,
                         "morok.antidbg.dr.child.ptracer");
    emitLinuxPrctlDirect(ChildB, M, TT, 38, 1, 0, 0, 0,
                         "morok.antidbg.dr.child.no_new_privs");
    ChildB.CreateCall(helper->getFunctionType(), helper, {});
    emitLinuxSyscall(ChildB, M, TT, exitNr, {ConstantInt::get(ip, 0)});
    ChildB.CreateUnreachable();

    IRBuilder<> ParentB(parentBB);
    auto *buddyStore = ParentB.CreateStore(pid, BuddyPid);
    buddyStore->setVolatile(true);
    auto *inactive =
        ParentB.CreateStore(
            ParentB.CreateAnd(
                ParentB.CreateICmpSGT(pid, ConstantInt::get(ip, 0),
                                      "morok.antidbg.dr.pid.valid"),
                ParentB.CreateOr(yama.mode0, yama.unreadable,
                                 "morok.antidbg.dr.ptracer.scope.open"),
                "morok.antidbg.dr.ptracer.open.active"),
            SentinelActive);
    inactive->setVolatile(true);
    inactive->setAlignment(Align(1));
    ParentB.CreateCondBr(
        ParentB.CreateAnd(
            ParentB.CreateICmpSGT(pid, ConstantInt::get(ip, 0),
                                  "morok.antidbg.dr.pid.valid.ptracer"),
            yama.mode1, "morok.antidbg.dr.ptracer.scope1"),
        setPtracerBB, contBB);

    IRBuilder<> PB(setPtracerBB);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr);
    Value *prctlRc = emitLinuxSyscall(
        PB, M, TT, prctlNr,
        {ConstantInt::get(ip, 0x59616D61), pid, ConstantInt::get(ip, 0),
         ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)});
    prctlRc->setName("morok.antidbg.dr.ptracer.rc");
    // PR_SET_PTRACER can be denied by Yama, seccomp, or container policy on a
    // clean host.  That denial disables the DR sentinel; later /proc checks
    // provide the corroborated debugger evidence that may poison State.
    Value *ptracerRestricted =
        PB.CreateICmpNE(prctlRc, ConstantInt::get(ip, 0),
                        "morok.antidbg.dr.ptracer.restricted");
    Value *ptracerOk =
        PB.CreateNot(ptracerRestricted, "morok.antidbg.dr.ptracer.ok");
    auto *activeStore = PB.CreateStore(ptracerOk, SentinelActive);
    activeStore->setVolatile(true);
    activeStore->setAlignment(Align(1));
    PB.CreateBr(contBB);

    B.SetInsertPoint(contBB);
    return true;
}

void emitLinuxHardening(IRBuilder<> &B, Module &M, GlobalVariable *State,
                        ir::IRRandom &rng, const Triple &TT,
                        bool PreservePtracer = false) {
    emitLinuxDumpableHardening(B, M, State, TT,
                               "morok.antidbg.harden.dumpable",
                               0xE41B63D79A2508CFULL);
    if (!PreservePtracer) {
        LinuxYamaScopeSample yama = emitLinuxYamaPtraceScopeRead(
            B, M, rng, TT, "morok.antidbg.yama.harden");
        foldLinuxYamaPtraceScope(B, State, yama, "morok.antidbg.yama.harden");

        Function *fn = B.GetInsertBlock()->getParent();
        auto *setPtracerBB =
            BasicBlock::Create(M.getContext(), "morok.antidbg.yama.ptracer", fn);
        auto *contBB =
            BasicBlock::Create(M.getContext(), "morok.antidbg.yama.cont", fn);
        B.CreateCondBr(yama.mode1, setPtracerBB, contBB);

        IRBuilder<> PB(setPtracerBB);
        emitLinuxPrctlDirect(PB, M, TT, 0x59616D61, 0, 0, 0, 0,
                             "morok.antidbg.yama.ptracer.rc");
        PB.CreateBr(contBB);
        B.SetInsertPoint(contBB);
    }
    emitLinuxPrctlDirect(B, M, TT, 38, 1, 0, 0, 0,
                         "morok.antidbg.harden.no_new_privs");
}

bool linuxSyscallNumbers(const Triple &TT, std::uint32_t &Ptrace,
                         std::uint32_t &ProcessVmReadv,
                         std::uint32_t &ProcessVmWritev) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        Ptrace = 101;
        ProcessVmReadv = 310;
        ProcessVmWritev = 311;
        return true;
    case Triple::aarch64:
        Ptrace = 117;
        ProcessVmReadv = 270;
        ProcessVmWritev = 271;
        return true;
    default:
        return false;
    }
}

bool linuxSeccompInstall(const Triple &TT, std::uint32_t &Seccomp,
                         std::uint32_t &AuditArch, bool &RejectX32) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        Seccomp = 317;
        AuditArch = 0xC000003E; // AUDIT_ARCH_X86_64
        RejectX32 = true;
        return true;
    case Triple::aarch64:
        Seccomp = 277;
        AuditArch = 0xC00000B7; // AUDIT_ARCH_AARCH64
        RejectX32 = false;
        return true;
    default:
        return false;
    }
}

bool linuxSeccompTraceSyscalls(const Triple &TT, std::uint32_t &RtSigaction,
                               std::uint32_t &Sentinel,
                               ir::IRRandom &rng) {
    constexpr std::uint32_t kReservedSentinelBase = 0x3fff0000U;
    constexpr std::uint32_t kReservedSentinelSpan = 0x1000U;
    switch (TT.getArch()) {
    case Triple::x86_64:
        RtSigaction = 13;
        Sentinel = kReservedSentinelBase + rng.range(kReservedSentinelSpan);
        return true;
    case Triple::aarch64:
        RtSigaction = 134;
        Sentinel = kReservedSentinelBase + rng.range(kReservedSentinelSpan);
        return true;
    default:
        return false;
    }
}

struct LinuxRawSigactionLayout {
    std::uint64_t actionSize = 0;
    std::uint64_t flagsOffset = 0;
    std::uint64_t restorerOffset = 0;
    std::uint64_t sigsetSize = 8;
    std::uint64_t flags = 0;
    bool needsRestorer = false;
};

bool linuxRawSigactionLayout(const Triple &TT, LinuxRawSigactionLayout &L) {
    if (!TT.isOSLinux())
        return false;
    constexpr std::uint64_t kSaSiginfo = 4;
    switch (TT.getArch()) {
    case Triple::x86_64:
        L.actionSize = 152;
        L.flagsOffset = 8;
        L.restorerOffset = 16;
        L.sigsetSize = 8;
        L.flags = kSaSiginfo | 0x04000000ULL; // SA_RESTORER
        L.needsRestorer = true;
        return true;
    case Triple::x86:
        L.actionSize = 20;
        L.flagsOffset = 4;
        L.restorerOffset = 8;
        L.sigsetSize = 8;
        L.flags = kSaSiginfo | 0x04000000ULL; // SA_RESTORER
        L.needsRestorer = true;
        return true;
    case Triple::aarch64:
        L.actionSize = 32;
        L.flagsOffset = 8;
        L.sigsetSize = 8;
        L.flags = kSaSiginfo;
        L.needsRestorer = false;
        return true;
    default:
        return false;
    }
}

GlobalVariable *linuxSeccompSigsysResult(Module &M) {
    if (auto *existing =
            M.getGlobalVariable("morok.antidbg.seccomp.sigsys.slot",
                                /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i32, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i32, 0), "morok.antidbg.seccomp.sigsys.slot");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    gv->setAlignment(Align(4));
    return gv;
}

Function *linuxSeccompSigsysHandler(Module &M) {
    if (Function *existing = M.getFunction("morok.antidbg.seccomp.sigsys"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), {i32, ptr, ptr}, false),
        GlobalValue::PrivateLinkage, "morok.antidbg.seccomp.sigsys", &M);
    fn->addFnAttr(Attribute::NoInline);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *st = B.CreateStore(ConstantInt::get(i32, 1),
                             linuxSeccompSigsysResult(M));
    st->setVolatile(true);
    st->setAlignment(Align(4));
    B.CreateRetVoid();
    return fn;
}

Function *linuxRtSigreturnRestorer(Module &M, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antidbg.seccomp.sigreturn"))
        return existing;
    if (TT.getArch() != Triple::x86_64 && TT.getArch() != Triple::x86)
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), false),
        GlobalValue::PrivateLinkage, "morok.antidbg.seccomp.sigreturn", &M);
    fn->addFnAttr(Attribute::Naked);
    fn->addFnAttr(Attribute::NoUnwind);
    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *asmTy = FunctionType::get(Type::getVoidTy(ctx), false);
    const bool x86 = TT.getArch() == Triple::x86;
    InlineAsm *IA = InlineAsm::get(
        asmTy, x86 ? "mov $$173, %eax\nint $$0x80"
                   : "mov $$15, %rax\nsyscall",
        x86 ? "~{eax},~{memory},~{dirflag},~{fpsr},~{flags}"
            : "~{rax},~{rcx},~{r11},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    B.CreateCall(asmTy, IA);
    B.CreateUnreachable();
    return fn;
}

bool linuxFaultFlowSyscalls(const Triple &TT, std::uint32_t &RtSigaction,
                            std::uint32_t &Sigaltstack) {
    if (!TT.isOSLinux())
        return false;
    switch (TT.getArch()) {
    case Triple::x86_64:
        RtSigaction = 13;
        Sigaltstack = 131;
        return true;
    case Triple::aarch64:
        RtSigaction = 134;
        Sigaltstack = 132;
        return true;
    default:
        return false;
    }
}

struct LinuxFaultFlowLayout {
    std::uint64_t pcSlotOffset = 0;
    std::uint64_t siginfoAddrOffset = 16;
    std::uint32_t instructionBytes = 0;
    std::int32_t sigIll = 4;
};

bool linuxFaultFlowLayout(const Triple &TT, LinuxFaultFlowLayout &L) {
    if (!TT.isOSLinux())
        return false;
    switch (TT.getArch()) {
    case Triple::x86_64:
        L.pcSlotOffset = 168; // ucontext_t.uc_mcontext.gregs[REG_RIP]
        L.instructionBytes = 2;
        return true;
    case Triple::aarch64:
        // glibc aarch64 ucontext_t: uc_mcontext starts at offset 176;
        // mcontext_t.pc follows fault_address, regs[31], and sp:
        // 176 + 8 + (31 * 8) + 8 = 440. Offset 432 is saved sp.
        L.pcSlotOffset = 440;
        L.instructionBytes = 4;
        return true;
    default:
        return false;
    }
}

GlobalVariable *linuxFaultFlowSentinel(Module &M) {
    if (auto *existing =
            M.getGlobalVariable("morok.antidbg.faultcf.sentinel",
                                /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, 0), "morok.antidbg.faultcf.sentinel");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    gv->setAlignment(Align(8));
    return gv;
}

GlobalVariable *linuxFaultFlowToken(Module &M) {
    if (auto *existing =
            M.getGlobalVariable("morok.antidbg.faultcf.token",
                                /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, 0), "morok.antidbg.faultcf.token");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    gv->setAlignment(Align(8));
    return gv;
}

GlobalVariable *linuxFaultFlowExpectedSig(Module &M) {
    if (auto *existing =
            M.getGlobalVariable("morok.antidbg.faultcf.sig",
                                /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(M, i32, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(i32, 0),
                                  "morok.antidbg.faultcf.sig");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    gv->setAlignment(Align(4));
    return gv;
}

Function *linuxFaultFlowHandler(Module &M, GlobalVariable *State,
                                const LinuxFaultFlowLayout &Layout) {
    if (Function *existing = M.getFunction("morok.antidbg.faultcf.handler"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), {i32, ptr, ptr}, false),
        GlobalValue::PrivateLinkage, "morok.antidbg.faultcf.handler", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *sig = fn->getArg(0);
    sig->setName("sig");
    Argument *info = fn->getArg(1);
    info->setName("info");
    Argument *uctx = fn->getArg(2);
    uctx->setName("uctx");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *handledBB = BasicBlock::Create(ctx, "handled", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    Value *expectedSig =
        B.CreateLoad(i32, linuxFaultFlowExpectedSig(M),
                     "morok.antidbg.faultcf.sig.expected");
    cast<LoadInst>(expectedSig)->setVolatile(true);
    Value *sigOk = B.CreateICmpEQ(sig, expectedSig,
                                  "morok.antidbg.faultcf.sig.match");
    Value *ctxOk = B.CreateICmpNE(uctx, ConstantPointerNull::get(ptr),
                                  "morok.antidbg.faultcf.ctx");
    Value *infoOk = B.CreateICmpNE(info, ConstantPointerNull::get(ptr),
                                   "morok.antidbg.faultcf.info");
    B.CreateCondBr(B.CreateAnd(sigOk, B.CreateAnd(ctxOk, infoOk),
                               "morok.antidbg.faultcf.ready"),
                   handledBB, retBB);

    IRBuilder<> HB(handledBB);
    Value *pc = loadAt(HB, M, ip, uctx, Layout.pcSlotOffset,
                       "morok.antidbg.faultcf.pc");
    Value *nextPc =
        HB.CreateAdd(pc, ConstantInt::get(ip, Layout.instructionBytes),
                     "morok.antidbg.faultcf.pc.next");
    storeAt(HB, M, uctx, Layout.pcSlotOffset, nextPc,
            "morok.antidbg.faultcf.advance.pc");
    Value *token =
        HB.CreateLoad(i64, linuxFaultFlowToken(M),
                      "morok.antidbg.faultcf.token.v");
    cast<LoadInst>(token)->setVolatile(true);
    auto *sentinel = HB.CreateStore(token, linuxFaultFlowSentinel(M));
    sentinel->setVolatile(true);
    sentinel->setAlignment(Align(8));
    Value *fault = loadAt(HB, M, ip, info, Layout.siginfoAddrOffset,
                          "morok.antidbg.faultcf.si.addr");
    foldState(HB, State, fault, 0xB647D1E93A205C8FULL,
              "morok.antidbg.faultcf.addr.mix");
    foldState(HB, State, pc, 0x64A91C0BE73D528FULL,
              "morok.antidbg.faultcf.pc.mix");
    foldState(HB, State, token, 0xD38F24A10B6C95E7ULL,
              "morok.antidbg.faultcf.token.mix");
    HB.CreateBr(retBB);

    IRBuilder<> RB(retBB);
    RB.CreateRetVoid();
    return fn;
}

