Value *sandboxNeedleByte(IRBuilder<> &B, Value *Salt, std::uint8_t Plain,
                         std::uint32_t Site, const Twine &Name) {
    auto *i32 = Type::getInt32Ty(B.getContext());
    const std::uint32_t mix =
        (0x9E3779B9u * (Site + 1u)) ^ (0xA5C3D217u + (Site << 7));
    std::uint32_t key = ((mix >> ((Site & 3u) * 8u)) ^ mix ^ 0x5Du) & 0xffu;
    if (key == 0)
        key = 0xB7u;
    const std::uint32_t bias =
        ((0x6Du + Site * 29u) ^ (mix >> 11) ^ (Site << 3)) & 0xffu;
    const std::uint32_t encoded =
        ((static_cast<std::uint32_t>(Plain) + bias) & 0xffu) ^ key;
    Value *saltByte = B.CreateAnd(Salt, ConstantInt::get(i32, 0xff),
                                  Name + ".salt");
    Value *dynKey =
        B.CreateXor(ConstantInt::get(i32, key), saltByte, Name + ".key");
    Value *mixed =
        B.CreateXor(ConstantInt::get(i32, encoded), dynKey, Name + ".mix");
    Value *unbiased =
        B.CreateSub(mixed, ConstantInt::get(i32, bias), Name + ".unbias");
    return B.CreateAnd(unbiased, ConstantInt::get(i32, 0xff), Name);
}

Value *emitQemuBrandMatch(IRBuilder<> &B, Module &M) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    Value *extLeaf = emitCpuid(B, M, ConstantInt::get(i32, 0x80000000u),
                               ConstantInt::get(i32, 0));
    Value *maxExt =
        cpuidReg(B, extLeaf, 0, "morok.antihook.sandbox.brand.max");
    Value *brandAvailable = B.CreateICmpUGE(
        maxExt, ConstantInt::get(i32, 0x80000004u),
        "morok.antihook.sandbox.brand.available");

    auto *saltLoad = B.CreateLoad(i32, sandboxBrandSalt(M),
                                  "morok.antihook.sandbox.brand.salt.load");
    saltLoad->setVolatile(true);
    SmallVector<Value *, 48> bytes;
    bytes.reserve(48);
    for (std::uint32_t leaf = 0; leaf < 3; ++leaf) {
        Value *brandLeaf = emitCpuid(
            B, M, ConstantInt::get(i32, 0x80000002u + leaf),
            ConstantInt::get(i32, 0));
        for (unsigned reg = 0; reg < 4; ++reg) {
            Value *word = cpuidReg(
                B, brandLeaf, reg,
                Twine("morok.antihook.sandbox.brand.word.") + Twine(leaf) +
                    "." + Twine(reg));
            for (unsigned byte = 0; byte < 4; ++byte) {
                Value *shifted =
                    byte == 0
                        ? word
                        : B.CreateLShr(
                              word, ConstantInt::get(i32, byte * 8),
                              Twine("morok.antihook.sandbox.brand.shift.") +
                                  Twine(bytes.size()));
                bytes.push_back(B.CreateAnd(
                    shifted, ConstantInt::get(i32, 0xff),
                    Twine("morok.antihook.sandbox.brand.byte.") +
                        Twine(bytes.size())));
            }
        }
    }

    const std::array<std::uint8_t, 4> qemu = {
        std::uint8_t{0x51}, std::uint8_t{0x45}, std::uint8_t{0x4D},
        std::uint8_t{0x55}};
    Value *any = ConstantInt::getFalse(ctx);
    std::uint32_t site = 0;
    for (std::size_t offset = 0; offset + qemu.size() <= bytes.size();
         ++offset) {
        Value *window = ConstantInt::getTrue(ctx);
        for (std::size_t i = 0; i < qemu.size(); ++i) {
            Value *needle = sandboxNeedleByte(
                B, saltLoad, qemu[i], site++,
                Twine("morok.antihook.sandbox.qemu.brand.needle.") +
                    Twine(offset) + "." + Twine(i));
            Value *eq = B.CreateICmpEQ(
                bytes[offset + i], needle,
                Twine("morok.antihook.sandbox.qemu.brand.eq.") +
                    Twine(offset) + "." + Twine(i));
            window = B.CreateAnd(
                window, eq,
                Twine("morok.antihook.sandbox.qemu.brand.window.") +
                    Twine(offset) + "." + Twine(i));
        }
        any = B.CreateOr(any, window,
                         Twine("morok.antihook.sandbox.qemu.brand.any.") +
                             Twine(offset));
    }
    return B.CreateAnd(brandAvailable, any,
                       "morok.antihook.sandbox.qemu.brand");
}

Function *sandboxTbTimingTarget(Module &M) {
    if (Function *existing = M.getFunction("morok.antihook.sandbox.tb.target"))
        return existing;
    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, {i64}, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.sandbox.tb.target", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *seed = fn->getArg(0);
    seed->setName("seed");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *state = B.CreateLoad(i64, sandboxTbState(M),
                               "morok.antihook.sandbox.tb.state.load");
    state->setVolatile(true);
    Value *x = B.CreateXor(seed, state, "morok.antihook.sandbox.tb.mix");
    for (unsigned i = 0; i < 10; ++i) {
        Value *lo = B.CreateShl(x, ConstantInt::get(i64, (i % 7) + 3),
                                Twine("morok.antihook.sandbox.tb.lo.") +
                                    Twine(i));
        Value *hi = B.CreateLShr(x, ConstantInt::get(i64, (i % 5) + 11),
                                 Twine("morok.antihook.sandbox.tb.hi.") +
                                     Twine(i));
        x = B.CreateAdd(
            B.CreateXor(lo, hi,
                        Twine("morok.antihook.sandbox.tb.xor.") + Twine(i)),
            ConstantInt::get(i64,
                             0x9E3779B97F4A7C15ULL ^
                                 (0xD1B54A32D192ED03ULL * (i + 1))),
            Twine("morok.antihook.sandbox.tb.round.") + Twine(i));
    }
    auto *st = B.CreateStore(x, sandboxTbState(M));
    st->setVolatile(true);
    B.CreateRet(x);
    return fn;
}

Value *emitSandboxTbTiming(IRBuilder<> &B, Module &M, AllocaInst *Score) {
    Function *target = sandboxTbTimingTarget(M);
    auto *i64 = Type::getInt64Ty(M.getContext());
    Value *seed = B.CreatePtrToInt(target, i64,
                                   "morok.antihook.sandbox.tcg.tb.seed");
    Value *t0 = emitRdtscp(B, M);
    Value *coldResult =
        B.CreateCall(target->getFunctionType(), target, {seed},
                     "morok.antihook.sandbox.tcg.tb.cold.result");
    Value *t1 = emitRdtscp(B, M);
    Value *warmResult =
        B.CreateCall(target->getFunctionType(), target, {coldResult},
                     "morok.antihook.sandbox.tcg.tb.warm.result");
    Value *t2 = emitRdtscp(B, M);
    Value *cold = B.CreateSub(t1, t0, "morok.antihook.sandbox.tcg.tb.cold");
    Value *warm = B.CreateSub(t2, t1, "morok.antihook.sandbox.tcg.tb.warm");
    Value *clockOk = B.CreateAnd(
        B.CreateICmpUGT(t1, t0, "morok.antihook.sandbox.tcg.tb.t1.ok"),
        B.CreateICmpUGT(t2, t1, "morok.antihook.sandbox.tcg.tb.t2.ok"),
        "morok.antihook.sandbox.tcg.tb.clock.ok");
    Value *warmScaled =
        B.CreateShl(warm, ConstantInt::get(i64, 3),
                    "morok.antihook.sandbox.tcg.tb.warm.scaled");
    Value *ratio = B.CreateAnd(
        B.CreateICmpUGT(cold, warmScaled,
                        "morok.antihook.sandbox.tcg.tb.ratio"),
        B.CreateICmpUGT(cold, ConstantInt::get(i64, 20000),
                        "morok.antihook.sandbox.tcg.tb.floor"),
        "morok.antihook.sandbox.tcg.tb.slow");
    Value *resultOk =
        B.CreateICmpNE(warmResult, ConstantInt::get(i64, 0),
                       "morok.antihook.sandbox.tcg.tb.result.ok");
    Value *hit =
        B.CreateAnd(clockOk, B.CreateAnd(ratio, resultOk),
                    "morok.antihook.sandbox.tcg.tb.hit");
    incrementDiff(B, Score, hit, "morok.antihook.sandbox.tcg.tb");
    return hit;
}

Value *emitSandboxSmcLatency(IRBuilder<> &B, Module &M, const Triple &TT,
                           AllocaInst *Score) {
    if (intPtrTy(M)->getBitWidth() != 64 ||
        (!TT.isOSLinux() && !TT.isOSDarwin() && !TT.isOSWindows()))
        return nullptr;
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    Function *target = dbiSmcTarget(M);
    Function *parent = B.GetInsertBlock()->getParent();
    Value *targetAddr =
        B.CreatePtrToInt(target, ip, "morok.antihook.sandbox.smc.addr");
    Value *page = B.CreateAnd(targetAddr, ConstantInt::get(ip, ~0xfffULL),
                              "morok.antihook.sandbox.smc.page");
    Value *codePtr =
        B.CreateIntToPtr(targetAddr, ptr, "morok.antihook.sandbox.smc.ptr");
    Value *protectOk = ConstantInt::getFalse(ctx);
    if (TT.isOSLinux()) {
        Value *rc = emitLinuxMprotect(B, M, TT, page, ConstantInt::get(ip, 4096),
                                      ConstantInt::get(i32, 7));
        rc->setName("morok.antihook.sandbox.smc.mprotect.rwx");
        protectOk = B.CreateICmpEQ(rc, ConstantInt::get(i32, 0),
                                   "morok.antihook.sandbox.smc.rwx.ok");
    } else if (TT.isOSDarwin()) {
        Value *rc = emitDarwinMprotect(B, M, TT, page, ConstantInt::get(ip, 4096),
                                       ConstantInt::get(i32, 7));
        rc->setName("morok.antihook.sandbox.smc.mprotect.rwx");
        protectOk = B.CreateICmpEQ(rc, ConstantInt::get(i32, 0),
                                   "morok.antihook.sandbox.smc.rwx.ok");
    } else if (TT.isOSWindows()) {
        auto *oldProt =
            B.CreateAlloca(i32, nullptr, "morok.antihook.sandbox.smc.old");
        FunctionCallee virtualProtect = M.getOrInsertFunction(
            "VirtualProtect", FunctionType::get(i32, {ptr, ip, i32, ptr}, false));
        Value *rc = B.CreateCall(
            virtualProtect,
            {B.CreateIntToPtr(page, ptr), ConstantInt::get(ip, 4096),
             ConstantInt::get(i32, 0x40), oldProt},
            "morok.antihook.sandbox.smc.virtualprotect.rwx");
        protectOk = B.CreateICmpNE(rc, ConstantInt::get(i32, 0),
                                   "morok.antihook.sandbox.smc.rwx.ok");
    } else {
        return nullptr;
    }

    BasicBlock *preBB = B.GetInsertBlock();
    auto *hotBB = BasicBlock::Create(ctx, "morok.antihook.sandbox.smc", parent);
    auto *afterBB =
        BasicBlock::Create(ctx, "morok.antihook.sandbox.after.smc", parent);
    B.CreateCondBr(protectOk, hotBB, afterBB);

    IRBuilder<> HB(hotBB);
    auto *oldByte =
        HB.CreateLoad(i8, codePtr, "morok.antihook.sandbox.smc.byte");
    oldByte->setVolatile(true);
    auto *touch = HB.CreateStore(oldByte, codePtr);
    touch->setVolatile(true);
    if (TT.isOSLinux()) {
        Value *rc = emitLinuxMprotect(HB, M, TT, page,
                                      ConstantInt::get(ip, 4096),
                                      ConstantInt::get(i32, 5));
        rc->setName("morok.antihook.sandbox.smc.mprotect.rx");
    } else if (TT.isOSDarwin()) {
        Value *rc = emitDarwinMprotect(HB, M, TT, page,
                                       ConstantInt::get(ip, 4096),
                                       ConstantInt::get(i32, 5));
        rc->setName("morok.antihook.sandbox.smc.mprotect.rx");
    } else {
        auto *oldProt2 =
            HB.CreateAlloca(i32, nullptr, "morok.antihook.sandbox.smc.old2");
        FunctionCallee virtualProtect = M.getOrInsertFunction(
            "VirtualProtect", FunctionType::get(i32, {ptr, ip, i32, ptr}, false));
        HB.CreateCall(virtualProtect,
                      {HB.CreateIntToPtr(page, ptr),
                       ConstantInt::get(ip, 4096), ConstantInt::get(i32, 0x20),
                       oldProt2},
                      "morok.antihook.sandbox.smc.virtualprotect.rx");
    }
    Value *mid = emitRdtscp(HB, M);
    Value *first =
        HB.CreateCall(target->getFunctionType(), target, {},
                      "morok.antihook.sandbox.smc.first.result");
    Value *t1 = emitRdtscp(HB, M);
    Value *second =
        HB.CreateCall(target->getFunctionType(), target, {},
                      "morok.antihook.sandbox.smc.second.result");
    Value *t2 = emitRdtscp(HB, M);
    Value *flush =
        HB.CreateSub(t1, mid, "morok.antihook.sandbox.smc.flush");
    Value *warm = HB.CreateSub(t2, t1, "morok.antihook.sandbox.smc.warm");
    Value *clockOk = HB.CreateAnd(
        HB.CreateICmpUGT(t1, mid, "morok.antihook.sandbox.smc.t1.ok"),
        HB.CreateICmpUGT(t2, t1, "morok.antihook.sandbox.smc.t2.ok"),
        "morok.antihook.sandbox.smc.clock.ok");
    Value *warmScaled =
        HB.CreateShl(warm, ConstantInt::get(i64, 3),
                     "morok.antihook.sandbox.smc.warm.scaled");
    Value *slow = HB.CreateAnd(
        HB.CreateICmpUGT(flush, warmScaled,
                         "morok.antihook.sandbox.smc.ratio"),
        HB.CreateICmpUGT(flush, ConstantInt::get(i64, 20000),
                         "morok.antihook.sandbox.smc.floor"),
        "morok.antihook.sandbox.smc.slow");
    Value *resultsOk = HB.CreateAnd(
        HB.CreateICmpEQ(first, ConstantInt::get(i32, 0x13579BDFu),
                        "morok.antihook.sandbox.smc.first.ok"),
        HB.CreateICmpEQ(second, ConstantInt::get(i32, 0x13579BDFu),
                        "morok.antihook.sandbox.smc.second.ok"),
        "morok.antihook.sandbox.smc.result.ok");
    Value *hit =
        HB.CreateAnd(clockOk, HB.CreateAnd(slow, resultsOk),
                     "morok.antihook.sandbox.smc.flush.hit");
    incrementDiff(HB, Score, hit, "morok.antihook.sandbox.smc.flush");
    HB.CreateBr(afterBB);

    IRBuilder<> AB(afterBB);
    auto *observed =
        AB.CreatePHI(Type::getInt1Ty(ctx), 2,
                     "morok.antihook.sandbox.smc.flush.observed");
    observed->addIncoming(ConstantInt::getFalse(ctx), preBB);
    observed->addIncoming(hit, hotBB);
    B.SetInsertPoint(afterBB);
    return observed;
}

Value *emitSandboxCpuidExitLatency(IRBuilder<> &B, Module &M,
                                   AllocaInst *Score, AllocaInst *Coherence,
                                   Value *IdentityEvidence) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    SmallVector<Value *, 8> nakedSamples;
    SmallVector<Value *, 8> leaf0Samples;
    SmallVector<Value *, 8> hvLeafSamples;
    SmallVector<Value *, 8> varianceSamples;
    nakedSamples.reserve(7);
    leaf0Samples.reserve(7);
    hvLeafSamples.reserve(7);
    varianceSamples.reserve(7);

    for (unsigned sample = 0; sample < 7; ++sample) {
        Value *nakedStart = emitRdtscp(B, M);
        Value *nakedEnd = emitRdtscp(B, M);
        Value *nakedDelta =
            B.CreateSub(nakedEnd, nakedStart,
                        "morok.antihook.sandbox.cpuid.naked.delta");
        nakedSamples.push_back(nakedDelta);

        Value *leaf0Start = emitRdtscp(B, M);
        (void)emitCpuid(B, M, ConstantInt::get(i32, 0),
                        ConstantInt::get(i32, sample & 1u));
        Value *leaf0End = emitRdtscp(B, M);
        Value *leaf0Delta =
            B.CreateSub(leaf0End, leaf0Start,
                        "morok.antihook.sandbox.cpuid.leaf0.delta");
        leaf0Samples.push_back(leaf0Delta);

        Value *hvStart = emitRdtscp(B, M);
        (void)emitCpuid(B, M, ConstantInt::get(i32, 0x40000000u),
                        ConstantInt::get(i32, sample & 1u));
        Value *hvEnd = emitRdtscp(B, M);
        Value *hvDelta =
            B.CreateSub(hvEnd, hvStart,
                        "morok.antihook.sandbox.cpuid.hvleaf.delta");
        hvLeafSamples.push_back(hvDelta);

        Value *hvSlower =
            B.CreateICmpUGT(hvDelta, leaf0Delta,
                            "morok.antihook.sandbox.cpuid.hvleaf.gt");
        Value *variance = B.CreateSelect(
            hvSlower,
            B.CreateSub(hvDelta, leaf0Delta,
                        "morok.antihook.sandbox.cpuid.hvleaf.minus.leaf0"),
            B.CreateSub(leaf0Delta, hvDelta,
                        "morok.antihook.sandbox.cpuid.leaf0.minus.hvleaf"),
            "morok.antihook.sandbox.cpuid.leaf.variance");
        varianceSamples.push_back(variance);
    }

    auto sortSamples = [&](SmallVector<Value *, 8> samples,
                           const Twine &prefix) {
        for (unsigned i = 0; i < samples.size(); ++i) {
            for (unsigned j = i + 1; j < samples.size(); ++j) {
                Value *swap = B.CreateICmpUGT(samples[i], samples[j],
                                             prefix + ".gt");
                Value *lo = B.CreateSelect(swap, samples[j], samples[i],
                                           prefix + ".lo");
                Value *hi = B.CreateSelect(swap, samples[i], samples[j],
                                           prefix + ".hi");
                samples[i] = lo;
                samples[j] = hi;
            }
        }
        return samples;
    };

    SmallVector<Value *, 8> sortedNaked =
        sortSamples(nakedSamples, "morok.antihook.sandbox.cpuid.naked.sort");
    SmallVector<Value *, 8> sortedLeaf0 =
        sortSamples(leaf0Samples, "morok.antihook.sandbox.cpuid.leaf0.sort");
    SmallVector<Value *, 8> sortedHv = sortSamples(
        hvLeafSamples, "morok.antihook.sandbox.cpuid.hvleaf.sort");
    SmallVector<Value *, 8> sortedVariance = sortSamples(
        varianceSamples, "morok.antihook.sandbox.cpuid.variance.sort");

    Value *nakedMedian = sortedNaked[3];
    Value *leaf0Median = sortedLeaf0[3];
    Value *hvMedian = sortedHv[3];
    Value *varianceMedian = sortedVariance[3];
    nakedMedian->setName("morok.antihook.sandbox.cpuid.naked.median");
    leaf0Median->setName("morok.antihook.sandbox.cpuid.leaf0.median");
    hvMedian->setName("morok.antihook.sandbox.cpuid.hvleaf.median");
    varianceMedian->setName("morok.antihook.sandbox.cpuid.variance.median");

    Value *baseline = B.CreateSelect(
        B.CreateICmpEQ(nakedMedian, ConstantInt::get(i64, 0),
                       "morok.antihook.sandbox.cpuid.naked.zero"),
        ConstantInt::get(i64, 1), nakedMedian,
        "morok.antihook.sandbox.cpuid.naked.baseline");
    Value *varianceSlow = B.CreateICmpUGT(
        varianceMedian,
        B.CreateMul(baseline, ConstantInt::get(i64, 8),
                    "morok.antihook.sandbox.cpuid.variance.scaled"),
        "morok.antihook.sandbox.cpuid.variance.slow");
    Value *hvLeafSlow = B.CreateICmpUGT(
        hvMedian,
        B.CreateAdd(leaf0Median,
                    B.CreateMul(baseline, ConstantInt::get(i64, 16),
                                "morok.antihook.sandbox.cpuid.leaf0.slack"),
                    "morok.antihook.sandbox.cpuid.leaf0.threshold"),
        "morok.antihook.sandbox.cpuid.hvleaf.slow");
    Value *latency = B.CreateAnd(varianceSlow, hvLeafSlow,
                                 "morok.antihook.sandbox.cpuid.latency");
    Value *composite =
        B.CreateAnd(latency, IdentityEvidence,
                    "morok.antihook.sandbox.cpuid.identity.latency");
    incrementWeightedGate(B, Score, composite, 2, 0xA20D61F3B49C875EULL,
                          "morok.antihook.sandbox.cpuid.identity.latency");
    Value *latencyWithoutIdentity = B.CreateAnd(
        latency,
        B.CreateNot(IdentityEvidence,
                    "morok.antihook.sandbox.cpuid.identity.absent"),
        "morok.antihook.sandbox.coherence.cpuid.no.identity");
    incrementWeightedGate(B, Coherence, latencyWithoutIdentity, 1,
                          0xE36C1084F59A27BDULL,
                          "morok.antihook.sandbox.coherence.cpuid.no.identity");
    return latency;
}

Function *sandboxHeuristicProbe(Module &M, const Triple &TT) {
    const bool X86 =
        TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64;
    const bool Posix = TT.isOSLinux() || TT.isOSDarwin();
    if (!X86 && !Posix)
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.sandbox"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i16 = Type::getInt16Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.sandbox", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    AllocaInst *score =
        B.CreateAlloca(i64, nullptr, "morok.antihook.sandbox.score");
    B.CreateStore(ConstantInt::get(i64, 0), score)->setVolatile(true);
    AllocaInst *coherence =
        B.CreateAlloca(i64, nullptr,
                       "morok.antihook.sandbox.coherence.penalty");
    B.CreateStore(ConstantInt::get(i64, 0), coherence)->setVolatile(true);
    Value *identityEvidence = ConstantInt::getFalse(ctx);

    if (X86) {
        auto *tripwire = B.CreateLoad(i8, sandboxTripwireGate(M),
                                      "morok.antihook.sandbox.tripwire.load");
        tripwire->setVolatile(true);
        Value *tripwireArmed = B.CreateICmpNE(
            tripwire, ConstantInt::get(i8, 0),
            "morok.antihook.sandbox.tripwire.armed");

        Value *leaf1 = emitCpuid(B, M, ConstantInt::get(i32, 1),
                                 ConstantInt::get(i32, 0));
        Value *ecx =
            cpuidReg(B, leaf1, 2, "morok.antihook.sandbox.cpuid.ecx");
        Value *hypervisor = B.CreateICmpNE(
            B.CreateAnd(ecx, ConstantInt::get(i32, 1u << 31),
                        "morok.antihook.sandbox.cpuid.hypervisor.bit"),
            ConstantInt::get(i32, 0),
            "morok.antihook.sandbox.cpuid.hypervisor");

        Value *hvLeaf = emitCpuid(B, M, ConstantInt::get(i32, 0x40000000u),
                                  ConstantInt::get(i32, 0));
        Value *hvMax =
            cpuidReg(B, hvLeaf, 0, "morok.antihook.sandbox.cpuid.hv.max");
        Value *hvEbx =
            cpuidReg(B, hvLeaf, 1, "morok.antihook.sandbox.cpuid.hv.ebx");
        Value *hvEcx =
            cpuidReg(B, hvLeaf, 2, "morok.antihook.sandbox.cpuid.hv.ecx");
        Value *hvEdx =
            cpuidReg(B, hvLeaf, 3, "morok.antihook.sandbox.cpuid.hv.edx");
        Value *hvVendor = B.CreateICmpNE(
            hvMax, ConstantInt::get(i32, 0),
            "morok.antihook.sandbox.cpuid.hv.vendor");
        Value *hvVendorEvidence =
            B.CreateAnd(hypervisor, hvVendor,
                        "morok.antihook.sandbox.cpuid.vendor");
        Value *vmwareVendor = B.CreateAnd(
            B.CreateAnd(B.CreateICmpEQ(hvEbx, ConstantInt::get(i32, 0x61774D56u)),
                        B.CreateICmpEQ(hvEcx,
                                       ConstantInt::get(i32, 0x4D566572u))),
            B.CreateICmpEQ(hvEdx, ConstantInt::get(i32, 0x65726177u)),
            "morok.antihook.sandbox.vmware.vendor");
        Value *tcgVendor = B.CreateAnd(
            B.CreateAnd(B.CreateICmpEQ(hvEbx, ConstantInt::get(i32, 0x54474354u)),
                        B.CreateICmpEQ(hvEcx,
                                       ConstantInt::get(i32, 0x43544743u))),
            B.CreateICmpEQ(hvEdx, ConstantInt::get(i32, 0x47435447u)),
            "morok.antihook.sandbox.tcg.vendor");
        Value *qemuBrand = emitQemuBrandMatch(B, M);
        Value *leafIdentity =
            B.CreateOr(hypervisor, hvVendorEvidence,
                       "morok.antihook.sandbox.cpuid.leaf.identity");
        identityEvidence =
            B.CreateOr(B.CreateOr(leafIdentity, vmwareVendor),
                       B.CreateOr(tcgVendor, qemuBrand),
                       "morok.antihook.sandbox.identity.evidence");
        (void)emitSandboxCpuidExitLatency(B, M, score, coherence,
                                          identityEvidence);
        Value *hvWithoutLeaf =
            B.CreateAnd(hypervisor,
                        B.CreateNot(hvVendor,
                                    "morok.antihook.sandbox.hv.vendor.missing"),
                        "morok.antihook.sandbox.coherence.hv.no.vendor");
        incrementWeightedGate(B, coherence, hvWithoutLeaf, 2,
                              0xD9A6C13E7B4F0285ULL,
                              "morok.antihook.sandbox.coherence.hv.no.vendor");
        Value *vendorWithoutHv = B.CreateAnd(
            B.CreateOr(vmwareVendor, tcgVendor,
                       "morok.antihook.sandbox.vendor.identity"),
            B.CreateNot(hypervisor,
                        "morok.antihook.sandbox.hypervisor.absent"),
            "morok.antihook.sandbox.coherence.vendor.no.hv");
        incrementWeightedGate(
            B, coherence, vendorWithoutHv, 2, 0x74E2B93D1C8056AFULL,
            "morok.antihook.sandbox.coherence.vendor.no.hv");
        Value *brandWithoutHv =
            B.CreateAnd(qemuBrand,
                        B.CreateNot(hypervisor,
                                    "morok.antihook.sandbox.brand.hv.absent"),
                        "morok.antihook.sandbox.coherence.brand.no.hv");
        incrementWeightedGate(B, coherence, brandWithoutHv, 1,
                              0xB51F28E6C4097D3AULL,
                              "morok.antihook.sandbox.coherence.brand.no.hv");
        if (TT.isArch64Bit()) {
            Value *tbHit = emitSandboxTbTiming(B, M, score);
            Value *smcHit = emitSandboxSmcLatency(B, M, TT, score);
            Value *timingHit = tbHit ? tbHit : ConstantInt::getFalse(ctx);
            if (smcHit)
                timingHit =
                    B.CreateOr(timingHit, smcHit,
                               "morok.antihook.sandbox.timing.artifact");
            Value *timingWithoutIdentity = B.CreateAnd(
                timingHit,
                B.CreateNot(identityEvidence,
                            "morok.antihook.sandbox.identity.absent"),
                "morok.antihook.sandbox.coherence.timing.no.identity");
            incrementWeightedGate(
                B, coherence, timingWithoutIdentity, 1,
                0xC2E7A49B581D306FULL,
                "morok.antihook.sandbox.coherence.timing.no.identity");
        }

        auto *backdoorBB =
            BasicBlock::Create(ctx, "morok.antihook.sandbox.vmware", fn);
        auto *afterBackdoorBB =
            BasicBlock::Create(ctx, "morok.antihook.sandbox.after.vmware", fn);
        B.CreateCondBr(B.CreateAnd(B.CreateAnd(hypervisor, vmwareVendor),
                                   tripwireArmed),
                       backdoorBB, afterBackdoorBB);

        IRBuilder<> VB(backdoorBB);
        Value *reply = emitVmwareBackdoor(VB, M);
        incrementDiff(VB, score,
                      VB.CreateICmpEQ(reply, ConstantInt::get(i32, 0x564D5868u),
                                      "morok.antihook.sandbox.vmware.reply"),
                      "morok.antihook.sandbox.vmware.backdoor");
        VB.CreateBr(afterBackdoorBB);
        B.SetInsertPoint(afterBackdoorBB);

        auto *descriptorBB =
            BasicBlock::Create(ctx, "morok.antihook.sandbox.descriptor", fn);
        auto *afterDescriptorBB = BasicBlock::Create(
            ctx, "morok.antihook.sandbox.after.descriptor", fn);
        B.CreateCondBr(tripwireArmed, descriptorBB, afterDescriptorBB);

        IRBuilder<> DB(descriptorBB);
        auto *descTy = ArrayType::get(i8, 16);
        AllocaInst *idt = DB.CreateAlloca(descTy, nullptr,
                                          "morok.antihook.sandbox.sidt.buf");
        AllocaInst *gdt = DB.CreateAlloca(descTy, nullptr,
                                          "morok.antihook.sandbox.sgdt.buf");
        AllocaInst *ldt = DB.CreateAlloca(descTy, nullptr,
                                          "morok.antihook.sandbox.sldt.buf");
        emitDescriptorStore(DB, idt, "sidt ($0)",
                            "morok.antihook.sandbox.sidt");
        emitDescriptorStore(DB, gdt, "sgdt ($0)",
                            "morok.antihook.sandbox.sgdt");
        emitDescriptorStore(DB, ldt, "sldt ($0)",
                            "morok.antihook.sandbox.sldt");

        Value *idtBase =
            loadAt(DB, M, i64, idt, 2, "morok.antihook.sandbox.sidt.base");
        Value *gdtBase =
            loadAt(DB, M, i64, gdt, 2, "morok.antihook.sandbox.sgdt.base");
        Value *ldtSel =
            loadAt(DB, M, i16, ldt, 0ULL, "morok.antihook.sandbox.sldt.sel");
        Value *lowIdt = DB.CreateICmpULT(
            idtBase, ConstantInt::get(i64, 0x100000000ULL),
            "morok.antihook.sandbox.sidt.low");
        Value *lowGdt = DB.CreateICmpULT(
            gdtBase, ConstantInt::get(i64, 0x100000000ULL),
            "morok.antihook.sandbox.sgdt.low");
        Value *ldtSet = DB.CreateICmpNE(
            ldtSel, ConstantInt::get(i16, 0),
            "morok.antihook.sandbox.sldt.set");
        incrementDiff(DB, score, DB.CreateOr(lowIdt, lowGdt),
                      "morok.antihook.sandbox.redpill");
        incrementDiff(DB, score, ldtSet, "morok.antihook.sandbox.ldt");
        DB.CreateBr(afterDescriptorBB);
        B.SetInsertPoint(afterDescriptorBB);
    }

    if (Function *clockCoherence = sandboxClockCoherenceProbe(M, TT)) {
        Value *diff = B.CreateCall(clockCoherence->getFunctionType(),
                                   clockCoherence, {},
                                   "morok.antihook.sandbox.clock.diff");
        Value *changed =
            B.CreateICmpNE(diff, ConstantInt::get(i64, 0),
                           "morok.antihook.sandbox.clock.changed");
        incrementDiff(B, score, changed, "morok.antihook.sandbox.clock");
    }
    if (Function *firmwareCoherence = windowsFirmwareCoherenceProbe(M)) {
        Value *diff = B.CreateCall(firmwareCoherence->getFunctionType(),
                                   firmwareCoherence, {},
                                   "morok.antihook.sandbox.firmware.diff");
        Value *changed =
            B.CreateICmpNE(diff, ConstantInt::get(i64, 0),
                           "morok.antihook.sandbox.firmware.changed");
        incrementDiff(B, score, changed, "morok.antihook.sandbox.firmware");
    }

    if (TT.isOSLinux()) {
        FunctionCallee sysconf = sysconfDecl(M);
        Value *cpus = B.CreateCall(sysconf, {ConstantInt::get(i32, 84)},
                                   "morok.antihook.sandbox.cpu.count");
        Value *pages = B.CreateCall(sysconf, {ConstantInt::get(i32, 85)},
                                    "morok.antihook.sandbox.ram.pages");
        Value *oneCpu = B.CreateICmpSLE(
            cpus, ConstantInt::getSigned(ip, 1),
            "morok.antihook.sandbox.cpu.low");
        Value *lowPages = B.CreateICmpULT(
            B.CreateZExtOrTrunc(pages, i64), ConstantInt::get(i64, 262144),
            "morok.antihook.sandbox.ram.low");
        incrementDiff(B, score, oneCpu, "morok.antihook.sandbox.cpu");
        incrementDiff(B, score, lowPages, "morok.antihook.sandbox.ram");
        Value *lowResource =
            B.CreateOr(oneCpu, lowPages,
                       "morok.antihook.sandbox.low.resource");
        Value *resourceWithoutIdentity = B.CreateAnd(
            lowResource,
            B.CreateNot(identityEvidence,
                        "morok.antihook.sandbox.resource.identity.absent"),
            "morok.antihook.sandbox.coherence.resource.no.identity");
        incrementWeightedGate(
            B, coherence, resourceWithoutIdentity, 1,
            0x8F13D6A0C254B79EULL,
            "morok.antihook.sandbox.coherence.resource.no.identity");

        // The clock_gettime/nanosleep heuristics below model `struct timespec`
        // as two 64-bit fields and read it back with emitClockGettimeNanos's
        // LP64 layout.  That is only correct where `long` is 64-bit (LP64);
        // on a 32-bit linux-gnu ABI timespec is two 32-bit longs, so nanosleep
        // would read tv_sec/tv_nsec from the wrong offsets and clock_gettime
        // would fold tv_nsec into the seconds load — corrupting the sandbox
        // score (false tamper state or defeated sleep-skip checks).  Skip the
        // timing heuristics there; the sysconf CPU/RAM checks above still run.
        if (TT.isArch64Bit()) {
        Value *boot =
            emitClockGettimeNanos(B, M, 7, "morok.antihook.sandbox.boottime");
        Value *shortUptime = B.CreateAnd(
            B.CreateICmpNE(boot, ConstantInt::get(i64, 0),
                           "morok.antihook.sandbox.uptime.ok"),
            B.CreateICmpULT(boot, ConstantInt::get(i64, 300000000000ULL),
                            "morok.antihook.sandbox.uptime.short"),
            "morok.antihook.sandbox.uptime.flag");
        incrementDiff(B, score, shortUptime, "morok.antihook.sandbox.uptime");

        Value *sleepStart = emitClockGettimeNanos(
            B, M, 1, "morok.antihook.sandbox.sleep.start");
        auto *tsTy = StructType::get(ctx, {i64, i64});
        auto *req = B.CreateAlloca(tsTy, nullptr,
                                   "morok.antihook.sandbox.sleep.req");
        B.CreateStore(ConstantInt::get(i64, 0), B.CreateStructGEP(tsTy, req, 0));
        B.CreateStore(ConstantInt::get(i64, 5000000),
                      B.CreateStructGEP(tsTy, req, 1));
        Value *sleepRc = B.CreateCall(
            nanosleepDecl(M),
            {req, ConstantPointerNull::get(PointerType::getUnqual(ctx))},
            "morok.antihook.sandbox.sleep.rc");
        Value *sleepEnd =
            emitClockGettimeNanos(B, M, 1, "morok.antihook.sandbox.sleep.end");
        Value *sleepDelta = B.CreateSub(
            sleepEnd, sleepStart, "morok.antihook.sandbox.sleep.delta");
        Value *sleepClockOk = B.CreateAnd(
            B.CreateICmpNE(sleepStart, ConstantInt::get(i64, 0)),
            B.CreateICmpUGT(sleepEnd, sleepStart),
            "morok.antihook.sandbox.sleep.clock.ok");
        Value *sleepSkipped = B.CreateAnd(
            B.CreateAnd(sleepClockOk,
                        B.CreateICmpEQ(sleepRc, ConstantInt::get(i32, 0))),
            B.CreateICmpULT(sleepDelta, ConstantInt::get(i64, 1000000)),
            "morok.antihook.sandbox.sleep.skip");
        incrementDiff(B, score, sleepSkipped, "morok.antihook.sandbox.sleep");
        Value *timeOnly =
            B.CreateAnd(B.CreateOr(shortUptime, sleepSkipped,
                                   "morok.antihook.sandbox.time.artifact"),
                        B.CreateNot(identityEvidence,
                                    "morok.antihook.sandbox.time.identity.absent"),
                        "morok.antihook.sandbox.coherence.time.no.identity");
        incrementWeightedGate(
            B, coherence, timeOnly, 1, 0xA4619C7D502E38B5ULL,
            "morok.antihook.sandbox.coherence.time.no.identity");
        } // TT.isArch64Bit()
    }

    Value *raw =
        loadGateCounter(B, score, "morok.antihook.sandbox.raw.score");
    Value *penalty = loadGateCounter(
        B, coherence, "morok.antihook.sandbox.coherence.penalty.final");
    Value *cap = B.CreateLShr(raw, ConstantInt::get(i64, 1),
                              "morok.antihook.sandbox.coherence.cap");
    Value *cappedPenalty = B.CreateSelect(
        B.CreateICmpUGT(penalty, cap,
                        "morok.antihook.sandbox.coherence.over.cap"),
        cap, penalty, "morok.antihook.sandbox.coherence.capped");
    Value *out =
        B.CreateSub(raw, cappedPenalty, "morok.antihook.sandbox.score.ret");
    B.CreateRet(out);
    return fn;
}

GlobalVariable *emuSignalMaskGlobal(Module &M) {
    if (auto *existing = M.getGlobalVariable("morok.antihook.emu.sig.mask",
                                             /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(M, i32, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(i32, 0),
                                  "morok.antihook.emu.sig.mask");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *emuFaultAddrGlobal(Module &M) {
    if (auto *existing = M.getGlobalVariable("morok.antihook.emu.fault.addr",
                                             /*AllowInternal=*/true))
        return existing;
    auto *ip = intPtrTy(M);
    auto *gv = new GlobalVariable(M, ip, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(ip, 0),
                                  "morok.antihook.emu.fault.addr");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

// Module-global storage for the saved SIGSEGV/SIGILL dispositions captured at
// install time. They must be reachable from the signal handler (not stack
// allocas in the probe) so the handler can chain an unrecognized fault back to
// the previous action (#228). Sized to the Linux x86_64 struct sigaction.
GlobalVariable *emuOldActionGlobal(Module &M, StringRef Name) {
    if (auto *existing = M.getGlobalVariable(Name, /*AllowInternal=*/true))
        return existing;
    constexpr std::uint64_t kLinuxX64SigactionSize = 152;
    auto *ty = ArrayType::get(Type::getInt8Ty(M.getContext()),
                              kLinuxX64SigactionSize);
    auto *gv = new GlobalVariable(M, ty, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantAggregateZero::get(ty), Name);
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *emuOldSegvActionGlobal(Module &M) {
    return emuOldActionGlobal(M, "morok.antihook.emu.old.segv.action");
}

GlobalVariable *emuOldIllActionGlobal(Module &M) {
    return emuOldActionGlobal(M, "morok.antihook.emu.old.ill.action");
}

GlobalVariable *fsGsSignalMaskGlobal(Module &M) {
    if (auto *existing = M.getGlobalVariable("morok.antihook.fsgs.sig.mask",
                                             /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(M, i32, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(i32, 0),
                                  "morok.antihook.fsgs.sig.mask");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *fsGsOldIllActionGlobal(Module &M) {
    return emuOldActionGlobal(M, "morok.antihook.fsgs.old.ill.action");
}

void storeEmuSiginfoAction(IRBuilder<> &B, Module &M, AllocaInst *Action,
                           Function *Handler, const Twine &Prefix) {
    constexpr std::uint64_t kLinuxX64SigactionSize = 152;
    constexpr std::uint64_t kLinuxX64SigactionFlagsOffset = 136;
    constexpr std::uint32_t kSaSiginfo = 4;
    // SA_NODEFER keeps SIGSEGV/SIGILL unmasked while the handler runs, so a
    // re-delivered synchronous fault (including one raised by the handler's own
    // RIP read, or a foreign fault that the handler chains back to the previous
    // action) is not force-killed by the kernel default action (#228).
    constexpr std::uint32_t kSaNodefer = 0x40000000u;
    constexpr std::uint32_t kSaFlags = kSaSiginfo | kSaNodefer;
    auto *i8 = Type::getInt8Ty(M.getContext());
    auto *i32 = Type::getInt32Ty(M.getContext());
    for (std::uint64_t i = 0; i < kLinuxX64SigactionSize; ++i)
        B.CreateStore(ConstantInt::get(i8, 0),
                      gepI8(B, M, Action, constIp(M, i)));
    B.CreateStore(Handler,
                  gepI8(B, M, Action, constIp(M, 0), Prefix + ".handler"));
    B.CreateStore(ConstantInt::get(i32, kSaFlags),
                  gepI8(B, M, Action,
                        constIp(M, kLinuxX64SigactionFlagsOffset),
                        Prefix + ".flags"));
}

Function *emuLinuxX86SignalHandler(Module &M) {
    if (Function *existing = M.getFunction("morok.antihook.emu.sig.handler"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), {i32, ptr, ptr}, false),
        GlobalValue::PrivateLinkage, "morok.antihook.emu.sig.handler", &M);
    fn->setDSOLocal(true);
    Argument *sig = fn->getArg(0);
    sig->setName("sig");
    Argument *info = fn->getArg(1);
    info->setName("info");
    Argument *uctx = fn->getArg(2);
    uctx->setName("uctx");

    constexpr std::uint64_t kLinuxX64SiginfoAddrOffset = 16;
    constexpr std::uint64_t kLinuxX64UcontextRipOffset = 168;
    constexpr std::uint32_t kSegvBit = 1u;
    constexpr std::uint32_t kUd2Bit = 2u;
    constexpr std::uint32_t kLockNopBit = 4u;

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *loadFaultBB = BasicBlock::Create(ctx, "fault.addr", fn);
    auto *classifyBB = BasicBlock::Create(ctx, "classify", fn);
    auto *decodeBB = BasicBlock::Create(ctx, "decode", fn);
    auto *knownBB = BasicBlock::Create(ctx, "known", fn);
    auto *unknownBB = BasicBlock::Create(ctx, "unknown", fn);
    auto *doneBB = BasicBlock::Create(ctx, "done", fn);

    IRBuilder<> B(entry);
    B.CreateCondBr(B.CreateICmpNE(info, ConstantPointerNull::get(ptr)),
                   loadFaultBB, classifyBB);

    IRBuilder<> FB(loadFaultBB);
    Value *fault = loadAt(FB, M, ip, info, kLinuxX64SiginfoAddrOffset,
                          "morok.antihook.emu.sig.fault");
    FB.CreateBr(classifyBB);

    IRBuilder<> CB(classifyBB);
    auto *faultPhi = CB.CreatePHI(ip, 2, "morok.antihook.emu.sig.fault.phi");
    faultPhi->addIncoming(ConstantInt::get(ip, 0), entry);
    faultPhi->addIncoming(fault, loadFaultBB);
    CB.CreateCondBr(CB.CreateICmpNE(uctx, ConstantPointerNull::get(ptr)),
                    decodeBB, doneBB);

    IRBuilder<> DB(decodeBB);
    Value *ripSlot = gepI8(DB, M, uctx, constIp(M, kLinuxX64UcontextRipOffset),
                           "morok.antihook.emu.sig.rip.slot");
    Value *rip = DB.CreateLoad(ip, ripSlot, "morok.antihook.emu.sig.rip");
    cast<LoadInst>(rip)->setAlignment(Align(1));
    Value *pc = DB.CreateIntToPtr(rip, ptr, "morok.antihook.emu.sig.pc");
    auto *op0 = DB.CreateLoad(i8, pc, "morok.antihook.emu.sig.op0");
    op0->setVolatile(true);
    op0->setAlignment(Align(1));
    auto *op1 = DB.CreateLoad(
        i8, gepI8(DB, M, pc, constIp(M, 1), "morok.antihook.emu.sig.op1.ptr"),
        "morok.antihook.emu.sig.op1");
    op1->setVolatile(true);
    op1->setAlignment(Align(1));

    Value *isSegv =
        DB.CreateICmpEQ(sig, ConstantInt::get(i32, 11),
                        "morok.antihook.emu.sig.segv");
    Value *isIll = DB.CreateICmpEQ(sig, ConstantInt::get(i32, 4),
                                   "morok.antihook.emu.sig.ill");
    Value *segvOp = DB.CreateAnd(
        DB.CreateICmpEQ(op0, ConstantInt::get(i8, 0x8a)),
        DB.CreateICmpEQ(op1, ConstantInt::get(i8, 0x08)),
        "morok.antihook.emu.sig.segv.op");
    Value *segvHit = DB.CreateAnd(isSegv, segvOp,
                                  "morok.antihook.emu.sig.segv.hit");
    Value *ud2Hit = DB.CreateAnd(
        isIll,
        DB.CreateAnd(DB.CreateICmpEQ(op0, ConstantInt::get(i8, 0x0f)),
                     DB.CreateICmpEQ(op1, ConstantInt::get(i8, 0x0b))),
        "morok.antihook.emu.sig.ud2");
    Value *lockNopHit = DB.CreateAnd(
        isIll,
        DB.CreateAnd(DB.CreateICmpEQ(op0, ConstantInt::get(i8, 0xf0)),
                     DB.CreateICmpEQ(op1, ConstantInt::get(i8, 0x90))),
        "morok.antihook.emu.sig.locknop");
    Value *bit = DB.CreateSelect(
        segvHit, ConstantInt::get(i32, kSegvBit),
        DB.CreateSelect(ud2Hit, ConstantInt::get(i32, kUd2Bit),
                        DB.CreateSelect(lockNopHit,
                                        ConstantInt::get(i32, kLockNopBit),
                                        ConstantInt::get(i32, 0))),
        "morok.antihook.emu.sig.bit");
    auto *oldMask =
        DB.CreateLoad(i32, emuSignalMaskGlobal(M), "morok.antihook.emu.sig.mask.old");
    oldMask->setVolatile(true);
    Value *nextMask =
        DB.CreateOr(oldMask, bit, "morok.antihook.emu.sig.mask.next");
    DB.CreateStore(nextMask, emuSignalMaskGlobal(M))->setVolatile(true);

    auto *oldFault = DB.CreateLoad(ip, emuFaultAddrGlobal(M),
                                   "morok.antihook.emu.fault.addr.old");
    oldFault->setVolatile(true);
    Value *faultNext =
        DB.CreateSelect(segvHit, faultPhi, oldFault,
                        "morok.antihook.emu.fault.addr.next");
    DB.CreateStore(faultNext, emuFaultAddrGlobal(M))->setVolatile(true);

    Value *known = DB.CreateICmpNE(bit, ConstantInt::get(i32, 0),
                                   "morok.antihook.emu.sig.known");
    DB.CreateCondBr(known, knownBB, unknownBB);

    // Recognized probe instruction: step the saved RIP over the 2-byte stimulus
    // and return so the probe thread resumes after it.
    IRBuilder<> KB(knownBB);
    auto *pcStore =
        KB.CreateStore(KB.CreateAdd(rip, ConstantInt::get(ip, 2),
                                    "morok.antihook.emu.sig.rip.next"),
                       ripSlot);
    pcStore->setAlignment(Align(1));
    KB.CreateBr(doneBB);

    // Unrecognized/foreign fault: do NOT advance RIP (we cannot know its
    // length) and do NOT swallow it. Restore the previous disposition for this
    // signal and return, so the fault re-triggers and is delivered to the
    // original handler / default action instead of looping or being lost (#228).
    IRBuilder<> XB(unknownBB);
    Value *oldAction =
        XB.CreateSelect(isSegv, emuOldSegvActionGlobal(M),
                        emuOldIllActionGlobal(M),
                        "morok.antihook.emu.sig.old.action");
    XB.CreateCall(sigactionDecl(M),
                  {sig, oldAction, ConstantPointerNull::get(ptr)},
                  "morok.antihook.emu.sig.chain.restore");
    XB.CreateBr(doneBB);

    IRBuilder<> RB(doneBB);
    RB.CreateRetVoid();
    return fn;
}

Function *fsGsLinuxX86SignalHandler(Module &M) {
    if (Function *existing = M.getFunction("morok.antihook.fsgs.sig.handler"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), {i32, ptr, ptr}, false),
        GlobalValue::PrivateLinkage, "morok.antihook.fsgs.sig.handler", &M);
    fn->setDSOLocal(true);
    Argument *sig = fn->getArg(0);
    sig->setName("sig");
    fn->getArg(1)->setName("info");
    Argument *uctx = fn->getArg(2);
    uctx->setName("uctx");

    constexpr std::uint64_t kLinuxX64UcontextRipOffset = 168;
    constexpr std::uint32_t kFsFaultBit = 1u;
    constexpr std::uint32_t kGsFaultBit = 2u;

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *decodeBB = BasicBlock::Create(ctx, "decode", fn);
    auto *knownBB = BasicBlock::Create(ctx, "known", fn);
    auto *unknownBB = BasicBlock::Create(ctx, "unknown", fn);
    auto *doneBB = BasicBlock::Create(ctx, "done", fn);

    IRBuilder<> B(entry);
    B.CreateCondBr(B.CreateICmpNE(uctx, ConstantPointerNull::get(ptr)),
                   decodeBB, doneBB);

    IRBuilder<> DB(decodeBB);
    Value *ripSlot = gepI8(DB, M, uctx, constIp(M, kLinuxX64UcontextRipOffset),
                           "morok.antihook.fsgs.sig.rip.slot");
    auto *rip = DB.CreateLoad(ip, ripSlot, "morok.antihook.fsgs.sig.rip");
    rip->setAlignment(Align(1));
    Value *pc = DB.CreateIntToPtr(rip, ptr, "morok.antihook.fsgs.sig.pc");
    auto loadOp = [&](std::uint64_t Offset, const Twine &Name) {
        auto *op = DB.CreateLoad(
            i8, gepI8(DB, M, pc, constIp(M, Offset), Name + ".ptr"), Name);
        op->setVolatile(true);
        op->setAlignment(Align(1));
        return op;
    };
    auto *op0 = loadOp(0, "morok.antihook.fsgs.sig.op0");
    auto *op1 = loadOp(1, "morok.antihook.fsgs.sig.op1");
    auto *op2 = loadOp(2, "morok.antihook.fsgs.sig.op2");
    auto *op3 = loadOp(3, "morok.antihook.fsgs.sig.op3");
    auto *op4 = loadOp(4, "morok.antihook.fsgs.sig.op4");
    Value *isIll = DB.CreateICmpEQ(sig, ConstantInt::get(i32, 4),
                                   "morok.antihook.fsgs.sig.ill");
    Value *prefix = DB.CreateAnd(
        DB.CreateAnd(DB.CreateICmpEQ(op0, ConstantInt::get(i8, 0xf3)),
                     DB.CreateICmpEQ(op1, ConstantInt::get(i8, 0x48))),
        DB.CreateAnd(DB.CreateICmpEQ(op2, ConstantInt::get(i8, 0x0f)),
                     DB.CreateICmpEQ(op3, ConstantInt::get(i8, 0xae))),
        "morok.antihook.fsgs.sig.prefix");
    Value *fsHit = DB.CreateAnd(
        isIll, DB.CreateAnd(prefix,
                            DB.CreateICmpEQ(op4, ConstantInt::get(i8, 0xc0))),
        "morok.antihook.fsgs.sig.rdfsbase");
    Value *gsHit = DB.CreateAnd(
        isIll, DB.CreateAnd(prefix,
                            DB.CreateICmpEQ(op4, ConstantInt::get(i8, 0xc8))),
        "morok.antihook.fsgs.sig.rdgsbase");
    Value *bit = DB.CreateSelect(
        fsHit, ConstantInt::get(i32, kFsFaultBit),
        DB.CreateSelect(gsHit, ConstantInt::get(i32, kGsFaultBit),
                        ConstantInt::get(i32, 0)),
        "morok.antihook.fsgs.sig.bit");
    auto *oldMask = DB.CreateLoad(i32, fsGsSignalMaskGlobal(M),
                                  "morok.antihook.fsgs.sig.mask.old");
    oldMask->setVolatile(true);
    DB.CreateStore(DB.CreateOr(oldMask, bit,
                               "morok.antihook.fsgs.sig.mask.next"),
                   fsGsSignalMaskGlobal(M))
        ->setVolatile(true);
    DB.CreateCondBr(DB.CreateICmpNE(bit, ConstantInt::get(i32, 0),
                                    "morok.antihook.fsgs.sig.known"),
                    knownBB, unknownBB);

    IRBuilder<> KB(knownBB);
    auto *ripStore =
        KB.CreateStore(KB.CreateAdd(rip, ConstantInt::get(ip, 5),
                                    "morok.antihook.fsgs.sig.rip.next"),
                       ripSlot);
    ripStore->setAlignment(Align(1));
    KB.CreateBr(doneBB);

    IRBuilder<> UB(unknownBB);
    UB.CreateCall(sigactionDecl(M),
                  {sig, fsGsOldIllActionGlobal(M),
                   ConstantPointerNull::get(ptr)},
                  "morok.antihook.fsgs.sig.chain.restore");
    UB.CreateBr(doneBB);

    IRBuilder<> RB(doneBB);
    RB.CreateRetVoid();
    return fn;
}

Value *emitRdrandCarry(IRBuilder<> &B, const Twine &Name) {
    auto *i32 = Type::getInt32Ty(B.getContext());
    auto *asmTy = FunctionType::get(i32, false);
    InlineAsm *rdrand = InlineAsm::get(
        asmTy, "rdrandq %rax\n\tsetc %al\n\tmovzbl %al, %eax",
        "={eax},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    return B.CreateCall(asmTy, rdrand, {}, Name);
}

void emitRdrandCfGap(IRBuilder<> &B, Module &M, Function *Fn,
                     AllocaInst *Diff, Value *Leaf1Ecx) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    Value *supported = B.CreateICmpNE(
        B.CreateAnd(Leaf1Ecx, ConstantInt::get(i32, 1u << 30),
                    "morok.antihook.emu.rdrand.bit"),
        ConstantInt::get(i32, 0), "morok.antihook.emu.rdrand.supported");

    auto *tryBB = BasicBlock::Create(ctx, "morok.antihook.emu.rdrand.try", Fn);
    auto *doneBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.rdrand.done", Fn);
    B.CreateCondBr(supported, tryBB, doneBB);

    IRBuilder<> RB(tryBB);
    Value *cfTotal = ConstantInt::get(i32, 0);
    for (unsigned attempt = 0; attempt < 10; ++attempt) {
        Value *cf = emitRdrandCarry(
            RB, Twine("morok.antihook.emu.rdrand.cf") + Twine(attempt));
        cfTotal = RB.CreateAdd(cfTotal, cf,
                               "morok.antihook.emu.rdrand.cf.total");
    }
    Value *mismatch =
        RB.CreateICmpEQ(cfTotal, ConstantInt::get(i32, 0),
                        "morok.antihook.emu.rdrand.cf.mismatch");
    incrementDiff(RB, Diff, mismatch, "morok.antihook.emu.rdrand.cf");
    RB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
}

void emitLinuxX86SemanticGapProbe(IRBuilder<> &B, Module &M, const Triple &TT,
                                  Function *Fn, AllocaInst *Diff) {
    if (!TT.isOSLinux() || !useDirectLinuxSyscalls(M, TT))
        return;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    constexpr std::uint32_t kIoctl = 16;
    constexpr std::uint32_t kFcntl = 72;
    constexpr std::uint64_t kLinuxX64SigactionSize = 152;
    constexpr std::uint32_t kSegvBit = 1u;
    constexpr std::uint32_t kUd2Bit = 2u;
    constexpr std::uint32_t kLockNopBit = 4u;
    constexpr std::uint32_t kExpectedSignalMask =
        kSegvBit | kUd2Bit | kLockNopBit;

    Value *ioctlRc = emitLinuxSyscall(
        B, M, TT, kIoctl,
        {ConstantInt::getSigned(ip, -1), ConstantInt::get(ip, 0),
         ConstantInt::get(ip, 0)});
    ioctlRc->setName("morok.antihook.emu.errno.ioctl");
    Value *ioctlBad =
        B.CreateICmpNE(ioctlRc, ConstantInt::getSigned(ip, -9),
                       "morok.antihook.emu.errno.ioctl.bad");
    Value *fcntlRc = emitLinuxSyscall(
        B, M, TT, kFcntl,
        {ConstantInt::getSigned(ip, -1), ConstantInt::get(ip, 3),
         ConstantInt::get(ip, 0)});
    fcntlRc->setName("morok.antihook.emu.errno.fcntl");
    Value *fcntlBad =
        B.CreateICmpNE(fcntlRc, ConstantInt::getSigned(ip, -9),
                       "morok.antihook.emu.errno.fcntl.bad");
    Value *errnoMismatch =
        B.CreateOr(ioctlBad, fcntlBad, "morok.antihook.emu.errno.mismatch");
    incrementDiff(B, Diff, errnoMismatch, "morok.antihook.emu.errno");

    Value *pageSize = ConstantInt::get(ip, 4096);
    Value *mapped = emitPosixAnonMmapAddr(
        B, M, TT, pageSize, ConstantInt::get(ip, 3),
        ConstantInt::get(ip, 2u | 0x20u), "morok.antihook.emu.fault.mmap");
    mapped->setName("morok.antihook.emu.fault.mmap");
    Value *mappedOk = B.CreateAnd(
        B.CreateICmpUGT(mapped, ConstantInt::get(ip, 4096)),
        B.CreateICmpULT(mapped, ConstantInt::getSigned(ip, -4095)),
        "morok.antihook.emu.fault.mapped");

    auto *installSegvBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.install.segv", Fn);
    auto *installIllBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.install.ill", Fn);
    auto *restoreSegvBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.restore.segv", Fn);
    auto *protectBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.fault.protect", Fn);
    auto *stimuliBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.stimuli", Fn);
    auto *analyzeBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.analyze", Fn);
    auto *restoreAllBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.sig.restore.all", Fn);
    auto *unmapBB =
        BasicBlock::Create(ctx, "morok.antihook.emu.fault.unmap", Fn);
    auto *doneBB = BasicBlock::Create(ctx, "morok.antihook.emu.sig.done", Fn);
    B.CreateCondBr(mappedOk, installSegvBB, doneBB);

    IRBuilder<> SB(installSegvBB);
    SB.CreateStore(ConstantInt::get(i32, 0), emuSignalMaskGlobal(M))
        ->setVolatile(true);
    SB.CreateStore(ConstantInt::get(ip, 0), emuFaultAddrGlobal(M))
        ->setVolatile(true);
    Function *handler = emuLinuxX86SignalHandler(M);
    auto *actionTy = ArrayType::get(i8, kLinuxX64SigactionSize);
    AllocaInst *action =
        SB.CreateAlloca(actionTy, nullptr, "morok.antihook.emu.sa");
    // Saved dispositions live in module globals (not stack allocas) so the
    // signal handler can reach them to chain unrecognized faults (#228).
    GlobalVariable *oldSegv = emuOldSegvActionGlobal(M);
    GlobalVariable *oldIll = emuOldIllActionGlobal(M);
    storeEmuSiginfoAction(SB, M, action, handler, "morok.antihook.emu.sa");
    FunctionCallee sigactionFn = sigactionDecl(M);
    Value *segvRc =
        SB.CreateCall(sigactionFn,
                      {ConstantInt::get(i32, 11), action, oldSegv},
                      "morok.antihook.emu.sigaction.segv");
    SB.CreateCondBr(SB.CreateICmpEQ(segvRc, ConstantInt::get(i32, 0),
                                    "morok.antihook.emu.sigaction.segv.ok"),
                    installIllBB, unmapBB);

    IRBuilder<> IB(installIllBB);
    Value *illRc =
        IB.CreateCall(sigactionFn, {ConstantInt::get(i32, 4), action, oldIll},
                      "morok.antihook.emu.sigaction.ill");
    IB.CreateCondBr(IB.CreateICmpEQ(illRc, ConstantInt::get(i32, 0),
                                    "morok.antihook.emu.sigaction.ill.ok"),
                    protectBB, restoreSegvBB);

    IRBuilder<> RSB(restoreSegvBB);
    RSB.CreateCall(sigactionFn,
                   {ConstantInt::get(i32, 11), oldSegv,
                    ConstantPointerNull::get(ptr)},
                   "morok.antihook.emu.restore.segv.partial");
    RSB.CreateBr(unmapBB);

    IRBuilder<> PB(protectBB);
    Value *noneRc = emitPosixMprotect(PB, M, TT, mapped, pageSize,
                                      ConstantInt::get(ip, 0));
    noneRc->setName("morok.antihook.emu.mprotect.none");
    PB.CreateCondBr(PB.CreateICmpEQ(noneRc, ConstantInt::get(i32, 0),
                                    "morok.antihook.emu.mprotect.none.ok"),
                    stimuliBB, restoreAllBB);

    IRBuilder<> TB(stimuliBB);
    auto *voidTy = FunctionType::get(Type::getVoidTy(ctx), false);
    InlineAsm *ud2 = InlineAsm::get(voidTy, "ud2",
                                    "~{dirflag},~{fpsr},~{flags}",
                                    /*hasSideEffects=*/true);
    TB.CreateCall(voidTy, ud2);
    InlineAsm *lockNop =
        InlineAsm::get(voidTy, ".byte 0xf0,0x90",
                       "~{dirflag},~{fpsr},~{flags}",
                       /*hasSideEffects=*/true);
    TB.CreateCall(voidTy, lockNop);
    Value *faultAddr =
        TB.CreateAdd(mapped, ConstantInt::get(ip, 37),
                     "morok.antihook.emu.fault.expected");
    auto *faultTy = FunctionType::get(Type::getVoidTy(ctx), {ptr}, false);
    InlineAsm *faultLoad =
        InlineAsm::get(faultTy, "movb (%rax), %cl",
                       "{rax},~{rcx},~{memory},~{dirflag},~{fpsr},~{flags}",
                       /*hasSideEffects=*/true);
    TB.CreateCall(faultTy, faultLoad,
                  {TB.CreateIntToPtr(faultAddr, ptr,
                                     "morok.antihook.emu.fault.ptr")});
    TB.CreateBr(analyzeBB);

    IRBuilder<> AB(analyzeBB);
    auto *mask =
        AB.CreateLoad(i32, emuSignalMaskGlobal(M), "morok.antihook.emu.sig.mask");
    mask->setVolatile(true);
    Value *illMaskBad =
        AB.CreateICmpNE(AB.CreateAnd(mask,
                                     ConstantInt::get(i32, kUd2Bit | kLockNopBit),
                                     "morok.antihook.emu.ill.mask"),
                        ConstantInt::get(i32, kUd2Bit | kLockNopBit),
                        "morok.antihook.emu.ill.mask.bad");
    auto *observedFault =
        AB.CreateLoad(ip, emuFaultAddrGlobal(M), "morok.antihook.emu.fault.addr");
    observedFault->setVolatile(true);
    Value *faultMaskBad = AB.CreateICmpNE(
        AB.CreateAnd(mask, ConstantInt::get(i32, kSegvBit),
                     "morok.antihook.emu.fault.mask"),
        ConstantInt::get(i32, kSegvBit), "morok.antihook.emu.fault.mask.bad");
    Value *faultAddrBad =
        AB.CreateICmpNE(observedFault, faultAddr,
                        "morok.antihook.emu.fault.addr.bad");
    Value *signalMaskBad =
        AB.CreateICmpNE(mask, ConstantInt::get(i32, kExpectedSignalMask),
                        "morok.antihook.emu.sig.mask.bad");
    Value *signalMismatch = AB.CreateOr(
        AB.CreateOr(illMaskBad, faultMaskBad),
        AB.CreateOr(faultAddrBad, signalMaskBad),
        "morok.antihook.emu.signal.mismatch");
    incrementDiff(AB, Diff, signalMismatch, "morok.antihook.emu.signal");
    AB.CreateBr(restoreAllBB);

    IRBuilder<> RB(restoreAllBB);
    RB.CreateCall(sigactionFn,
                  {ConstantInt::get(i32, 4), oldIll,
                   ConstantPointerNull::get(ptr)},
                  "morok.antihook.emu.restore.ill");
    RB.CreateCall(sigactionFn,
                  {ConstantInt::get(i32, 11), oldSegv,
                   ConstantPointerNull::get(ptr)},
                  "morok.antihook.emu.restore.segv");
    RB.CreateBr(unmapBB);

    IRBuilder<> UB(unmapBB);
    emitLinuxMunmap(UB, M, TT, mapped, pageSize);
    UB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
}

Value *emitFsGsBaseRead(IRBuilder<> &B, bool Gs, const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    auto *asmTy = FunctionType::get(i64, false);
    InlineAsm *IA = InlineAsm::get(
        asmTy,
        Gs ? "xorq %rax, %rax\n\t.byte 0xf3,0x48,0x0f,0xae,0xc8"
           : "xorq %rax, %rax\n\t.byte 0xf3,0x48,0x0f,0xae,0xc0",
        "={rax},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    return B.CreateCall(asmTy, IA, {}, Name);
}

Value *emitWindowsGsSelfRead(IRBuilder<> &B, const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    auto *asmTy = FunctionType::get(i64, false);
    InlineAsm *IA =
        InlineAsm::get(asmTy, "movq %gs:0x30, $0",
                       "=r,~{memory},~{dirflag},~{fpsr},~{flags}",
                       /*hasSideEffects=*/true);
    return B.CreateCall(asmTy, IA, {}, Name);
}

Function *fsGsBaseGapProbe(Module &M, const Triple &TT) {
    if (TT.getArch() != Triple::x86_64)
        return nullptr;
    if (!TT.isOSLinux() && !TT.isOSWindows())
        return nullptr;
    if (TT.isOSLinux() && !useDirectLinuxSyscalls(M, TT))
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.fsgs.x86"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.fsgs.x86", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->addFnAttr(Attribute::NoRedZone);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *probeBB = BasicBlock::Create(ctx, "morok.antihook.fsgs.probe", fn);
    auto *doneBB = BasicBlock::Create(ctx, "morok.antihook.fsgs.done", fn);
    IRBuilder<> B(entry);
    AllocaInst *diff = B.CreateAlloca(i64, nullptr, "morok.antihook.fsgs.diff");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);

    Value *leaf7 = emitCpuid(B, M, ConstantInt::get(i32, 7),
                             ConstantInt::get(i32, 0));
    Value *ebx7 = cpuidReg(B, leaf7, 1, "morok.antihook.fsgs.cpuid.ebx7");
    Value *supported = B.CreateICmpNE(
        B.CreateAnd(ebx7, ConstantInt::get(i32, 1),
                    "morok.antihook.fsgs.cpuid.fsgsbase"),
        ConstantInt::get(i32, 0), "morok.antihook.fsgs.supported");

    if (TT.isOSWindows()) {
        B.CreateCondBr(supported, probeBB, doneBB);
        IRBuilder<> WB(probeBB);
        Value *gsBase = emitFsGsBaseRead(WB, /*Gs=*/true,
                                         "morok.antihook.fsgs.win.rdgsbase");
        Value *gsSelf =
            emitWindowsGsSelfRead(WB, "morok.antihook.fsgs.win.gs.self");
        Value *ready =
            WB.CreateICmpNE(gsSelf, ConstantInt::get(i64, 0),
                            "morok.antihook.fsgs.win.gs.ready");
        Value *mismatch = WB.CreateAnd(
            ready,
            WB.CreateICmpNE(gsBase, gsSelf,
                            "morok.antihook.fsgs.win.gs.base.diff"),
            "morok.antihook.fsgs.win.gs.mismatch");
        incrementDiff(WB, diff, mismatch, "morok.antihook.fsgs.win.gs");
        WB.CreateBr(doneBB);

        IRBuilder<> DB(doneBB);
        emitRetDiff(DB, diff);
        return fn;
    }

    auto *installBB =
        BasicBlock::Create(ctx, "morok.antihook.fsgs.sig.install", fn);
    auto *restoreBB =
        BasicBlock::Create(ctx, "morok.antihook.fsgs.sig.restore", fn);
    B.CreateCondBr(supported, installBB, doneBB);

    IRBuilder<> IB(installBB);
    constexpr std::uint64_t kLinuxX64SigactionSize = 152;
    constexpr std::uint32_t kArchPrctl = 158;
    constexpr std::uint64_t kArchGetFs = 0x1003;
    constexpr std::uint64_t kArchGetGs = 0x1004;
    constexpr std::uint32_t kFsFaultBit = 1u;
    constexpr std::uint32_t kGsFaultBit = 2u;
    IB.CreateStore(ConstantInt::get(i32, 0), fsGsSignalMaskGlobal(M))
        ->setVolatile(true);
    Function *handler = fsGsLinuxX86SignalHandler(M);
    auto *actionTy = ArrayType::get(i8, kLinuxX64SigactionSize);
    AllocaInst *action =
        IB.CreateAlloca(actionTy, nullptr, "morok.antihook.fsgs.sa");
    GlobalVariable *oldIll = fsGsOldIllActionGlobal(M);
    storeEmuSiginfoAction(IB, M, action, handler, "morok.antihook.fsgs.sa");
    FunctionCallee sigactionFn = sigactionDecl(M);
    Value *illRc =
        IB.CreateCall(sigactionFn, {ConstantInt::get(i32, 4), action, oldIll},
                      "morok.antihook.fsgs.sigaction.ill");
    IB.CreateCondBr(IB.CreateICmpEQ(illRc, ConstantInt::get(i32, 0),
                                    "morok.antihook.fsgs.sigaction.ill.ok"),
                    probeBB, doneBB);

    IRBuilder<> PB(probeBB);
    AllocaInst *fsSlot =
        PB.CreateAlloca(ip, nullptr, "morok.antihook.fsgs.fs.slot");
    AllocaInst *gsSlot =
        PB.CreateAlloca(ip, nullptr, "morok.antihook.fsgs.gs.slot");
    PB.CreateStore(ConstantInt::get(ip, 0), fsSlot)->setVolatile(true);
    PB.CreateStore(ConstantInt::get(ip, 0), gsSlot)->setVolatile(true);
    Value *fsBase =
        emitFsGsBaseRead(PB, /*Gs=*/false, "morok.antihook.fsgs.rdfsbase");
    Value *gsBase =
        emitFsGsBaseRead(PB, /*Gs=*/true, "morok.antihook.fsgs.rdgsbase");
    Value *fsRc = emitLinuxSyscall(
        PB, M, TT, kArchPrctl,
        {ConstantInt::get(ip, kArchGetFs),
         PB.CreatePtrToInt(fsSlot, ip, "morok.antihook.fsgs.fs.slot.ip")});
    fsRc->setName("morok.antihook.fsgs.fs.arch_prctl");
    Value *gsRc = emitLinuxSyscall(
        PB, M, TT, kArchPrctl,
        {ConstantInt::get(ip, kArchGetGs),
         PB.CreatePtrToInt(gsSlot, ip, "morok.antihook.fsgs.gs.slot.ip")});
    gsRc->setName("morok.antihook.fsgs.gs.arch_prctl");
    auto *fsSys = PB.CreateLoad(ip, fsSlot, "morok.antihook.fsgs.fs.sys");
    fsSys->setVolatile(true);
    auto *gsSys = PB.CreateLoad(ip, gsSlot, "morok.antihook.fsgs.gs.sys");
    gsSys->setVolatile(true);
    auto *mask =
        PB.CreateLoad(i32, fsGsSignalMaskGlobal(M),
                      "morok.antihook.fsgs.sig.mask");
    mask->setVolatile(true);
    Value *fsTrapped = PB.CreateICmpNE(
        PB.CreateAnd(mask, ConstantInt::get(i32, kFsFaultBit),
                     "morok.antihook.fsgs.sig.fs.bit"),
        ConstantInt::get(i32, 0), "morok.antihook.fsgs.sig.fs.trapped");
    Value *gsTrapped = PB.CreateICmpNE(
        PB.CreateAnd(mask, ConstantInt::get(i32, kGsFaultBit),
                     "morok.antihook.fsgs.sig.gs.bit"),
        ConstantInt::get(i32, 0), "morok.antihook.fsgs.sig.gs.trapped");
    Value *fsReady = PB.CreateAnd(
        PB.CreateICmpEQ(fsRc, ConstantInt::get(ip, 0),
                        "morok.antihook.fsgs.fs.arch.ok"),
        PB.CreateNot(fsTrapped), "morok.antihook.fsgs.fs.ready");
    Value *gsReady = PB.CreateAnd(
        PB.CreateICmpEQ(gsRc, ConstantInt::get(ip, 0),
                        "morok.antihook.fsgs.gs.arch.ok"),
        PB.CreateNot(gsTrapped), "morok.antihook.fsgs.gs.ready");
    Value *fsMismatch = PB.CreateAnd(
        fsReady,
        PB.CreateICmpNE(fsBase, PB.CreateZExtOrTrunc(fsSys, i64),
                        "morok.antihook.fsgs.fs.base.diff"),
        "morok.antihook.fsgs.fs.mismatch");
    Value *gsMismatch = PB.CreateAnd(
        gsReady,
        PB.CreateICmpNE(gsBase, PB.CreateZExtOrTrunc(gsSys, i64),
                        "morok.antihook.fsgs.gs.base.diff"),
        "morok.antihook.fsgs.gs.mismatch");
    incrementDiff(PB, diff, PB.CreateOr(fsMismatch, gsMismatch,
                                        "morok.antihook.fsgs.mismatch"),
                  "morok.antihook.fsgs.base");
    PB.CreateBr(restoreBB);

    IRBuilder<> RB(restoreBB);
    RB.CreateCall(sigactionFn,
                  {ConstantInt::get(i32, 4), oldIll,
                   ConstantPointerNull::get(ptr)},
                  "morok.antihook.fsgs.restore.ill");
    RB.CreateBr(doneBB);

    IRBuilder<> DB(doneBB);
    emitRetDiff(DB, diff);
    return fn;
}

Function *emulationDivergenceProbe(Module &M, const Triple &TT) {
    if (TT.getArch() != Triple::x86_64)
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.emu.x86"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.emu.x86", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->addFnAttr(Attribute::NoRedZone);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    AllocaInst *diff = B.CreateAlloca(i64, nullptr, "morok.antihook.emu.diff");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);

    auto *flagsTy = FunctionType::get(i64, false);
    auto *i32 = Type::getInt32Ty(ctx);
    InlineAsm *flagsAsm = InlineAsm::get(
        flagsTy, "xorq %rax, %rax\n\tpushfq\n\tpopq $0",
        "=r,~{rax},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *flags =
        B.CreateCall(flagsTy, flagsAsm, {}, "morok.antihook.emu.flags.raw");
    constexpr std::uint64_t kStableXorFlagMask =
        (1ull << 0) | (1ull << 2) | (1ull << 6) | (1ull << 7) | (1ull << 11);
    constexpr std::uint64_t kExpectedXorFlags = (1ull << 2) | (1ull << 6);
    Value *masked = B.CreateAnd(
        flags, ConstantInt::get(i64, kStableXorFlagMask),
        "morok.antihook.emu.flags.masked");
    Value *mismatch =
        B.CreateICmpNE(masked, ConstantInt::get(i64, kExpectedXorFlags),
                       "morok.antihook.emu.flags.mismatch");
    incrementDiff(B, diff, mismatch, "morok.antihook.emu.flags");

    auto *fullFlagsTy = StructType::get(ctx, {i64, i64});
    auto *fullFlagsFnTy = FunctionType::get(fullFlagsTy, false);
    InlineAsm *fullFlagsAsm = InlineAsm::get(
        fullFlagsFnTy,
        "pushfq\n\tpopq %rcx\n\txorq %rax, %rax\n\tpushfq\n\tpopq %rax",
        "={rax},={rcx},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *fullFlags = B.CreateCall(fullFlagsFnTy, fullFlagsAsm, {},
                                    "morok.antihook.emu.eflags.full.raw");
    Value *fullAfter =
        B.CreateExtractValue(fullFlags, {0}, "morok.antihook.emu.eflags.after");
    Value *fullBefore = B.CreateExtractValue(
        fullFlags, {1}, "morok.antihook.emu.eflags.before");
    constexpr std::uint64_t kFullEflagsMask = 0x003F7FD5ULL;
    constexpr std::uint64_t kArithmeticFlagMask =
        (1ull << 0) | (1ull << 2) | (1ull << 4) | (1ull << 6) |
        (1ull << 7) | (1ull << 11);
    constexpr std::uint64_t kXorArithmeticFlags = (1ull << 2) | (1ull << 6);
    Value *fullAfterMasked =
        B.CreateAnd(fullAfter, ConstantInt::get(i64, kFullEflagsMask),
                    "morok.antihook.emu.eflags.masked");
    Value *preservedExpected = B.CreateAnd(
        fullBefore,
        ConstantInt::get(i64, kFullEflagsMask & ~kArithmeticFlagMask),
        "morok.antihook.emu.eflags.preserved");
    Value *fullExpected = B.CreateOr(
        preservedExpected, ConstantInt::get(i64, kXorArithmeticFlags),
        "morok.antihook.emu.eflags.expected");
    Value *fullWord = B.CreateXor(fullAfterMasked, fullExpected,
                                  "morok.antihook.emu.eflags.word");
    Value *fullMismatch =
        B.CreateICmpNE(fullWord, ConstantInt::get(i64, 0),
                       "morok.antihook.emu.eflags.mismatch");
    incrementDiff(B, diff, fullMismatch, "morok.antihook.emu.eflags");

    InlineAsm *cmpFlagsAsm = InlineAsm::get(
        flagsTy,
        "xorq %rax, %rax\n\tmovq %rax, %rcx\n\tincq %rcx\n\tcmpq %rcx, "
        "%rax\n\tpushfq\n\tpopq $0",
        "=r,~{rax},~{rcx},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *cmpFlags = B.CreateCall(flagsTy, cmpFlagsAsm, {},
                                   "morok.antihook.emu.cmp.flags.raw");
    constexpr std::uint64_t kExpectedCmpFlags =
        (1ull << 0) | (1ull << 2) | (1ull << 7);
    Value *cmpMasked = B.CreateAnd(
        cmpFlags, ConstantInt::get(i64, kStableXorFlagMask),
        "morok.antihook.emu.cmp.flags.masked");
    Value *cmpMismatch =
        B.CreateICmpNE(cmpMasked, ConstantInt::get(i64, kExpectedCmpFlags),
                       "morok.antihook.emu.cmp.flags.mismatch");
    incrementDiff(B, diff, cmpMismatch, "morok.antihook.emu.cmp.flags");

    auto *setccTy = StructType::get(ctx, {i32, i32, i32, i32});
    auto *setccFnTy = FunctionType::get(setccTy, false);
    InlineAsm *setccAsm = InlineAsm::get(
        setccFnTy,
        "xorq %rax, %rax\n\tmovq %rax, %rcx\n\tincq %rcx\n\tcmpq %rcx, "
        "%rax\n\tsetb %al\n\tsetz %cl\n\tsetl %dl\n\tsetg %bl\n\tmovzbl "
        "%al, %eax\n\tmovzbl %cl, %ecx\n\tmovzbl %dl, %edx\n\tmovzbl %bl, "
        "%ebx",
        "={eax},={ecx},={edx},={ebx},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *setcc =
        B.CreateCall(setccFnTy, setccAsm, {}, "morok.antihook.emu.setcc.raw");
    Value *setb = B.CreateExtractValue(setcc, {0}, "morok.antihook.emu.setb");
    Value *setz = B.CreateExtractValue(setcc, {1}, "morok.antihook.emu.setz");
    Value *setl = B.CreateExtractValue(setcc, {2}, "morok.antihook.emu.setl");
    Value *setg = B.CreateExtractValue(setcc, {3}, "morok.antihook.emu.setg");
    Value *setccMismatch = B.CreateOr(
        B.CreateOr(B.CreateICmpNE(setb, ConstantInt::get(i32, 1)),
                   B.CreateICmpNE(setz, ConstantInt::get(i32, 0))),
        B.CreateOr(B.CreateICmpNE(setl, ConstantInt::get(i32, 1)),
                   B.CreateICmpNE(setg, ConstantInt::get(i32, 0))),
        "morok.antihook.emu.setcc.mismatch");
    incrementDiff(B, diff, setccMismatch, "morok.antihook.emu.setcc");

    Value *leaf0 = emitCpuid(B, M, ConstantInt::get(i32, 0),
                             ConstantInt::get(i32, 0));
    Value *maxBasic = cpuidReg(B, leaf0, 0, "morok.antihook.emu.cpuid.max");
    Value *vendorBits = B.CreateOr(
        cpuidReg(B, leaf0, 1, "morok.antihook.emu.cpuid.ebx"),
        B.CreateOr(cpuidReg(B, leaf0, 2, "morok.antihook.emu.cpuid.ecx"),
                   cpuidReg(B, leaf0, 3, "morok.antihook.emu.cpuid.edx")),
        "morok.antihook.emu.cpuid.vendor.bits");
    Value *leaf0Bad = B.CreateOr(
        B.CreateICmpEQ(maxBasic, ConstantInt::get(i32, 0)),
        B.CreateICmpEQ(vendorBits, ConstantInt::get(i32, 0)),
        "morok.antihook.emu.cpuid.leaf0.bad");
    Value *leaf1 = emitCpuid(B, M, ConstantInt::get(i32, 1),
                             ConstantInt::get(i32, 0));
    Value *ecx = cpuidReg(B, leaf1, 2, "morok.antihook.emu.cpuid.ecx1");
    Value *edx = cpuidReg(B, leaf1, 3, "morok.antihook.emu.cpuid.edx1");
    constexpr std::uint32_t kX86_64BaselineFeatures =
        (1u << 0) | (1u << 15) | (1u << 26); // FPU, CMOV, SSE2.
    Value *baseline =
        B.CreateAnd(edx, ConstantInt::get(i32, kX86_64BaselineFeatures),
                    "morok.antihook.emu.cpuid.baseline");
    Value *baselineBad = B.CreateICmpNE(
        baseline, ConstantInt::get(i32, kX86_64BaselineFeatures),
        "morok.antihook.emu.cpuid.baseline.bad");
    Value *cpuidMismatch = B.CreateOr(leaf0Bad, baselineBad,
                                      "morok.antihook.emu.cpuid.mismatch");
    incrementDiff(B, diff, cpuidMismatch, "morok.antihook.emu.cpuid");
    emitRdrandCfGap(B, M, fn, diff, ecx);
    emitLinuxX86SemanticGapProbe(B, M, TT, fn, diff);
    emitRetDiff(B, diff);
    return fn;
}

Function *fpuSimdDivergenceProbe(Module &M, const Triple &TT) {
    const bool IsX64 = TT.getArch() == Triple::x86_64;
    const bool IsX86 = TT.getArch() == Triple::x86;
    if (!IsX64 && !IsX86)
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.fpu.x86"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.fpu.x86", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->addFnAttr(Attribute::NoRedZone);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    AllocaInst *diff = B.CreateAlloca(i64, nullptr, "morok.antihook.fpu.diff");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);

    Value *leaf1 = emitCpuid(B, M, ConstantInt::get(i32, 1),
                             ConstantInt::get(i32, 0));
    Value *edx = cpuidReg(B, leaf1, 3, "morok.antihook.fpu.cpuid.edx");
    Value *sseFlag = B.CreateAnd(edx, ConstantInt::get(i32, 1u << 25),
                                 "morok.antihook.fpu.cpuid.sse");
    Value *hasSse =
        B.CreateICmpNE(sseFlag, ConstantInt::get(i32, 0),
                       "morok.antihook.fpu.sse.supported");
    BasicBlock *probeBB =
        BasicBlock::Create(ctx, "morok.antihook.fpu.probe", fn);
    BasicBlock *doneBB = BasicBlock::Create(ctx, "morok.antihook.fpu.done", fn);
    B.CreateCondBr(hasSse, probeBB, doneBB);
    B.SetInsertPoint(probeBB);

    auto *asmTy = FunctionType::get(i32, false);
    const char *Asm =
        IsX64
            ? "xorl %eax, %eax\n\t"
              "subq $$128, %rsp\n\t"
              "stmxcsr 0(%rsp)\n\t"
              "fnstcw 4(%rsp)\n\t"
              "movl $$0x00001fc0, 8(%rsp)\n\t"
              "ldmxcsr 8(%rsp)\n\t"
              "movl $$0x00000001, 16(%rsp)\n\t"
              "movl $$0x00000000, 20(%rsp)\n\t"
              "movss 16(%rsp), %xmm0\n\t"
              "addss 20(%rsp), %xmm0\n\t"
              "stmxcsr 24(%rsp)\n\t"
              "movl 24(%rsp), %esi\n\t"
              "andl $$0x2, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00001f80, 8(%rsp)\n\t"
              "ldmxcsr 8(%rsp)\n\t"
              "movss 16(%rsp), %xmm0\n\t"
              "addss 20(%rsp), %xmm0\n\t"
              "stmxcsr 24(%rsp)\n\t"
              "movl 24(%rsp), %esi\n\t"
              "andl $$0x2, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$1, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00001f80, 8(%rsp)\n\t"
              "ldmxcsr 8(%rsp)\n\t"
              "movl $$0x7f800001, 32(%rsp)\n\t"
              "movss 32(%rsp), %xmm0\n\t"
              "addss 20(%rsp), %xmm0\n\t"
              "stmxcsr 24(%rsp)\n\t"
              "movl 24(%rsp), %esi\n\t"
              "andl $$0x1, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$2, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00007f80, 8(%rsp)\n\t"
              "ldmxcsr 8(%rsp)\n\t"
              "stmxcsr 24(%rsp)\n\t"
              "movl 24(%rsp), %esi\n\t"
              "andl $$0x6000, %esi\n\t"
              "cmpl $$0x6000, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$3, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movw $$0x0f7f, 36(%rsp)\n\t"
              "fldcw 36(%rsp)\n\t"
              "fnstcw 40(%rsp)\n\t"
              "movzwl 40(%rsp), %esi\n\t"
              "andl $$0x0c00, %esi\n\t"
              "cmpl $$0x0c00, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$4, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "fnclex\n\t"
              "fldz\n\t"
              "fnstenv 48(%rsp)\n\t"
              "fstp %st(0)\n\t"
              "movl 60(%rsp), %esi\n\t"
              "testl %esi, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$5, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "ldmxcsr 0(%rsp)\n\t"
              "fldcw 4(%rsp)\n\t"
              "addq $$128, %rsp"
            : "xorl %eax, %eax\n\t"
              "subl $$128, %esp\n\t"
              "stmxcsr 0(%esp)\n\t"
              "fnstcw 4(%esp)\n\t"
              "movl $$0x00001fc0, 8(%esp)\n\t"
              "ldmxcsr 8(%esp)\n\t"
              "movl $$0x00000001, 16(%esp)\n\t"
              "movl $$0x00000000, 20(%esp)\n\t"
              "movss 16(%esp), %xmm0\n\t"
              "addss 20(%esp), %xmm0\n\t"
              "stmxcsr 24(%esp)\n\t"
              "movl 24(%esp), %esi\n\t"
              "andl $$0x2, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00001f80, 8(%esp)\n\t"
              "ldmxcsr 8(%esp)\n\t"
              "movss 16(%esp), %xmm0\n\t"
              "addss 20(%esp), %xmm0\n\t"
              "stmxcsr 24(%esp)\n\t"
              "movl 24(%esp), %esi\n\t"
              "andl $$0x2, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$1, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00001f80, 8(%esp)\n\t"
              "ldmxcsr 8(%esp)\n\t"
              "movl $$0x7f800001, 32(%esp)\n\t"
              "movss 32(%esp), %xmm0\n\t"
              "addss 20(%esp), %xmm0\n\t"
              "stmxcsr 24(%esp)\n\t"
              "movl 24(%esp), %esi\n\t"
              "andl $$0x1, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$2, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movl $$0x00007f80, 8(%esp)\n\t"
              "ldmxcsr 8(%esp)\n\t"
              "stmxcsr 24(%esp)\n\t"
              "movl 24(%esp), %esi\n\t"
              "andl $$0x6000, %esi\n\t"
              "cmpl $$0x6000, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$3, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "movw $$0x0f7f, 36(%esp)\n\t"
              "fldcw 36(%esp)\n\t"
              "fnstcw 40(%esp)\n\t"
              "movzwl 40(%esp), %esi\n\t"
              "andl $$0x0c00, %esi\n\t"
              "cmpl $$0x0c00, %esi\n\t"
              "setne %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$4, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "fnclex\n\t"
              "fldz\n\t"
              "fnstenv 48(%esp)\n\t"
              "fstp %st(0)\n\t"
              "movl 60(%esp), %esi\n\t"
              "testl %esi, %esi\n\t"
              "sete %cl\n\t"
              "movzbl %cl, %ecx\n\t"
              "shll $$5, %ecx\n\t"
              "orl %ecx, %eax\n\t"
              "ldmxcsr 0(%esp)\n\t"
              "fldcw 4(%esp)\n\t"
              "addl $$128, %esp";
    InlineAsm *ProbeAsm = InlineAsm::get(
        asmTy, Asm,
        "={eax},~{ecx},~{esi},~{xmm0},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *bits =
        B.CreateCall(asmTy, ProbeAsm, {}, "morok.antihook.fpu.bits.raw");
    auto mixProbe = [&](IRBuilder<> &Builder, Value *Flag, const Twine &Name,
                        std::uint64_t Salt) {
        auto *old = Builder.CreateLoad(i64, diff, Name + ".old");
        old->setVolatile(true);
        Value *wide = Builder.CreateZExtOrTrunc(Flag, i64, Name + ".wide");
        Value *mask =
            Builder.CreateSub(ConstantInt::get(i64, 0), wide, Name + ".mask");
        Value *selected = Builder.CreateAnd(mask, ConstantInt::get(i64, Salt),
                                            Name + ".salt");
        Value *mixed = Builder.CreateMul(
            Builder.CreateXor(old, selected, Name + ".xor"),
            ConstantInt::get(i64, Salt ^ 0x9E3779B97F4A7C15ULL),
            Name + ".mul");
        Value *next = Builder.CreateXor(
            mixed, Builder.CreateLShr(mixed, ConstantInt::get(i64, 29)),
            Name + ".next");
        auto *st = Builder.CreateStore(next, diff);
        st->setVolatile(true);
    };
    auto subProbe = [&](std::uint32_t Mask, const Twine &Name,
                        std::uint64_t Salt) {
        Value *Flag = B.CreateICmpNE(
            B.CreateAnd(bits, ConstantInt::get(i32, Mask), Name + ".masked"),
            ConstantInt::get(i32, 0), Name + ".mismatch");
        mixProbe(B, Flag, Name, Salt);
    };
    subProbe(1u << 0, "morok.antihook.fpu.daz.flush",
             0xA16B4F927C35D8E1ULL);
    subProbe(1u << 1, "morok.antihook.fpu.denormal.flag",
             0x5C8E21D3A7946F0BULL);
    subProbe(1u << 2, "morok.antihook.fpu.snan.invalid",
             0xD3B64109E85A27C4ULL);
    subProbe(1u << 3, "morok.antihook.fpu.mxcsr.round",
             0x7E492CA1B603D5F8ULL);
    subProbe(1u << 4, "morok.antihook.fpu.fcw.round",
             0x2B8F70D4C15A9E36ULL);
    subProbe(1u << 5, "morok.antihook.fpu.fnstenv.ip",
             0xE0953C6AB27D184FULL);

    Value *ecx = cpuidReg(B, leaf1, 2, "morok.antihook.fpu.cpuid.ecx");
    Value *aesFlag = B.CreateAnd(ecx, ConstantInt::get(i32, 1u << 25),
                                 "morok.antihook.fpu.cpuid.aes");
    Value *hasAes =
        B.CreateICmpNE(aesFlag, ConstantInt::get(i32, 0),
                       "morok.antihook.fpu.aes.supported");
    BasicBlock *aesBB = BasicBlock::Create(ctx, "morok.antihook.fpu.aes", fn);
    B.CreateCondBr(hasAes, aesBB, doneBB);

    IRBuilder<> AB(aesBB);
    InlineAsm *AesAsm = InlineAsm::get(
        asmTy,
        "xorl %eax, %eax\n\t"
        "pxor %xmm1, %xmm1\n\t"
        "pcmpeqd %xmm0, %xmm0\n\t"
        "movdqa %xmm0, %xmm2\n\t"
        ".byte 0x66,0x0f,0x38,0xdd,0xc1\n\t"
        ".byte 0x66,0x0f,0x38,0xdf,0xc1\n\t"
        "pcmpeqd %xmm2, %xmm0\n\t"
        "pmovmskb %xmm0, %ecx\n\t"
        "cmpl $$0xffff, %ecx\n\t"
        "setne %al",
        "={eax},~{ecx},~{xmm0},~{xmm1},~{xmm2},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *aes =
        AB.CreateCall(asmTy, AesAsm, {}, "morok.antihook.fpu.aes.raw");
    Value *aesMismatch =
        AB.CreateICmpNE(aes, ConstantInt::get(i32, 0),
                        "morok.antihook.fpu.aes.roundtrip");
    mixProbe(AB, aesMismatch, "morok.antihook.fpu.aes",
             0x91D62B4F0CA758E3ULL);
    AB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    emitRetDiff(B, diff);
    return fn;
}

Value *bufferHasLiteral(IRBuilder<> &B, Module &M, AllocaInst *Buf, Value *N,
                        std::initializer_list<unsigned char> Literal,
                        std::uint64_t MaxBytes, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    if (Literal.size() == 0 || MaxBytes < Literal.size())
        return ConstantInt::getFalse(ctx);

    std::vector<unsigned char> bytes(Literal.begin(), Literal.end());
    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);

    auto *loopBB = BasicBlock::Create(ctx, (Name + ".loop").str(), fn);
    auto *bodyBB = BasicBlock::Create(ctx, (Name + ".body").str(), fn);
    auto *hitBB = BasicBlock::Create(ctx, (Name + ".hit").str(), fn);
    auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(loopBB);

    IRBuilder<> LB(loopBB);
    auto *found = LB.CreateLoad(i1, foundSlot, Name + ".found.v");
    found->setVolatile(true);
    auto *idx = LB.CreateLoad(ip, idxSlot, Name + ".idx");
    idx->setVolatile(true);
    Value *end = LB.CreateAdd(idx, ConstantInt::get(ip, bytes.size()),
                              Name + ".end");
    Value *withinRead = LB.CreateICmpSLE(end, N, Name + ".within.read");
    Value *withinBuf = LB.CreateICmpULE(end, ConstantInt::get(ip, MaxBytes),
                                        Name + ".within.buf");
    LB.CreateCondBr(LB.CreateAnd(LB.CreateAnd(withinRead, withinBuf),
                                 LB.CreateNot(found)),
                    bodyBB, doneBB);

    IRBuilder<> MB(bodyBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < bytes.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf,
                           MB.CreateAdd(idx, ConstantInt::get(ip, j)),
                           Name + ".ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, bytes[j])),
            Name + ".match");
    }
    MB.CreateCondBr(match, hitBB, nextBB);

    IRBuilder<> HB(hitBB);
    HB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    HB.CreateBr(doneBB);

    IRBuilder<> NB(nextBB);
    NB.CreateStore(NB.CreateAdd(idx, ConstantInt::get(ip, 1), Name + ".idx.next"),
                   idxSlot)
        ->setVolatile(true);
    NB.CreateBr(loopBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreateLoad(i1, foundSlot, Name + ".out");
    out->setVolatile(true);
    return out;
}

Value *bufferEqualsLiteral(IRBuilder<> &B, Module &M, AllocaInst *Buf, Value *N,
                           std::initializer_list<unsigned char> Literal,
                           std::uint64_t MaxBytes, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    if (Literal.size() == 0 || MaxBytes < Literal.size())
        return ConstantInt::getFalse(ctx);

    std::vector<unsigned char> bytes(Literal.begin(), Literal.end());
    auto *bodyBB = BasicBlock::Create(ctx, (Name + ".body").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    BasicBlock *guardBB = B.GetInsertBlock();
    Value *sameSize =
        B.CreateICmpEQ(N, ConstantInt::get(ip, bytes.size()), Name + ".size");
    B.CreateCondBr(sameSize, bodyBB, doneBB);

    IRBuilder<> MB(bodyBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < bytes.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf, ConstantInt::get(ip, j),
                           Name + ".ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, bytes[j])),
            Name + ".match");
    }
    MB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreatePHI(Type::getInt1Ty(ctx), 2, Name + ".out");
    out->addIncoming(ConstantInt::getFalse(ctx), guardBB);
    out->addIncoming(match, bodyBB);
    return out;
}

Value *bufferBasenameEqualsLiteral(IRBuilder<> &B, Module &M, AllocaInst *Buf,
                                   Value *N,
                                   std::initializer_list<unsigned char> Literal,
                                   std::uint64_t MaxBytes,
                                   const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    if (Literal.size() == 0 || MaxBytes < Literal.size())
        return ConstantInt::getFalse(ctx);

    std::vector<unsigned char> bytes(Literal.begin(), Literal.end());
    auto *prefixBB = BasicBlock::Create(ctx, (Name + ".prefix").str(), fn);
    auto *prevBB = BasicBlock::Create(ctx, (Name + ".prev").str(), fn);
    auto *matchBB = BasicBlock::Create(ctx, (Name + ".match").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    BasicBlock *guardBB = B.GetInsertBlock();
    Value *longEnough =
        B.CreateICmpSGE(N, ConstantInt::get(ip, bytes.size()), Name + ".len");
    Value *withinBuf = B.CreateICmpSLE(N, ConstantInt::get(ip, MaxBytes),
                                       Name + ".within.buf");
    B.CreateCondBr(B.CreateAnd(longEnough, withinBuf, Name + ".ready"),
                   prefixBB, doneBB);

    IRBuilder<> PB(prefixBB);
    Value *start = PB.CreateSub(N, ConstantInt::get(ip, bytes.size()),
                                Name + ".start");
    Value *atStart = PB.CreateICmpEQ(start, ConstantInt::get(ip, 0),
                                     Name + ".at.start");
    PB.CreateCondBr(atStart, matchBB, prevBB);

    IRBuilder<> PRB(prevBB);
    Value *prevIdx = PRB.CreateSub(start, ConstantInt::get(ip, 1),
                                   Name + ".prev.idx");
    Value *prev = loadAt(PRB, M, i8, Buf, prevIdx, Name + ".prev.ch");
    Value *afterSlash =
        PRB.CreateICmpEQ(prev, ConstantInt::get(i8, '/'), Name + ".after.slash");
    PRB.CreateCondBr(afterSlash, matchBB, doneBB);

    IRBuilder<> MB(matchBB);
    Value *matchStart = MB.CreateSub(N, ConstantInt::get(ip, bytes.size()),
                                     Name + ".match.start");
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < bytes.size(); ++j) {
        Value *ch = loadAt(MB, M, i8, Buf,
                           MB.CreateAdd(matchStart, ConstantInt::get(ip, j)),
                           Name + ".ch");
        match = MB.CreateAnd(
            match, MB.CreateICmpEQ(ch, ConstantInt::get(i8, bytes[j])),
            Name + ".match");
    }
    MB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreatePHI(i1, 3, Name + ".out");
    out->addIncoming(ConstantInt::getFalse(ctx), guardBB);
    out->addIncoming(ConstantInt::getFalse(ctx), prevBB);
    out->addIncoming(match, matchBB);
    return out;
}

Value *bufferHasLinuxParentToolComm(IRBuilder<> &B, Module &M, AllocaInst *Buf,
                                    Value *N, std::uint64_t MaxBytes,
                                    const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Value *hit = ConstantInt::getFalse(ctx);
    unsigned idx = 0;
    auto add = [&](std::initializer_list<unsigned char> bytes) {
        Value *one = bufferEqualsLiteral(B, M, Buf, N, bytes, MaxBytes,
                                         Name + ".n" + Twine(idx++));
        hit = B.CreateOr(hit, one, Name + ".any");
    };
    add({0x67, 0x64, 0x62, 0x0a});
    add({0x6c, 0x6c, 0x64, 0x62, 0x0a});
    add({0x73, 0x74, 0x72, 0x61, 0x63, 0x65, 0x0a});
    add({0x6c, 0x74, 0x72, 0x61, 0x63, 0x65, 0x0a});
    add({0x72, 0x72, 0x0a});
    add({0x70, 0x65, 0x72, 0x66, 0x0a});
    add({0x76, 0x61, 0x6c, 0x67, 0x72, 0x69, 0x6e, 0x64, 0x0a});
    add({0x67, 0x63, 0x6f, 0x72, 0x65, 0x0a});
    return hit;
}

Value *bufferHasLinuxParentToolBasename(IRBuilder<> &B, Module &M,
                                        AllocaInst *Buf, Value *N,
                                        std::uint64_t MaxBytes,
                                        const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Value *hit = ConstantInt::getFalse(ctx);
    unsigned idx = 0;
    auto add = [&](std::initializer_list<unsigned char> bytes) {
        Value *one = bufferBasenameEqualsLiteral(B, M, Buf, N, bytes, MaxBytes,
                                                 Name + ".n" + Twine(idx++));
        hit = B.CreateOr(hit, one, Name + ".any");
    };
    add({0x67, 0x64, 0x62});
    add({0x6c, 0x6c, 0x64, 0x62});
    add({0x73, 0x74, 0x72, 0x61, 0x63, 0x65});
    add({0x6c, 0x74, 0x72, 0x61, 0x63, 0x65});
    add({0x72, 0x72});
    add({0x70, 0x65, 0x72, 0x66});
    add({0x76, 0x61, 0x6c, 0x67, 0x72, 0x69, 0x6e, 0x64});
    add({0x67, 0x63, 0x6f, 0x72, 0x65});
    return hit;
}

Value *bufferHasLinuxAnonymousExecMap(IRBuilder<> &B, Module &M,
                                      AllocaInst *Buf, Value *N,
                                      std::uint64_t MaxBytes,
                                      const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);

    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 1), idxSlot)->setVolatile(true);

    auto *loopBB = BasicBlock::Create(ctx, (Name + ".loop").str(), fn);
    auto *bodyBB = BasicBlock::Create(ctx, (Name + ".body").str(), fn);
    auto *hitBB = BasicBlock::Create(ctx, (Name + ".hit").str(), fn);
    auto *nextBB = BasicBlock::Create(ctx, (Name + ".next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(loopBB);

    IRBuilder<> LB(loopBB);
    auto *found = LB.CreateLoad(i1, foundSlot, Name + ".found.v");
    found->setVolatile(true);
    auto *idx = LB.CreateLoad(ip, idxSlot, Name + ".idx");
    idx->setVolatile(true);
    Value *end = LB.CreateAdd(idx, ConstantInt::get(ip, 86), Name + ".end");
    Value *withinRead = LB.CreateICmpSLE(end, N, Name + ".within.read");
    Value *withinBuf = LB.CreateICmpULE(end, ConstantInt::get(ip, MaxBytes),
                                        Name + ".within.buf");
    LB.CreateCondBr(LB.CreateAnd(LB.CreateAnd(withinRead, withinBuf),
                                 LB.CreateNot(found)),
                    bodyBB, doneBB);

    IRBuilder<> MB(bodyBB);
    auto isChar = [&](Value *V, char C) {
        return MB.CreateICmpEQ(
            V, ConstantInt::get(i8, static_cast<unsigned char>(C)));
    };
    Value *prev = loadAt(MB, M, i8, Buf,
                         MB.CreateSub(idx, ConstantInt::get(ip, 1)),
                         Name + ".prev");
    Value *p0 = loadAt(MB, M, i8, Buf, idx, Name + ".perm0");
    Value *p1 = loadAt(MB, M, i8, Buf,
                       MB.CreateAdd(idx, ConstantInt::get(ip, 1)),
                       Name + ".perm1");
    Value *p2 = loadAt(MB, M, i8, Buf,
                       MB.CreateAdd(idx, ConstantInt::get(ip, 2)),
                       Name + ".perm2");
    Value *p3 = loadAt(MB, M, i8, Buf,
                       MB.CreateAdd(idx, ConstantInt::get(ip, 3)),
                       Name + ".perm3");
    Value *after = loadAt(MB, M, i8, Buf,
                          MB.CreateAdd(idx, ConstantInt::get(ip, 4)),
                          Name + ".after");
    Value *permWindow = MB.CreateAnd(
        MB.CreateAnd(isChar(prev, ' '), isChar(after, ' ')),
        MB.CreateAnd(
            MB.CreateAnd(MB.CreateOr(isChar(p0, 'r'), isChar(p0, '-')),
                         MB.CreateOr(isChar(p1, 'w'), isChar(p1, '-'))),
            MB.CreateAnd(MB.CreateOr(isChar(p2, 'x'), isChar(p2, '-')),
                         MB.CreateOr(isChar(p3, 'p'), isChar(p3, 's')))),
        Name + ".perms");
    Value *seenSlash = ConstantInt::getFalse(ctx);
    Value *seenBracket = ConstantInt::getFalse(ctx);
    Value *seenPathNonSpace = ConstantInt::getFalse(ctx);
    Value *seenNewline = ConstantInt::getFalse(ctx);
    Value *inToken = ConstantInt::getFalse(ctx);
    Value *fieldCount = ConstantInt::get(i8, 0);
    // /proc/self/maps pathnames start after offset/dev/inode. Bracketed
    // kernel pseudo-maps like [vdso] are named mappings, not anonymous JIT
    // scratch pages.
    for (std::uint64_t off = 5; off < 86; ++off) {
        Value *ch = loadAt(MB, M, i8, Buf,
                           MB.CreateAdd(idx, ConstantInt::get(ip, off)),
                           Name + ".path.ch");
        Value *beforeNl = MB.CreateNot(seenNewline);
        Value *isNl = isChar(ch, '\n');
        Value *isSpace =
            MB.CreateOr(isChar(ch, ' '), isChar(ch, '\t'), Name + ".path.ws");
        Value *terminator =
            MB.CreateOr(isSpace, isNl, Name + ".path.terminator");
        Value *dataChar =
            MB.CreateAnd(beforeNl, MB.CreateNot(terminator), Name + ".path.data");
        Value *pathField = MB.CreateAnd(
            beforeNl,
            MB.CreateICmpUGE(fieldCount, ConstantInt::get(i8, 3),
                             Name + ".path.field"),
            Name + ".path.field.ready");
        Value *pathChar =
            MB.CreateAnd(pathField, dataChar, Name + ".path.nonspace");
        seenSlash =
            MB.CreateOr(seenSlash, MB.CreateAnd(pathChar, isChar(ch, '/')),
                        Name + ".path.slash");
        seenBracket =
            MB.CreateOr(seenBracket, MB.CreateAnd(pathChar, isChar(ch, '[')),
                        Name + ".path.bracket");
        seenPathNonSpace =
            MB.CreateOr(seenPathNonSpace, pathChar, Name + ".path.any");
        Value *tokenEnd = MB.CreateAnd(
            MB.CreateAnd(beforeNl, inToken, Name + ".path.token.live"),
            terminator, Name + ".path.token.end");
        Value *tokenStart = MB.CreateAnd(
            MB.CreateAnd(beforeNl, MB.CreateNot(inToken),
                         Name + ".path.token.idle"),
            dataChar, Name + ".path.token.start");
        fieldCount = MB.CreateAdd(fieldCount, MB.CreateZExt(tokenEnd, i8),
                                  Name + ".path.field.count");
        inToken =
            MB.CreateOr(MB.CreateAnd(inToken, MB.CreateNot(tokenEnd),
                                     Name + ".path.token.keep"),
                        tokenStart, Name + ".path.token");
        seenNewline =
            MB.CreateOr(seenNewline, isNl, Name + ".path.nl");
    }
    Value *pathClear = MB.CreateAnd(
        MB.CreateAnd(MB.CreateNot(seenSlash), MB.CreateNot(seenBracket),
                     Name + ".path.pseudo.clear"),
        MB.CreateNot(seenPathNonSpace, Name + ".path.empty"),
        Name + ".path.clear");
    Value *anonExec = MB.CreateAnd(
        permWindow,
        MB.CreateAnd(MB.CreateAnd(isChar(p2, 'x'), isChar(p3, 'p')),
                     pathClear),
        Name + ".anon.exec");
    MB.CreateCondBr(anonExec, hitBB, nextBB);

    IRBuilder<> HB(hitBB);
    HB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    HB.CreateBr(doneBB);

    IRBuilder<> NB(nextBB);
    NB.CreateStore(NB.CreateAdd(idx, ConstantInt::get(ip, 1),
                                Name + ".idx.next"),
                   idxSlot)
        ->setVolatile(true);
    NB.CreateBr(loopBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreateLoad(i1, foundSlot, Name + ".out");
    out->setVolatile(true);
    return out;
}

Value *bufferHasLinuxRxMemoryLiteral(IRBuilder<> &B, Module &M, AllocaInst *Buf,
                                     Value *N,
                                     std::initializer_list<unsigned char> Literal,
                                     std::uint64_t MaxBytes,
                                     std::uint64_t MaxRegionBytes,
                                     std::uint64_t MaxRegions,
                                     const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    if (Literal.size() == 0 || MaxRegionBytes < Literal.size() ||
        MaxRegions == 0)
        return ConstantInt::getFalse(ctx);

    std::vector<unsigned char> bytes(Literal.begin(), Literal.end());
    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    auto *rangeSlot = B.CreateAlloca(ip, nullptr, Name + ".range.slot");
    auto *lineSlot = B.CreateAlloca(ip, nullptr, Name + ".line.slot");
    auto *posSlot = B.CreateAlloca(ip, nullptr, Name + ".pos.slot");
    auto *startSlot = B.CreateAlloca(ip, nullptr, Name + ".start.slot");
    auto *endSlot = B.CreateAlloca(ip, nullptr, Name + ".end.slot");
    auto *dashSlot = B.CreateAlloca(i1, nullptr, Name + ".dash.slot");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 1), idxSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 0), rangeSlot)->setVolatile(true);

    auto *mapLoopBB = BasicBlock::Create(ctx, (Name + ".map.loop").str(), fn);
    auto *mapBodyBB = BasicBlock::Create(ctx, (Name + ".map.body").str(), fn);
    auto *lineLoopBB = BasicBlock::Create(ctx, (Name + ".line.loop").str(), fn);
    auto *lineBodyBB = BasicBlock::Create(ctx, (Name + ".line.body").str(), fn);
    auto *lineStepBB = BasicBlock::Create(ctx, (Name + ".line.step").str(), fn);
    auto *parseInitBB =
        BasicBlock::Create(ctx, (Name + ".parse.init").str(), fn);
    auto *parseLoopBB =
        BasicBlock::Create(ctx, (Name + ".parse.loop").str(), fn);
    auto *parseBodyBB =
        BasicBlock::Create(ctx, (Name + ".parse.body").str(), fn);
    auto *scanGateBB =
        BasicBlock::Create(ctx, (Name + ".scan.gate").str(), fn);
    auto *memLoopBB = BasicBlock::Create(ctx, (Name + ".mem.loop").str(), fn);
    auto *memBodyBB = BasicBlock::Create(ctx, (Name + ".mem.body").str(), fn);
    auto *memHitBB = BasicBlock::Create(ctx, (Name + ".mem.hit").str(), fn);
    auto *memNextBB = BasicBlock::Create(ctx, (Name + ".mem.next").str(), fn);
    auto *mapNextBB = BasicBlock::Create(ctx, (Name + ".map.next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(mapLoopBB);

    IRBuilder<> MLB(mapLoopBB);
    auto *found = MLB.CreateLoad(i1, foundSlot, Name + ".found.v");
    found->setVolatile(true);
    auto *idx = MLB.CreateLoad(ip, idxSlot, Name + ".idx");
    idx->setVolatile(true);
    auto *ranges = MLB.CreateLoad(ip, rangeSlot, Name + ".ranges");
    ranges->setVolatile(true);
    Value *end = MLB.CreateAdd(idx, ConstantInt::get(ip, 5), Name + ".end");
    Value *withinRead = MLB.CreateICmpSLE(end, N, Name + ".within.read");
    Value *withinBuf = MLB.CreateICmpULE(end, ConstantInt::get(ip, MaxBytes),
                                         Name + ".within.buf");
    Value *rangeBudget =
        MLB.CreateICmpULT(ranges, ConstantInt::get(ip, MaxRegions),
                          Name + ".range.budget");
    MLB.CreateCondBr(MLB.CreateAnd(MLB.CreateAnd(withinRead, withinBuf),
                                   MLB.CreateAnd(rangeBudget,
                                                 MLB.CreateNot(found))),
                     mapBodyBB, doneBB);

    IRBuilder<> MBB(mapBodyBB);
    auto isMapChar = [&](Value *V, char C) {
        return MBB.CreateICmpEQ(
            V, ConstantInt::get(i8, static_cast<unsigned char>(C)));
    };
    Value *prev = loadAt(MBB, M, i8, Buf,
                         MBB.CreateSub(idx, ConstantInt::get(ip, 1)),
                         Name + ".prev");
    Value *p0 = loadAt(MBB, M, i8, Buf, idx, Name + ".perm0");
    Value *p1 = loadAt(MBB, M, i8, Buf,
                       MBB.CreateAdd(idx, ConstantInt::get(ip, 1)),
                       Name + ".perm1");
    Value *p2 = loadAt(MBB, M, i8, Buf,
                       MBB.CreateAdd(idx, ConstantInt::get(ip, 2)),
                       Name + ".perm2");
    Value *p3 = loadAt(MBB, M, i8, Buf,
                       MBB.CreateAdd(idx, ConstantInt::get(ip, 3)),
                       Name + ".perm3");
    Value *after = loadAt(MBB, M, i8, Buf,
                          MBB.CreateAdd(idx, ConstantInt::get(ip, 4)),
                          Name + ".after");
    Value *permWindow = MBB.CreateAnd(
        MBB.CreateAnd(isMapChar(prev, ' '), isMapChar(after, ' ')),
        MBB.CreateAnd(
            MBB.CreateAnd(MBB.CreateOr(isMapChar(p0, 'r'), isMapChar(p0, '-')),
                          MBB.CreateOr(isMapChar(p1, 'w'), isMapChar(p1, '-'))),
            MBB.CreateAnd(MBB.CreateOr(isMapChar(p2, 'x'), isMapChar(p2, '-')),
                          MBB.CreateOr(isMapChar(p3, 'p'), isMapChar(p3, 's')))),
        Name + ".perms");
    Value *readExec = MBB.CreateAnd(
        permWindow, MBB.CreateAnd(isMapChar(p0, 'r'), isMapChar(p2, 'x')),
        Name + ".rx");
    MBB.CreateStore(idx, lineSlot)->setVolatile(true);
    MBB.CreateCondBr(readExec, lineLoopBB, mapNextBB);

    IRBuilder<> LLB(lineLoopBB);
    auto *line = LLB.CreateLoad(ip, lineSlot, Name + ".line");
    line->setVolatile(true);
    Value *canStepBack = LLB.CreateAnd(
        LLB.CreateICmpUGT(line, ConstantInt::get(ip, 0), Name + ".line.gt0"),
        LLB.CreateICmpULT(LLB.CreateSub(idx, line, Name + ".line.back"),
                          ConstantInt::get(ip, 48), Name + ".line.cap"),
        Name + ".line.keep");
    LLB.CreateCondBr(canStepBack, lineBodyBB, parseInitBB);

    IRBuilder<> LBB(lineBodyBB);
    Value *prevIdx =
        LBB.CreateSub(line, ConstantInt::get(ip, 1), Name + ".line.prev.idx");
    Value *lineCh = loadAt(LBB, M, i8, Buf, prevIdx, Name + ".line.ch");
    LBB.CreateCondBr(LBB.CreateICmpEQ(lineCh, ConstantInt::get(i8, '\n'),
                                      Name + ".line.nl"),
                     parseInitBB, lineStepBB);

    IRBuilder<> LSB(lineStepBB);
    LSB.CreateStore(prevIdx, lineSlot)->setVolatile(true);
    LSB.CreateBr(lineLoopBB);

    IRBuilder<> PIB(parseInitBB);
    auto *lineStart = PIB.CreateLoad(ip, lineSlot, Name + ".line.start");
    lineStart->setVolatile(true);
    PIB.CreateStore(lineStart, posSlot)->setVolatile(true);
    PIB.CreateStore(ConstantInt::get(ip, 0), startSlot)->setVolatile(true);
    PIB.CreateStore(ConstantInt::get(ip, 0), endSlot)->setVolatile(true);
    PIB.CreateStore(ConstantInt::getFalse(ctx), dashSlot)->setVolatile(true);
    PIB.CreateBr(parseLoopBB);

    IRBuilder<> PLB(parseLoopBB);
    auto *pos = PLB.CreateLoad(ip, posSlot, Name + ".pos");
    pos->setVolatile(true);
    Value *addrEnd = PLB.CreateSub(idx, ConstantInt::get(ip, 1),
                                   Name + ".addr.end");
    Value *parseLive =
        PLB.CreateAnd(PLB.CreateICmpULT(pos, addrEnd, Name + ".pos.live"),
                      PLB.CreateICmpULT(pos, ConstantInt::get(ip, MaxBytes),
                                        Name + ".pos.in.buf"),
                      Name + ".parse.live");
    PLB.CreateCondBr(parseLive, parseBodyBB, scanGateBB);

    IRBuilder<> PBB(parseBodyBB);
    Value *ch = loadAt(PBB, M, i8, Buf, pos, Name + ".addr.ch");
    Value *dec = PBB.CreateAnd(
        PBB.CreateICmpUGE(ch, ConstantInt::get(i8, '0'), Name + ".dec.lo"),
        PBB.CreateICmpULE(ch, ConstantInt::get(i8, '9'), Name + ".dec.hi"),
        Name + ".dec");
    Value *lower = PBB.CreateAnd(
        PBB.CreateICmpUGE(ch, ConstantInt::get(i8, 'a'), Name + ".lower.lo"),
        PBB.CreateICmpULE(ch, ConstantInt::get(i8, 'f'), Name + ".lower.hi"),
        Name + ".lower");
    Value *upper = PBB.CreateAnd(
        PBB.CreateICmpUGE(ch, ConstantInt::get(i8, 'A'), Name + ".upper.lo"),
        PBB.CreateICmpULE(ch, ConstantInt::get(i8, 'F'), Name + ".upper.hi"),
        Name + ".upper");
    Value *isHex =
        PBB.CreateOr(dec, PBB.CreateOr(lower, upper), Name + ".is.hex");
    Value *decDigit =
        PBB.CreateSub(PBB.CreateZExt(ch, ip), ConstantInt::get(ip, '0'),
                      Name + ".digit.dec");
    Value *lowerDigit =
        PBB.CreateAdd(PBB.CreateSub(PBB.CreateZExt(ch, ip),
                                    ConstantInt::get(ip, 'a')),
                      ConstantInt::get(ip, 10), Name + ".digit.lower");
    Value *upperDigit =
        PBB.CreateAdd(PBB.CreateSub(PBB.CreateZExt(ch, ip),
                                    ConstantInt::get(ip, 'A')),
                      ConstantInt::get(ip, 10), Name + ".digit.upper");
    Value *digit = PBB.CreateSelect(
        dec, decDigit,
        PBB.CreateSelect(lower, lowerDigit, upperDigit, Name + ".digit.alpha"),
        Name + ".digit");
    auto *dash = PBB.CreateLoad(i1, dashSlot, Name + ".dash");
    dash->setVolatile(true);
    auto *start = PBB.CreateLoad(ip, startSlot, Name + ".start.old");
    start->setVolatile(true);
    auto *rangeEnd = PBB.CreateLoad(ip, endSlot, Name + ".end.old");
    rangeEnd->setVolatile(true);
    Value *dashChar =
        PBB.CreateICmpEQ(ch, ConstantInt::get(i8, '-'), Name + ".dash.char");
    Value *startNext = PBB.CreateSelect(
        PBB.CreateAnd(isHex, PBB.CreateNot(dash), Name + ".start.hex"),
        PBB.CreateOr(PBB.CreateShl(start, ConstantInt::get(ip, 4),
                                   Name + ".start.shift"),
                     digit, Name + ".start.add"),
        start, Name + ".start.next");
    Value *endNext = PBB.CreateSelect(
        PBB.CreateAnd(isHex, dash, Name + ".end.hex"),
        PBB.CreateOr(PBB.CreateShl(rangeEnd, ConstantInt::get(ip, 4),
                                   Name + ".end.shift"),
                     digit, Name + ".end.add"),
        rangeEnd, Name + ".end.next");
    PBB.CreateStore(startNext, startSlot)->setVolatile(true);
    PBB.CreateStore(endNext, endSlot)->setVolatile(true);
    PBB.CreateStore(PBB.CreateOr(dash, dashChar, Name + ".dash.next"),
                    dashSlot)
        ->setVolatile(true);
    PBB.CreateStore(PBB.CreateAdd(pos, ConstantInt::get(ip, 1),
                                  Name + ".pos.next"),
                    posSlot)
        ->setVolatile(true);
    PBB.CreateBr(parseLoopBB);

    IRBuilder<> SGB(scanGateBB);
    auto *memStart = SGB.CreateLoad(ip, startSlot, Name + ".mem.start");
    memStart->setVolatile(true);
    auto *memEnd = SGB.CreateLoad(ip, endSlot, Name + ".mem.end");
    memEnd->setVolatile(true);
    auto *rangeUsed = SGB.CreateLoad(ip, rangeSlot, Name + ".range.used");
    rangeUsed->setVolatile(true);
    Value *rangeBytes = SGB.CreateSub(memEnd, memStart, Name + ".range.bytes");
    Value *rangeReady = SGB.CreateAnd(
        SGB.CreateICmpUGT(memEnd, memStart, Name + ".range.ordered"),
        SGB.CreateAnd(SGB.CreateICmpUGE(rangeBytes,
                                        ConstantInt::get(ip, bytes.size()),
                                        Name + ".range.min"),
                      SGB.CreateICmpULT(rangeUsed,
                                        ConstantInt::get(ip, MaxRegions),
                                        Name + ".range.left")),
        Name + ".range.ready");
    Value *scanLimit = SGB.CreateSelect(
        SGB.CreateICmpUGT(rangeBytes, ConstantInt::get(ip, MaxRegionBytes),
                          Name + ".range.clamp"),
        ConstantInt::get(ip, MaxRegionBytes), rangeBytes,
        Name + ".scan.limit");
    SGB.CreateStore(SGB.CreateAdd(rangeUsed, ConstantInt::get(ip, 1),
                                  Name + ".range.next"),
                    rangeSlot)
        ->setVolatile(true);
    SGB.CreateCondBr(rangeReady, memLoopBB, mapNextBB);

    IRBuilder<> ML(memLoopBB);
    auto *off = ML.CreatePHI(ip, 2, Name + ".mem.off");
    off->addIncoming(ConstantInt::get(ip, 0), scanGateBB);
    auto *memFound = ML.CreateLoad(i1, foundSlot, Name + ".mem.found");
    memFound->setVolatile(true);
    Value *needleEnd =
        ML.CreateAdd(off, ConstantInt::get(ip, bytes.size()), Name + ".mem.end");
    Value *memLive =
        ML.CreateAnd(ML.CreateICmpULE(needleEnd, scanLimit, Name + ".mem.live"),
                     ML.CreateNot(memFound), Name + ".mem.keep");
    ML.CreateCondBr(memLive, memBodyBB, mapNextBB);

    IRBuilder<> MBY(memBodyBB);
    Value *match = ConstantInt::getTrue(ctx);
    for (std::uint64_t j = 0; j < bytes.size(); ++j) {
        Value *addr = MBY.CreateAdd(
            memStart,
            MBY.CreateAdd(off, ConstantInt::get(ip, j), Name + ".byte.off"),
            Name + ".byte.addr");
        Value *memPtr = MBY.CreateIntToPtr(addr, ptr, Name + ".byte.ptr");
        auto *memByte = MBY.CreateLoad(i8, memPtr, Name + ".byte");
        memByte->setVolatile(true);
        memByte->setAlignment(Align(1));
        match = MBY.CreateAnd(
            match, MBY.CreateICmpEQ(memByte, ConstantInt::get(i8, bytes[j])),
            Name + ".match");
    }
    MBY.CreateCondBr(match, memHitBB, memNextBB);

    IRBuilder<> MHB(memHitBB);
    MHB.CreateStore(ConstantInt::getTrue(ctx), foundSlot)->setVolatile(true);
    MHB.CreateBr(doneBB);

    IRBuilder<> MNB(memNextBB);
    Value *nextOff =
        MNB.CreateAdd(off, ConstantInt::get(ip, 1), Name + ".mem.off.next");
    MNB.CreateBr(memLoopBB);
    off->addIncoming(nextOff, memNextBB);

    IRBuilder<> MNB2(mapNextBB);
    MNB2.CreateStore(MNB2.CreateAdd(idx, ConstantInt::get(ip, 1),
                                    Name + ".idx.next"),
                     idxSlot)
        ->setVolatile(true);
    MNB2.CreateBr(mapLoopBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreateLoad(i1, foundSlot, Name + ".out");
    out->setVolatile(true);
    return out;
}

bool linuxDbiParentSyscalls(const Triple &TT, std::uint32_t &Getppid,
                            std::uint32_t &Readlinkat) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        Getppid = 110;
        Readlinkat = 267;
        return true;
    case Triple::aarch64:
        Getppid = 173;
        Readlinkat = 78;
        return true;
    case Triple::arm:
        Getppid = 64;
        Readlinkat = 332;
        return true;
    default:
        return false;
    }
}

bool linuxDbiGetdents64Syscall(const Triple &TT, std::uint32_t &Getdents64) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        Getdents64 = 217;
        return true;
    case Triple::aarch64:
        Getdents64 = 61;
        return true;
    default:
        return false;
    }
}

Value *bufferHasLinuxDbiTcpPortForSocketLink(
    IRBuilder<> &B, Module &M, AllocaInst *TcpBuf, Value *TcpN,
    AllocaInst *LinkBuf, Value *LinkN, std::uint64_t TcpMax,
    std::uint64_t LinkMax, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    Function *fn = B.GetInsertBlock()->getParent();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);

    auto *inodeSlot = B.CreateAlloca(ip, nullptr, Name + ".inode.slot");
    auto *idxSlot = B.CreateAlloca(ip, nullptr, Name + ".idx.slot");
    auto *posSlot = B.CreateAlloca(ip, nullptr, Name + ".pos.slot");
    auto *foundSlot = B.CreateAlloca(i1, nullptr, Name + ".found.slot");
    auto *linePortSlot = B.CreateAlloca(i1, nullptr, Name + ".line.port.slot");
    auto *accSlot = B.CreateAlloca(ip, nullptr, Name + ".acc.slot");
    auto *seenSlot = B.CreateAlloca(i1, nullptr, Name + ".seen.slot");
    B.CreateStore(ConstantInt::get(ip, 0), inodeSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);

    auto *linkLoopBB = BasicBlock::Create(ctx, (Name + ".link.loop").str(), fn);
    auto *linkBodyBB = BasicBlock::Create(ctx, (Name + ".link.body").str(), fn);
    auto *digitInitBB =
        BasicBlock::Create(ctx, (Name + ".digit.init").str(), fn);
    auto *digitLoopBB =
        BasicBlock::Create(ctx, (Name + ".digit.loop").str(), fn);
    auto *digitBodyBB =
        BasicBlock::Create(ctx, (Name + ".digit.body").str(), fn);
    auto *linkNextBB = BasicBlock::Create(ctx, (Name + ".link.next").str(), fn);
    auto *tcpInitBB = BasicBlock::Create(ctx, (Name + ".tcp.init").str(), fn);
    auto *tcpLoopBB = BasicBlock::Create(ctx, (Name + ".tcp.loop").str(), fn);
    auto *tcpBodyBB = BasicBlock::Create(ctx, (Name + ".tcp.body").str(), fn);
    auto *tcpNextBB = BasicBlock::Create(ctx, (Name + ".tcp.next").str(), fn);
    auto *doneBB = BasicBlock::Create(ctx, (Name + ".done").str(), fn);
    B.CreateBr(linkLoopBB);

    IRBuilder<> LLB(linkLoopBB);
    auto *linkIdx = LLB.CreateLoad(ip, idxSlot, Name + ".link.idx");
    linkIdx->setVolatile(true);
    Value *prefixEnd =
        LLB.CreateAdd(linkIdx, ConstantInt::get(ip, 8), Name + ".prefix.end");
    Value *linkLive =
        LLB.CreateAnd(LLB.CreateICmpSLE(prefixEnd, LinkN,
                                        Name + ".prefix.in.read"),
                      LLB.CreateICmpULE(prefixEnd, ConstantInt::get(ip, LinkMax),
                                        Name + ".prefix.in.buf"),
                      Name + ".link.live");
    LLB.CreateCondBr(linkLive, linkBodyBB, doneBB);

    IRBuilder<> LBB(linkBodyBB);
    Value *prefix = ConstantInt::getTrue(ctx);
    constexpr std::array<unsigned char, 8> kSocketPrefix = {
        0x73, 0x6f, 0x63, 0x6b, 0x65, 0x74, 0x3a, 0x5b};
    for (std::uint64_t i = 0; i < kSocketPrefix.size(); ++i) {
        Value *ch = loadAt(LBB, M, i8, LinkBuf,
                           LBB.CreateAdd(linkIdx, ConstantInt::get(ip, i)),
                           Name + ".prefix.ch");
        prefix = LBB.CreateAnd(
            prefix, LBB.CreateICmpEQ(ch, ConstantInt::get(i8, kSocketPrefix[i])),
            Name + ".prefix.match");
    }
    LBB.CreateCondBr(prefix, digitInitBB, linkNextBB);

    IRBuilder<> DIB(digitInitBB);
    DIB.CreateStore(prefixEnd, posSlot)->setVolatile(true);
    DIB.CreateStore(ConstantInt::get(ip, 0), inodeSlot)->setVolatile(true);
    DIB.CreateStore(ConstantInt::getFalse(ctx), seenSlot)->setVolatile(true);
    DIB.CreateBr(digitLoopBB);

    IRBuilder<> DLB(digitLoopBB);
    auto *digitPos = DLB.CreateLoad(ip, posSlot, Name + ".digit.pos");
    digitPos->setVolatile(true);
    Value *digitLive =
        DLB.CreateAnd(DLB.CreateICmpSLT(digitPos, LinkN,
                                        Name + ".digit.in.read"),
                      DLB.CreateICmpULT(digitPos, ConstantInt::get(ip, LinkMax),
                                        Name + ".digit.in.buf"),
                      Name + ".digit.live");
    DLB.CreateCondBr(digitLive, digitBodyBB, doneBB);

    IRBuilder<> DBB(digitBodyBB);
    Value *digitCh = loadAt(DBB, M, i8, LinkBuf, digitPos, Name + ".digit.ch");
    Value *isDigit = DBB.CreateAnd(
        DBB.CreateICmpUGE(digitCh, ConstantInt::get(i8, '0'),
                          Name + ".digit.ge0"),
        DBB.CreateICmpULE(digitCh, ConstantInt::get(i8, '9'),
                          Name + ".digit.le9"),
        Name + ".digit");
    auto *oldInode = DBB.CreateLoad(ip, inodeSlot, Name + ".inode.old");
    oldInode->setVolatile(true);
    Value *digitValue =
        DBB.CreateZExt(DBB.CreateSub(digitCh, ConstantInt::get(i8, '0'),
                                     Name + ".digit.raw"),
                       ip, Name + ".digit.value");
    Value *nextInode =
        DBB.CreateAdd(DBB.CreateMul(oldInode, ConstantInt::get(ip, 10),
                                    Name + ".inode.mul"),
                      digitValue, Name + ".inode.next");
    DBB.CreateStore(DBB.CreateSelect(isDigit, nextInode, oldInode,
                                     Name + ".inode.select"),
                    inodeSlot)
        ->setVolatile(true);
    auto *seenDigit = DBB.CreateLoad(i1, seenSlot, Name + ".seen.digit");
    seenDigit->setVolatile(true);
    DBB.CreateStore(DBB.CreateOr(seenDigit, isDigit, Name + ".seen.next"),
                    seenSlot)
        ->setVolatile(true);
    Value *closeBracket =
        DBB.CreateICmpEQ(digitCh, ConstantInt::get(i8, ']'), Name + ".bracket");
    Value *ready = DBB.CreateAnd(closeBracket, seenDigit, Name + ".ready");
    auto *digitNextBB =
        BasicBlock::Create(ctx, (Name + ".digit.next").str(), fn);
    auto *digitStopBB =
        BasicBlock::Create(ctx, (Name + ".digit.stop").str(), fn);
    DBB.CreateCondBr(ready, tcpInitBB, digitStopBB);

    IRBuilder<> DSB(digitStopBB);
    DSB.CreateCondBr(isDigit, digitNextBB, doneBB);

    IRBuilder<> DNB(digitNextBB);
    DNB.CreateStore(DNB.CreateAdd(digitPos, ConstantInt::get(ip, 1),
                                  Name + ".digit.pos.next"),
                    posSlot)
        ->setVolatile(true);
    DNB.CreateBr(digitLoopBB);

    IRBuilder<> LNB(linkNextBB);
    LNB.CreateStore(LNB.CreateAdd(linkIdx, ConstantInt::get(ip, 1),
                                  Name + ".link.idx.next"),
                    idxSlot)
        ->setVolatile(true);
    LNB.CreateBr(linkLoopBB);

    IRBuilder<> TIB(tcpInitBB);
    TIB.CreateStore(ConstantInt::get(ip, 0), idxSlot)->setVolatile(true);
    TIB.CreateStore(ConstantInt::getFalse(ctx), linePortSlot)
        ->setVolatile(true);
    TIB.CreateStore(ConstantInt::get(ip, 0), accSlot)->setVolatile(true);
    TIB.CreateStore(ConstantInt::getFalse(ctx), seenSlot)->setVolatile(true);
    TIB.CreateBr(tcpLoopBB);

    IRBuilder<> TLB(tcpLoopBB);
    auto *tcpIdx = TLB.CreateLoad(ip, idxSlot, Name + ".tcp.idx");
    tcpIdx->setVolatile(true);
    auto *found = TLB.CreateLoad(i1, foundSlot, Name + ".found");
    found->setVolatile(true);
    Value *tcpWindow =
        TLB.CreateAdd(tcpIdx, ConstantInt::get(ip, 4), Name + ".tcp.window");
    Value *tcpLive =
        TLB.CreateAnd(TLB.CreateICmpSLE(tcpWindow, TcpN, Name + ".tcp.in.read"),
                      TLB.CreateICmpULE(tcpWindow, ConstantInt::get(ip, TcpMax),
                                        Name + ".tcp.in.buf"),
                      Name + ".tcp.live");
    TLB.CreateCondBr(TLB.CreateAnd(tcpLive, TLB.CreateNot(found),
                                   Name + ".tcp.keep"),
                     tcpBodyBB, doneBB);

    IRBuilder<> TBB(tcpBodyBB);
    Value *tcpCh = loadAt(TBB, M, i8, TcpBuf, tcpIdx, Name + ".tcp.ch");
    auto tcpCharAt = [&](std::uint64_t Off, unsigned char C) -> Value * {
        Value *pos = TBB.CreateAdd(tcpIdx, ConstantInt::get(ip, Off),
                                   Name + ".tcp.port.pos");
        Value *ch = loadAt(TBB, M, i8, TcpBuf, pos, Name + ".tcp.port.ch");
        return TBB.CreateICmpEQ(ch, ConstantInt::get(i8, C),
                                Name + ".tcp.port.eq");
    };
    Value *portSafe =
        TBB.CreateAnd(TBB.CreateICmpSLE(TBB.CreateAdd(tcpIdx,
                                                      ConstantInt::get(ip, 4)),
                                        TcpN, Name + ".tcp.port.in.read"),
                      TBB.CreateICmpULE(TBB.CreateAdd(tcpIdx,
                                                      ConstantInt::get(ip, 4)),
                                        ConstantInt::get(ip, TcpMax),
                                        Name + ".tcp.port.in.buf"),
                      Name + ".tcp.port.safe");
    Value *port69A2 =
        TBB.CreateAnd(TBB.CreateAnd(tcpCharAt(0, '6'), tcpCharAt(1, '9')),
                      TBB.CreateAnd(tcpCharAt(2, 'A'), tcpCharAt(3, '2')),
                      Name + ".tcp.port.69A2");
    Value *port69a2 =
        TBB.CreateAnd(TBB.CreateAnd(tcpCharAt(0, '6'), tcpCharAt(1, '9')),
                      TBB.CreateAnd(tcpCharAt(2, 'a'), tcpCharAt(3, '2')),
                      Name + ".tcp.port.69a2");
    Value *port69A3 =
        TBB.CreateAnd(TBB.CreateAnd(tcpCharAt(0, '6'), tcpCharAt(1, '9')),
                      TBB.CreateAnd(tcpCharAt(2, 'A'), tcpCharAt(3, '3')),
                      Name + ".tcp.port.69A3");
    Value *port69a3 =
        TBB.CreateAnd(TBB.CreateAnd(tcpCharAt(0, '6'), tcpCharAt(1, '9')),
                      TBB.CreateAnd(tcpCharAt(2, 'a'), tcpCharAt(3, '3')),
                      Name + ".tcp.port.69a3");
    Value *portHere = TBB.CreateAnd(
        portSafe,
        TBB.CreateOr(TBB.CreateOr(port69A2, port69a2),
                     TBB.CreateOr(port69A3, port69a3), Name + ".tcp.port.any"),
        Name + ".tcp.port.hit");
    auto *linePort = TBB.CreateLoad(i1, linePortSlot, Name + ".line.port");
    linePort->setVolatile(true);
    Value *isNl =
        TBB.CreateICmpEQ(tcpCh, ConstantInt::get(i8, '\n'), Name + ".tcp.nl");
    Value *linePortNext = TBB.CreateSelect(
        isNl, ConstantInt::getFalse(ctx),
        TBB.CreateOr(linePort, portHere, Name + ".line.port.or"),
        Name + ".line.port.next");
    Value *tcpDigit = TBB.CreateAnd(
        TBB.CreateICmpUGE(tcpCh, ConstantInt::get(i8, '0'),
                          Name + ".tcp.digit.ge0"),
        TBB.CreateICmpULE(tcpCh, ConstantInt::get(i8, '9'),
                          Name + ".tcp.digit.le9"),
        Name + ".tcp.digit");
    auto *oldAcc = TBB.CreateLoad(ip, accSlot, Name + ".tcp.acc.old");
    oldAcc->setVolatile(true);
    auto *oldSeen = TBB.CreateLoad(i1, seenSlot, Name + ".tcp.seen.old");
    oldSeen->setVolatile(true);
    Value *tcpDigitValue =
        TBB.CreateZExt(TBB.CreateSub(tcpCh, ConstantInt::get(i8, '0'),
                                     Name + ".tcp.digit.raw"),
                       ip, Name + ".tcp.digit.value");
    Value *accNext =
        TBB.CreateAdd(TBB.CreateMul(oldAcc, ConstantInt::get(ip, 10),
                                    Name + ".tcp.acc.mul"),
                      tcpDigitValue, Name + ".tcp.acc.next");
    auto *targetInode =
        TBB.CreateLoad(ip, inodeSlot, Name + ".target.inode");
    targetInode->setVolatile(true);
    Value *numberDone =
        TBB.CreateAnd(oldSeen, TBB.CreateNot(tcpDigit), Name + ".number.done");
    Value *inodeMatch = TBB.CreateAnd(
        numberDone,
        TBB.CreateAnd(linePort, TBB.CreateICmpEQ(oldAcc, targetInode,
                                                 Name + ".inode.eq")),
        Name + ".inode.match");
    TBB.CreateStore(TBB.CreateOr(found, inodeMatch, Name + ".found.next"),
                    foundSlot)
        ->setVolatile(true);
    TBB.CreateStore(TBB.CreateSelect(tcpDigit, accNext, ConstantInt::get(ip, 0),
                                     Name + ".acc.store"),
                    accSlot)
        ->setVolatile(true);
    TBB.CreateStore(tcpDigit, seenSlot)->setVolatile(true);
    TBB.CreateStore(linePortNext, linePortSlot)->setVolatile(true);
    TBB.CreateBr(tcpNextBB);

    IRBuilder<> TNB(tcpNextBB);
    TNB.CreateStore(TNB.CreateAdd(tcpIdx, ConstantInt::get(ip, 1),
                                  Name + ".tcp.idx.next"),
                    idxSlot)
        ->setVolatile(true);
    TNB.CreateBr(tcpLoopBB);

    B.SetInsertPoint(doneBB);
    auto *out = B.CreateLoad(i1, foundSlot, Name + ".out");
    out->setVolatile(true);
    return out;
}

void emitLinuxDbiThreadTableScan(IRBuilder<> &B, Module &M, Function *Fn,
                                 AllocaInst *StrongDiff,
                                 AllocaInst *WeakDiff, ir::IRRandom &rng,
                                 const Triple &TT) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i16 = Type::getInt16Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t getdentsNr = 0;
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr) ||
        !linuxDbiGetdents64Syscall(TT, getdentsNr))
        return;

    auto *pathTy = ArrayType::get(i8, 128);
    auto *dirTy = ArrayType::get(i8, 4096);
    auto *commTy = ArrayType::get(i8, 64);
    AllocaInst *path =
        B.CreateAlloca(pathTy, nullptr, "morok.antihook.dbi.thread.task.path");
    AllocaInst *dirBuf =
        B.CreateAlloca(dirTy, nullptr, "morok.antihook.dbi.thread.task.dir");
    AllocaInst *commBuf =
        B.CreateAlloca(commTy, nullptr, "morok.antihook.dbi.thread.task.comm.buf");
    Value *taskPath = ir::emitCloakedSymbol(B, M, "/proc/self/task", rng);
    Value *fd = emitLinuxSyscall(B, M, TT, openatNr,
                                 {ConstantInt::getSigned(ip, -100), taskPath,
                                  ConstantInt::get(ip, 0x10000),
                                  ConstantInt::get(ip, 0)});
    fd->setName("morok.antihook.dbi.thread.task.fd");
    auto *readBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.read", Fn);
    auto *scanLoopBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.scan.loop", Fn);
    auto *scanBodyBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.scan.body", Fn);
    auto *readCommBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.comm.read", Fn);
    auto *scanCommBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.comm.scan", Fn);
    auto *scanNextBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.scan.next", Fn);
    auto *closeBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.close", Fn);
    auto *doneBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.thread.task.done", Fn);
    B.CreateCondBr(B.CreateICmpSGE(fd, ConstantInt::get(ip, 0),
                                   "morok.antihook.dbi.thread.task.fd.ok"),
                   readBB, doneBB);

    IRBuilder<> RB(readBB);
    Value *dirPtr = RB.CreateInBoundsGEP(
        dirTy, dirBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.thread.task.dir.ptr");
    Value *nread = emitLinuxSyscall(
        RB, M, TT, getdentsNr, {fd, dirPtr, ConstantInt::get(ip, 4096)});
    nread->setName("morok.antihook.dbi.thread.task.getdents");
    RB.CreateCondBr(RB.CreateICmpSGT(nread, ConstantInt::get(ip, 0),
                                     "morok.antihook.dbi.thread.task.nread"),
                    scanLoopBB, closeBB);

    IRBuilder<> SLB(scanLoopBB);
    auto *off = SLB.CreatePHI(ip, 2, "morok.antihook.dbi.thread.task.off");
    off->addIncoming(ConstantInt::get(ip, 0), readBB);
    SLB.CreateCondBr(SLB.CreateICmpULT(off, nread,
                                       "morok.antihook.dbi.thread.task.live"),
                     scanBodyBB, closeBB);

    IRBuilder<> SB(scanBodyBB);
    Value *reclenOff =
        SB.CreateAdd(off, ConstantInt::get(ip, 16),
                     "morok.antihook.dbi.thread.task.reclen.off");
    Value *reclen =
        loadAt(SB, M, i16, dirBuf, reclenOff,
               "morok.antihook.dbi.thread.task.reclen");
    Value *nameBase =
        SB.CreateAdd(off, ConstantInt::get(ip, 19),
                     "morok.antihook.dbi.thread.task.name.off");
    Value *tid = ConstantInt::get(ip, 0);
    Value *active = ConstantInt::getTrue(ctx);
    Value *any = ConstantInt::getFalse(ctx);
    for (std::uint64_t i = 0; i < 12; ++i) {
        Value *ch =
            loadAt(SB, M, i8, dirBuf, SB.CreateAdd(nameBase,
                                                   ConstantInt::get(ip, i)),
                   "morok.antihook.dbi.thread.task.name.ch");
        Value *digit = SB.CreateAnd(
            active,
            SB.CreateAnd(SB.CreateICmpUGE(ch, ConstantInt::get(i8, '0')),
                         SB.CreateICmpULE(ch, ConstantInt::get(i8, '9'))),
            "morok.antihook.dbi.thread.task.name.digit");
        Value *dval =
            SB.CreateZExt(SB.CreateSub(ch, ConstantInt::get(i8, '0')), ip,
                          "morok.antihook.dbi.thread.task.name.dval");
        Value *nextTid =
            SB.CreateAdd(SB.CreateMul(tid, ConstantInt::get(ip, 10)),
                         dval, "morok.antihook.dbi.thread.task.tid.next");
        tid = SB.CreateSelect(digit, nextTid, tid,
                              "morok.antihook.dbi.thread.task.tid.acc");
        any = SB.CreateOr(any, digit, "morok.antihook.dbi.thread.task.any");
        active = digit;
    }
    SB.CreateCondBr(any, readCommBB, scanNextBB);

    IRBuilder<> PCB(readCommBB);
    Value *pathPtr = PCB.CreateInBoundsGEP(
        pathTy, path, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.thread.task.path.ptr");
    FunctionCallee snprintfFn =
        M.getOrInsertFunction("snprintf", FunctionType::get(i32, {ptr, ip, ptr},
                                                             true));
    PCB.CreateCall(snprintfFn,
                   {pathPtr, ConstantInt::get(ip, 128),
                    ir::emitCloakedSymbol(PCB, M, "/proc/self/task/%ld/comm",
                                          rng),
                    tid},
                   "morok.antihook.dbi.thread.task.path.n");
    Value *commFd = emitLinuxSyscall(
        PCB, M, TT, openatNr,
        {ConstantInt::getSigned(ip, -100), pathPtr, ConstantInt::get(ip, 0),
         ConstantInt::get(ip, 0)});
    commFd->setName("morok.antihook.dbi.thread.task.comm.fd");
    PCB.CreateCondBr(PCB.CreateICmpSGE(commFd, ConstantInt::get(ip, 0),
                                       "morok.antihook.dbi.thread.task.comm.fd.ok"),
                     scanCommBB, scanNextBB);

    IRBuilder<> CB(scanCommBB);
    Value *commPtr = CB.CreateInBoundsGEP(
        commTy, commBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.thread.task.comm.ptr");
    Value *commN = emitLinuxSyscall(
        CB, M, TT, readNr, {commFd, commPtr, ConstantInt::get(ip, 63)});
    commN->setName("morok.antihook.dbi.thread.task.comm.read.n");
    emitLinuxSyscall(CB, M, TT, closeNr, {commFd});
    Value *gumLoop = bufferHasLiteral(
        CB, M, commBuf, commN,
        {0x67, 0x75, 0x6d, 0x2d, 0x6a, 0x73, 0x2d, 0x6c, 0x6f, 0x6f, 0x70},
        64, "morok.antihook.dbi.thread.task.gum_js_loop");
    Value *fridaAgent = bufferHasLiteral(
        CB, M, commBuf, commN,
        {0x66, 0x72, 0x69, 0x64, 0x61, 0x2d, 0x61, 0x67, 0x65, 0x6e, 0x74},
        64, "morok.antihook.dbi.thread.task.frida_agent");
    Value *poolFrida = bufferHasLiteral(
        CB, M, commBuf, commN,
        {0x70, 0x6f, 0x6f, 0x6c, 0x2d, 0x66, 0x72, 0x69, 0x64, 0x61},
        64, "morok.antihook.dbi.thread.task.pool_frida");
    Value *linjector = bufferHasLiteral(
        CB, M, commBuf, commN,
        {0x6c, 0x69, 0x6e, 0x6a, 0x65, 0x63, 0x74, 0x6f, 0x72}, 64,
        "morok.antihook.dbi.thread.task.linjector");
    Value *gmain = bufferHasLiteral(
        CB, M, commBuf, commN, {0x67, 0x6d, 0x61, 0x69, 0x6e}, 64,
        "morok.antihook.dbi.thread.task.gmain");
    Value *gdbus = bufferHasLiteral(
        CB, M, commBuf, commN, {0x67, 0x64, 0x62, 0x75, 0x73}, 64,
        "morok.antihook.dbi.thread.task.gdbus");
    Value *strong = CB.CreateOr(
        CB.CreateOr(gumLoop, fridaAgent),
        CB.CreateOr(poolFrida, linjector),
        "morok.antihook.dbi.thread.task.strong");
    Value *weak =
        CB.CreateOr(gmain, gdbus, "morok.antihook.dbi.thread.task.weak");
    incrementDiff(CB, StrongDiff, strong,
                  "morok.antihook.dbi.frida.thread.task.strong");
    incrementDiff(CB, WeakDiff, weak,
                  "morok.antihook.dbi.frida.thread.task.weak");
    CB.CreateBr(scanNextBB);

    IRBuilder<> SNB(scanNextBB);
    Value *safeReclen = SNB.CreateSelect(
        SNB.CreateICmpUGT(reclen, ConstantInt::get(i16, 0),
                          "morok.antihook.dbi.thread.task.reclen.ok"),
        SNB.CreateZExt(reclen, ip), nread,
        "morok.antihook.dbi.thread.task.reclen.safe");
    Value *nextOff = SNB.CreateAdd(off, safeReclen,
                                   "morok.antihook.dbi.thread.task.next");
    SNB.CreateBr(scanLoopBB);
    off->addIncoming(nextOff, scanNextBB);

    IRBuilder<> CLB(closeBB);
    emitLinuxSyscall(CLB, M, TT, closeNr, {fd});
    CLB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
}

Value *emitLinuxDbiFdTcpCrossRef(IRBuilder<> &B, Module &M, Function *Fn,
                                 AllocaInst *TcpBuf, Value *TcpN,
                                 ir::IRRandom &rng, const Triple &TT) {
    LLVMContext &ctx = M.getContext();
    auto *i1 = Type::getInt1Ty(ctx);
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i16 = Type::getInt16Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t getdentsNr = 0;
    std::uint32_t getppidNr = 0;
    std::uint32_t readlinkatNr = 0;
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr) ||
        !linuxDbiGetdents64Syscall(TT, getdentsNr) ||
        !linuxDbiParentSyscalls(TT, getppidNr, readlinkatNr))
        return ConstantInt::getFalse(ctx);

    auto *dirTy = ArrayType::get(i8, 4096);
    auto *linkTy = ArrayType::get(i8, 128);
    AllocaInst *dirBuf =
        B.CreateAlloca(dirTy, nullptr, "morok.antihook.dbi.fd.dir.buf");
    AllocaInst *linkBuf =
        B.CreateAlloca(linkTy, nullptr, "morok.antihook.dbi.fd.link.buf");
    AllocaInst *foundSlot =
        B.CreateAlloca(i1, nullptr, "morok.antihook.dbi.fd.tcp.found");
    B.CreateStore(ConstantInt::getFalse(ctx), foundSlot)->setVolatile(true);
    Value *fdPath = ir::emitCloakedSymbol(B, M, "/proc/self/fd", rng);
    Value *fd = emitLinuxSyscall(B, M, TT, openatNr,
                                 {ConstantInt::getSigned(ip, -100), fdPath,
                                  ConstantInt::get(ip, 0x10000),
                                  ConstantInt::get(ip, 0)});
    fd->setName("morok.antihook.dbi.fd.dir.fd");

    auto *readBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.read", Fn);
    auto *loopBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.loop", Fn);
    auto *bodyBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.body", Fn);
    auto *scanBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.scan", Fn);
    auto *nextBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.next", Fn);
    auto *closeBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.close", Fn);
    auto *doneBB = BasicBlock::Create(ctx, "morok.antihook.dbi.fd.done", Fn);
    B.CreateCondBr(B.CreateICmpSGE(fd, ConstantInt::get(ip, 0),
                                   "morok.antihook.dbi.fd.dir.ok"),
                   readBB, doneBB);

    IRBuilder<> RB(readBB);
    Value *dirPtr = RB.CreateInBoundsGEP(
        dirTy, dirBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.fd.dir.ptr");
    Value *nread = emitLinuxSyscall(
        RB, M, TT, getdentsNr, {fd, dirPtr, ConstantInt::get(ip, 4096)});
    nread->setName("morok.antihook.dbi.fd.getdents");
    RB.CreateCondBr(RB.CreateICmpSGT(nread, ConstantInt::get(ip, 0),
                                     "morok.antihook.dbi.fd.nread"),
                    loopBB, closeBB);

    IRBuilder<> LB(loopBB);
    auto *off = LB.CreatePHI(ip, 2, "morok.antihook.dbi.fd.off");
    off->addIncoming(ConstantInt::get(ip, 0), readBB);
    auto *found = LB.CreateLoad(i1, foundSlot, "morok.antihook.dbi.fd.found.v");
    found->setVolatile(true);
    LB.CreateCondBr(LB.CreateAnd(LB.CreateICmpULT(off, nread,
                                                  "morok.antihook.dbi.fd.live"),
                                 LB.CreateNot(found)),
                    bodyBB, closeBB);

    IRBuilder<> BB(bodyBB);
    Value *reclenOff =
        BB.CreateAdd(off, ConstantInt::get(ip, 16),
                     "morok.antihook.dbi.fd.reclen.off");
    Value *reclen =
        loadAt(BB, M, i16, dirBuf, reclenOff,
               "morok.antihook.dbi.fd.reclen");
    Value *nameBase =
        BB.CreateAdd(off, ConstantInt::get(ip, 19),
                     "morok.antihook.dbi.fd.name.off");
    Value *namePtr =
        gepI8(BB, M, dirBuf, nameBase, "morok.antihook.dbi.fd.name.ptr");
    Value *linkPtr = BB.CreateInBoundsGEP(
        linkTy, linkBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.fd.link.ptr");
    Value *linkN = emitLinuxSyscall(
        BB, M, TT, readlinkatNr,
        {fd, namePtr, linkPtr, ConstantInt::get(ip, 127)});
    linkN->setName("morok.antihook.dbi.fd.readlink");
    BB.CreateCondBr(BB.CreateICmpSGT(linkN, ConstantInt::get(ip, 0),
                                     "morok.antihook.dbi.fd.link.ready"),
                    scanBB, nextBB);

    IRBuilder<> SB(scanBB);
    Value *hit = bufferHasLinuxDbiTcpPortForSocketLink(
        SB, M, TcpBuf, TcpN, linkBuf, linkN, 4096, 128,
        "morok.antihook.dbi.fd.tcp.cross");
    SB.CreateStore(SB.CreateOr(found, hit, "morok.antihook.dbi.fd.hit.next"),
                   foundSlot)
        ->setVolatile(true);
    SB.CreateBr(nextBB);

    IRBuilder<> NB(nextBB);
    Value *safeReclen = NB.CreateSelect(
        NB.CreateICmpUGT(reclen, ConstantInt::get(i16, 0),
                         "morok.antihook.dbi.fd.reclen.ok"),
        NB.CreateZExt(reclen, ip), nread,
        "morok.antihook.dbi.fd.reclen.safe");
    Value *nextOff =
        NB.CreateAdd(off, safeReclen, "morok.antihook.dbi.fd.next.off");
    NB.CreateBr(loopBB);
    off->addIncoming(nextOff, nextBB);

    IRBuilder<> CB(closeBB);
    emitLinuxSyscall(CB, M, TT, closeNr, {fd});
    CB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
    auto *out =
        B.CreateLoad(i1, foundSlot, "morok.antihook.dbi.fd.tcp.out");
    out->setVolatile(true);
    return out;
}

Value *emitValgrindRunningRequest(IRBuilder<> &B, Module &M) {
    const Triple TT(M.getTargetTriple());
    if (TT.getArch() != Triple::x86_64)
        return ConstantInt::get(Type::getInt64Ty(M.getContext()), 0);

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *argsTy = ArrayType::get(i64, 6);
    AllocaInst *args =
        B.CreateAlloca(argsTy, nullptr, "morok.antihook.dbi.valgrind.args");
    for (unsigned i = 0; i < 6; ++i) {
        B.CreateStore(ConstantInt::get(i64, i == 0 ? 0x1001ULL : 0ULL),
                      B.CreateInBoundsGEP(
                          argsTy, args,
                          {ConstantInt::get(intPtrTy(M), 0),
                           ConstantInt::get(intPtrTy(M), i)}));
    }
    Value *argsPtr = B.CreateInBoundsGEP(
        argsTy, args, {ConstantInt::get(intPtrTy(M), 0),
                       ConstantInt::get(intPtrTy(M), 0)},
        "morok.antihook.dbi.valgrind.args.ptr");
    auto *asmTy = FunctionType::get(i64, {ptr}, false);
    auto emitRequest = [&](StringRef Name, StringRef Rotations) -> Value * {
        InlineAsm *request = InlineAsm::get(
            asmTy, (Twine("xorq %rdx, %rdx\n\t") + Rotations +
                    "\n\txchgq %rbx, %rbx\n\tmovq %rdx, $0")
                       .str(),
            "=r,{rax},~{rdx},~{rdi},~{memory},~{dirflag},~{fpsr},~{flags}",
            /*hasSideEffects=*/true);
        return B.CreateCall(asmTy, request, {argsPtr}, Name);
    };
    Value *standard = emitRequest(
        "morok.antihook.dbi.valgrind.magic.std",
        "rolq $$3, %rdi\n\trolq $$13, %rdi\n\trolq $$61, %rdi\n\trolq $$51, %rdi");
    Value *issueVariant = emitRequest(
        "morok.antihook.dbi.valgrind.magic.issue",
        "rolq $$3, %rdi\n\trolq $$13, %rdi\n\trolq $$29, %rdi\n\trolq $$61, %rdi");
    return B.CreateOr(standard, issueVariant,
                      "morok.antihook.dbi.valgrind.magic");
}

GlobalVariable *dbiSmcGate(Module &M) {
    if (auto *existing = M.getGlobalVariable("morok.antihook.dbi.smc.gate",
                                             /*AllowInternal=*/true))
        return existing;
    auto *i8 = Type::getInt8Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i8, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i8, 0), "morok.antihook.dbi.smc.gate");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

Value *smcStatePtr(IRBuilder<> &B, Module &M, Value *State,
                   std::uint64_t Offset, const Twine &Name) {
    return gepI8(B, M, State, constIp(M, Offset), Name);
}

LoadInst *smcAtomicLoad(IRBuilder<> &B, Type *Ty, Value *Ptr, Align A,
                        const Twine &Name) {
    auto *L = B.CreateLoad(Ty, Ptr, Name);
    L->setVolatile(true);
    L->setAtomic(AtomicOrdering::SequentiallyConsistent);
    L->setAlignment(A);
    return L;
}

StoreInst *smcAtomicStore(IRBuilder<> &B, Value *Val, Value *Ptr, Align A) {
    auto *S = B.CreateStore(Val, Ptr);
    S->setVolatile(true);
    S->setAtomic(AtomicOrdering::SequentiallyConsistent);
    S->setAlignment(A);
    return S;
}

Value *smcRaceValueValid(IRBuilder<> &B, Value *V, const Twine &Name) {
    auto *i64 = Type::getInt64Ty(B.getContext());
    Value *valid = B.CreateICmpEQ(V, ConstantInt::get(i64, 0),
                                  Name + ".zero");
    for (std::uint64_t allowed : {0x41C67EA6B7D92F15ULL,
                                  0x9E3779B97F4A7C15ULL,
                                  0xD1B54A32D192ED03ULL,
                                  0x94D049BB133111EBULL}) {
        valid = B.CreateOr(
            valid, B.CreateICmpEQ(V, ConstantInt::get(i64, allowed)),
            Name + ".allow");
    }
    return valid;
}

void smcRaceAccumulateBad(IRBuilder<> &B, Value *BadPtr, Value *Bad,
                          const Twine &Name) {
    auto *i64 = Type::getInt64Ty(B.getContext());
    Value *inc = B.CreateZExt(Bad, i64, Name + ".inc");
    B.CreateAtomicRMW(AtomicRMWInst::Add, BadPtr, inc, Align(8),
                      AtomicOrdering::SequentiallyConsistent);
}

Function *dbiSmcLockRaceWorker(Module &M) {
    if (Function *existing =
            M.getFunction("morok.antihook.dbi.smc.lock.worker"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(FunctionType::get(ptr, {ptr}, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.dbi.smc.lock.worker", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    Argument *state = fn->getArg(0);
    state->setName("state");
    Value *slotPtr = nullptr;
    Value *badPtr = nullptr;
    Value *readyPtr = nullptr;
    Value *goPtr = nullptr;
    Value *donePtr = nullptr;

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *waitBB = BasicBlock::Create(ctx, "wait", fn);
    auto *waitMoreBB = BasicBlock::Create(ctx, "wait.more", fn);
    auto *raceBB = BasicBlock::Create(ctx, "race", fn);
    auto *bodyBB = BasicBlock::Create(ctx, "body", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> EB(entry);
    slotPtr = smcStatePtr(EB, M, state, 0,
                          "morok.antihook.dbi.smc.lock.worker.slot");
    badPtr = smcStatePtr(EB, M, state, 8,
                         "morok.antihook.dbi.smc.lock.worker.bad");
    readyPtr = smcStatePtr(EB, M, state, 16,
                           "morok.antihook.dbi.smc.lock.worker.ready.ptr");
    goPtr = smcStatePtr(EB, M, state, 20,
                        "morok.antihook.dbi.smc.lock.worker.go.ptr");
    donePtr = smcStatePtr(EB, M, state, 24,
                          "morok.antihook.dbi.smc.lock.worker.done.ptr");
    smcAtomicStore(EB, ConstantInt::get(i32, 1), readyPtr, Align(4));
    EB.CreateBr(waitBB);

    IRBuilder<> WB(waitBB);
    auto *go =
        smcAtomicLoad(WB, i32, goPtr, Align(4),
                      "morok.antihook.dbi.smc.lock.worker.go");
    auto *waitDone =
        smcAtomicLoad(WB, i32, donePtr, Align(4),
                      "morok.antihook.dbi.smc.lock.worker.done.wait");
    Value *goSet = WB.CreateICmpNE(go, ConstantInt::get(i32, 0),
                                   "morok.antihook.dbi.smc.lock.worker.go.set");
    Value *doneSet = WB.CreateICmpNE(
        waitDone, ConstantInt::get(i32, 0),
        "morok.antihook.dbi.smc.lock.worker.done.set");
    WB.CreateCondBr(goSet, raceBB, waitMoreBB);

    IRBuilder<> WMB(waitMoreBB);
    WMB.CreateCondBr(doneSet, retBB, waitBB);

    IRBuilder<> LB(raceBB);
    auto *iter = LB.CreatePHI(i32, 2,
                              "morok.antihook.dbi.smc.lock.worker.iter");
    iter->addIncoming(ConstantInt::get(i32, 0), waitBB);
    auto *loopDone =
        smcAtomicLoad(LB, i32, donePtr, Align(4),
                      "morok.antihook.dbi.smc.lock.worker.done.loop");
    Value *keep = LB.CreateAnd(
        LB.CreateICmpULT(iter, ConstantInt::get(i32, 64),
                         "morok.antihook.dbi.smc.lock.worker.bound"),
        LB.CreateICmpEQ(loopDone, ConstantInt::get(i32, 0),
                        "morok.antihook.dbi.smc.lock.worker.open"),
        "morok.antihook.dbi.smc.lock.worker.keep");
    LB.CreateCondBr(keep, bodyBB, retBB);

    IRBuilder<> BB(bodyBB);
    smcAtomicStore(BB, ConstantInt::get(i64, 0xD1B54A32D192ED03ULL), slotPtr,
                   Align(8));
    auto *claim = BB.CreateAtomicCmpXchg(
        slotPtr, ConstantInt::get(i64, 0xD1B54A32D192ED03ULL),
        ConstantInt::get(i64, 0x94D049BB133111EBULL), MaybeAlign(8),
        AtomicOrdering::SequentiallyConsistent,
        AtomicOrdering::SequentiallyConsistent);
    claim->setName("morok.antihook.dbi.smc.lock.worker.cmpxchg");
    Value *observed = BB.CreateExtractValue(
        claim, 0, "morok.antihook.dbi.smc.lock.worker.observed");
    auto *final =
        smcAtomicLoad(BB, i64, slotPtr, Align(8),
                      "morok.antihook.dbi.smc.lock.worker.final");
    Value *bad = BB.CreateOr(
        BB.CreateNot(smcRaceValueValid(
            BB, observed, "morok.antihook.dbi.smc.lock.worker.observed.valid")),
        BB.CreateNot(smcRaceValueValid(
            BB, final, "morok.antihook.dbi.smc.lock.worker.final.valid")),
        "morok.antihook.dbi.smc.lock.worker.torn");
    smcRaceAccumulateBad(BB, badPtr, bad,
                         "morok.antihook.dbi.smc.lock.worker.bad");
    Value *next =
        BB.CreateAdd(iter, ConstantInt::get(i32, 1),
                     "morok.antihook.dbi.smc.lock.worker.next");
    BB.CreateBr(raceBB);
    iter->addIncoming(next, bodyBB);

    IRBuilder<> RB(retBB);
    RB.CreateRet(ConstantPointerNull::get(ptr));
    return fn;
}

void emitSmcLockCmpxchgProbe(IRBuilder<> &B, Module &M, AllocaInst *Diff,
                              const Triple &TT) {
    if (TT.getArch() != Triple::x86_64)
        return;
    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    AllocaInst *slot =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.smc.lock.slot");
    slot->setAlignment(Align(8));
    B.CreateStore(ConstantInt::get(i64, 1), slot)->setVolatile(true);
    auto *claim = B.CreateAtomicCmpXchg(
        slot, ConstantInt::get(i64, 1), ConstantInt::get(i64, 2),
        MaybeAlign(8), AtomicOrdering::SequentiallyConsistent,
        AtomicOrdering::SequentiallyConsistent);
    claim->setName("morok.antihook.dbi.smc.lock.cmpxchg");
    Value *observed =
        B.CreateExtractValue(claim, 0, "morok.antihook.dbi.smc.lock.observed");
    Value *success =
        B.CreateExtractValue(claim, 1, "morok.antihook.dbi.smc.lock.success");
    auto *final =
        B.CreateLoad(i64, slot, "morok.antihook.dbi.smc.lock.final");
    final->setVolatile(true);
    Value *mismatch = B.CreateOr(
        B.CreateNot(success, "morok.antihook.dbi.smc.lock.fail"),
        B.CreateOr(B.CreateICmpNE(observed, ConstantInt::get(i64, 1)),
                   B.CreateICmpNE(final, ConstantInt::get(i64, 2))),
        "morok.antihook.dbi.smc.lock.mismatch");
    incrementDiff(B, Diff, mismatch, "morok.antihook.dbi.smc.lock");
}

void emitSmcLockThreadRaceProbe(IRBuilder<> &B, Module &M, Function *Fn,
                                AllocaInst *Diff, const Triple &TT) {
    if (TT.getArch() != Triple::x86_64 ||
        (!TT.isOSLinux() && !TT.isOSDarwin() && !TT.isOSWindows()))
        return;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    Function *worker = dbiSmcLockRaceWorker(M);

    auto *stateTy = ArrayType::get(i8, 32);
    auto *state =
        B.CreateAlloca(stateTy, nullptr, "morok.antihook.dbi.smc.lock.state");
    state->setAlignment(Align(8));
    Value *statePtr = B.CreateInBoundsGEP(
        stateTy, state, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.smc.lock.state.ptr");
    Value *slotPtr =
        smcStatePtr(B, M, statePtr, 0, "morok.antihook.dbi.smc.lock.race.slot");
    Value *badPtr =
        smcStatePtr(B, M, statePtr, 8, "morok.antihook.dbi.smc.lock.race.bad");
    Value *readyPtr = smcStatePtr(B, M, statePtr, 16,
                                  "morok.antihook.dbi.smc.lock.race.ready.ptr");
    Value *goPtr = smcStatePtr(B, M, statePtr, 20,
                               "morok.antihook.dbi.smc.lock.race.go.ptr");
    Value *donePtr = smcStatePtr(B, M, statePtr, 24,
                                 "morok.antihook.dbi.smc.lock.race.done.ptr");
    smcAtomicStore(B, ConstantInt::get(i64, 0), slotPtr, Align(8));
    smcAtomicStore(B, ConstantInt::get(i64, 0), badPtr, Align(8));
    smcAtomicStore(B, ConstantInt::get(i32, 0), readyPtr, Align(4));
    smcAtomicStore(B, ConstantInt::get(i32, 0), goPtr, Align(4));
    smcAtomicStore(B, ConstantInt::get(i32, 0), donePtr, Align(4));

    const bool posixThread = TT.isOSLinux() || TT.isOSDarwin();
    Type *threadTokenTy = ip;
    if (TT.isOSDarwin() || TT.isOSWindows())
        threadTokenTy = ptr;
    Value *threadToken = nullptr;
    AllocaInst *thread = nullptr;
    Value *created = nullptr;
    FunctionCallee pthreadJoin;
    FunctionCallee waitForSingleObject;
    FunctionCallee closeHandle;
    if (posixThread) {
        thread = B.CreateAlloca(threadTokenTy, nullptr,
                                "morok.antihook.dbi.smc.lock.thread");
        thread->setAlignment(Align(8));
        FunctionCallee pthreadCreate = M.getOrInsertFunction(
            "pthread_create",
            FunctionType::get(i32, {ptr, ptr, ptr, ptr}, false));
        pthreadJoin = M.getOrInsertFunction(
            "pthread_join",
            FunctionType::get(i32, {threadTokenTy, ptr}, false));
        Value *rc = B.CreateCall(
            pthreadCreate,
            {thread, ConstantPointerNull::get(ptr), worker, statePtr},
            "morok.antihook.dbi.smc.lock.pthread");
        created = B.CreateICmpEQ(
            rc, ConstantInt::get(i32, 0),
            "morok.antihook.dbi.smc.lock.thread.created");
    } else {
        FunctionCallee createThread = M.getOrInsertFunction(
            "CreateThread",
            FunctionType::get(ptr, {ptr, ip, ptr, ptr, i32, ptr}, false));
        waitForSingleObject = M.getOrInsertFunction(
            "WaitForSingleObject", FunctionType::get(i32, {ptr, i32}, false));
        closeHandle = M.getOrInsertFunction(
            "CloseHandle", FunctionType::get(i32, {ptr}, false));
        threadToken = B.CreateCall(
            createThread,
            {ConstantPointerNull::get(ptr), ConstantInt::get(ip, 0), worker,
             statePtr, ConstantInt::get(i32, 0),
             ConstantPointerNull::get(ptr)},
            "morok.antihook.dbi.smc.lock.createthread");
        created = B.CreateICmpNE(
            threadToken, ConstantPointerNull::get(ptr),
            "morok.antihook.dbi.smc.lock.thread.created");
    }

    auto *waitBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.wait", Fn);
    auto *waitMoreBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.wait.more", Fn);
    auto *startBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.start", Fn);
    auto *raceBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.race", Fn);
    auto *bodyBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.body", Fn);
    auto *finishBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.finish", Fn);
    auto *timeoutBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.timeout", Fn);
    auto *joinBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.join", Fn);
    auto *doneBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.lock.done", Fn);
    BasicBlock *entryBB = B.GetInsertBlock();
    B.CreateCondBr(created, waitBB, doneBB);

    IRBuilder<> WB(waitBB);
    auto *waitIter =
        WB.CreatePHI(i32, 2, "morok.antihook.dbi.smc.lock.wait.iter");
    waitIter->addIncoming(ConstantInt::get(i32, 0), entryBB);
    auto *ready =
        smcAtomicLoad(WB, i32, readyPtr, Align(4),
                      "morok.antihook.dbi.smc.lock.ready");
    WB.CreateCondBr(WB.CreateICmpNE(ready, ConstantInt::get(i32, 0),
                                    "morok.antihook.dbi.smc.lock.ready.set"),
                    startBB, waitMoreBB);

    IRBuilder<> WMB(waitMoreBB);
    Value *nextWait =
        WMB.CreateAdd(waitIter, ConstantInt::get(i32, 1),
                      "morok.antihook.dbi.smc.lock.wait.next");
    WMB.CreateCondBr(WMB.CreateICmpULT(
                         nextWait, ConstantInt::get(i32, 4096),
                         "morok.antihook.dbi.smc.lock.wait.more"),
                     waitBB, timeoutBB);
    waitIter->addIncoming(nextWait, waitMoreBB);

    IRBuilder<> SB(startBB);
    smcAtomicStore(SB, ConstantInt::get(i32, 1), goPtr, Align(4));
    SB.CreateBr(raceBB);

    IRBuilder<> RB(raceBB);
    auto *raceIter =
        RB.CreatePHI(i32, 2, "morok.antihook.dbi.smc.lock.race.iter");
    raceIter->addIncoming(ConstantInt::get(i32, 0), startBB);
    RB.CreateCondBr(RB.CreateICmpULT(raceIter, ConstantInt::get(i32, 64),
                                     "morok.antihook.dbi.smc.lock.race.bound"),
                    bodyBB, finishBB);

    IRBuilder<> BB(bodyBB);
    smcAtomicStore(BB, ConstantInt::get(i64, 0x41C67EA6B7D92F15ULL), slotPtr,
                   Align(8));
    auto *claim = BB.CreateAtomicCmpXchg(
        slotPtr, ConstantInt::get(i64, 0x41C67EA6B7D92F15ULL),
        ConstantInt::get(i64, 0x9E3779B97F4A7C15ULL), MaybeAlign(8),
        AtomicOrdering::SequentiallyConsistent,
        AtomicOrdering::SequentiallyConsistent);
    claim->setName("morok.antihook.dbi.smc.lock.race.cmpxchg");
    Value *observed = BB.CreateExtractValue(
        claim, 0, "morok.antihook.dbi.smc.lock.race.observed");
    auto *final =
        smcAtomicLoad(BB, i64, slotPtr, Align(8),
                      "morok.antihook.dbi.smc.lock.race.final");
    Value *bad = BB.CreateOr(
        BB.CreateNot(smcRaceValueValid(
            BB, observed, "morok.antihook.dbi.smc.lock.race.observed.valid")),
        BB.CreateNot(smcRaceValueValid(
            BB, final, "morok.antihook.dbi.smc.lock.race.final.valid")),
        "morok.antihook.dbi.smc.lock.race.torn");
    smcRaceAccumulateBad(BB, badPtr, bad,
                         "morok.antihook.dbi.smc.lock.race.bad");
    Value *nextRace =
        BB.CreateAdd(raceIter, ConstantInt::get(i32, 1),
                     "morok.antihook.dbi.smc.lock.race.next");
    BB.CreateBr(raceBB);
    raceIter->addIncoming(nextRace, bodyBB);

    IRBuilder<> FB(finishBB);
    smcAtomicStore(FB, ConstantInt::get(i32, 1), donePtr, Align(4));
    FB.CreateBr(joinBB);

    IRBuilder<> TB(timeoutBB);
    smcAtomicStore(TB, ConstantInt::get(i32, 1), donePtr, Align(4));
    TB.CreateBr(joinBB);

    IRBuilder<> JB(joinBB);
    if (posixThread) {
        auto *tid = JB.CreateLoad(threadTokenTy, thread,
                                  "morok.antihook.dbi.smc.lock.thread.id");
        JB.CreateCall(pthreadJoin, {tid, ConstantPointerNull::get(ptr)},
                      "morok.antihook.dbi.smc.lock.join.rc");
    } else {
        JB.CreateCall(waitForSingleObject,
                      {threadToken, ConstantInt::get(i32, 0xFFFFFFFFu)},
                      "morok.antihook.dbi.smc.lock.wait.rc");
        JB.CreateCall(closeHandle, {threadToken},
                      "morok.antihook.dbi.smc.lock.close.rc");
    }
    auto *badFinal =
        smcAtomicLoad(JB, i64, badPtr, Align(8),
                      "morok.antihook.dbi.smc.lock.race.bad.final");
    Value *mismatch =
        JB.CreateICmpNE(badFinal, ConstantInt::get(i64, 0),
                        "morok.antihook.dbi.smc.lock.race.mismatch");
    incrementDiff(JB, Diff, mismatch, "morok.antihook.dbi.smc.lock.race");
    JB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
}

void emitSmcClflushProbe(IRBuilder<> &B, Module &M, Function *Fn,
                         AllocaInst *Diff, const Triple &TT) {
    if (TT.getArch() != Triple::x86_64)
        return;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    AllocaInst *scratch =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.smc.clflush.scratch");
    scratch->setAlignment(Align(64));
    B.CreateStore(ConstantInt::get(i64, 0), scratch)->setVolatile(true);

    Value *leaf1 = emitCpuid(B, M, ConstantInt::get(i32, 1),
                             ConstantInt::get(i32, 0));
    Value *edx = cpuidReg(B, leaf1, 3, "morok.antihook.dbi.smc.cpuid.edx");
    Value *clflushBit =
        B.CreateAnd(edx, ConstantInt::get(i32, 1u << 19),
                    "morok.antihook.dbi.smc.cpuid.clflush");
    Value *hasClflush =
        B.CreateICmpNE(clflushBit, ConstantInt::get(i32, 0),
                       "morok.antihook.dbi.smc.clflush.supported");
    auto *flushBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.clflush", Fn);
    auto *doneBB =
        BasicBlock::Create(ctx, "morok.antihook.dbi.smc.clflush.done", Fn);
    B.CreateCondBr(hasClflush, flushBB, doneBB);

    IRBuilder<> FB(flushBB);
    auto *asmTy = FunctionType::get(i64, {ptr}, false);
    InlineAsm *flush = InlineAsm::get(
        asmTy,
        "movabsq $$0x1122334455667788, %rax\n\t"
        "movq %rax, (%rdi)\n\t"
        "mfence\n\t"
        "clflush (%rdi)\n\t"
        "mfence\n\t"
        "movabsq $$0x8877665544332211, %rax\n\t"
        "movq %rax, (%rdi)\n\t"
        "mfence\n\t"
        "clflush (%rdi)\n\t"
        "mfence\n\t"
        "movq (%rdi), %rax",
        "={rax},{rdi},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    Value *observed = FB.CreateCall(
        asmTy, flush, {scratch}, "morok.antihook.dbi.smc.clflush.value");
    Value *mismatch =
        FB.CreateICmpNE(observed, ConstantInt::get(i64, 0x8877665544332211ULL),
                        "morok.antihook.dbi.smc.clflush.mismatch");
    incrementDiff(FB, Diff, mismatch, "morok.antihook.dbi.smc.clflush");
    FB.CreateBr(doneBB);

    B.SetInsertPoint(doneBB);
}

Function *dbiSmcTarget(Module &M) {
    if (Function *existing = M.getFunction("morok.antihook.dbi.smc.target"))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *fn = Function::Create(FunctionType::get(i32, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.dbi.smc.target", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    auto *entry = BasicBlock::Create(M.getContext(), "entry", fn);
    IRBuilder<> B(entry);
    B.CreateRet(ConstantInt::get(i32, 0x13579BDFu));
    return fn;
}

Function *dbiSmcTripwireProbe(Module &M, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.antihook.dbi.smc"))
        return existing;
    if (intPtrTy(M)->getBitWidth() != 64)
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    Function *target = dbiSmcTarget(M);

    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.dbi.smc", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *hotBB = BasicBlock::Create(ctx, "hot", fn);
    auto *writeBB = BasicBlock::Create(ctx, "write", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    AllocaInst *diff = B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.smc.diff");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);
    emitSmcLockCmpxchgProbe(B, M, diff, TT);
    emitSmcClflushProbe(B, M, fn, diff, TT);
    emitSmcLockThreadRaceProbe(B, M, fn, diff, TT);
    GlobalVariable *smcGate = dbiSmcGate(M);
    Value *gateSeed =
        B.CreatePtrToInt(target, ip, "morok.antihook.dbi.smc.gate.seed");
    Value *gateArm = B.CreateOr(
        B.CreateTrunc(gateSeed, i8, "morok.antihook.dbi.smc.gate.seed8"),
        ConstantInt::get(i8, 1), "morok.antihook.dbi.smc.gate.arm");
    B.CreateStore(gateArm, smcGate)->setVolatile(true);
    auto *gate = B.CreateLoad(i8, smcGate, "morok.antihook.dbi.smc.load");
    gate->setVolatile(true);
    B.CreateCondBr(B.CreateICmpNE(gate, ConstantInt::get(i8, 0),
                                  "morok.antihook.dbi.smc.armed"),
                   hotBB, retBB);

    IRBuilder<> HB(hotBB);
    Value *targetAddr = HB.CreatePtrToInt(target, ip, "morok.antihook.dbi.smc.addr");
    Value *page = HB.CreateAnd(targetAddr, ConstantInt::get(ip, ~0xfffULL),
                               "morok.antihook.dbi.smc.page");
    Value *codePtr = HB.CreateIntToPtr(targetAddr, ptr, "morok.antihook.dbi.smc.ptr");
    Value *protectOk = ConstantInt::getTrue(ctx);
    if (TT.isOSLinux()) {
        Value *rc = emitLinuxMprotect(HB, M, TT, page, ConstantInt::get(ip, 4096),
                                      ConstantInt::get(i32, 7));
        rc->setName("morok.antihook.dbi.smc.mprotect.rwx");
        protectOk = HB.CreateICmpEQ(rc, ConstantInt::get(i32, 0),
                                    "morok.antihook.dbi.smc.rwx.ok");
    } else if (TT.isOSDarwin()) {
        Value *rc = emitDarwinMprotect(HB, M, TT, page, ConstantInt::get(ip, 4096),
                                       ConstantInt::get(i32, 7));
        rc->setName("morok.antihook.dbi.smc.mprotect.rwx");
        protectOk = HB.CreateICmpEQ(rc, ConstantInt::get(i32, 0),
                                    "morok.antihook.dbi.smc.rwx.ok");
    } else if (TT.isOSWindows()) {
        auto *oldProt = HB.CreateAlloca(i32, nullptr, "morok.antihook.dbi.smc.old");
        FunctionCallee virtualProtect = M.getOrInsertFunction(
            "VirtualProtect", FunctionType::get(i32, {ptr, ip, i32, ptr}, false));
        Value *rc = HB.CreateCall(
            virtualProtect,
            {HB.CreateIntToPtr(page, ptr), ConstantInt::get(ip, 4096),
             ConstantInt::get(i32, 0x40), oldProt},
            "morok.antihook.dbi.smc.virtualprotect.rwx");
        protectOk = HB.CreateICmpNE(rc, ConstantInt::get(i32, 0),
                                    "morok.antihook.dbi.smc.rwx.ok");
    }
    HB.CreateCondBr(protectOk, writeBB, retBB);

    IRBuilder<> WB(writeBB);
    auto *oldByte = WB.CreateLoad(i8, codePtr, "morok.antihook.dbi.smc.byte");
    oldByte->setVolatile(true);
    auto *touch = WB.CreateStore(oldByte, codePtr);
    touch->setVolatile(true);
    Value *patchPtr =
        gepI8(WB, M, codePtr, constIp(M, 1),
              "morok.antihook.dbi.smc.patch.ptr");
    auto *oldPatch =
        WB.CreateLoad(i8, patchPtr, "morok.antihook.dbi.smc.patch.byte");
    oldPatch->setVolatile(true);
    Value *canPatch =
        WB.CreateICmpEQ(oldByte, ConstantInt::get(i8, 0xB8),
                        "morok.antihook.dbi.smc.patch.mov");
    Value *patchFlip =
        WB.CreateXor(oldPatch, ConstantInt::get(i8, 1),
                     "morok.antihook.dbi.smc.patch.flip");
    Value *patchByte =
        WB.CreateSelect(canPatch, patchFlip, oldPatch,
                        "morok.antihook.dbi.smc.patch.next");
    auto *patchStore = WB.CreateStore(patchByte, patchPtr);
    patchStore->setVolatile(true);
    if (TT.getArch() == Triple::x86_64) {
        // mfence only orders memory; it is NOT instruction-serializing and does
        // not flush prefetched/decoded bytes, so the just-written code byte
        // could execute from a stale fetch and trip on a clean host. CPUID is
        // architecturally serializing (Intel SDM Vol. 3A 8.1.3, self-modifying
        // code): it flushes the pipeline so the patched/restored byte is
        // refetched before the call below.
        (void)emitCpuid(WB, M, ConstantInt::get(i32, 0),
                        ConstantInt::get(i32, 0));
    }
    Value *patchResult =
        WB.CreateCall(target, {}, "morok.antihook.dbi.smc.patch.result");
    Value *patchExpected = WB.CreateSelect(
        canPatch, ConstantInt::get(i32, 0x13579BDEu),
        ConstantInt::get(i32, 0x13579BDFu),
        "morok.antihook.dbi.smc.patch.expected");
    Value *patchBad =
        WB.CreateICmpNE(patchResult, patchExpected,
                        "morok.antihook.dbi.smc.patch.bad");
    auto *restorePatch = WB.CreateStore(oldPatch, patchPtr);
    restorePatch->setVolatile(true);
    if (TT.getArch() == Triple::x86_64) {
        // mfence only orders memory; it is NOT instruction-serializing and does
        // not flush prefetched/decoded bytes, so the just-written code byte
        // could execute from a stale fetch and trip on a clean host. CPUID is
        // architecturally serializing (Intel SDM Vol. 3A 8.1.3, self-modifying
        // code): it flushes the pipeline so the patched/restored byte is
        // refetched before the call below.
        (void)emitCpuid(WB, M, ConstantInt::get(i32, 0),
                        ConstantInt::get(i32, 0));
    }
    if (TT.isOSLinux()) {
        Value *rc = emitLinuxMprotect(WB, M, TT, page, ConstantInt::get(ip, 4096),
                                      ConstantInt::get(i32, 5));
        rc->setName("morok.antihook.dbi.smc.mprotect.rx");
    } else if (TT.isOSDarwin()) {
        Value *rc = emitDarwinMprotect(WB, M, TT, page, ConstantInt::get(ip, 4096),
                                       ConstantInt::get(i32, 5));
        rc->setName("morok.antihook.dbi.smc.mprotect.rx");
    } else if (TT.isOSWindows()) {
        auto *oldProt2 =
            WB.CreateAlloca(i32, nullptr, "morok.antihook.dbi.smc.old2");
        FunctionCallee virtualProtect = M.getOrInsertFunction(
            "VirtualProtect", FunctionType::get(i32, {ptr, ip, i32, ptr}, false));
        WB.CreateCall(virtualProtect,
                      {WB.CreateIntToPtr(page, ptr), ConstantInt::get(ip, 4096),
                       ConstantInt::get(i32, 0x20), oldProt2},
                      "morok.antihook.dbi.smc.virtualprotect.rx");
    }
    Value *result = WB.CreateCall(target, {}, "morok.antihook.dbi.smc.result");
    Value *restoreBad =
        WB.CreateICmpNE(result, ConstantInt::get(i32, 0x13579BDFu),
                        "morok.antihook.dbi.smc.restore.bad");
    incrementDiff(WB, diff,
                  WB.CreateOr(patchBad, restoreBad,
                              "morok.antihook.dbi.smc.trip"),
                  "morok.antihook.dbi.smc.trip");
    WB.CreateBr(retBB);

    IRBuilder<> RB(retBB);
    emitRetDiff(RB, diff);
    return fn;
}

Function *linuxDbiSignatureProbe(Module &M, ir::IRRandom &rng,
                                 const Triple &TT) {
    if (!TT.isOSLinux() || intPtrTy(M)->getBitWidth() != 64)
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.dbi.linux"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);

    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.dbi.linux", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *afterMapsBB = BasicBlock::Create(ctx, "after.maps", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    AllocaInst *diff = B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.diff");
    AllocaInst *jitDiff =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.jit.diff");
    AllocaInst *pinDiff =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.pin.diff");
    AllocaInst *fridaDiff =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.frida.diff");
    AllocaInst *fridaSoftDiff =
        B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.frida.soft.diff");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), jitDiff)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), pinDiff)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), fridaDiff)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), fridaSoftDiff)->setVolatile(true);
    ReadFileIR maps =
        emitReadSmallFile(B, M, fn, "/proc/self/maps", 8192, rng, TT);

    IRBuilder<> MFB(maps.ret0);
    MFB.CreateBr(afterMapsBB);

    IRBuilder<> MB(maps.afterRead);
    Value *mapSig0 = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x66, 0x72, 0x69, 0x64, 0x61}, 8192,
        "morok.antihook.dbi.maps.sig0");
    Value *mapSig1 = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x67, 0x61, 0x64, 0x67, 0x65, 0x74}, 8192,
        "morok.antihook.dbi.maps.sig1");
    Value *mapSig2 = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x72, 0x65, 0x2e, 0x66, 0x72, 0x69, 0x64, 0x61}, 8192,
        "morok.antihook.dbi.maps.sig2");
    Value *mapDyn = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x6c, 0x69, 0x62, 0x64, 0x79, 0x6e, 0x61, 0x6d, 0x6f, 0x72, 0x69,
         0x6f},
        8192, "morok.antihook.dbi.maps.dynamorio");
    Value *mapQbdi = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x6c, 0x69, 0x62, 0x51, 0x42, 0x44, 0x49}, 8192,
        "morok.antihook.dbi.maps.qbdi");
    Value *mapVgPreload = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x76, 0x67, 0x70, 0x72, 0x65, 0x6c, 0x6f, 0x61, 0x64, 0x5f}, 8192,
        "morok.antihook.dbi.maps.vgpreload");
    Value *mapValgrind = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x76, 0x61, 0x6c, 0x67, 0x72, 0x69, 0x6e, 0x64}, 8192,
        "morok.antihook.dbi.maps.valgrind");
    Value *mapQemu = bufferHasLiteral(
        MB, M, maps.buf, maps.n, {0x71, 0x65, 0x6d, 0x75, 0x2d}, 8192,
        "morok.antihook.dbi.maps.qemu");
    Value *mapPin = bufferHasLiteral(
        MB, M, maps.buf, maps.n, {0x70, 0x69, 0x6e, 0x62, 0x69, 0x6e}, 8192,
        "morok.antihook.dbi.maps.pinbin");
    Value *mapLibPin = bufferHasLiteral(
        MB, M, maps.buf, maps.n, {0x6c, 0x69, 0x62, 0x70, 0x69, 0x6e}, 8192,
        "morok.antihook.dbi.maps.libpin");
    Value *mapPinVm = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x70, 0x69, 0x6e, 0x76, 0x6d, 0x2e, 0x73, 0x6f}, 8192,
        "morok.antihook.dbi.pin.maps.pinvm");
    Value *mapPinCharmve = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x2e, 0x63, 0x68, 0x61, 0x72, 0x6d, 0x76, 0x65}, 8192,
        "morok.antihook.dbi.pin.maps.charmve");
    Value *mapPinClie = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x2e, 0x70, 0x69, 0x6e, 0x63, 0x6c, 0x69, 0x65}, 8192,
        "morok.antihook.dbi.pin.maps.pinclie");
    Value *mapPinEncoder = bufferHasLinuxRxMemoryLiteral(
        MB, M, maps.buf, maps.n,
        {0x49, 0x6e, 0x74, 0x65, 0x6c, 0x28, 0x52, 0x29, 0x20, 0x58,
         0x38, 0x36, 0x20, 0x45, 0x6e, 0x63, 0x6f, 0x64, 0x65, 0x72},
        8192, 65536, 8, "morok.antihook.dbi.pin.rx.encoder");
    // "hluda-" — a Frida fork that renames the "frida"/"gum" artifacts to
    // "hluda" specifically to evade the "frida" substring match above. Anchored
    // to the trailing '-' of its module convention (hluda-agent / hluda-gadget
    // / hluda-server / libhluda-gum, mirroring frida-agent / frida-gadget) so
    // the enforced match cannot false-positive on a benign path that merely
    // contains the bare 5-byte token "hluda" — a free-floating substring is not
    // zero-on-clean for the consumed seal (#236). The dash anchor is as
    // boundary-safe as the existing "qemu-" literal while still catching every
    // hluda artifact form.
    Value *mapHluda = bufferHasLiteral(
        MB, M, maps.buf, maps.n, {0x68, 0x6c, 0x75, 0x64, 0x61, 0x2d}, 8192,
        "morok.antihook.dbi.maps.hluda");
    Value *mapSig = MB.CreateOr(
        MB.CreateOr(MB.CreateOr(mapSig0, mapSig1), mapSig2),
        MB.CreateOr(MB.CreateOr(mapDyn, mapQbdi),
                    MB.CreateOr(MB.CreateOr(mapVgPreload, mapValgrind),
                                MB.CreateOr(mapQemu, mapHluda))),
        "morok.antihook.dbi.maps.sig");
    incrementDiff(MB, diff, mapSig, "morok.antihook.dbi.maps");
    Value *mapPinStock = MB.CreateOr(
        MB.CreateOr(mapPin, mapLibPin, "morok.antihook.dbi.pin.maps.libs"),
        MB.CreateOr(MB.CreateOr(mapPinVm, mapPinEncoder,
                                "morok.antihook.dbi.pin.maps.vm.rx"),
                    MB.CreateOr(mapPinCharmve, mapPinClie,
                                "morok.antihook.dbi.pin.maps.sections"),
                    "morok.antihook.dbi.pin.maps.vm.sections"),
        "morok.antihook.dbi.pin.maps.stock");
    incrementDiff(MB, pinDiff, mapPinStock, "morok.antihook.dbi.pin.maps");
    Value *mapJitCache = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x6a, 0x69, 0x74, 0x2d, 0x63, 0x61, 0x63, 0x68, 0x65}, 8192,
        "morok.antihook.dbi.jit.maps.jitcache");
    Value *mapCodeCache = bufferHasLiteral(
        MB, M, maps.buf, maps.n,
        {0x63, 0x6f, 0x64, 0x65, 0x2d, 0x63, 0x61, 0x63, 0x68, 0x65}, 8192,
        "morok.antihook.dbi.jit.maps.codecache");
    Value *mapTcgCache = bufferHasLiteral(
        MB, M, maps.buf, maps.n, {0x74, 0x63, 0x67, 0x2d}, 8192,
        "morok.antihook.dbi.jit.maps.tcgcache");
    Value *mapAnonExec = bufferHasLinuxAnonymousExecMap(
        MB, M, maps.buf, maps.n, 8192,
        "morok.antihook.dbi.jit.maps.anon");
    Value *mapJitShape =
        MB.CreateOr(MB.CreateOr(mapJitCache, mapCodeCache),
                    MB.CreateOr(mapTcgCache, mapAnonExec),
                    "morok.antihook.dbi.jit.maps.shape");
    incrementDiff(MB, jitDiff, mapJitShape, "morok.antihook.dbi.jit.maps");
    MB.CreateBr(afterMapsBB);

    IRBuilder<> TB(afterMapsBB);
    auto *nameTy = ArrayType::get(i8, 16);
    AllocaInst *name =
        TB.CreateAlloca(nameTy, nullptr, "morok.antihook.dbi.thread.name");
    Value *namePtr = TB.CreateInBoundsGEP(
        nameTy, name, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antihook.dbi.thread.ptr");
    for (unsigned i = 0; i < 16; ++i)
        TB.CreateStore(ConstantInt::get(i8, 0),
                       TB.CreateInBoundsGEP(nameTy, name,
                                            {ConstantInt::get(ip, 0),
                                             ConstantInt::get(ip, i)}));
    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    if (linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr)) {
        emitLinuxSyscall(TB, M, TT, prctlNr,
                         {ConstantInt::get(i32, 16), namePtr,
                          ConstantInt::get(ip, 0), ConstantInt::get(ip, 0),
                          ConstantInt::get(ip, 0)});
    }
    Value *threadSig0 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x67, 0x75, 0x6d, 0x2d, 0x6a, 0x73, 0x2d, 0x6c, 0x6f, 0x6f, 0x70},
        16, "morok.antihook.dbi.thread.sig0");
    Value *threadSig1 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x67, 0x6d, 0x61, 0x69, 0x6e}, 16,
        "morok.antihook.dbi.thread.sig1");
    Value *threadSig2 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x66, 0x72, 0x69, 0x64, 0x61, 0x2d, 0x61, 0x67, 0x65, 0x6e, 0x74},
        16, "morok.antihook.dbi.thread.sig2");
    Value *threadSig3 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x70, 0x6f, 0x6f, 0x6c, 0x2d, 0x66, 0x72, 0x69, 0x64, 0x61}, 16,
        "morok.antihook.dbi.thread.pool_frida");
    Value *threadSig4 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x67, 0x64, 0x62, 0x75, 0x73}, 16,
        "morok.antihook.dbi.thread.gdbus");
    Value *threadSig5 = bufferHasLiteral(
        TB, M, name, ConstantInt::get(ip, 16),
        {0x6c, 0x69, 0x6e, 0x6a, 0x65, 0x63, 0x74, 0x6f, 0x72}, 16,
        "morok.antihook.dbi.thread.linjector");
    Value *threadStrong = TB.CreateOr(
        TB.CreateOr(threadSig0, threadSig2),
        TB.CreateOr(threadSig3, threadSig5),
        "morok.antihook.dbi.thread.strong");
    Value *threadWeak =
        TB.CreateOr(threadSig1, threadSig4, "morok.antihook.dbi.thread.weak");
    TB.CreateOr(threadStrong, threadWeak, "morok.antihook.dbi.thread.sig");
    incrementDiff(TB, fridaDiff, threadStrong,
                  "morok.antihook.dbi.frida.thread.self.strong");
    incrementDiff(TB, fridaSoftDiff, threadWeak,
                  "morok.antihook.dbi.frida.thread.self.weak");
    emitLinuxDbiThreadTableScan(TB, M, fn, fridaDiff, fridaSoftDiff, rng, TT);

    FunctionCallee dlsym =
        M.getOrInsertFunction("dlsym", FunctionType::get(ptr, {ptr, ptr}, false));
    Value *rtldDefault = ConstantPointerNull::get(ptr);
    Value *drAppStart = TB.CreateCall(
        dlsym, {rtldDefault, ir::emitCloakedSymbol(TB, M, "dr_app_start", rng)},
        "morok.antihook.dbi.dlsym.dr");
    Value *qbdiCodeRange = TB.CreateCall(
        dlsym,
        {rtldDefault,
         ir::emitCloakedSymbol(TB, M, "QBDI_addCodeRangeCB", rng)},
        "morok.antihook.dbi.dlsym.qbdi");
    Value *pinSetDebug = TB.CreateCall(
        dlsym,
        {rtldDefault, ir::emitCloakedSymbol(TB, M, "PIN_SetDebugMode", rng)},
        "morok.antihook.dbi.pin.dlsym.set_debug");
    Value *pinCommitHash = TB.CreateCall(
        dlsym,
        {rtldDefault, ir::emitCloakedSymbol(TB, M, "PinCommitHashC", rng)},
        "morok.antihook.dbi.pin.dlsym.commit_hash");
    Value *pinTls = TB.CreateCall(
        dlsym, {rtldDefault, ir::emitCloakedSymbol(TB, M, "__pin_tls", rng)},
        "morok.antihook.dbi.pin.dlsym.tls");
    Value *symbolSig = TB.CreateOr(
        TB.CreateICmpNE(drAppStart, ConstantPointerNull::get(ptr),
                        "morok.antihook.dbi.dlsym.dr.hit"),
        TB.CreateICmpNE(qbdiCodeRange, ConstantPointerNull::get(ptr),
                        "morok.antihook.dbi.dlsym.qbdi.hit"),
        "morok.antihook.dbi.dlsym.sig");
    incrementDiff(TB, diff, symbolSig, "morok.antihook.dbi.dlsym");
    Value *pinSymbolSig = TB.CreateOr(
        TB.CreateICmpNE(pinSetDebug, ConstantPointerNull::get(ptr),
                        "morok.antihook.dbi.pin.dlsym.set_debug.hit"),
        TB.CreateOr(TB.CreateICmpNE(pinCommitHash,
                                    ConstantPointerNull::get(ptr),
                                    "morok.antihook.dbi.pin.dlsym.commit_hash.hit"),
                    TB.CreateICmpNE(pinTls, ConstantPointerNull::get(ptr),
                                    "morok.antihook.dbi.pin.dlsym.tls.hit"),
                    "morok.antihook.dbi.pin.dlsym.commit.tls"),
        "morok.antihook.dbi.pin.dlsym.sig");
    incrementDiff(TB, pinDiff, pinSymbolSig, "morok.antihook.dbi.pin.dlsym");

    Value *vgMagic = emitValgrindRunningRequest(TB, M);
    Value *vgHit =
        TB.CreateICmpNE(vgMagic, ConstantInt::get(i64, 0),
                        "morok.antihook.dbi.valgrind.hit");
    incrementDiff(TB, diff, vgHit, "morok.antihook.dbi.valgrind");

    auto *afterParentBB = BasicBlock::Create(ctx, "after.parent", fn);
    std::uint32_t getppidNr = 0;
    std::uint32_t readlinkatNr = 0;
    if (linuxDbiParentSyscalls(TT, getppidNr, readlinkatNr) &&
        linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr)) {
        Value *ppid = emitLinuxSyscall(TB, M, TT, getppidNr, {});
        ppid->setName("morok.antihook.dbi.parent.pid");
        auto *pathTy = ArrayType::get(i8, 96);
        auto *exeTy = ArrayType::get(i8, 256);
        AllocaInst *commPath =
            TB.CreateAlloca(pathTy, nullptr, "morok.antihook.dbi.parent.comm.path");
        Value *commPathPtr = TB.CreateInBoundsGEP(
            pathTy, commPath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
            "morok.antihook.dbi.parent.comm.path.ptr");
        FunctionCallee snprintfFn = M.getOrInsertFunction(
            "snprintf", FunctionType::get(i32, {ptr, ip, ptr}, true));
        TB.CreateCall(snprintfFn,
                      {commPathPtr, ConstantInt::get(ip, 96),
                       ir::emitCloakedSymbol(TB, M, "/proc/%ld/comm", rng),
                       ppid},
                      "morok.antihook.dbi.parent.comm.path.n");
        ReadFileIR comm = emitReadPathValue(
            TB, M, fn, commPathPtr, 128, TT, "morok.antihook.dbi.parent.comm");
        auto *afterCommBB = BasicBlock::Create(ctx, "after.parent.comm", fn);

        IRBuilder<> CMissB(comm.ret0);
        CMissB.CreateBr(afterCommBB);

        IRBuilder<> CB(comm.afterRead);
        Value *commQemu = bufferHasLiteral(
            CB, M, comm.buf, comm.n, {0x71, 0x65, 0x6d, 0x75, 0x2d}, 128,
            "morok.antihook.dbi.parent.comm.qemu");
        Value *commValgrind = bufferHasLiteral(
            CB, M, comm.buf, comm.n,
            {0x76, 0x61, 0x6c, 0x67, 0x72, 0x69, 0x6e, 0x64}, 128,
            "morok.antihook.dbi.parent.comm.valgrind");
        Value *commPin = bufferHasLiteral(
            CB, M, comm.buf, comm.n, {0x70, 0x69, 0x6e, 0x0a}, 128,
            "morok.antihook.dbi.parent.comm.pin");
        Value *commPinBin = bufferHasLiteral(
            CB, M, comm.buf, comm.n,
            {0x70, 0x69, 0x6e, 0x62, 0x69, 0x6e}, 128,
            "morok.antihook.dbi.parent.comm.pinbin");
        incrementDiff(CB, diff, CB.CreateOr(commQemu, commValgrind),
                      "morok.antihook.dbi.parent.comm");
        incrementDiff(CB, pinDiff, CB.CreateOr(commPin, commPinBin),
                      "morok.antihook.dbi.pin.parent.comm");
        CB.CreateBr(afterCommBB);

        IRBuilder<> PCB(afterCommBB);
        AllocaInst *exePath =
            PCB.CreateAlloca(pathTy, nullptr, "morok.antihook.dbi.parent.exe.path");
        AllocaInst *exeBuf =
            PCB.CreateAlloca(exeTy, nullptr, "morok.antihook.dbi.parent.exe.buf");
        Value *exePathPtr = PCB.CreateInBoundsGEP(
            pathTy, exePath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
            "morok.antihook.dbi.parent.exe.path.ptr");
        Value *exeBufPtr = PCB.CreateInBoundsGEP(
            exeTy, exeBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
            "morok.antihook.dbi.parent.exe.ptr");
        PCB.CreateCall(snprintfFn,
                       {exePathPtr, ConstantInt::get(ip, 96),
                        ir::emitCloakedSymbol(PCB, M, "/proc/%ld/exe", rng),
                        ppid},
                       "morok.antihook.dbi.parent.exe.path.n");
        Value *exeN = emitLinuxSyscall(
            PCB, M, TT, readlinkatNr,
            {ConstantInt::getSigned(ip, -100), exePathPtr, exeBufPtr,
             ConstantInt::get(ip, 255)});
        exeN->setName("morok.antihook.dbi.parent.exe.readlink");
        Value *exeQemu = bufferHasLiteral(
            PCB, M, exeBuf, exeN, {0x71, 0x65, 0x6d, 0x75, 0x2d}, 256,
            "morok.antihook.dbi.parent.exe.qemu");
        Value *exeValgrind = bufferHasLiteral(
            PCB, M, exeBuf, exeN,
            {0x76, 0x61, 0x6c, 0x67, 0x72, 0x69, 0x6e, 0x64}, 256,
            "morok.antihook.dbi.parent.exe.valgrind");
        Value *exePin = bufferBasenameEqualsLiteral(
            PCB, M, exeBuf, exeN, {0x70, 0x69, 0x6e}, 256,
            "morok.antihook.dbi.parent.exe.pin");
        Value *exePinBin = bufferBasenameEqualsLiteral(
            PCB, M, exeBuf, exeN,
            {0x70, 0x69, 0x6e, 0x62, 0x69, 0x6e}, 256,
            "morok.antihook.dbi.parent.exe.pinbin");
        incrementDiff(PCB, diff, PCB.CreateOr(exeQemu, exeValgrind),
                      "morok.antihook.dbi.parent.exe");
        incrementDiff(PCB, pinDiff, PCB.CreateOr(exePin, exePinBin),
                      "morok.antihook.dbi.pin.parent.exe");
        PCB.CreateBr(afterParentBB);
    } else {
        TB.CreateBr(afterParentBB);
    }

    IRBuilder<> APB(afterParentBB);
    ReadFileIR tcp =
        emitReadSmallFile(APB, M, fn, "/proc/net/tcp", 4096, rng, TT);

    IRBuilder<> TFB(tcp.ret0);
    TFB.CreateBr(retBB);

    IRBuilder<> PB(tcp.afterRead);
    Value *portSig0 = bufferHasLiteral(
        PB, M, tcp.buf, tcp.n, {0x36, 0x39, 0x41, 0x32}, 4096,
        "morok.antihook.dbi.port.sig0");
    Value *portSig1 = bufferHasLiteral(
        PB, M, tcp.buf, tcp.n, {0x36, 0x39, 0x61, 0x32}, 4096,
        "morok.antihook.dbi.port.sig1");
    Value *portSig2 = bufferHasLiteral(
        PB, M, tcp.buf, tcp.n, {0x36, 0x39, 0x41, 0x33}, 4096,
        "morok.antihook.dbi.port.sig2");
    Value *portSig3 = bufferHasLiteral(
        PB, M, tcp.buf, tcp.n, {0x36, 0x39, 0x61, 0x33}, 4096,
        "morok.antihook.dbi.port.sig3");
    Value *portSig = PB.CreateOr(
        PB.CreateOr(portSig0, portSig1),
        PB.CreateOr(portSig2, portSig3),
        "morok.antihook.dbi.port.sig");
    Value *fdTcp =
        emitLinuxDbiFdTcpCrossRef(PB, M, fn, tcp.buf, tcp.n, rng, TT);
    incrementDiff(PB, fridaDiff, portSig,
                  "morok.antihook.dbi.frida.port");
    incrementDiff(PB, fridaDiff, fdTcp,
                  "morok.antihook.dbi.frida.fd.tcp");
    PB.CreateBr(retBB);

    IRBuilder<> RB(retBB);
    auto *hard = RB.CreateLoad(i64, diff, "morok.antihook.dbi.diff.hard");
    hard->setVolatile(true);
    auto *soft =
        RB.CreateLoad(i64, jitDiff, "morok.antihook.dbi.jit.diff.soft");
    soft->setVolatile(true);
    auto *frida =
        RB.CreateLoad(i64, fridaDiff, "morok.antihook.dbi.frida.diff.hard");
    frida->setVolatile(true);
    auto *fridaSoft =
        RB.CreateLoad(i64, fridaSoftDiff, "morok.antihook.dbi.frida.diff.soft");
    fridaSoft->setVolatile(true);
    auto *pin =
        RB.CreateLoad(i64, pinDiff, "morok.antihook.dbi.pin.diff.hard");
    pin->setVolatile(true);
    Value *fridaConfirmed =
        RB.CreateICmpUGE(frida, ConstantInt::get(i64, 2),
                         "morok.antihook.dbi.frida.confirmed");
    Value *hardWithFrida =
        RB.CreateAdd(hard, RB.CreateZExt(fridaConfirmed, i64),
                     "morok.antihook.dbi.diff.hard.frida");
    Value *softWithFrida =
        RB.CreateAdd(RB.CreateAdd(soft, frida,
                                  "morok.antihook.dbi.frida.hard.soft"),
                     fridaSoft, "morok.antihook.dbi.frida.soft");
    Value *pinConfirmed =
        RB.CreateICmpUGE(pin, ConstantInt::get(i64, 2),
                         "morok.antihook.dbi.pin.confirmed");
    Value *hardWithPin =
        RB.CreateAdd(hardWithFrida, RB.CreateZExt(pinConfirmed, i64),
                     "morok.antihook.dbi.diff.hard.pin");
    Value *softWithPin =
        RB.CreateAdd(softWithFrida, pin, "morok.antihook.dbi.jit.pin.soft");
    Value *packedHard =
        RB.CreateAnd(hardWithPin, ConstantInt::get(i64, 0xffffffffULL),
                     "morok.antihook.dbi.diff.pack.hard");
    Value *packedSoft = RB.CreateShl(
        RB.CreateAnd(softWithPin, ConstantInt::get(i64, 0xffffffffULL),
                     "morok.antihook.dbi.jit.diff.pack.soft"),
        ConstantInt::get(i64, 32), "morok.antihook.dbi.jit.diff.shift");
    RB.CreateRet(RB.CreateOr(packedHard, packedSoft,
                             "morok.antihook.dbi.diff.ret"));
    return fn;
}

void emitProloguePatternChecks(IRBuilder<> &B, Module &M, const Triple &TT,
                               GlobalVariable *State,
                               const std::vector<Function *> &Targets,
                               ir::IRRandom &rng) {
    if (Targets.empty())
        return;

    const bool x86 =
        TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64;
    const bool arm64 =
        TT.getArch() == Triple::aarch64 || TT.getArch() == Triple::aarch64_32;
    if (!x86 && !arm64)
        return;

    std::uint32_t site = 1;
    for (Function *target : Targets) {
        Value *hit = x86 ? emitX86ProloguePattern(B, M, target)
                         : emitArm64ProloguePattern(B, M, target);
        foldEnforcedFlag(
            B, State, hit, rng.next() ^ (0x9E3779B97F4A7C15ULL * site++),
            "morok.antihook.prologue");
    }
}

StringRef canonicalImportName(Function &F) {
    StringRef name = F.getName();
    if (name.starts_with("\01"))
        name = name.drop_front();
    return name;
}

bool posixStubIntegrityTarget(const Triple &TT, Function &F, StringRef &Label,
                              std::uint64_t &Salt) {
    if (!F.isDeclaration() || F.isIntrinsic())
        return false;

    StringRef name = canonicalImportName(F);
    auto match = [&](StringRef symbol, StringRef label,
                     std::uint64_t salt) -> bool {
        if (name != symbol)
            return false;
        Label = label;
        Salt = salt;
        return true;
    };

    if (TT.isOSLinux()) {
        return match("getpid", "getpid", 0x2B61D73C9E84A51FULL) ||
               match("getppid", "getppid", 0x8C14F0A35D69E2B7ULL) ||
               match("sigaction", "sigaction", 0x41E8B27D6C903AF5ULL) ||
               match("clock_gettime", "clock_gettime",
                     0xF17A4C59B603D82EULL) ||
               match("nanosleep", "nanosleep", 0x6D8B203FCA91475EULL) ||
               match("getauxval", "getauxval", 0xB4E59178A2C63D0FULL) ||
               match("sysconf", "sysconf", 0x39C6A18F52D70B4EULL);
    }

    if (TT.isOSDarwin()) {
        return match("getpid", "getpid", 0xC5309E4B71A6D28FULL) ||
               match("getppid", "getppid", 0x7A91D4F628C35BE0ULL) ||
               match("sigaction", "sigaction", 0xE28B5C13A97F406DULL) ||
               match("getpagesize", "getpagesize", 0x1F63B8D40A95C2E7ULL) ||
               match("clock_gettime", "clock_gettime",
                     0xAB04D7C95E3162F8ULL) ||
               match("mach_absolute_time", "mach_absolute_time",
                     0x5D276F90C13A8BE4ULL) ||
               match("_NSGetExecutablePath", "nsgetpath",
                     0x90E4B36A1C58F72DULL) ||
               match("_dyld_image_count", "dyld_count",
                     0x4B75A92C6E10D3F8ULL) ||
               match("_dyld_get_image_header", "dyld_header",
                     0xD62C0F81B3E95A47ULL) ||
               match("_dyld_get_image_vmaddr_slide", "dyld_slide",
                     0x269F74B0E5C813ADULL) ||
               match("mach_vm_region", "mach_vm_region",
                     0x8F03C6A15D72E4B9ULL) ||
               match("mach_port_deallocate", "mach_port_deallocate",
                     0x3A7D91C40E6B58F2ULL);
    }

    return false;
}

void emitPosixStubIntegrityChecks(IRBuilder<> &B, Module &M, const Triple &TT,
                                  GlobalVariable *State,
                                  ir::IRRandom &rng) {
    const bool x86 =
        TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64;
    if (!x86 || (!TT.isOSLinux() && !TT.isOSDarwin()))
        return;

    std::uint32_t site = 1;
    for (Function &F : M) {
        StringRef label;
        std::uint64_t salt = 0;
        if (!posixStubIntegrityTarget(TT, F, label, salt))
            continue;

        std::string base = (Twine("morok.antihook.stub.") + label).str();
        Value *hit = emitX86ImportStubPattern(B, M, &F, base);
        foldEnforcedFlag(
            B, State, hit,
            rng.next() ^ salt ^ (0xA24BAED4963EE407ULL * site++),
            base);
    }
}

Function *antiDebugProbe(Module &M, GlobalVariable *State, ir::IRRandom &rng,
                         const Triple &TT, bool AllowSelfTrace,
                         bool DistributionSigned) {
    if (Function *existing = M.getFunction("morok.antidbg.probe"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *voidTy = Type::getVoidTy(ctx);
    auto *fn = Function::Create(FunctionType::get(voidTy, {i64}, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.probe", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *tag = fn->getArg(0);
    tag->setName("tag");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    foldState(B, State, tag, 0x9A86B1D32F4C79E5ULL, "morok.antidbg.probe.tag");

    if (TT.isOSLinux()) {
        auto *i32 = Type::getInt32Ty(ctx);
        Function *statusFn = linuxStatusTracerCheck(M, rng, TT);
        Function *statFn = linuxStatField4Check(M, rng, TT);
        Value *status = B.CreateCall(statusFn);
        Value *stat4 = B.CreateCall(statFn);
        Value *statusTraced =
            B.CreateICmpNE(status, ConstantInt::get(i32, 0),
                           "morok.antidbg.probe.status.traced");
        foldLinuxTracerPidVerdict(B, State, statusTraced, AllowSelfTrace,
                                  0x3FEC9A6245A7DB13ULL,
                                  0x71D64A930CB25FE8ULL,
                                  "morok.antidbg.probe.status");
        foldState(B, State, stat4, 0x84379D6FA21708C9ULL,
                  "morok.antidbg.probe.stat4");
        Value *statCoherence = packedI32Flag(
            B, stat4, 1u << 8, "morok.antidbg.probe.stat.coherence.bits",
            "morok.antidbg.probe.stat.coherence.anomaly");
        foldEnforcedFlag(B, State, statCoherence, 0x3B6D81E5F0C24A97ULL,
                         "morok.antidbg.probe.stat.coherence");
        emitLinuxSigtrapCoherence(B, M, State, statusTraced, tag, rng, TT,
                                  "morok.antidbg.probe.sigtrap");
        if (Function *faultCf =
                linuxIntentionalFaultFlowProbe(M, State, rng, TT))
            B.CreateCall(faultCf->getFunctionType(), faultCf, {tag});
    } else if (TT.isOSDarwin()) {
        emitDarwinSysctlCheck(B, M, State, TT);
        DarwinCsopsSignals csops =
            emitDarwinCsopsCheck(B, M, State, TT, DistributionSigned);
        emitDarwinTaskForPidSelfProbe(B, M, State, TT, csops);
    } else if (TT.isOSWindows()) {
        if (Function *dr = windowsHardwareBreakpointProbe(M, State, rng, TT))
            B.CreateCall(dr->getFunctionType(), dr, {tag});
    } else {
        auto *i32 = Type::getInt32Ty(ctx);
        Value *rc = emitPtrace(B, M, 0);
        foldFlag(B, State, B.CreateICmpSLT(rc, ConstantInt::getSigned(i32, 0)),
                 0xA082B7C1D94E530FULL, "morok.antidbg.probe.ptrace");
    }

    B.CreateRetVoid();
    return fn;
}

bool isProbeInsertionPoint(Instruction &I) {
    if (isa<PHINode>(I) || isa<AllocaInst>(I) || I.isTerminator() ||
        I.isEHPad())
        return false;
    return true;
}

void insertGuardedProbeCall(Module &M, Instruction &I, Function *Probe,
                            std::uint64_t Tag, std::uint8_t ArmedByte,
                            std::uint32_t SiteId) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);

    auto *gate = new GlobalVariable(
        M, i8, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i8, 0), "morok.antidbg.site");
    gate->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);

    Function *parent = I.getFunction();
    BasicBlock *headBB = I.getParent();
    BasicBlock *contBB =
        headBB->splitBasicBlock(I.getIterator(), "morok.antidbg.site.cont");
    headBB->getTerminator()->eraseFromParent();
    auto *callBB =
        BasicBlock::Create(ctx, "morok.antidbg.site.call", parent, contBB);

    IRBuilder<> HB(headBB);
    auto *seen = HB.CreateLoad(i8, gate, "morok.antidbg.site.seen");
    seen->setVolatile(true);
    Value *shouldRun = HB.CreateICmpEQ(seen, ConstantInt::get(i8, 0));
    HB.CreateCondBr(shouldRun, callBB, contBB);

    IRBuilder<> CB(callBB);
    auto *armed = CB.CreateStore(ConstantInt::get(i8, ArmedByte), gate);
    armed->setVolatile(true);
    CB.CreateCall(Probe->getFunctionType(), Probe,
                  {ConstantInt::get(CB.getInt64Ty(),
                                    Tag ^ (0x9E3779B97F4A7C15ULL * SiteId))});
    CB.CreateBr(contBB);
}

bool insertAntiDebugCallsiteProbes(Module &M, Function *Probe,
                                   ir::IRRandom &rng) {
    constexpr std::uint32_t kMaxProbeSites = 32;
    constexpr std::uint32_t kFunctionChance = 100;

    std::vector<Instruction *> sites;
    sites.reserve(kMaxProbeSites);
    for (Function &F : M) {
        if (sites.size() >= kMaxProbeSites)
            break;
        if (F.isDeclaration() || F.hasAvailableExternallyLinkage() ||
            F.getName().starts_with("morok."))
            continue;
        if (directlyRecursive(F))
            continue;
        if (!rng.chance(kFunctionChance))
            continue;

        SmallPtrSet<BasicBlock *, 32> LoopBlocks = naturalLoopBlocks(F);
        std::vector<Instruction *> candidates;
        candidates.reserve(8);
        for (BasicBlock &BB : F) {
            if (BB.isEHPad() || BB.isLandingPad())
                continue;
            if (LoopBlocks.contains(&BB))
                continue;
            for (Instruction &I : BB)
                if (isProbeInsertionPoint(I))
                    candidates.push_back(&I);
        }
        if (candidates.empty())
            continue;
        sites.push_back(candidates[rng.range(
            static_cast<std::uint32_t>(candidates.size()))]);
    }

    std::uint32_t siteId = 1;
    for (Instruction *I : sites)
        insertGuardedProbeCall(
            M, *I, Probe, rng.next(),
            static_cast<std::uint8_t>((rng.next() | 1) & 0xffu), siteId++);
    return !sites.empty();
}

bool isTaggedVoidProbe(Function *Probe) {
    return Probe && Probe->arg_size() == 1 &&
           Probe->getReturnType()->isVoidTy() &&
           Probe->getFunctionType()->getParamType(0)->isIntegerTy(64);
}

void emitTaggedProbeCall(IRBuilder<> &B, Module &M, Function *Probe, Value *Tag,
                         const Twine &Prefix, ir::IRRandom &rng,
                         std::uint32_t SiteId) {
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(M.getContext());
    const std::uint64_t key = rng.next() | 1ULL;
    const std::uint64_t salt = rng.next() | 1ULL;
    std::string prefix = Prefix.str();

    auto *keyGv = new GlobalVariable(
        M, ip, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(ip, key), prefix + ".key");
    keyGv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    keyGv->setAlignment(Align(ip->getBitWidth() / 8));
    keyGv->setDSOLocal(true);

    Value *loadedKey = B.CreateLoad(ip, keyGv, prefix + ".key.load");
    cast<LoadInst>(loadedKey)->setVolatile(true);
    Value *targetIp = B.CreatePtrToInt(Probe, ip, prefix + ".target.ip");
    Value *encoded = nullptr;
    Value *decoded = nullptr;
    switch ((rng.next() ^ SiteId) & 3ULL) {
    case 0:
        encoded = B.CreateXor(targetIp, ConstantInt::get(ip, key),
                              prefix + ".target.encoded");
        decoded = B.CreateXor(encoded, loadedKey, prefix + ".target.decoded");
        break;
    case 1:
        encoded = B.CreateXor(B.CreateAdd(targetIp, ConstantInt::get(ip, key)),
                              ConstantInt::get(ip, salt),
                              prefix + ".target.encoded");
        decoded = B.CreateSub(B.CreateXor(encoded, ConstantInt::get(ip, salt)),
                              loadedKey, prefix + ".target.decoded");
        break;
    case 2:
        encoded = B.CreateSub(B.CreateXor(targetIp, ConstantInt::get(ip, salt)),
                              ConstantInt::get(ip, key),
                              prefix + ".target.encoded");
        decoded = B.CreateXor(B.CreateAdd(encoded, loadedKey),
                              ConstantInt::get(ip, salt),
                              prefix + ".target.decoded");
        break;
    default:
        encoded = B.CreateXor(B.CreateAdd(targetIp, ConstantInt::get(ip, salt)),
                              ConstantInt::get(ip, key),
                              prefix + ".target.encoded");
        decoded = B.CreateSub(B.CreateXor(encoded, loadedKey),
                              ConstantInt::get(ip, salt),
                              prefix + ".target.decoded");
        break;
    }
    Value *callee = B.CreateIntToPtr(decoded, ptr, prefix + ".callee");
    B.CreateCall(Probe->getFunctionType(), callee, {Tag});
}

Function *makeStaggeredRecheckCtor(Module &M, Function *Probe, StringRef Stem,
                                   unsigned Index, unsigned Priority,
                                   ir::IRRandom &rng) {
    std::string name = (Twine("morok.") + Stem + ".recheck.ctor." +
                        Twine(Index))
                           .str();
    Function *ctor = makeCtorShell(M, name.c_str());
    ctor->addFnAttr(Attribute::NoInline);
    ctor->setDSOLocal(true);

    IRBuilder<> B(&ctor->getEntryBlock());
    auto *tag = ConstantInt::get(
        Type::getInt64Ty(M.getContext()),
        rng.next() ^ (0xB5E3F1D97A4C620FULL * (Priority + Index + 1ULL)));
    emitTaggedProbeCall(B, M, Probe, tag,
                        Twine("morok.") + Stem + ".recheck.ctor." +
                            Twine(Index),
                        rng, Index + 1);
    B.CreateRetVoid();
    return ctor;
}

bool appendStaggeredRecheckCtors(Module &M, Function *Probe, StringRef Stem,
                                 ir::IRRandom &rng) {
    if (!isTaggedVoidProbe(Probe))
        return false;
    constexpr unsigned kPriorities[] = {101, 1000, 65534};
    for (unsigned i = 0; i < 3; ++i)
        appendToGlobalCtors(
            M, makeStaggeredRecheckCtor(M, Probe, Stem, i, kPriorities[i], rng),
            static_cast<int>(kPriorities[i]));
    return true;
}

void insertStagedRecheckSite(Module &M, Instruction &I, Function *Probe,
                             StringRef Stem, std::uint64_t Tag,
                             std::uint8_t ArmedByte, std::uint32_t SiteId,
                             ir::IRRandom &rng) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);

    auto *gate = new GlobalVariable(
        M, i8, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i8, 0), (Twine("morok.") + Stem + ".recheck.site").str());
    gate->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);

    Function *parent = I.getFunction();
    BasicBlock *headBB = I.getParent();
    BasicBlock *contBB = headBB->splitBasicBlock(
        I.getIterator(), (Twine("morok.") + Stem + ".recheck.site.cont").str());
    headBB->getTerminator()->eraseFromParent();
    auto *callBB =
        BasicBlock::Create(ctx, (Twine("morok.") + Stem + ".recheck.site.call").str(),
                           parent, contBB);

    IRBuilder<> HB(headBB);
    auto *seen = HB.CreateLoad(i8, gate,
                               (Twine("morok.") + Stem + ".recheck.site.seen")
                                   .str());
    seen->setVolatile(true);
    Value *shouldRun = HB.CreateICmpEQ(
        seen, ConstantInt::get(i8, 0),
        (Twine("morok.") + Stem + ".recheck.site.armed").str());
    HB.CreateCondBr(shouldRun, callBB, contBB);

    IRBuilder<> CB(callBB);
    auto *armed = CB.CreateStore(ConstantInt::get(i8, ArmedByte), gate);
    armed->setVolatile(true);
    emitTaggedProbeCall(
        CB, M, Probe,
        ConstantInt::get(CB.getInt64Ty(),
                         Tag ^ (0x9E3779B97F4A7C15ULL * SiteId)),
        Twine("morok.") + Stem + ".recheck.mid." + Twine(SiteId), rng,
        SiteId);
    CB.CreateBr(contBB);
}

bool insertStagedRecheckSites(Module &M, Function *Probe, StringRef Stem,
                              ir::IRRandom &rng) {
    if (!isTaggedVoidProbe(Probe))
        return false;
    constexpr std::uint32_t kMaxProbeSites = 4;

    std::vector<Instruction *> sites;
    sites.reserve(kMaxProbeSites);
    for (Function &F : M) {
        if (sites.size() >= kMaxProbeSites)
            break;
        if (F.isDeclaration() || F.hasAvailableExternallyLinkage() ||
            F.getName().starts_with("morok.") || directlyRecursive(F))
            continue;

        SmallPtrSet<BasicBlock *, 32> loopBlocks = naturalLoopBlocks(F);
        std::vector<Instruction *> candidates;
        candidates.reserve(8);
        for (BasicBlock &BB : F) {
            if (BB.isEHPad() || BB.isLandingPad() || loopBlocks.contains(&BB))
                continue;
            for (Instruction &Inst : BB)
                if (isProbeInsertionPoint(Inst))
                    candidates.push_back(&Inst);
        }
        if (!candidates.empty())
            sites.push_back(candidates[rng.range(
                static_cast<std::uint32_t>(candidates.size()))]);
    }

    std::uint32_t siteId = 1;
    for (Instruction *I : sites)
        insertStagedRecheckSite(
            M, *I, Probe, Stem, rng.next(),
            static_cast<std::uint8_t>((rng.next() | 1) & 0xffu), siteId++,
            rng);
    return !sites.empty();
}

Function *antiHookRecheckProbe(Module &M, GlobalVariable *State,
                               Function *GotRecheckProbe,
                               Function *StackCheck, ir::IRRandom &rng) {
    if (Function *existing = M.getFunction("morok.antihook.recheck.phase"))
        return existing;
    if (!State && !GotRecheckProbe && !StackCheck)
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), {i64},
                                                  false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.recheck.phase", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *tag = fn->getArg(0);
    tag->setName("tag");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    if (State)
        foldState(B, State, tag, 0xA34E6D17C829F5B1ULL,
                  "morok.antihook.recheck.tag");
    if (GotRecheckProbe)
        emitTaggedProbeCall(B, M, GotRecheckProbe,
                            B.CreateXor(tag, ConstantInt::get(i64, rng.next()),
                                        "morok.antihook.recheck.got.tag"),
                            "morok.antihook.recheck.got", rng, 1);
    if (StackCheck && State) {
        FunctionCallee returnAddress = returnAddressDecl(M);
        Value *ra = B.CreateCall(returnAddress, {ConstantInt::get(i32, 0)},
                                 "morok.antihook.recheck.ra");
        Value *addr =
            B.CreatePtrToInt(ra, intPtrTy(M), "morok.antihook.recheck.addr");
        Value *ok =
            B.CreateCall(StackCheck->getFunctionType(), StackCheck, {addr},
                         "morok.antihook.recheck.stack.module");
        Value *changed = B.CreateICmpEQ(ok, ConstantInt::get(i32, 0),
                                        "morok.antihook.recheck.stack.changed");
        foldEnforcedFlag(B, State, changed, 0x8E43A7D61C9250BFULL,
                         "morok.antihook.recheck.stack.changed");
    }
    B.CreateRetVoid();
    return fn;
}

Function *antiDebugRecheckProbe(Module &M, GlobalVariable *State,
                                Function *FullProbe, ir::IRRandom &rng,
                                const Triple &TT, bool DistributionSigned) {
    if (!TT.isOSDarwin())
        return FullProbe;
    if (Function *existing = M.getFunction("morok.antidbg.recheck.phase"))
        return existing;
    if (!State)
        return FullProbe;

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), {i64},
                                                  false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.recheck.phase", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);
    Argument *tag = fn->getArg(0);
    tag->setName("tag");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    foldState(B, State, tag, rng.next() ^ 0x63B79D2EA514C80FULL,
              "morok.antidbg.recheck.tag");
    emitDarwinSysctlCheck(B, M, State, TT);
    emitDarwinCsopsCheck(B, M, State, TT, DistributionSigned);
    B.CreateRetVoid();
    return fn;
}

GlobalVariable *timingOracleState(Module &M, ir::IRRandom &rng) {
    if (auto *existing =
            M.getGlobalVariable("morok.timing.state", /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, rng.next()), "morok.timing.state");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *schedulerStepOracleState(Module &M, ir::IRRandom &rng) {
    if (auto *existing =
            M.getGlobalVariable("morok.step.state", /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, rng.next()), "morok.step.state");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

bool isX86Target(const Triple &TT) {
    return TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64;
}

// Combine the EDX:EAX timestamp pair returned by an rdtsc/rdtscp asm into i64.
Value *combineTscPair(IRBuilder<> &B, Value *pair) {
    auto *i64 = Type::getInt64Ty(B.getContext());
    Value *lo = B.CreateExtractValue(pair, {0}, "morok.timing.tsc.lo");
    Value *hi = B.CreateExtractValue(pair, {1}, "morok.timing.tsc.hi");
    return B.CreateOr(
        B.CreateZExt(lo, i64),
        B.CreateShl(B.CreateZExt(hi, i64), ConstantInt::get(i64, 32)),
        "morok.timing.tsc");
}

// A noinline helper that reads the timestamp counter, gating RDTSCP behind a
// CPUID(0x80000001).EDX[27] feature test.  RDTSCP raises #UD on x86 CPUs (old
// or deliberately masked virtual machines) that lack it, which would crash the
// protected binary on the first timing probe; when the feature bit is clear we
// fall back to plain RDTSC (baseline since the original Pentium, never #UD).
// Both paths bracket the read with lfence for serialization and consume only
// the EDX:EAX timestamp.  The branch caches nothing per call, but the CPUID
// cost is constant across the paired start/end reads so it cancels in the delta.
Function *getOrCreateTscHelper(Module &M) {
    if (Function *Existing = M.getFunction("morok.timing.tsc.read"))
        return Existing;
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *pairTy = StructType::get(ctx, {i32, i32});
    auto *asmTy = FunctionType::get(pairTy, false);

    auto *Fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::InternalLinkage,
                                "morok.timing.tsc.read", &M);
    Fn->addFnAttr(Attribute::NoInline);
    Fn->setDSOLocal(true);

    BasicBlock *Entry = BasicBlock::Create(ctx, "entry", Fn);
    BasicBlock *PBB = BasicBlock::Create(ctx, "rdtscp", Fn);
    BasicBlock *RBB = BasicBlock::Create(ctx, "rdtsc", Fn);
    BasicBlock *Merge = BasicBlock::Create(ctx, "merge", Fn);

    IRBuilder<> EB(Entry);
    Value *cpuid = emitCpuid(EB, M, ConstantInt::get(i32, 0x80000001u),
                             ConstantInt::get(i32, 0));
    Value *edx = cpuidReg(EB, cpuid, 3, "morok.timing.feat.edx");
    Value *bit = EB.CreateAnd(EB.CreateLShr(edx, ConstantInt::get(i32, 27)),
                              ConstantInt::get(i32, 1), "morok.timing.feat.rdtscp");
    EB.CreateCondBr(EB.CreateICmpNE(bit, ConstantInt::get(i32, 0)), PBB, RBB);

    IRBuilder<> PB(PBB);
    InlineAsm *rdtscp =
        InlineAsm::get(asmTy, "lfence\nrdtscp\nlfence",
                       "={eax},={edx},~{ecx},~{dirflag},~{fpsr},~{flags}",
                       /*hasSideEffects=*/true);
    Value *tscP =
        combineTscPair(PB, PB.CreateCall(asmTy, rdtscp, {}, "morok.timing.rdtscp"));
    PB.CreateBr(Merge);

    IRBuilder<> RB(RBB);
    InlineAsm *rdtsc =
        InlineAsm::get(asmTy, "lfence\nrdtsc\nlfence",
                       "={eax},={edx},~{dirflag},~{fpsr},~{flags}",
                       /*hasSideEffects=*/true);
    Value *tscR =
        combineTscPair(RB, RB.CreateCall(asmTy, rdtsc, {}, "morok.timing.rdtsc"));
    RB.CreateBr(Merge);

    IRBuilder<> MB(Merge);
    PHINode *Phi = MB.CreatePHI(i64, 2, "morok.timing.tsc.val");
    Phi->addIncoming(tscP, PBB);
    Phi->addIncoming(tscR, RBB);
    MB.CreateRet(Phi);
    return Fn;
}

Value *emitRdtscp(IRBuilder<> &B, Module &M) {
    Function *H = getOrCreateTscHelper(M);
    return B.CreateCall(H->getFunctionType(), H, {}, "morok.timing.tsc");
}

Value *emitClockGettimeNanos(IRBuilder<> &B, Module &M, std::int32_t ClockId,
                             const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *tsTy = StructType::get(ctx, {i64, i64});
    auto *ts = B.CreateAlloca(tsTy, nullptr, Name + ".ts");

    Value *secPtr = B.CreateStructGEP(tsTy, ts, 0, Name + ".sec.ptr");
    Value *nsecPtr = B.CreateStructGEP(tsTy, ts, 1, Name + ".nsec.ptr");
    B.CreateStore(ConstantInt::get(i64, 0), secPtr);
    B.CreateStore(ConstantInt::get(i64, 0), nsecPtr);

    FunctionCallee clockGettime = M.getOrInsertFunction(
        "clock_gettime",
        FunctionType::get(i32, {i32, PointerType::getUnqual(ctx)}, false));
    Value *rc = B.CreateCall(
        clockGettime, {ConstantInt::getSigned(i32, ClockId), ts}, Name + ".rc");
    Value *sec = B.CreateLoad(i64, secPtr, Name + ".sec");
    Value *nsec = B.CreateLoad(i64, nsecPtr, Name + ".nsec");
    Value *nanos =
        B.CreateAdd(B.CreateMul(sec, ConstantInt::get(i64, 1000000000ULL)),
                    nsec, Name + ".nanos");
    return B.CreateSelect(B.CreateICmpEQ(rc, ConstantInt::get(i32, 0)), nanos,
                          ConstantInt::get(i64, 0), Name + ".ok");
}

Value *emitMachAbsoluteTime(IRBuilder<> &B, Module &M, const Twine &Name) {
    FunctionCallee mach = M.getOrInsertFunction(
        "mach_absolute_time", FunctionType::get(B.getInt64Ty(), false));
    return B.CreateCall(mach, {}, Name);
}

Value *emitWindowsQpc(IRBuilder<> &B, Module &M, const Twine &Name) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *slot = B.CreateAlloca(i64, nullptr, Name + ".slot");
    B.CreateStore(ConstantInt::get(i64, 0), slot);
    FunctionCallee qpc = M.getOrInsertFunction(
        "QueryPerformanceCounter",
        FunctionType::get(i32, {PointerType::getUnqual(M.getContext())},
                          false));
    Value *rc = B.CreateCall(qpc, {slot}, Name + ".rc");
    Value *ticks = B.CreateLoad(i64, slot, Name + ".ticks");
    return B.CreateSelect(B.CreateICmpNE(rc, ConstantInt::get(i32, 0)), ticks,
                          ConstantInt::get(i64, 0), Name + ".ok");
}

Value *emitTimingPrimaryClock(IRBuilder<> &B, Module &M, const Triple &TT,
                              const Twine &Name) {
    if (isX86Target(TT))
        return emitRdtscp(B, M);
    if (TT.isOSDarwin())
        return emitMachAbsoluteTime(B, M, Name + ".mach");
    if (TT.isOSWindows())
        return emitWindowsQpc(B, M, Name + ".qpc");
    return emitClockGettimeNanos(B, M, 1, Name + ".mono");
}

Value *emitTimingSecondaryClock(IRBuilder<> &B, Module &M, const Triple &TT,
                                const Twine &Name) {
    if (TT.isOSDarwin() && isX86Target(TT))
        return emitMachAbsoluteTime(B, M, Name + ".mach");
    if (TT.isOSWindows())
        return emitWindowsQpc(B, M, Name + ".qpc");
    return emitClockGettimeNanos(B, M, 4, Name + ".raw");
}

void emitShortTimingSpan(IRBuilder<> &B, AllocaInst *Acc, std::uint64_t Salt) {
    auto *i64 = B.getInt64Ty();
    for (unsigned i = 0; i < 16; ++i) {
        auto *load = B.CreateLoad(i64, Acc, "morok.timing.span.load");
        load->setVolatile(true);
        Value *mixed = B.CreateXor(
            B.CreateAdd(load, ConstantInt::get(
                                  i64, Salt + 0xD6E8FEB86659FD93ULL * (i + 1))),
            B.CreateLShr(load, ConstantInt::get(i64, (i % 17) + 1)));
        mixed = B.CreateMul(
            mixed,
            ConstantInt::get(i64, (Salt | 1ULL) ^ (0x9E3779B97F4A7C15ULL * i)));
        auto *store = B.CreateStore(mixed, Acc);
        store->setVolatile(true);
    }
}

Function *timingOracleProbe(Module &M, GlobalVariable *State, ir::IRRandom &rng,
                            const Triple &TT) {
    if (Function *existing = M.getFunction("morok.timing.oracle"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), false),
                                GlobalValue::PrivateLinkage,
                                "morok.timing.oracle", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *acc = B.CreateAlloca(i64, nullptr, "morok.timing.span.acc");
    B.CreateStore(ConstantInt::get(i64, rng.next()), acc)->setVolatile(true);

    Value *badSamples = ConstantInt::get(i32, 0);
    Value *coherentSamples = ConstantInt::get(i32, 0);
    Value *divergentSamples = ConstantInt::get(i32, 0);
    Value *mix = ConstantInt::get(i64, rng.next());
    const bool hasCycleClock = isX86Target(TT);
    const std::uint64_t primaryThreshold =
        hasCycleClock ? 20000000ULL : 10000000ULL;
    constexpr std::uint64_t secondaryThreshold = 10000000ULL;

    for (unsigned sample = 0; sample < 5; ++sample) {
        Value *primaryStart =
            emitTimingPrimaryClock(B, M, TT, "morok.timing.primary.start");
        Value *secondaryStart =
            emitTimingSecondaryClock(B, M, TT, "morok.timing.secondary.start");
        emitShortTimingSpan(B, acc, rng.next());
        Value *primaryEnd =
            emitTimingPrimaryClock(B, M, TT, "morok.timing.primary.end");
        Value *secondaryEnd =
            emitTimingSecondaryClock(B, M, TT, "morok.timing.secondary.end");

        Value *primaryDelta =
            B.CreateSub(primaryEnd, primaryStart, "morok.timing.primary.delta");
        Value *secondaryDelta = B.CreateSub(secondaryEnd, secondaryStart,
                                            "morok.timing.secondary.delta");
        Value *primarySlow = B.CreateICmpUGT(
            primaryDelta, ConstantInt::get(i64, primaryThreshold),
            "morok.timing.primary.slow");
        Value *secondarySlow = B.CreateICmpUGT(
            secondaryDelta, ConstantInt::get(i64, secondaryThreshold),
            "morok.timing.secondary.slow");
        Value *sampleSlow =
            B.CreateOr(primarySlow, secondarySlow, "morok.timing.sample.slow");
        Value *sampleCoherent = B.CreateAnd(primarySlow, secondarySlow,
                                            "morok.timing.sample.coherent");
        Value *sampleDiverged = B.CreateXor(primarySlow, secondarySlow,
                                            "morok.timing.sample.diverged");
        badSamples = B.CreateAdd(badSamples, B.CreateZExt(sampleSlow, i32),
                                 "morok.timing.bad.n");
        coherentSamples =
            B.CreateAdd(coherentSamples, B.CreateZExt(sampleCoherent, i32),
                        "morok.timing.coherent.n");
        divergentSamples =
            B.CreateAdd(divergentSamples, B.CreateZExt(sampleDiverged, i32),
                        "morok.timing.divergent.n");
        mix = B.CreateXor(
            B.CreateAdd(mix,
                        B.CreateMul(primaryDelta,
                                    ConstantInt::get(i64, rng.next() | 1ULL))),
            B.CreateMul(secondaryDelta,
                        ConstantInt::get(i64, rng.next() | 1ULL)),
            "morok.timing.mix");
    }

    if (hasCycleClock) {
        SmallVector<Value *, 8> nakedSamples;
        SmallVector<Value *, 8> bracketSamples;
        nakedSamples.reserve(7);
        bracketSamples.reserve(7);
        for (unsigned sample = 0; sample < 7; ++sample) {
            Value *nakedStart = emitRdtscp(B, M);
            Value *nakedEnd = emitRdtscp(B, M);
            Value *nakedDelta = B.CreateSub(nakedEnd, nakedStart,
                                            "morok.timing.cpuid.naked.delta");
            nakedSamples.push_back(nakedDelta);

            Value *bracketStart = emitRdtscp(B, M);
            Value *leaf = emitCpuid(B, M, ConstantInt::get(i32, 0),
                                    ConstantInt::get(i32, sample & 1u));
            Value *leafMix = cpuidReg(B, leaf, sample % 4,
                                      "morok.timing.cpuid.leaf.mix");
            Value *bracketEnd = emitRdtscp(B, M);
            Value *bracketDelta =
                B.CreateSub(bracketEnd, bracketStart,
                            "morok.timing.cpuid.bracket.delta");
            bracketSamples.push_back(bracketDelta);
            mix = B.CreateXor(
                B.CreateAdd(mix,
                            B.CreateMul(bracketDelta,
                                        ConstantInt::get(i64, rng.next() | 1ULL))),
                B.CreateXor(nakedDelta, B.CreateZExt(leafMix, i64),
                            "morok.timing.cpuid.sample.mix"),
                "morok.timing.cpuid.mix");
        }

        auto sortSamples = [&](SmallVector<Value *, 8> samples,
                               const Twine &prefix) {
            for (unsigned i = 0; i < samples.size(); ++i) {
                for (unsigned j = i + 1; j < samples.size(); ++j) {
                    Value *swap = B.CreateICmpUGT(samples[i], samples[j],
                                                 prefix + ".gt");
                    Value *lo =
                        B.CreateSelect(swap, samples[j], samples[i],
                                       prefix + ".lo");
                    Value *hi =
                        B.CreateSelect(swap, samples[i], samples[j],
                                       prefix + ".hi");
                    samples[i] = lo;
                    samples[j] = hi;
                }
            }
            return samples;
        };

        SmallVector<Value *, 8> sortedNaked =
            sortSamples(nakedSamples, "morok.timing.cpuid.naked.sort");
        SmallVector<Value *, 8> sortedBracket =
            sortSamples(bracketSamples, "morok.timing.cpuid.bracket.sort");
        Value *nakedMin = sortedNaked[0];
        Value *bracketMin = sortedBracket[0];
        Value *nakedMedian = sortedNaked[3];
        Value *bracketMedian = sortedBracket[3];
        nakedMin->setName("morok.timing.cpuid.naked.min");
        bracketMin->setName("morok.timing.cpuid.bracket.min");
        nakedMedian->setName("morok.timing.cpuid.naked.median");
        bracketMedian->setName("morok.timing.cpuid.bracket.median");
        Value *nakedBase = B.CreateSelect(
            B.CreateICmpEQ(nakedMedian, ConstantInt::get(i64, 0),
                           "morok.timing.cpuid.naked.zero"),
            ConstantInt::get(i64, 1), nakedMedian,
            "morok.timing.cpuid.naked.baseline");
        Value *nakedMinBase = B.CreateSelect(
            B.CreateICmpEQ(nakedMin, ConstantInt::get(i64, 0),
                           "morok.timing.cpuid.naked.min.zero"),
            ConstantInt::get(i64, 1), nakedMin,
            "morok.timing.cpuid.naked.min.baseline");
        Value *medianRatio = B.CreateICmpUGT(
            bracketMedian,
            B.CreateMul(nakedBase, ConstantInt::get(i64, 16),
                        "morok.timing.cpuid.naked.scaled"),
            "morok.timing.cpuid.ratio");
        Value *minRatio = B.CreateICmpUGT(
            bracketMin,
            B.CreateMul(nakedMinBase, ConstantInt::get(i64, 8),
                        "morok.timing.cpuid.naked.min.scaled"),
            "morok.timing.cpuid.min.ratio");
        Value *exitRatio =
            B.CreateAnd(medianRatio, minRatio,
                        "morok.timing.cpuid.exit.ratio");
        foldState(B, State, nakedMedian, 0x8B17E0D56C3A49F2ULL,
                  "morok.timing.cpuid.naked.median");
        foldState(B, State, bracketMedian, 0x51C49E7A236D80BFULL,
                  "morok.timing.cpuid.bracket.median");
        foldState(B, State, nakedMin, 0xC72E5A913B04D68FULL,
                  "morok.timing.cpuid.naked.min");
        foldState(B, State, bracketMin, 0x2A93D8C45F6071BEULL,
                  "morok.timing.cpuid.bracket.min");
        foldFlag(B, State, medianRatio, 0xD4B2E8175C90A36FULL,
                 "morok.timing.cpuid.ratio");
        foldFlag(B, State, minRatio, 0x6A51C3F08E27B94DULL,
                 "morok.timing.cpuid.min.ratio");
        foldFlag(B, State, exitRatio, 0xB90F2E6C41A57D38ULL,
                 "morok.timing.cpuid.exit.ratio");
    }

    foldState(B, State, mix, 0x275C92B4EF31D68BULL, "morok.timing.mix");
    foldState(B, State, badSamples, 0x7A6D2E10B94F35C1ULL,
              "morok.timing.bad.samples");
    foldState(B, State, coherentSamples, 0x13BA2A5F4E1C6D07ULL,
              "morok.timing.coherent.samples");
    foldState(B, State, divergentSamples, 0xC541A9E72318BE6FULL,
              "morok.timing.divergent.samples");
    Value *badDistribution = B.CreateICmpUGE(
        badSamples, ConstantInt::get(i32, 3),
        "morok.timing.bad.distribution");
    Value *coherentDistribution = B.CreateICmpUGE(
        coherentSamples, ConstantInt::get(i32, 3),
        "morok.timing.coherent.distribution");
    Value *divergentDistribution = B.CreateICmpUGE(
        divergentSamples, ConstantInt::get(i32, 2),
        "morok.timing.divergent.distribution");
    const bool scoreSoftTiming = hasCycleClock;
    // Score only the stronger two-clock coherent signal. A coherent stall is a
    // subset of the broader bad-sample distribution, so scoring both would let
    // one timing oracle satisfy the weighted seal threshold by itself.
    foldFlag(B, State, badDistribution, 0xA331D8B47E1C5905ULL,
             "morok.timing.bad.distribution");
    foldFlag(B, State, coherentDistribution, 0x4B1D6A80C2E39F17ULL,
             "morok.timing.coherent.distribution", scoreSoftTiming);
    foldFlag(B, State, divergentDistribution, 0x5E74B29D13C8A60BULL,
             "morok.timing.divergent.distribution");
    B.CreateRetVoid();
    return fn;
}

struct SchedulerCounterSample {
    Value *value;
    Value *ready;
};

struct LinuxPerfParanoidSample {
    Value *value;
    Value *ready;
    Value *high;
    Value *strict;
};

bool linuxSchedulerStepSyscalls(const Triple &TT, std::uint32_t &PerfOpen,
                                std::uint32_t &Read, std::uint32_t &Close,
                                std::uint32_t &Ioctl) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        PerfOpen = 298;
        Read = 0;
        Close = 3;
        Ioctl = 16;
        return true;
    case Triple::aarch64:
        PerfOpen = 241;
        Read = 63;
        Close = 57;
        Ioctl = 29;
        return true;
    case Triple::x86:
        PerfOpen = 336;
        Read = 3;
        Close = 6;
        Ioctl = 54;
        return true;
    default:
        return false;
    }
}

struct LinuxPmuMmapSyscalls {
    std::uint32_t mmap = 0;
    std::uint32_t munmap = 0;
};

bool linuxPmuMmapSyscalls(const Triple &TT, LinuxPmuMmapSyscalls &Out) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        Out.mmap = 9;
        Out.munmap = 11;
        return true;
    case Triple::aarch64:
        Out.mmap = 222;
        Out.munmap = 215;
        return true;
    case Triple::x86:
        Out.mmap = 192; // mmap2(addr, len, prot, flags, fd, pgoffset)
        Out.munmap = 91;
        return true;
    default:
        return false;
    }
}

Value *gepI8Offset(IRBuilder<> &B, Module &M, Value *Base,
                   std::uint64_t Offset, const Twine &Name) {
    return B.CreateGEP(Type::getInt8Ty(M.getContext()), Base,
                       ConstantInt::get(intPtrTy(M), Offset), Name);
}

StoreInst *storeI32AtOffset(IRBuilder<> &B, Module &M, Value *Base,
                            std::uint64_t Offset, std::uint32_t V,
                            const Twine &Name) {
    auto *st = B.CreateStore(
        ConstantInt::get(Type::getInt32Ty(M.getContext()), V),
        gepI8Offset(B, M, Base, Offset, Name + ".ptr"));
    st->setAlignment(Align(4));
    return st;
}

StoreInst *storeI64AtOffset(IRBuilder<> &B, Module &M, Value *Base,
                            std::uint64_t Offset, std::uint64_t V,
                            const Twine &Name) {
    auto *st = B.CreateStore(
        ConstantInt::get(Type::getInt64Ty(M.getContext()), V),
        gepI8Offset(B, M, Base, Offset, Name + ".ptr"));
    st->setAlignment(Align(8));
    return st;
}

LoadInst *loadI64AtOffset(IRBuilder<> &B, Module &M, Value *Base,
                          std::uint64_t Offset, const Twine &Name) {
    auto *li = B.CreateLoad(Type::getInt64Ty(M.getContext()),
                            gepI8Offset(B, M, Base, Offset, Name + ".ptr"),
                            Name);
    li->setVolatile(true);
    li->setAlignment(Align(8));
    return li;
}

LoadInst *loadI32AtOffset(IRBuilder<> &B, Module &M, Value *Base,
                          std::uint64_t Offset, const Twine &Name) {
    auto *li = B.CreateLoad(Type::getInt32Ty(M.getContext()),
                            gepI8Offset(B, M, Base, Offset, Name + ".ptr"),
                            Name);
    li->setVolatile(true);
    li->setAlignment(Align(4));
    return li;
}

LoadInst *loadI16AtOffset(IRBuilder<> &B, Module &M, Value *Base,
                          std::uint64_t Offset, const Twine &Name) {
    auto *li = B.CreateLoad(Type::getInt16Ty(M.getContext()),
                            gepI8Offset(B, M, Base, Offset, Name + ".ptr"),
                            Name);
    li->setVolatile(true);
    li->setAlignment(Align(2));
    return li;
}

Value *emitLinuxPerfOpen(IRBuilder<> &B, Module &M, const Triple &TT,
                         std::uint32_t Type, std::uint64_t Config,
                         std::uint64_t AttrFlags, std::uint64_t OpenFlags,
                         const Twine &Name, Value *&Ready) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *attrTy = ArrayType::get(i8, 128);
    auto *attr = B.CreateAlloca(attrTy, nullptr, Name + ".attr");
    B.CreateMemSet(attr, ConstantInt::get(i8, 0), ConstantInt::get(ip, 128),
                   MaybeAlign(1));
    // struct perf_event_attr: type, size, config, then packed flag bits.
    storeI32AtOffset(B, M, attr, 0, Type, Name + ".type");
    storeI32AtOffset(B, M, attr, 4, 128, Name + ".size");
    storeI64AtOffset(B, M, attr, 8, Config, Name + ".config");
    if (AttrFlags != 0)
        storeI64AtOffset(B, M, attr, 40, AttrFlags, Name + ".flags");

    std::uint32_t perfNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t ioctlNr = 0;
    if (!linuxSchedulerStepSyscalls(TT, perfNr, readNr, closeNr, ioctlNr)) {
        Ready = ConstantInt::getFalse(ctx);
        return ConstantInt::getSigned(ip, -1);
    }

    // pid=0,cpu=-1 scopes the event to the current thread on any CPU.
    Value *fd = emitLinuxSyscall(
        B, M, TT, perfNr,
        {attr, ConstantInt::getSigned(ip, 0), ConstantInt::getSigned(ip, -1),
         ConstantInt::getSigned(ip, -1), ConstantInt::get(ip, OpenFlags)});
    fd->setName(Name + ".fd");
    Ready = B.CreateICmpSGE(fd, ConstantInt::getSigned(ip, 0), Name + ".ready");
    return fd;
}

Value *emitLinuxPerfContextSwitchOpen(IRBuilder<> &B, Module &M,
                                      const Triple &TT, Value *&Ready) {
    return emitLinuxPerfOpen(B, M, TT, /*Type=*/1, /*Config=*/3,
                             /*AttrFlags=*/0, /*OpenFlags=*/0,
                             "morok.step.perf.open", Ready);
}

Value *linuxPerfOpenErrnoMatches(IRBuilder<> &B, Module &M, const Triple &TT,
                                 Value *Rc,
                                 std::initializer_list<int> Errnos,
                                 const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    Value *match = ConstantInt::getFalse(ctx);
    if (useDirectLinuxSyscalls(M, TT)) {
        for (int err : Errnos) {
            Value *eq = B.CreateICmpEQ(Rc, ConstantInt::getSigned(ip, -err),
                                       Name + ".raw");
            match = B.CreateOr(match, eq, Name + ".raw.any");
        }
        return B.CreateOr(match, ConstantInt::getFalse(ctx), Name);
    }

    Value *failed = B.CreateICmpEQ(Rc, ConstantInt::getSigned(ip, -1),
                                   Name + ".failed");
    Value *errnoPtr = B.CreateCall(linuxErrnoLocationDecl(M), {}, Name + ".ptr");
    auto *errnoVal = B.CreateLoad(i32, errnoPtr, Name + ".value");
    errnoVal->setVolatile(true);
    for (int err : Errnos) {
        Value *eq = B.CreateICmpEQ(errnoVal, ConstantInt::getSigned(i32, err),
                                   Name + ".errno");
        match = B.CreateOr(match, eq, Name + ".errno.any");
    }
    return B.CreateAnd(failed, match, Name);
}

Value *emitLinuxPerfMetadataMmap(IRBuilder<> &B, Module &M, const Triple &TT,
                                 Value *Fd, Value *&Ready,
                                 const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *ip = intPtrTy(M);
    LinuxPmuMmapSyscalls sys;
    if (!linuxPmuMmapSyscalls(TT, sys)) {
        Ready = ConstantInt::getFalse(ctx);
        return ConstantInt::getSigned(ip, -1);
    }

    constexpr std::uint64_t kPerfMmapPage = 4096;
    constexpr std::uint64_t kProtRead = 1;
    constexpr std::uint64_t kMapShared = 1;
    Value *addr = emitLinuxSyscall(
        B, M, TT, sys.mmap,
        {ConstantInt::get(ip, 0), ConstantInt::get(ip, kPerfMmapPage),
         ConstantInt::get(ip, kProtRead), ConstantInt::get(ip, kMapShared), Fd,
         ConstantInt::get(ip, 0)});
    addr->setName(Name);
    Ready = B.CreateAnd(
        B.CreateICmpNE(addr, ConstantInt::get(ip, 0), Name + ".nonzero"),
        B.CreateICmpULT(addr, ConstantInt::getSigned(ip, -4095),
                        Name + ".not.err"),
        Name + ".ready");
    return addr;
}

void emitLinuxPerfMetadataMunmap(IRBuilder<> &B, Module &M, const Triple &TT,
                                 Value *Addr) {
    LinuxPmuMmapSyscalls sys;
    if (!linuxPmuMmapSyscalls(TT, sys))
        return;
    auto *ip = intPtrTy(M);
    Value *rc =
        emitLinuxSyscall(B, M, TT, sys.munmap,
                         {Addr, ConstantInt::get(ip, 4096)});
    rc->setName("morok.step.pmu.munmap");
}

SchedulerCounterSample emitLinuxPerfRead(IRBuilder<> &B, Module &M,
                                         const Triple &TT, Value *Fd,
                                         const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t perfNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t ioctlNr = 0;
    if (!linuxSchedulerStepSyscalls(TT, perfNr, readNr, closeNr, ioctlNr))
        return {ConstantInt::get(i64, 0), ConstantInt::getFalse(ctx)};

    auto *slot = B.CreateAlloca(i64, nullptr, Name + ".slot");
    B.CreateStore(ConstantInt::get(i64, 0), slot)->setVolatile(true);
    Value *rc = emitLinuxSyscall(B, M, TT, readNr,
                                 {Fd, slot, ConstantInt::get(ip, 8)});
    auto *value = B.CreateLoad(i64, slot, Name + ".value");
    value->setVolatile(true);
    value->setAlignment(Align(8));
    Value *ready =
        B.CreateICmpEQ(rc, ConstantInt::get(ip, 8), Name + ".ready");
    return {value, ready};
}

void emitLinuxPerfClose(IRBuilder<> &B, Module &M, const Triple &TT,
                        Value *Fd) {
    std::uint32_t perfNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t ioctlNr = 0;
    if (!linuxSchedulerStepSyscalls(TT, perfNr, readNr, closeNr, ioctlNr))
        return;
    emitLinuxSyscall(B, M, TT, closeNr, {Fd});
}

Value *emitLinuxPerfIoctl(IRBuilder<> &B, Module &M, const Triple &TT,
                          Value *Fd, std::uint64_t Cmd, const Twine &Name) {
    auto *ip = intPtrTy(M);
    std::uint32_t perfNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t ioctlNr = 0;
    if (!linuxSchedulerStepSyscalls(TT, perfNr, readNr, closeNr, ioctlNr))
        return ConstantInt::getSigned(ip, -38);
    Value *rc = emitLinuxSyscall(
        B, M, TT, ioctlNr,
        {Fd, ConstantInt::get(ip, Cmd), ConstantInt::get(ip, 0)});
    rc->setName(Name);
    return rc;
}

LinuxPerfParanoidSample emitLinuxPerfParanoidRead(IRBuilder<> &B, Module &M,
                                                  ir::IRRandom &rng,
                                                  const Triple &TT,
                                                  const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ip = intPtrTy(M);
    constexpr std::uint64_t kBufBytes = 16;

    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr)) {
        Value *zero = ConstantInt::get(i32, 0);
        Value *notReady = ConstantInt::getFalse(ctx);
        return {zero, notReady, notReady, notReady};
    }

    auto *bufTy = ArrayType::get(i8, kBufBytes);
    AllocaInst *buf = B.CreateAlloca(bufTy, nullptr, Name + ".buf");
    B.CreateMemSet(buf, ConstantInt::get(i8, 0),
                   ConstantInt::get(ip, kBufBytes), MaybeAlign(1));
    Value *path =
        ir::emitCloakedSymbol(B, M, "/proc/sys/kernel/perf_event_paranoid", rng);
    Value *fd = emitLinuxSyscall(B, M, TT, openatNr,
                                 {ConstantInt::getSigned(ip, -100), path,
                                  ConstantInt::get(ip, 0),
                                  ConstantInt::get(ip, 0)});
    fd->setName(Name + ".fd");
    Value *bufPtr = B.CreateInBoundsGEP(
        bufTy, buf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        Name + ".ptr");
    Value *nread = emitLinuxSyscall(
        B, M, TT, readNr, {fd, bufPtr, ConstantInt::get(ip, kBufBytes - 1)});
    nread->setName(Name + ".read.n");
    emitLinuxSyscall(B, M, TT, closeNr, {fd});

    Value *c0 = loadAt(B, M, i8, buf, 0ULL, Name + ".c0");
    Value *c1 = loadAt(B, M, i8, buf, 1ULL, Name + ".c1");
    Value *c2 = loadAt(B, M, i8, buf, 2ULL, Name + ".c2");
    Value *minus =
        B.CreateICmpEQ(c0, ConstantInt::get(i8, '-'), Name + ".minus");
    Value *first = B.CreateSelect(minus, c1, c0, Name + ".first");
    Value *second = B.CreateSelect(minus, c2, c1, Name + ".second");

    auto digit = [&](Value *Ch, const Twine &Prefix) {
        Value *ge0 = B.CreateICmpUGE(Ch, ConstantInt::get(i8, '0'),
                                     Prefix + ".ge0");
        Value *le9 = B.CreateICmpULE(Ch, ConstantInt::get(i8, '9'),
                                     Prefix + ".le9");
        return B.CreateAnd(ge0, le9, Prefix + ".digit");
    };
    Value *firstDigit = digit(first, Name + ".first");
    Value *secondDigit = digit(second, Name + ".second");
    Value *firstVal = B.CreateZExt(
        B.CreateSub(first, ConstantInt::get(i8, '0'), Name + ".first.raw"),
        i32, Name + ".first.val");
    Value *secondVal = B.CreateZExt(
        B.CreateSub(second, ConstantInt::get(i8, '0'), Name + ".second.raw"),
        i32, Name + ".second.val");
    Value *twoDigit =
        B.CreateAdd(B.CreateMul(firstVal, ConstantInt::get(i32, 10),
                                Name + ".tens"),
                    secondVal, Name + ".two");
    Value *parsed = B.CreateSelect(secondDigit, twoDigit, firstVal,
                                   Name + ".parsed");
    Value *readOk = B.CreateICmpSGT(nread, ConstantInt::get(ip, 0),
                                    Name + ".read.ok");
    Value *ready = B.CreateAnd(readOk, firstDigit, Name + ".ready");
    Value *nonNegative = B.CreateNot(minus, Name + ".nonnegative");
    Value *value = B.CreateSelect(B.CreateAnd(ready, nonNegative),
                                  parsed, ConstantInt::get(i32, 0),
                                  Name + ".value");
    Value *high = B.CreateAnd(
        ready,
        B.CreateAnd(nonNegative,
                    B.CreateICmpUGE(value, ConstantInt::get(i32, 2),
                                    Name + ".ge2"),
                    Name + ".policy"),
        Name + ".high");
    Value *strict = B.CreateAnd(
        ready,
        B.CreateAnd(nonNegative,
                    B.CreateICmpUGE(value, ConstantInt::get(i32, 3),
                                    Name + ".ge3"),
                    Name + ".strict.policy"),
        Name + ".strict");
    return {value, ready, high, strict};
}

SchedulerCounterSample emitLinuxRusageSwitches(IRBuilder<> &B, Module &M,
                                               const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *bufTy = ArrayType::get(i8, 144);
    auto *buf = B.CreateAlloca(bufTy, nullptr, Name + ".rusage");
    B.CreateMemSet(buf, ConstantInt::get(i8, 0), ConstantInt::get(ip, 144),
                   MaybeAlign(1));
    FunctionCallee getrusage = M.getOrInsertFunction(
        "getrusage", FunctionType::get(i32, {i32, PointerType::getUnqual(ctx)},
                                        false));
    Value *rc = B.CreateCall(getrusage, {ConstantInt::get(i32, 1), buf},
                             Name + ".rc");
    Value *nv = loadI64AtOffset(B, M, buf, 128, Name + ".nvcsw");
    Value *ni = loadI64AtOffset(B, M, buf, 136, Name + ".nivcsw");
    Value *total = B.CreateAdd(nv, ni, Name + ".total.raw");
    Value *ready =
        B.CreateICmpEQ(rc, ConstantInt::get(i32, 0), Name + ".ready");
    return {B.CreateSelect(ready, total, ConstantInt::get(i64, 0),
                           Name + ".total"),
            ready};
}

struct LinuxClockSample {
    Value *nanos;
    Value *ready;
};

bool linuxClockGettimeSyscall(const Triple &TT, std::uint32_t &ClockGettime) {
    switch (TT.getArch()) {
    case Triple::x86_64:
        ClockGettime = 228;
        return true;
    case Triple::aarch64:
        ClockGettime = 113;
        return true;
    default:
        return false;
    }
}

LinuxClockSample emitLinuxRawClockGettimeNanos(IRBuilder<> &B, Module &M,
                                               const Triple &TT,
                                               std::int32_t ClockId,
                                               const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    std::uint32_t clockNr = 0;
    if (!linuxClockGettimeSyscall(TT, clockNr))
        return {ConstantInt::get(i64, 0), ConstantInt::getFalse(ctx)};

    auto *tsTy = StructType::get(ctx, {i64, i64});
    auto *ts = B.CreateAlloca(tsTy, nullptr, Name + ".ts");
    Value *secPtr = B.CreateStructGEP(tsTy, ts, 0, Name + ".sec.ptr");
    Value *nsecPtr = B.CreateStructGEP(tsTy, ts, 1, Name + ".nsec.ptr");
    B.CreateStore(ConstantInt::get(i64, 0), secPtr)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), nsecPtr)->setVolatile(true);

    Value *rc = emitLinuxSyscall(B, M, TT, clockNr,
                                 {ConstantInt::getSigned(i32, ClockId), ts});
    rc->setName(Name + ".rc");
    auto *sec = B.CreateLoad(i64, secPtr, Name + ".sec");
    auto *nsec = B.CreateLoad(i64, nsecPtr, Name + ".nsec");
    sec->setVolatile(true);
    nsec->setVolatile(true);
    Value *ready = B.CreateICmpEQ(rc, ConstantInt::get(ip, 0), Name + ".ready");
    Value *nanos =
        B.CreateAdd(B.CreateMul(sec, ConstantInt::get(i64, 1000000000ULL),
                                Name + ".sec.ns"),
                    nsec, Name + ".nanos.raw");
    return {B.CreateSelect(ready, nanos, ConstantInt::get(i64, 0),
                           Name + ".nanos"),
            ready};
}

Function *linuxParentAncestryProbe(Module &M, GlobalVariable *State,
                                   ir::IRRandom &rng, const Triple &TT) {
    if (!TT.isOSLinux())
        return nullptr;
    if (Function *existing = M.getFunction("morok.antidbg.parent"))
        return existing;

    std::uint32_t ptraceNr = 0;
    std::uint32_t prctlNr = 0;
    std::uint32_t openatNr = 0;
    std::uint32_t readNr = 0;
    std::uint32_t closeNr = 0;
    std::uint32_t getppidNr = 0;
    std::uint32_t readlinkatNr = 0;
    if (!linuxCoreSyscalls(TT, ptraceNr, prctlNr, openatNr, readNr, closeNr) ||
        !linuxDbiParentSyscalls(TT, getppidNr, readlinkatNr))
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);

    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.parent", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *loopBB = BasicBlock::Create(ctx, "morok.antidbg.parent.loop", fn);
    auto *bodyBB = BasicBlock::Create(ctx, "morok.antidbg.parent.body", fn);
    auto *doneBB = BasicBlock::Create(ctx, "morok.antidbg.parent.done", fn);

    IRBuilder<> B(entry);
    auto *pathTy = ArrayType::get(i8, 96);
    auto *exeTy = ArrayType::get(i8, 256);
    auto *commPath =
        B.CreateAlloca(pathTy, nullptr, "morok.antidbg.parent.comm.path");
    auto *exePath =
        B.CreateAlloca(pathTy, nullptr, "morok.antidbg.parent.exe.path");
    auto *statusPath =
        B.CreateAlloca(pathTy, nullptr, "morok.antidbg.parent.status.path");
    auto *exeBuf = B.CreateAlloca(exeTy, nullptr,
                                  "morok.antidbg.parent.exe.buf");
    auto *hits = B.CreateAlloca(i64, nullptr, "morok.antidbg.parent.hits");
    auto *pidSlot = B.CreateAlloca(ip, nullptr, "morok.antidbg.parent.pid.slot");
    auto *depthSlot =
        B.CreateAlloca(i32, nullptr, "morok.antidbg.parent.depth.slot");
    B.CreateStore(ConstantInt::get(i64, 0), hits)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i32, 0), depthSlot)->setVolatile(true);
    Value *initialPid = emitLinuxSyscall(B, M, TT, getppidNr, {});
    initialPid->setName("morok.antidbg.parent.getppid");
    B.CreateStore(initialPid, pidSlot)->setVolatile(true);
    B.CreateBr(loopBB);

    IRBuilder<> LB(loopBB);
    auto *depth = LB.CreateLoad(i32, depthSlot, "morok.antidbg.parent.depth");
    depth->setVolatile(true);
    auto *pid = LB.CreateLoad(ip, pidSlot, "morok.antidbg.parent.pid");
    pid->setVolatile(true);
    Value *depthOk = LB.CreateICmpULT(depth, ConstantInt::get(i32, 5),
                                      "morok.antidbg.parent.depth.ok");
    Value *pidLive = LB.CreateICmpSGT(pid, ConstantInt::get(ip, 1),
                                      "morok.antidbg.parent.pid.live");
    LB.CreateCondBr(LB.CreateAnd(depthOk, pidLive,
                                 "morok.antidbg.parent.keep"),
                    bodyBB, doneBB);

    IRBuilder<> BB(bodyBB);
    FunctionCallee snprintfFn = M.getOrInsertFunction(
        "snprintf", FunctionType::get(i32, {ptr, ip, ptr}, true));
    Value *commPathPtr = BB.CreateInBoundsGEP(
        pathTy, commPath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.parent.comm.path.ptr");
    BB.CreateCall(snprintfFn,
                  {commPathPtr, ConstantInt::get(ip, 96),
                   ir::emitCloakedSymbol(BB, M, "/proc/%ld/comm", rng), pid},
                  "morok.antidbg.parent.comm.path.n");
    ReadFileIR comm = emitReadPathValue(
        BB, M, fn, commPathPtr, 64, TT, "morok.antidbg.parent.comm");
    auto *afterCommBB =
        BasicBlock::Create(ctx, "morok.antidbg.parent.after.comm", fn);

    IRBuilder<> CMB(comm.ret0);
    CMB.CreateBr(afterCommBB);

    IRBuilder<> CB(comm.afterRead);
    Value *commHit = bufferHasLinuxParentToolComm(
        CB, M, comm.buf, comm.n, 64, "morok.antidbg.parent.comm.tool");
    incrementDiff(CB, hits, commHit, "morok.antidbg.parent.comm.hit");
    CB.CreateBr(afterCommBB);

    IRBuilder<> EB(afterCommBB);
    Value *exePathPtr = EB.CreateInBoundsGEP(
        pathTy, exePath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.parent.exe.path.ptr");
    Value *exeBufPtr = EB.CreateInBoundsGEP(
        exeTy, exeBuf, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.parent.exe.ptr");
    EB.CreateCall(snprintfFn,
                  {exePathPtr, ConstantInt::get(ip, 96),
                   ir::emitCloakedSymbol(EB, M, "/proc/%ld/exe", rng), pid},
                  "morok.antidbg.parent.exe.path.n");
    Value *exeN = emitLinuxSyscall(
        EB, M, TT, readlinkatNr,
        {ConstantInt::getSigned(ip, -100), exePathPtr, exeBufPtr,
         ConstantInt::get(ip, 255)});
    exeN->setName("morok.antidbg.parent.exe.readlink");
    Value *exeHit = bufferHasLinuxParentToolBasename(
        EB, M, exeBuf, exeN, 256, "morok.antidbg.parent.exe.tool");
    incrementDiff(EB, hits, exeHit, "morok.antidbg.parent.exe.hit");

    Value *statusPathPtr = EB.CreateInBoundsGEP(
        pathTy, statusPath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
        "morok.antidbg.parent.status.path.ptr");
    EB.CreateCall(
        snprintfFn,
        {statusPathPtr, ConstantInt::get(ip, 96),
         ir::emitCloakedSymbol(EB, M, "/proc/%ld/status", rng), pid},
        "morok.antidbg.parent.status.path.n");
    ReadFileIR status = emitReadPathValue(
        EB, M, fn, statusPathPtr, 768, TT, "morok.antidbg.parent.status");
    auto *afterStatusBB =
        BasicBlock::Create(ctx, "morok.antidbg.parent.after.status", fn);

    IRBuilder<> SMB(status.ret0);
    SMB.CreateStore(ConstantInt::get(ip, 1), pidSlot)->setVolatile(true);
    SMB.CreateBr(afterStatusBB);

    IRBuilder<> SB(status.afterRead);
    StatusDecimalFieldIR nextPid = parseProcStatusDecimalField(
        SB, M, status.buf, status.n, {0x50, 0x50, 0x69, 0x64, 0x3a}, 768,
        "morok.antidbg.parent.status.ppid");
    Value *nextPidLive =
        SB.CreateAnd(nextPid.found,
                     SB.CreateICmpUGT(nextPid.value, ConstantInt::get(i64, 1),
                                      "morok.antidbg.parent.status.ppid.live"),
                     "morok.antidbg.parent.status.ppid.ready");
    Value *nextPidWord = SB.CreateSelect(
        nextPidLive, nextPid.value, ConstantInt::get(i64, 1),
        "morok.antidbg.parent.status.ppid.next");
    SB.CreateStore(SB.CreateZExtOrTrunc(nextPidWord, ip), pidSlot)
        ->setVolatile(true);
    SB.CreateBr(afterStatusBB);

    IRBuilder<> ASB(afterStatusBB);
    auto *oldDepth =
        ASB.CreateLoad(i32, depthSlot, "morok.antidbg.parent.depth.old");
    oldDepth->setVolatile(true);
    ASB.CreateStore(ASB.CreateAdd(oldDepth, ConstantInt::get(i32, 1),
                                  "morok.antidbg.parent.depth.next"),
                    depthSlot)
        ->setVolatile(true);
    ASB.CreateBr(loopBB);

    IRBuilder<> DB(doneBB);
    auto *hitCount =
        DB.CreateLoad(i64, hits, "morok.antidbg.parent.ancestry.hits");
    hitCount->setVolatile(true);
    Value *hitAny =
        DB.CreateICmpNE(hitCount, ConstantInt::get(i64, 0),
                        "morok.antidbg.parent.ancestry.hit");
    foldState(DB, State, hitCount, 0xF0D4B9A6218C73E5ULL,
              "morok.antidbg.parent.ancestry.count");
    foldFlag(DB, State, hitAny, 0x6C58A1E9D4B7302FULL,
             "morok.antidbg.parent.ancestry");
    DB.CreateRetVoid();
    return fn;
}

Function *linuxRrReplayProbe(Module &M, GlobalVariable *State,
                             ir::IRRandom &rng, const Triple &TT) {
    if (!TT.isOSLinux() || intPtrTy(M)->getBitWidth() != 64)
        return nullptr;
    if (Function *existing = M.getFunction("morok.antidbg.rr"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i8 = Type::getInt8Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);

    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), false),
                                GlobalValue::PrivateLinkage,
                                "morok.antidbg.rr", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);

    LinuxPerfParanoidSample paranoid = emitLinuxPerfParanoidRead(
        B, M, rng, TT, "morok.antidbg.rr.perf.paranoid");
    Value *hwReady = nullptr;
    Value *hwFd = emitLinuxPerfOpen(
        B, M, TT, /*Type=*/0, /*Config=*/1,
        /*AttrFlags=*/(1ULL << 5) | (1ULL << 6), /*OpenFlags=*/8,
        "morok.antidbg.rr.perf.hw.open", hwReady);
    Value *hwDenied = B.CreateOr(
        B.CreateICmpEQ(hwFd, ConstantInt::getSigned(ip, -1),
                       "morok.antidbg.rr.perf.hw.eperm"),
        B.CreateICmpEQ(hwFd, ConstantInt::getSigned(ip, -13),
                       "morok.antidbg.rr.perf.hw.eacces"),
        "morok.antidbg.rr.perf.hw.denied");
    emitLinuxPerfClose(B, M, TT, hwFd);
    Value *paranoidLt3 =
        B.CreateAnd(paranoid.ready,
                    B.CreateNot(paranoid.strict,
                                "morok.antidbg.rr.perf.paranoid.strict.not"),
                    "morok.antidbg.rr.perf.paranoid.lt3");
    Value *hwDeniedLowPolicy =
        B.CreateAnd(hwDenied, paranoidLt3,
                    "morok.antidbg.rr.perf.hw.denied.lowpolicy");
    foldState(B, State, paranoid.value, 0xF62D8C4E5A0193B7ULL,
              "morok.antidbg.rr.perf.paranoid.value");
    foldFlag(B, State, paranoid.strict, 0xC38A701DBE64925FULL,
             "morok.antidbg.rr.perf.paranoid.strict");
    foldFlag(B, State, hwDeniedLowPolicy, 0x4AB73D5E90C2186FULL,
             "morok.antidbg.rr.perf.hw.denied.lowpolicy");

    auto *clockAcc = B.CreateAlloca(i64, nullptr, "morok.antidbg.rr.clock.acc");
    B.CreateStore(ConstantInt::get(i64, rng.next()), clockAcc)->setVolatile(true);
    Value *clockHits = ConstantInt::get(i32, 0);
    Value *clockReadySamples = ConstantInt::get(i32, 0);
    Value *clockMix = ConstantInt::get(i64, rng.next());
    for (unsigned sample = 0; sample < 3; ++sample) {
        LinuxClockSample before = emitLinuxRawClockGettimeNanos(
            B, M, TT, 4, "morok.antidbg.rr.clock.raw.before");
        emitShortTimingSpan(B, clockAcc,
                            rng.next() ^ (0x91E10DA5C79E7B1DULL * (sample + 1)));
        LinuxClockSample after = emitLinuxRawClockGettimeNanos(
            B, M, TT, 4, "morok.antidbg.rr.clock.raw.after");
        Value *ordered = B.CreateICmpUGE(after.nanos, before.nanos,
                                         "morok.antidbg.rr.clock.raw.ordered");
        Value *sampleReady =
            B.CreateAnd(B.CreateAnd(before.ready, after.ready),
                        ordered, "morok.antidbg.rr.clock.raw.ready");
        Value *delta = B.CreateSelect(
            sampleReady, B.CreateSub(after.nanos, before.nanos),
            ConstantInt::get(i64, 0), "morok.antidbg.rr.clock.raw.delta");
        Value *zero =
            B.CreateAnd(sampleReady,
                        B.CreateICmpEQ(delta, ConstantInt::get(i64, 0),
                                       "morok.antidbg.rr.clock.raw.zero"),
                        "morok.antidbg.rr.clock.zero");
        Value *quantum = B.CreateAnd(
            sampleReady,
            B.CreateAnd(B.CreateICmpUGT(delta, ConstantInt::get(i64, 0),
                                        "morok.antidbg.rr.clock.raw.nonzero"),
                        B.CreateICmpEQ(
                            B.CreateURem(delta, ConstantInt::get(i64, 10000),
                                         "morok.antidbg.rr.clock.raw.mod"),
                            ConstantInt::get(i64, 0),
                            "morok.antidbg.rr.clock.raw.quantum"),
                        "morok.antidbg.rr.clock.raw.quantized"),
            "morok.antidbg.rr.clock.quantized");
        Value *sampleHit =
            B.CreateOr(zero, quantum, "morok.antidbg.rr.clock.sample.hit");
        clockHits = B.CreateAdd(clockHits, B.CreateZExt(sampleHit, i32),
                                "morok.antidbg.rr.clock.hits.n");
        clockReadySamples =
            B.CreateAdd(clockReadySamples, B.CreateZExt(sampleReady, i32),
                        "morok.antidbg.rr.clock.ready.n");
        clockMix = B.CreateXor(
            B.CreateAdd(clockMix,
                        B.CreateMul(delta,
                                    ConstantInt::get(i64, rng.next() | 1ULL))),
            B.CreateZExt(sampleHit, i64), "morok.antidbg.rr.clock.mix.step");
    }
    Value *clockSuspicious =
        B.CreateICmpUGE(clockHits, ConstantInt::get(i32, 2),
                        "morok.antidbg.rr.clock.suspicious");
    foldState(B, State, clockMix, 0x2F0C9A81D5E746B3ULL,
              "morok.antidbg.rr.clock.mix");
    foldState(B, State, clockReadySamples, 0x8B1462D9C0E53F7AULL,
              "morok.antidbg.rr.clock.ready");
    foldState(B, State, clockHits, 0x571AC8E3D06F92B5ULL,
              "morok.antidbg.rr.clock.hits");
    foldFlag(B, State, clockSuspicious, 0xD4F3A9126E58C07BULL,
             "morok.antidbg.rr.clock.suspicious");

    std::uint32_t getppidNr = 0;
    std::uint32_t readlinkatNr = 0;
    if (linuxDbiParentSyscalls(TT, getppidNr, readlinkatNr)) {
        Value *ppid = emitLinuxSyscall(B, M, TT, getppidNr, {});
        ppid->setName("morok.antidbg.rr.parent.pid");
        auto *pathTy = ArrayType::get(i8, 96);
        AllocaInst *commPath =
            B.CreateAlloca(pathTy, nullptr, "morok.antidbg.rr.parent.comm.path");
        Value *commPathPtr = B.CreateInBoundsGEP(
            pathTy, commPath, {ConstantInt::get(ip, 0), ConstantInt::get(ip, 0)},
            "morok.antidbg.rr.parent.comm.path.ptr");
        FunctionCallee snprintfFn = M.getOrInsertFunction(
            "snprintf", FunctionType::get(i32, {ptr, ip, ptr}, true));
        B.CreateCall(snprintfFn,
                     {commPathPtr, ConstantInt::get(ip, 96),
                      ir::emitCloakedSymbol(B, M, "/proc/%ld/comm", rng), ppid},
                     "morok.antidbg.rr.parent.comm.path.n");
        ReadFileIR comm = emitReadPathValue(
            B, M, fn, commPathPtr, 64, TT, "morok.antidbg.rr.parent.comm");
        auto *afterCommBB =
            BasicBlock::Create(ctx, "morok.antidbg.rr.after.parent.comm", fn);

        IRBuilder<> MissB(comm.ret0);
        MissB.CreateBr(afterCommBB);

        IRBuilder<> CB(comm.afterRead);
        Value *commRr = bufferHasLiteral(
            CB, M, comm.buf, comm.n, {0x72, 0x72, 0x0a}, 64,
            "morok.antidbg.rr.parent.comm.rr");
        Value *commDetach = bufferHasLiteral(
            CB, M, comm.buf, comm.n,
            {0x72, 0x72, 0x2d, 0x64, 0x65, 0x74, 0x61, 0x63, 0x68}, 64,
            "morok.antidbg.rr.parent.comm.detach");
        Value *commHit =
            CB.CreateOr(commRr, commDetach, "morok.antidbg.rr.parent.comm.hit");
        foldFlag(CB, State, commHit, 0xAE63D18C47F2059BULL,
                 "morok.antidbg.rr.parent.comm");
        CB.CreateBr(afterCommBB);

        B.SetInsertPoint(afterCommBB);
    }

    B.CreateRetVoid();
    return fn;
}

SchedulerCounterSample emitDarwinThreadCpuNanos(IRBuilder<> &B, Module &M,
                                                const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *infoTy = ArrayType::get(i32, 10);
    auto *info = B.CreateAlloca(infoTy, nullptr, Name + ".basic");
    auto *count = B.CreateAlloca(i32, nullptr, Name + ".count");
    B.CreateMemSet(info, ConstantInt::get(Type::getInt8Ty(ctx), 0),
                   ConstantInt::get(ip, 40), MaybeAlign(4));
    B.CreateStore(ConstantInt::get(i32, 10), count);
    FunctionCallee self = M.getOrInsertFunction(
        "mach_thread_self", FunctionType::get(i32, false));
    FunctionCallee threadInfo = M.getOrInsertFunction(
        "thread_info",
        FunctionType::get(i32, {i32, i32, PointerType::getUnqual(ctx),
                                PointerType::getUnqual(ctx)},
                          false));
    Value *thread = B.CreateCall(self, {}, Name + ".thread");
    Value *rc = B.CreateCall(threadInfo,
                             {thread, ConstantInt::get(i32, 3), info, count},
                             Name + ".rc");
    auto loadWord = [&](unsigned idx, const Twine &WordName) -> Value * {
        auto *ptr = B.CreateGEP(i32, info, ConstantInt::get(ip, idx),
                                WordName + ".ptr");
        auto *li = B.CreateLoad(i32, ptr, WordName);
        li->setVolatile(true);
        li->setAlignment(Align(4));
        return B.CreateSExt(li, i64, WordName + ".i64");
    };
    Value *userSec = loadWord(0, Name + ".user.sec");
    Value *userUsec = loadWord(1, Name + ".user.usec");
    Value *sysSec = loadWord(2, Name + ".sys.sec");
    Value *sysUsec = loadWord(3, Name + ".sys.usec");
    Value *secs = B.CreateAdd(userSec, sysSec, Name + ".secs");
    Value *usecs = B.CreateAdd(userUsec, sysUsec, Name + ".usecs");
    Value *nanos = B.CreateAdd(
        B.CreateMul(secs, ConstantInt::get(i64, 1000000000ULL)),
        B.CreateMul(usecs, ConstantInt::get(i64, 1000ULL)), Name + ".nanos");
    Value *ready =
        B.CreateICmpEQ(rc, ConstantInt::get(i32, 0), Name + ".ready");
    return {B.CreateSelect(ready, nanos, ConstantInt::get(i64, 0),
                           Name + ".nanos.safe"),
            ready};
}

SchedulerCounterSample emitWindowsThreadTime100ns(IRBuilder<> &B, Module &M,
                                                  const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    FunctionCallee getCurrentThread =
        M.getOrInsertFunction("GetCurrentThread", FunctionType::get(ptr, false));
    FunctionCallee getThreadTimes = M.getOrInsertFunction(
        "GetThreadTimes", FunctionType::get(i32, {ptr, ptr, ptr, ptr, ptr},
                                             false));
    Value *thread = B.CreateCall(getCurrentThread, {}, Name + ".thread");
    auto *creation = B.CreateAlloca(i64, nullptr, Name + ".creation");
    auto *exit = B.CreateAlloca(i64, nullptr, Name + ".exit");
    auto *kernel = B.CreateAlloca(i64, nullptr, Name + ".kernel");
    auto *user = B.CreateAlloca(i64, nullptr, Name + ".user");
    B.CreateStore(ConstantInt::get(i64, 0), creation)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), exit)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), kernel)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, 0), user)->setVolatile(true);
    Value *rc = B.CreateCall(getThreadTimes,
                             {thread, creation, exit, kernel, user},
                             Name + ".rc");
    auto *k = B.CreateLoad(i64, kernel, Name + ".kernel.100ns");
    auto *u = B.CreateLoad(i64, user, Name + ".user.100ns");
    k->setVolatile(true);
    u->setVolatile(true);
    k->setAlignment(Align(4));
    u->setAlignment(Align(4));
    Value *total = B.CreateAdd(k, u, Name + ".total.100ns");
    Value *ready =
        B.CreateICmpNE(rc, ConstantInt::get(i32, 0), Name + ".ready");
    return {B.CreateSelect(ready, total, ConstantInt::get(i64, 0),
                           Name + ".total.safe"),
            ready};
}

SchedulerCounterSample emitWindowsThreadCycles(IRBuilder<> &B, Module &M,
                                               const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    FunctionCallee getCurrentThread =
        M.getOrInsertFunction("GetCurrentThread", FunctionType::get(ptr, false));
    FunctionCallee queryCycles = M.getOrInsertFunction(
        "QueryThreadCycleTime", FunctionType::get(i32, {ptr, ptr}, false));
    auto *slot = B.CreateAlloca(i64, nullptr, Name + ".slot");
    B.CreateStore(ConstantInt::get(i64, 0), slot)->setVolatile(true);
    Value *thread = B.CreateCall(getCurrentThread, {}, Name + ".thread");
    Value *rc = B.CreateCall(queryCycles, {thread, slot}, Name + ".rc");
    auto *cycles = B.CreateLoad(i64, slot, Name + ".cycles");
    cycles->setVolatile(true);
    cycles->setAlignment(Align(8));
    Value *ready =
        B.CreateICmpNE(rc, ConstantInt::get(i32, 0), Name + ".ready");
    return {B.CreateSelect(ready, cycles, ConstantInt::get(i64, 0),
                           Name + ".cycles.safe"),
            ready};
}

Value *emitWindowsQpcFrequency(IRBuilder<> &B, Module &M, const Twine &Name) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *slot = B.CreateAlloca(i64, nullptr, Name + ".slot");
    B.CreateStore(ConstantInt::get(i64, 0), slot);
    FunctionCallee qpf = M.getOrInsertFunction(
        "QueryPerformanceFrequency",
        FunctionType::get(i32, {PointerType::getUnqual(M.getContext())},
                          false));
    Value *rc = B.CreateCall(qpf, {slot}, Name + ".rc");
    Value *freq = B.CreateLoad(i64, slot, Name + ".freq");
    return B.CreateSelect(B.CreateICmpNE(rc, ConstantInt::get(i32, 0)), freq,
                          ConstantInt::get(i64, 0), Name + ".ok");
}

void emitSchedulerStepSpan(IRBuilder<> &B, AllocaInst *Acc,
                           ir::IRRandom &rng) {
    for (unsigned part = 0; part < 8; ++part)
        emitShortTimingSpan(B, Acc,
                            rng.next() ^ (0xD1B54A32D192ED03ULL * (part + 1)));
}

bool schedulerStepTargetSupported(Module &M, const Triple &TT) {
    const unsigned wordBits = intPtrTy(M)->getBitWidth();
    if (TT.isOSLinux()) {
        if (TT.getArch() == Triple::x86)
            return wordBits == 32;
        return wordBits == 64;
    }
    return wordBits == 64 && (TT.isOSDarwin() || TT.isOSWindows());
}

Value *emitLinuxUserPmuCounterRead(IRBuilder<> &B, Module &M, const Triple &TT,
                                   Value *Index, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    if (TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64) {
        auto *pairTy = StructType::get(ctx, {i32, i32});
        auto *asmTy = FunctionType::get(pairTy, {i32}, false);
        InlineAsm *rdpmc =
            InlineAsm::get(asmTy, "rdpmc",
                           "={eax},={edx},{ecx},~{dirflag},~{fpsr},~{flags}",
                           /*hasSideEffects=*/true);
        Value *pair = B.CreateCall(
            asmTy, rdpmc, {B.CreateZExtOrTrunc(Index, i32)}, Name + ".rdpmc");
        Value *lo = B.CreateExtractValue(pair, {0}, Name + ".lo");
        Value *hi = B.CreateExtractValue(pair, {1}, Name + ".hi");
        return B.CreateOr(B.CreateZExt(lo, i64),
                          B.CreateShl(B.CreateZExt(hi, i64),
                                      ConstantInt::get(i64, 32),
                                      Name + ".hi.shift"),
                          Name);
    }
    if (TT.getArch() == Triple::aarch64) {
        auto *asmTy = FunctionType::get(i64, false);
        InlineAsm *pmccntr =
            InlineAsm::get(asmTy, "mrs $0, PMCCNTR_EL0", "=r,~{memory}",
                           /*hasSideEffects=*/true);
        return B.CreateCall(asmTy, pmccntr, {}, Name + ".pmccntr");
    }
    return ConstantInt::get(i64, 0);
}

Function *linuxPmuAccessProbe(Module &M, GlobalVariable *State,
                              ir::IRRandom &rng, const Triple &TT) {
    if (!TT.isOSLinux())
        return nullptr;
    if (Function *existing = M.getFunction("morok.step.pmu.oracle"))
        return existing;
    const bool supportedArch =
        TT.getArch() == Triple::x86 || TT.getArch() == Triple::x86_64 ||
        TT.getArch() == Triple::aarch64;
    if (!supportedArch)
        return nullptr;
    if (!schedulerStepTargetSupported(M, TT))
        return nullptr;

    LLVMContext &ctx = M.getContext();
    auto *i16 = Type::getInt16Ty(ctx);
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.step.pmu.oracle", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    auto *mmapBB = BasicBlock::Create(ctx, "mmap", fn);
    auto *capBB = BasicBlock::Create(ctx, "cap", fn);
    auto *enableBB = BasicBlock::Create(ctx, "enable", fn);
    auto *unreadyBB = BasicBlock::Create(ctx, "unready", fn);
    auto *sampleBB = BasicBlock::Create(ctx, "sample", fn);
    auto *cleanupBB = BasicBlock::Create(ctx, "cleanup", fn);
    auto *closeBB = BasicBlock::Create(ctx, "close", fn);
    auto *retBB = BasicBlock::Create(ctx, "ret", fn);

    IRBuilder<> B(entry);
    auto *mixSlot = B.CreateAlloca(i64, nullptr, "morok.step.pmu.mix.slot");
    auto *acc = B.CreateAlloca(i64, nullptr, "morok.step.pmu.span.acc");
    B.CreateStore(ConstantInt::get(i64, rng.next()), mixSlot)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, rng.next()), acc)->setVolatile(true);

    constexpr std::uint64_t kPerfFlagFdCloexec = 8;
    constexpr std::uint64_t kPerfAttrDisabledExcludeKernelHv =
        (1ULL << 0) | (1ULL << 5) | (1ULL << 6);
    Value *hwReady = nullptr;
    Value *fd = emitLinuxPerfOpen(
        B, M, TT, /*Type=*/0, /*Config=*/0,
        kPerfAttrDisabledExcludeKernelHv, kPerfFlagFdCloexec,
        "morok.step.pmu.open", hwReady);
    Value *denied = linuxPerfOpenErrnoMatches(
        B, M, TT, fd, {1, 13}, "morok.step.pmu.open.denied");
    Value *easyFp = linuxPerfOpenErrnoMatches(
        B, M, TT, fd, {2, 16, 95}, "morok.step.pmu.open.easyfp");
    foldFlag(B, State, denied, 0xB42D79E18C5036AFULL,
             "morok.step.pmu.open.denied");
    foldFlag(B, State, easyFp, 0x6F03C58A21D7E94BULL,
             "morok.step.pmu.open.easyfp");
    B.CreateCondBr(hwReady, mmapBB, retBB);

    IRBuilder<> MB(mmapBB);
    Value *mapReady = nullptr;
    Value *mapAddr =
        emitLinuxPerfMetadataMmap(MB, M, TT, fd, mapReady,
                                  "morok.step.pmu.mmap");
    MB.CreateCondBr(mapReady, capBB, closeBB);

    IRBuilder<> CB(capBB);
    Value *page = CB.CreateIntToPtr(mapAddr, ptr, "morok.step.pmu.page");
    Value *caps = loadI64AtOffset(CB, M, page, 40,
                                  "morok.step.pmu.capabilities");
    Value *capUserRdpmc =
        CB.CreateICmpNE(CB.CreateAnd(CB.CreateLShr(caps,
                                                   ConstantInt::get(i64, 2),
                                                   "morok.step.pmu.cap.shift"),
                                     ConstantInt::get(i64, 1),
                                     "morok.step.pmu.cap.bit"),
                       ConstantInt::get(i64, 0),
                       "morok.step.pmu.cap_user_rdpmc");
    Value *widthRaw =
        loadI16AtOffset(CB, M, page, 48, "morok.step.pmu.pmc_width");
    Value *width = CB.CreateZExt(widthRaw, i32, "morok.step.pmu.pmc_width.w");
    Value *widthOk =
        CB.CreateAnd(CB.CreateICmpNE(widthRaw, ConstantInt::get(i16, 0),
                                     "morok.step.pmu.pmc_width.nonzero"),
                     CB.CreateICmpULE(width, ConstantInt::get(i32, 64),
                                      "morok.step.pmu.pmc_width.sane"),
                     "morok.step.pmu.pmc_width.ok");
    Value *capReady = CB.CreateAnd(capUserRdpmc, widthOk,
                                   "morok.step.pmu.cap.ready");
    foldState(CB, State, caps, 0x9D41E630C5A78B2FULL,
              "morok.step.pmu.capabilities");
    foldState(CB, State, width, 0x348F0A6C91D257BEULL,
              "morok.step.pmu.pmc_width");
    foldFlag(CB, State, CB.CreateNot(capUserRdpmc,
                                     "morok.step.pmu.cap_user_rdpmc.missing"),
             0xC6E5A9703B18D42FULL, "morok.step.pmu.cap_user_rdpmc.missing");
    foldFlag(CB, State, CB.CreateNot(widthOk, "morok.step.pmu.pmc_width.bad"),
             0x817C2D40E9A65F3BULL, "morok.step.pmu.pmc_width.bad");
    CB.CreateCondBr(capReady, enableBB, cleanupBB);

    IRBuilder<> EB(enableBB);
    constexpr std::uint64_t kPerfEventIocEnable = 0x2400;
    constexpr std::uint64_t kPerfEventIocDisable = 0x2401;
    constexpr std::uint64_t kPerfEventIocReset = 0x2403;
    Value *resetRc =
        emitLinuxPerfIoctl(EB, M, TT, fd, kPerfEventIocReset,
                           "morok.step.pmu.reset");
    Value *enableRc =
        emitLinuxPerfIoctl(EB, M, TT, fd, kPerfEventIocEnable,
                           "morok.step.pmu.enable");
    Value *indexRaw =
        loadI32AtOffset(EB, M, page, 12, "morok.step.pmu.index");
    Value *indexOk = EB.CreateICmpNE(indexRaw, ConstantInt::get(i32, 0),
                                     "morok.step.pmu.index.nonzero");
    Value *flowOk = EB.CreateAnd(
        EB.CreateICmpEQ(resetRc, ConstantInt::get(ip, 0),
                        "morok.step.pmu.reset.ok"),
        EB.CreateAnd(EB.CreateICmpEQ(enableRc, ConstantInt::get(ip, 0),
                                     "morok.step.pmu.enable.ok"),
                     indexOk, "morok.step.pmu.enabled.index"),
        "morok.step.pmu.flow.ok");
    foldState(EB, State, indexRaw, 0x5AF0D36B82C41E97ULL,
              "morok.step.pmu.index");
    foldFlag(EB, State, EB.CreateNot(indexOk, "morok.step.pmu.index.missing"),
             0x24E8B3F06195CD7AULL, "morok.step.pmu.index.missing");
    EB.CreateCondBr(flowOk, sampleBB, unreadyBB);

    IRBuilder<> UB(unreadyBB);
    emitLinuxPerfIoctl(UB, M, TT, fd, kPerfEventIocDisable,
                       "morok.step.pmu.disable.unready");
    UB.CreateBr(cleanupBB);

    IRBuilder<> SB(sampleBB);
    Value *counterIndex =
        SB.CreateSub(indexRaw, ConstantInt::get(i32, 1),
                     "morok.step.pmu.counter.index");
    Value *before =
        emitLinuxUserPmuCounterRead(SB, M, TT, counterIndex,
                                    "morok.step.pmu.before");
    emitSchedulerStepSpan(SB, acc, rng);
    Value *after =
        emitLinuxUserPmuCounterRead(SB, M, TT, counterIndex,
                                    "morok.step.pmu.after");
    Value *disableRc =
        emitLinuxPerfIoctl(SB, M, TT, fd, kPerfEventIocDisable,
                           "morok.step.pmu.disable");
    Value *delta = SB.CreateSub(after, before, "morok.step.pmu.delta");
    Value *disableBad =
        SB.CreateICmpNE(disableRc, ConstantInt::get(ip, 0),
                        "morok.step.pmu.disable.bad");
    Value *deltaStalled =
        SB.CreateICmpEQ(delta, ConstantInt::get(i64, 0),
                        "morok.step.pmu.delta.stalled");
    auto *oldMix = SB.CreateLoad(i64, mixSlot, "morok.step.pmu.mix.old");
    oldMix->setVolatile(true);
    Value *nextMix = SB.CreateXor(
        SB.CreateMul(oldMix, ConstantInt::get(i64, rng.next() | 1ULL),
                     "morok.step.pmu.mix.mul"),
        SB.CreateAdd(delta, SB.CreateZExt(width, i64),
                     "morok.step.pmu.mix.delta"),
        "morok.step.pmu.mix");
    SB.CreateStore(nextMix, mixSlot)->setVolatile(true);
    foldState(SB, State, before, 0xE5A134C7906B2D8FULL,
              "morok.step.pmu.before");
    foldState(SB, State, after, 0x7B6D20E94A31C85FULL,
              "morok.step.pmu.after");
    foldState(SB, State, delta, 0xD0C7A4815E9B632FULL,
              "morok.step.pmu.delta");
    foldFlag(SB, State, disableBad, 0x96C418A7E35D02BFULL,
             "morok.step.pmu.disable.bad");
    foldEnforcedFlag(SB, State, deltaStalled, 0x43E8B0D61A9C752FULL,
                     "morok.step.pmu.delta.stalled");
    SB.CreateBr(cleanupBB);

    IRBuilder<> XB(cleanupBB);
    emitLinuxPerfMetadataMunmap(XB, M, TT, mapAddr);
    XB.CreateBr(closeBB);

    IRBuilder<> FB(closeBB);
    emitLinuxPerfClose(FB, M, TT, fd);
    FB.CreateBr(retBB);

    IRBuilder<> RB(retBB);
    auto *mix = RB.CreateLoad(i64, mixSlot, "morok.step.pmu.mix.final");
    mix->setVolatile(true);
    RB.CreateRet(mix);
    return fn;
}

Function *schedulerStepOracleProbe(Module &M, GlobalVariable *State,
                                   ir::IRRandom &rng, const Triple &TT) {
    if (!schedulerStepTargetSupported(M, TT))
        return nullptr;
    if (Function *existing = M.getFunction("morok.step.oracle"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *fn = Function::Create(FunctionType::get(Type::getVoidTy(ctx), false),
                                GlobalValue::PrivateLinkage,
                                "morok.step.oracle", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *acc = B.CreateAlloca(i64, nullptr, "morok.step.span.acc");
    B.CreateStore(ConstantInt::get(i64, rng.next()), acc)->setVolatile(true);

    Value *anomalousSamples = ConstantInt::get(i32, 0);
    Value *availableSamples = ConstantInt::get(i32, 0);
    Value *mix = ConstantInt::get(i64, rng.next());

    if (TT.isOSLinux()) {
        constexpr std::uint64_t kPerfFlagFdCloexec = 8;
        constexpr std::uint64_t kPerfAttrDisabledExcludeKernelHv =
            (1ULL << 0) | (1ULL << 5) | (1ULL << 6);
        constexpr std::uint64_t kPerfEventIocEnable = 0x2400;
        constexpr std::uint64_t kPerfEventIocDisable = 0x2401;
        constexpr std::uint64_t kPerfEventIocReset = 0x2403;

        if (Function *pmu = linuxPmuAccessProbe(M, State, rng, TT)) {
            Value *pmuMix = B.CreateCall(pmu->getFunctionType(), pmu, {},
                                         "morok.step.pmu.result");
            mix = B.CreateXor(
                B.CreateMul(mix, ConstantInt::get(i64, rng.next() | 1ULL),
                            "morok.step.pmu.outer.mul"),
                pmuMix, "morok.step.pmu.outer.mix");
        }

        LinuxPerfParanoidSample paranoid = emitLinuxPerfParanoidRead(
            B, M, rng, TT, "morok.step.perf.paranoid");
        const std::uint64_t hwConfig = rng.next() & 1ULL;
        Value *hwReady = nullptr;
        Value *hwFd = emitLinuxPerfOpen(
            B, M, TT, /*Type=*/0, hwConfig,
            kPerfAttrDisabledExcludeKernelHv, kPerfFlagFdCloexec,
            "morok.step.perf.hw.open", hwReady);
        Value *hwDenied = B.CreateOr(
            B.CreateICmpEQ(hwFd, ConstantInt::getSigned(ip, -1),
                           "morok.step.perf.hw.eperm"),
            B.CreateICmpEQ(hwFd, ConstantInt::getSigned(ip, -13),
                           "morok.step.perf.hw.eacces"),
            "morok.step.perf.hw.denied");
        Value *hwReset = emitLinuxPerfIoctl(B, M, TT, hwFd, kPerfEventIocReset,
                                            "morok.step.perf.hw.reset");
        Value *hwEnable = emitLinuxPerfIoctl(B, M, TT, hwFd, kPerfEventIocEnable,
                                             "morok.step.perf.hw.enable");
        emitSchedulerStepSpan(B, acc, rng);
        Value *hwDisable = emitLinuxPerfIoctl(
            B, M, TT, hwFd, kPerfEventIocDisable,
            "morok.step.perf.hw.disable");
        SchedulerCounterSample hwCount =
            emitLinuxPerfRead(B, M, TT, hwFd, "morok.step.perf.hw.count");
        emitLinuxPerfClose(B, M, TT, hwFd);

        auto ioctlOk = [&](Value *Rc, const Twine &Name) {
            return B.CreateICmpEQ(Rc, ConstantInt::get(ip, 0), Name);
        };
        Value *hwFlowOk = B.CreateAnd(
            hwReady,
            B.CreateAnd(ioctlOk(hwReset, "morok.step.perf.hw.reset.ok"),
                        B.CreateAnd(
                            ioctlOk(hwEnable, "morok.step.perf.hw.enable.ok"),
                            B.CreateAnd(ioctlOk(hwDisable,
                                                "morok.step.perf.hw.disable.ok"),
                                        hwCount.ready,
                                        "morok.step.perf.hw.read.path"),
                            "morok.step.perf.hw.enabled.path"),
                        "morok.step.perf.hw.ioctl.path"),
            "morok.step.perf.hw.flow.ok");
        Value *hwFlowBad =
            B.CreateAnd(hwReady, B.CreateNot(hwFlowOk),
                        "morok.step.perf.hw.flow.bad");
        Value *hwZeroCount = B.CreateAnd(
            hwFlowOk,
            B.CreateICmpEQ(hwCount.value, ConstantInt::get(i64, 0),
                           "morok.step.perf.hw.count.zero.raw"),
            "morok.step.perf.hw.count.zero");
        Value *deniedExpected =
            B.CreateAnd(hwDenied, paranoid.high,
                        "morok.step.perf.hw.denied.expected");
        Value *deniedUnexpected = B.CreateAnd(
            hwDenied,
            B.CreateAnd(paranoid.ready,
                        B.CreateNot(paranoid.high,
                                    "morok.step.perf.paranoid.not.high"),
                        "morok.step.perf.paranoid.low.ready"),
            "morok.step.perf.hw.denied.unexpected");
        Value *hwTelemetry =
            B.CreateOr(hwDenied, B.CreateOr(hwFlowBad, hwZeroCount),
                       "morok.step.perf.hw.telemetry");
        foldState(B, State, paranoid.value, 0x6B4391D8A25F0C7BULL,
                  "morok.step.perf.paranoid.value");
        foldFlag(B, State, paranoid.high, 0xC9F12E4A6B803D57ULL,
                 "morok.step.perf.paranoid.high");
        foldFlag(B, State, deniedExpected, 0xA0D47E6359B18C2FULL,
                 "morok.step.perf.hw.denied.expected");
        foldFlag(B, State, deniedUnexpected, 0x51E8B7C20D694A3FULL,
                 "morok.step.perf.hw.denied.unexpected");
        foldFlag(B, State, hwZeroCount, 0x2C7F91A4E058B36DULL,
                 "morok.step.perf.hw.count.zero");
        foldFlag(B, State, hwFlowBad, 0x9E23D580C47A61BFULL,
                 "morok.step.perf.hw.flow.bad");
        foldFlag(B, State, hwTelemetry, 0x73AE18C5D04B962FULL,
                 "morok.step.perf.hw.telemetry");
        mix = B.CreateXor(
            B.CreateAdd(mix,
                        B.CreateMul(hwCount.value,
                                    ConstantInt::get(i64, rng.next() | 1ULL))),
            B.CreateXor(B.CreateZExt(hwTelemetry, i64),
                        B.CreateZExt(paranoid.high, i64),
                        "morok.step.perf.hw.policy.mix"),
            "morok.step.perf.hw.mix");

        Value *perfReady = nullptr;
        Value *perfFd = emitLinuxPerfContextSwitchOpen(B, M, TT, perfReady);
        for (unsigned sample = 0; sample < 3; ++sample) {
            SchedulerCounterSample perfBefore =
                emitLinuxPerfRead(B, M, TT, perfFd,
                                  "morok.step.perf.before");
            SchedulerCounterSample usageBefore =
                emitLinuxRusageSwitches(B, M, "morok.step.getrusage.before");
            emitSchedulerStepSpan(B, acc, rng);
            SchedulerCounterSample perfAfter =
                emitLinuxPerfRead(B, M, TT, perfFd, "morok.step.perf.after");
            SchedulerCounterSample usageAfter =
                emitLinuxRusageSwitches(B, M, "morok.step.getrusage.after");

            Value *perfSampleReady = B.CreateAnd(
                perfReady, B.CreateAnd(perfBefore.ready, perfAfter.ready),
                "morok.step.perf.sample.ready");
            Value *usageSampleReady =
                B.CreateAnd(usageBefore.ready, usageAfter.ready,
                            "morok.step.getrusage.sample.ready");
            Value *perfDelta = B.CreateSub(perfAfter.value, perfBefore.value,
                                           "morok.step.perf.delta");
            Value *usageDelta =
                B.CreateSub(usageAfter.value, usageBefore.value,
                            "morok.step.getrusage.delta");
            Value *counterReady =
                B.CreateOr(perfSampleReady, usageSampleReady,
                           "morok.step.counter.ready");
            Value *counterDelta =
                B.CreateSelect(perfSampleReady, perfDelta, usageDelta,
                               "morok.step.counter.delta.raw");
            counterDelta = B.CreateSelect(counterReady, counterDelta,
                                          ConstantInt::get(i64, 0),
                                          "morok.step.counter.delta");
            Value *sampleBad = B.CreateAnd(
                counterReady,
                B.CreateICmpUGE(counterDelta, ConstantInt::get(i64, 16),
                                "morok.step.switch.anomaly"),
                "morok.step.switch.anomaly.ready");
            anomalousSamples =
                B.CreateAdd(anomalousSamples, B.CreateZExt(sampleBad, i32),
                            "morok.step.anomalous.n");
            availableSamples =
                B.CreateAdd(availableSamples, B.CreateZExt(counterReady, i32),
                            "morok.step.available.n");
            mix = B.CreateXor(
                B.CreateAdd(mix,
                            B.CreateMul(counterDelta,
                                        ConstantInt::get(i64, rng.next() | 1ULL))),
                B.CreateZExt(counterReady, i64), "morok.step.counter.mix");
        }
        emitLinuxPerfClose(B, M, TT, perfFd);
    } else if (TT.isOSDarwin()) {
        for (unsigned sample = 0; sample < 3; ++sample) {
            SchedulerCounterSample cpuBefore =
                emitDarwinThreadCpuNanos(B, M, "morok.step.thread.before");
            Value *wallBefore =
                emitClockGettimeNanos(B, M, 4, "morok.step.wall.before");
            emitSchedulerStepSpan(B, acc, rng);
            SchedulerCounterSample cpuAfter =
                emitDarwinThreadCpuNanos(B, M, "morok.step.thread.after");
            Value *wallAfter =
                emitClockGettimeNanos(B, M, 4, "morok.step.wall.after");

            Value *wallOrdered =
                B.CreateICmpUGE(wallAfter, wallBefore,
                                "morok.step.wall.ordered");
            Value *wallDelta = B.CreateSelect(
                wallOrdered, B.CreateSub(wallAfter, wallBefore),
                ConstantInt::get(i64, 0), "morok.step.wall.delta");
            Value *cpuDelta = B.CreateSub(cpuAfter.value, cpuBefore.value,
                                          "morok.step.cpu.delta");
            Value *cpuReady =
                B.CreateAnd(cpuBefore.ready, cpuAfter.ready,
                            "morok.step.cpu.ready");
            Value *sampleReady = B.CreateAnd(
                cpuReady,
                B.CreateAnd(wallOrdered,
                            B.CreateICmpNE(cpuDelta, ConstantInt::get(i64, 0),
                                           "morok.step.cpu.nonzero")),
                "morok.step.sample.ready");
            Value *limit = B.CreateAdd(
                B.CreateMul(cpuDelta, ConstantInt::get(i64, 256),
                            "morok.step.cpu.scaled"),
                ConstantInt::get(i64, 50000000ULL), "morok.step.wall.limit");
            Value *sampleBad =
                B.CreateAnd(sampleReady,
                            B.CreateICmpUGT(wallDelta, limit,
                                            "morok.step.thread.skew"),
                            "morok.step.thread.skew.ready");
            anomalousSamples =
                B.CreateAdd(anomalousSamples, B.CreateZExt(sampleBad, i32),
                            "morok.step.anomalous.n");
            availableSamples =
                B.CreateAdd(availableSamples, B.CreateZExt(sampleReady, i32),
                            "morok.step.available.n");
            mix = B.CreateXor(
                B.CreateAdd(mix,
                            B.CreateMul(wallDelta,
                                        ConstantInt::get(i64, rng.next() | 1ULL))),
                B.CreateMul(cpuDelta, ConstantInt::get(i64, rng.next() | 1ULL)),
                "morok.step.thread.mix");
        }
    } else {
        Value *qpcFreq = emitWindowsQpcFrequency(B, M, "morok.step.qpc.freq");
        for (unsigned sample = 0; sample < 3; ++sample) {
            SchedulerCounterSample cpuBefore =
                emitWindowsThreadTime100ns(B, M, "morok.step.thread.before");
            SchedulerCounterSample cyclesBefore =
                emitWindowsThreadCycles(B, M, "morok.step.cycles.before");
            Value *wallBefore = emitWindowsQpc(B, M, "morok.step.qpc.before");
            emitSchedulerStepSpan(B, acc, rng);
            SchedulerCounterSample cpuAfter =
                emitWindowsThreadTime100ns(B, M, "morok.step.thread.after");
            SchedulerCounterSample cyclesAfter =
                emitWindowsThreadCycles(B, M, "morok.step.cycles.after");
            Value *wallAfter = emitWindowsQpc(B, M, "morok.step.qpc.after");

            Value *wallOrdered =
                B.CreateICmpUGE(wallAfter, wallBefore,
                                "morok.step.qpc.ordered");
            Value *wallDelta = B.CreateSelect(
                wallOrdered, B.CreateSub(wallAfter, wallBefore),
                ConstantInt::get(i64, 0), "morok.step.qpc.delta");
            Value *cpuDelta = B.CreateSub(cpuAfter.value, cpuBefore.value,
                                          "morok.step.cpu.delta.100ns");
            Value *cpuReady =
                B.CreateAnd(cpuBefore.ready, cpuAfter.ready,
                            "morok.step.cpu.ready");
            Value *sampleReady = B.CreateAnd(
                B.CreateAnd(cpuReady, wallOrdered),
                B.CreateAnd(B.CreateICmpNE(cpuDelta, ConstantInt::get(i64, 0),
                                           "morok.step.cpu.nonzero"),
                            B.CreateICmpNE(qpcFreq, ConstantInt::get(i64, 0),
                                           "morok.step.qpc.freq.nonzero")),
                "morok.step.sample.ready");
            Value *cpuTicks = B.CreateUDiv(
                B.CreateMul(cpuDelta, qpcFreq, "morok.step.cpu.qpc.product"),
                ConstantInt::get(i64, 10000000ULL), "morok.step.cpu.qpc");
            Value *limit = B.CreateAdd(
                B.CreateMul(cpuTicks, ConstantInt::get(i64, 256),
                            "morok.step.cpu.qpc.scaled"),
                B.CreateUDiv(qpcFreq, ConstantInt::get(i64, 20),
                             "morok.step.qpc.floor"),
                "morok.step.qpc.limit");
            Value *sampleBad =
                B.CreateAnd(sampleReady,
                            B.CreateICmpUGT(wallDelta, limit,
                                            "morok.step.thread.skew"),
                            "morok.step.thread.skew.ready");
            Value *cyclesReady =
                B.CreateAnd(cyclesBefore.ready, cyclesAfter.ready,
                            "morok.step.cycles.ready");
            Value *cyclesDelta = B.CreateSelect(
                cyclesReady, B.CreateSub(cyclesAfter.value, cyclesBefore.value),
                ConstantInt::get(i64, 0), "morok.step.cycles.delta");
            anomalousSamples =
                B.CreateAdd(anomalousSamples, B.CreateZExt(sampleBad, i32),
                            "morok.step.anomalous.n");
            availableSamples =
                B.CreateAdd(availableSamples, B.CreateZExt(sampleReady, i32),
                            "morok.step.available.n");
            mix = B.CreateXor(
                B.CreateAdd(mix,
                            B.CreateMul(wallDelta,
                                        ConstantInt::get(i64, rng.next() | 1ULL))),
                B.CreateXor(
                    B.CreateMul(cpuDelta, ConstantInt::get(i64, rng.next() | 1ULL)),
                    B.CreateMul(cyclesDelta,
                                ConstantInt::get(i64, rng.next() | 1ULL))),
                "morok.step.thread.mix");
        }
    }

    foldState(B, State, mix, 0x9C07D36E4A12B5F1ULL, "morok.step.mix");
    foldState(B, State, availableSamples, 0x71AF63C49E20D8B5ULL,
              "morok.step.available.samples");
    foldState(B, State, anomalousSamples, 0xC2E4B8A1975D306FULL,
              "morok.step.anomalous.samples");
    Value *anomaly = B.CreateICmpUGE(anomalousSamples, ConstantInt::get(i32, 2),
                                     "morok.step.anomaly.distribution");
    // Telemetry only, NOT foldEnforcedFlag (#98): context-switch counts and
    // thread-time skew are host/jitter-sensitive — a loaded host, a VM/container
    // scheduler, or ordinary preemption trips this anomaly on a legitimate,
    // untraced run.  foldEnforcedFlag would fold that false positive into the
    // CONSUMED anti_debug seal channel (via sealFold), permanently moving the
    // seal off S0 and making VM bytecode / sealed data decode garbage at
    // startup.  Per the foldEnforcedFlag contract, host/jitter-sensitive probes
    // must stay foldFlag telemetry (recorded in the per-probe state, never the
    // consumed seal); only verdicts proven false on every clean run may enforce.
    foldFlag(B, State, anomaly, 0xF18D47A6C2B9035EULL,
             "morok.step.anomaly.distribution");
    B.CreateRetVoid();
    return fn;
}

Function *negativeTimingProbe(Module &M, ir::IRRandom &rng, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.negative.timing"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.negative.timing", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *diff = B.CreateAlloca(i64, nullptr, "morok.negative.timing.diff");
    auto *acc = B.CreateAlloca(i64, nullptr, "morok.negative.timing.acc");
    B.CreateStore(ConstantInt::get(i64, 0), diff)->setVolatile(true);
    B.CreateStore(ConstantInt::get(i64, rng.next()), acc)->setVolatile(true);

    Value *primaryStart =
        emitTimingPrimaryClock(B, M, TT, "morok.negative.timing.primary.start");
    Value *secondaryStart = emitTimingSecondaryClock(
        B, M, TT, "morok.negative.timing.secondary.start");
    emitShortTimingSpan(B, acc, rng.next());
    Value *primaryEnd =
        emitTimingPrimaryClock(B, M, TT, "morok.negative.timing.primary.end");
    Value *secondaryEnd =
        emitTimingSecondaryClock(B, M, TT, "morok.negative.timing.secondary.end");

    Value *primaryDelta = B.CreateSub(primaryEnd, primaryStart,
                                      "morok.negative.timing.primary.delta");
    Value *secondaryDelta = B.CreateSub(
        secondaryEnd, secondaryStart, "morok.negative.timing.secondary.delta");
    const bool hasCycleClock = isX86Target(TT);
    const std::uint64_t primaryThreshold =
        hasCycleClock ? 25000000ULL : 15000000ULL;
    constexpr std::uint64_t secondaryThreshold = 15000000ULL;
    Value *primarySlow = B.CreateICmpUGT(
        primaryDelta, ConstantInt::get(i64, primaryThreshold),
        "morok.negative.timing.primary.slow");
    Value *secondarySlow = B.CreateICmpUGT(
        secondaryDelta, ConstantInt::get(i64, secondaryThreshold),
        "morok.negative.timing.secondary.slow");
    Value *slow = B.CreateAnd(primarySlow, secondarySlow,
                              "morok.negative.timing.slow");
    incrementDiff(B, diff, slow, "morok.negative.timing.slow");
    emitRetDiff(B, diff);
    return fn;
}

std::uint64_t powRotR(std::uint64_t X, unsigned R) {
    R &= 63U;
    return (X >> R) | (X << ((64U - R) & 63U));
}

std::uint64_t powConstMix(std::uint64_t X) {
    X ^= X >> 32;
    X *= 0xD6E8FEB86659FD93ULL;
    X ^= X >> 29;
    X *= 0xA0761D6478BD642FULL;
    return X ^ (X >> 31);
}

GlobalVariable *powConstantKey(Module &M, std::uint64_t Seed) {
    if (auto *existing =
            M.getGlobalVariable("morok.antihook.pow.const.key",
                                /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, Seed), "morok.antihook.pow.const.key");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    gv->setAlignment(Align(8));
    return gv;
}

Value *emitPowConstMix(IRBuilder<> &B, Value *X, const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    X = B.CreateXor(X, B.CreateLShr(X, ConstantInt::get(i64, 32)),
                    Name + ".fold32");
    X = B.CreateMul(X, ConstantInt::get(i64, 0xD6E8FEB86659FD93ULL),
                    Name + ".mul0");
    X = B.CreateXor(X, B.CreateLShr(X, ConstantInt::get(i64, 29)),
                    Name + ".fold29");
    X = B.CreateMul(X, ConstantInt::get(i64, 0xA0761D6478BD642FULL),
                    Name + ".mul1");
    return B.CreateXor(X, B.CreateLShr(X, ConstantInt::get(i64, 31)),
                       Name + ".fold31");
}

Value *decodePowConstant(IRBuilder<> &B, GlobalVariable *Key,
                         std::uint64_t Plain, std::uint64_t Tag,
                         const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    auto *loaded = B.CreateLoad(i64, Key, Name + ".key");
    loaded->setVolatile(true);
    loaded->setAlignment(Align(8));
    constexpr std::uint64_t kDefaultSeed = 0xA53C9E721D48B60FULL;
    std::uint64_t seed = kDefaultSeed;
    if (Key && Key->hasInitializer())
        if (auto *CI = dyn_cast<ConstantInt>(Key->getInitializer()))
            seed = CI->getZExtValue();
    const unsigned rot = 11U + static_cast<unsigned>((Tag >> 59) & 31U);
    const std::uint64_t mask = powConstMix(seed ^ Tag);
    const std::uint64_t encoded = powRotR(Plain ^ mask, rot);
    Value *mixed =
        emitPowConstMix(B,
                        B.CreateXor(loaded, ConstantInt::get(i64, Tag),
                                    Name + ".tag"),
                        Name + ".mix");
    Value *unrot = ConstantInt::get(i64, encoded);
    unrot = B.CreateOr(
        B.CreateShl(unrot, ConstantInt::get(i64, rot), Name + ".rot.lo"),
        B.CreateLShr(unrot, ConstantInt::get(i64, 64U - rot),
                     Name + ".rot.hi"),
        Name + ".rot");
    return B.CreateXor(unrot, mixed, Name);
}

void emitPowScalarSpan(IRBuilder<> &B, AllocaInst *Acc, std::uint64_t Salt,
                       const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    for (unsigned i = 0; i < 96; ++i) {
        auto *old = B.CreateLoad(i64, Acc, Name + ".load");
        old->setVolatile(true);
        Value *a =
            B.CreateXor(B.CreateShl(old, ConstantInt::get(i64, (i % 19) + 3)),
                        B.CreateLShr(old,
                                     ConstantInt::get(i64, (i % 23) + 5)),
                        Name + ".spread");
        Value *b = B.CreateAdd(
            a, ConstantInt::get(i64, Salt ^ (0x9E3779B97F4A7C15ULL * (i + 1))),
            Name + ".add");
        Value *c = B.CreateMul(
            B.CreateXor(b, old, Name + ".xor"),
            ConstantInt::get(i64,
                             (Salt + 0xD1B54A32D192ED03ULL * (i + 7)) | 1ULL),
            Name + ".mul");
        auto *st = B.CreateStore(
            B.CreateXor(c, B.CreateLShr(c, ConstantInt::get(i64, 31)),
                        Name + ".fold"),
            Acc);
        st->setVolatile(true);
    }
}

Value *emitPowAesSpan(IRBuilder<> &B, Module &M, const Twine &Name) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *asmTy = FunctionType::get(i32, false);
    InlineAsm *aes = InlineAsm::get(
        asmTy,
        "xorl %eax, %eax\n\t"
        "pxor %xmm0, %xmm0\n\t"
        "pcmpeqd %xmm1, %xmm1\n\t"
        "movl $$96, %ecx\n\t"
        "0:\n\t"
        ".byte 0x66,0x0f,0x38,0xdc,0xc1\n\t"
        ".byte 0x66,0x0f,0x38,0xdc,0xc1\n\t"
        ".byte 0x66,0x0f,0x38,0xdc,0xc1\n\t"
        ".byte 0x66,0x0f,0x38,0xdc,0xc1\n\t"
        "paddq %xmm1, %xmm0\n\t"
        "decl %ecx\n\t"
        "jnz 0b\n\t"
        "pmovmskb %xmm0, %eax",
        "={eax},~{ecx},~{xmm0},~{xmm1},~{memory},~{dirflag},~{fpsr},~{flags}",
        /*hasSideEffects=*/true);
    return B.CreateZExt(B.CreateCall(asmTy, aes, {}, Name + ".raw"), i64,
                        Name + ".digest");
}

Value *mixPowRuntimeWord(IRBuilder<> &B, Value *X, std::uint64_t Salt,
                         const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    X = B.CreateXor(X, ConstantInt::get(i64, Salt), Name + ".salt");
    X = B.CreateAdd(
        X, B.CreateOr(B.CreateShl(X, ConstantInt::get(i64, 17)),
                      B.CreateLShr(X, ConstantInt::get(i64, 47)),
                      Name + ".rot"),
        Name + ".add");
    X = B.CreateMul(X, ConstantInt::get(i64, (Salt ^ 0x9E3779B97F4A7C15ULL) |
                                                 1ULL),
                    Name + ".mul");
    return B.CreateXor(X, B.CreateLShr(X, ConstantInt::get(i64, 33)),
                       Name + ".fold");
}

bool linuxPowNanosleepSyscall(const Triple &TT, std::uint32_t &Nanosleep) {
    if (TT.getArch() != Triple::x86_64)
        return false;
    Nanosleep = 35;
    return true;
}

struct PowSleepSample {
    Value *bad = nullptr;
    Value *word = nullptr;
};

PowSleepSample emitLinuxPowSleepCoherence(IRBuilder<> &B, Module &M,
                                          const Triple &TT,
                                          GlobalVariable *ConstKey,
                                          const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    auto *ip = intPtrTy(M);
    auto *ptr = PointerType::getUnqual(ctx);
    PowSleepSample out{ConstantInt::getFalse(ctx), ConstantInt::get(i64, 0)};
    if (!TT.isOSLinux() || intPtrTy(M)->getBitWidth() != 64 ||
        !useDirectLinuxSyscalls(M, TT))
        return out;
    std::uint32_t nanosleepNr = 0;
    if (!linuxPowNanosleepSyscall(TT, nanosleepNr))
        return out;

    auto *tsTy = StructType::get(ctx, {i64, i64});
    auto *req = B.CreateAlloca(tsTy, nullptr, Name + ".req");
    B.CreateStore(ConstantInt::get(i64, 0), B.CreateStructGEP(tsTy, req, 0))
        ->setVolatile(true);
    Value *reqNsec =
        decodePowConstant(B, ConstKey, 5000000ULL, 0xA3865C9217D0E4BFULL,
                          Name + ".req.nsec");
    B.CreateStore(reqNsec, B.CreateStructGEP(tsTy, req, 1))
        ->setVolatile(true);

    LinuxClockSample wall0 =
        emitLinuxRawClockGettimeNanos(B, M, TT, 1, Name + ".wall.start");
    Value *cycle0 = emitRdtscp(B, M);
    Value *rc = emitLinuxSyscall(
        B, M, TT, nanosleepNr,
        {req, ConstantPointerNull::get(ptr)});
    rc->setName(Name + ".nanosleep.rc");
    Value *cycle1 = emitRdtscp(B, M);
    LinuxClockSample wall1 =
        emitLinuxRawClockGettimeNanos(B, M, TT, 1, Name + ".wall.end");

    Value *wallDelta =
        B.CreateSub(wall1.nanos, wall0.nanos, Name + ".wall.delta");
    Value *cycleDelta =
        B.CreateSub(cycle1, cycle0, Name + ".cycle.delta");
    Value *wallReady =
        B.CreateAnd(wall0.ready, wall1.ready, Name + ".wall.ready");
    Value *clockOk = B.CreateAnd(
        wallReady,
        B.CreateAnd(B.CreateICmpUGT(wall1.nanos, wall0.nanos,
                                    Name + ".wall.forward"),
                    B.CreateICmpUGT(cycle1, cycle0, Name + ".cycle.forward"),
                    Name + ".cycle.ready"),
        Name + ".clock.ok");
    Value *wallSkipLimit =
        decodePowConstant(B, ConstKey, 1000000ULL, 0x5E4A9C2D71B603F8ULL,
                          Name + ".wall.skip.limit");
    Value *wallSleepFloor =
        decodePowConstant(B, ConstKey, 3000000ULL, 0xC90E7A31D4B6825FULL,
                          Name + ".wall.sleep.floor");
    Value *cycleSkipLimit =
        decodePowConstant(B, ConstKey, 100000ULL, 0x7D12C8E5A43B90F6ULL,
                          Name + ".cycle.skip.limit");
    Value *cycleSleepFloor =
        decodePowConstant(B, ConstKey, 250000ULL, 0xE2B45F08C9176A3DULL,
                          Name + ".cycle.sleep.floor");
    Value *wallSkipped =
        B.CreateICmpULT(wallDelta, wallSkipLimit, Name + ".wall.skipped");
    Value *cycleSkipped =
        B.CreateICmpULT(cycleDelta, cycleSkipLimit, Name + ".cycle.skipped");
    Value *wallSlept =
        B.CreateICmpUGT(wallDelta, wallSleepFloor, Name + ".wall.slept");
    Value *cycleSlept =
        B.CreateICmpUGT(cycleDelta, cycleSleepFloor, Name + ".cycle.slept");
    Value *bothSkipped =
        B.CreateAnd(wallSkipped, cycleSkipped, Name + ".both.skipped");
    Value *crossMismatch = B.CreateOr(
        B.CreateAnd(wallSkipped, cycleSlept, Name + ".wall.skip.cycle.slept"),
        B.CreateAnd(wallSlept, cycleSkipped, Name + ".wall.slept.cycle.skip"),
        Name + ".cross.mismatch");
    Value *rcOk = B.CreateICmpEQ(rc, ConstantInt::get(ip, 0), Name + ".rc.ok");
    out.bad = B.CreateAnd(
        B.CreateAnd(rcOk, clockOk, Name + ".ready"),
        B.CreateOr(bothSkipped, crossMismatch, Name + ".bad.raw"), Name + ".bad");
    Value *raw = mixPowRuntimeWord(
        B, B.CreateXor(wallDelta, cycleDelta, Name + ".word.delta"),
        0xA9E316C45B72D08FULL, Name + ".word.mix");
    out.word = B.CreateSelect(out.bad, raw, ConstantInt::get(i64, 0),
                              Name + ".word");
    return out;
}

Function *powResourceAsymmetryProbe(Module &M, ir::IRRandom &rng,
                                    const Triple &TT) {
    if (intPtrTy(M)->getBitWidth() != 64 || !isX86Target(TT))
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.pow"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.pow", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    const std::uint64_t seed = rng.next() | 1ULL;
    GlobalVariable *constKey = powConstantKey(M, rng.next() | 1ULL);
    auto derive = [seed](std::uint64_t tag) {
        return powConstMix(seed ^ (0xD1B54A32D192ED03ULL * (tag + 1)));
    };

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    AllocaInst *acc = B.CreateAlloca(i64, nullptr, "morok.antihook.pow.acc");
    B.CreateStore(ConstantInt::get(i64, derive(0x10)), acc)->setVolatile(true);

    Value *leaf1 = emitCpuid(B, M, ConstantInt::get(i32, 1),
                             ConstantInt::get(i32, 0));
    Value *ecx = cpuidReg(B, leaf1, 2, "morok.antihook.pow.cpuid.ecx");
    Value *aesBit =
        B.CreateAnd(ecx, ConstantInt::get(i32, 1u << 25),
                    "morok.antihook.pow.cpuid.aes");
    Value *hasAes =
        B.CreateICmpNE(aesBit, ConstantInt::get(i32, 0),
                       "morok.antihook.pow.aes.supported");

    Value *scalarStart =
        emitRdtscp(B, M);
    emitPowScalarSpan(B, acc, derive(0x20), "morok.antihook.pow.scalar");
    Value *scalarEnd =
        emitRdtscp(B, M);
    Value *scalarDelta =
        B.CreateSub(scalarEnd, scalarStart,
                    "morok.antihook.pow.scalar.delta");
    Value *scalarClockOk =
        B.CreateICmpUGT(scalarEnd, scalarStart,
                        "morok.antihook.pow.scalar.clock.ok");

    BasicBlock *preAesBB = B.GetInsertBlock();
    auto *aesBB = BasicBlock::Create(ctx, "morok.antihook.pow.aes", fn);
    auto *afterAesBB =
        BasicBlock::Create(ctx, "morok.antihook.pow.after.aes", fn);
    B.CreateCondBr(hasAes, aesBB, afterAesBB);

    IRBuilder<> AB(aesBB);
    Value *aesStart = emitRdtscp(AB, M);
    Value *aesDigest = emitPowAesSpan(AB, M, "morok.antihook.pow.aes");
    Value *aesEnd = emitRdtscp(AB, M);
    Value *aesDelta =
        AB.CreateSub(aesEnd, aesStart, "morok.antihook.pow.aes.delta");
    Value *aesClockOk =
        AB.CreateAnd(scalarClockOk,
                     AB.CreateICmpUGT(aesEnd, aesStart,
                                      "morok.antihook.pow.aes.clock.ok"),
                     "morok.antihook.pow.clock.ok");
    Value *floor =
        decodePowConstant(AB, constKey, 50000000ULL,
                          0x6BD81E5F0C24A973ULL,
                          "morok.antihook.pow.aes.floor");
    Value *scaled =
        AB.CreateAdd(AB.CreateShl(scalarDelta, ConstantInt::get(i64, 12),
                                  "morok.antihook.pow.scalar.scaled"),
                     floor, "morok.antihook.pow.aes.limit");
    Value *aesSlow =
        AB.CreateICmpUGT(aesDelta, scaled, "morok.antihook.pow.aes.slow");
    Value *powBad =
        AB.CreateAnd(aesClockOk, aesSlow, "morok.antihook.pow.aes.bad");
    Value *powRawWord = mixPowRuntimeWord(
        AB,
        AB.CreateXor(
            aesDigest,
            AB.CreateXor(AB.CreateMul(aesDelta,
                                      ConstantInt::get(i64, derive(0x30) | 1ULL),
                                      "morok.antihook.pow.aes.delta.mix"),
                         scalarDelta,
                         "morok.antihook.pow.aes.scalar.mix"),
            "morok.antihook.pow.aes.word.raw"),
        derive(0x31), "morok.antihook.pow.aes.word.mix");
    Value *powWord =
        AB.CreateSelect(powBad, powRawWord, ConstantInt::get(i64, 0),
                        "morok.antihook.pow.aes.word");
    AB.CreateBr(afterAesBB);

    B.SetInsertPoint(afterAesBB);
    auto *powFlagPhi =
        B.CreatePHI(Type::getInt1Ty(ctx), 2, "morok.antihook.pow.flag");
    powFlagPhi->addIncoming(ConstantInt::getFalse(ctx), preAesBB);
    powFlagPhi->addIncoming(powBad, aesBB);
    auto *powWordPhi =
        B.CreatePHI(i64, 2, "morok.antihook.pow.word.phi");
    powWordPhi->addIncoming(ConstantInt::get(i64, 0), preAesBB);
    powWordPhi->addIncoming(powWord, aesBB);

    PowSleepSample sleep =
        emitLinuxPowSleepCoherence(B, M, TT, constKey,
                                   "morok.antihook.pow.sleep");
    Value *flags = B.CreateOr(
        B.CreateZExt(sleep.bad, i64, "morok.antihook.pow.sleep.bit"),
        B.CreateShl(B.CreateZExt(powFlagPhi, i64,
                                  "morok.antihook.pow.aes.bit"),
                    ConstantInt::get(i64, 1),
                    "morok.antihook.pow.aes.bit.shift"),
        "morok.antihook.pow.flags");
    Value *active =
        B.CreateICmpNE(flags, ConstantInt::get(i64, 0),
                       "morok.antihook.pow.active");
    Value *combined = B.CreateXor(
        B.CreateXor(powWordPhi, sleep.word, "morok.antihook.pow.word.xor"),
        B.CreateMul(flags, ConstantInt::get(i64, derive(0x40) | 1ULL),
                    "morok.antihook.pow.flag.mix"),
        "morok.antihook.pow.word.input");
    Value *mixedWord =
        mixPowRuntimeWord(B, combined, derive(0x41),
                          "morok.antihook.pow.word.final");
    Value *word =
        B.CreateSelect(active, mixedWord, ConstantInt::get(i64, 0),
                       "morok.antihook.pow.word");
    Value *packed = B.CreateOr(
        flags,
        B.CreateShl(
            B.CreateAnd(word, ConstantInt::get(i64, 0x00FFFFFFFFFFFFFFULL),
                        "morok.antihook.pow.word.low"),
            ConstantInt::get(i64, 8), "morok.antihook.pow.word.shift"),
        "morok.antihook.pow.ret");
    B.CreateRet(packed);
    return fn;
}

void emitDbiOverheadLinearSpan(IRBuilder<> &B, AllocaInst *Acc,
                               std::uint64_t Salt, const Twine &Name) {
    auto *i64 = B.getInt64Ty();
    for (unsigned i = 0; i < 24; ++i) {
        auto *old = B.CreateLoad(i64, Acc, Name + ".load");
        old->setVolatile(true);
        Value *rot =
            B.CreateOr(B.CreateShl(old, ConstantInt::get(i64, (i % 11) + 3)),
                       B.CreateLShr(old, ConstantInt::get(i64, 64 - ((i % 11) + 3))),
                       Name + ".rot");
        Value *mixed = B.CreateMul(
            B.CreateXor(rot, ConstantInt::get(i64, Salt + 0xD1B54A32D192ED03ULL * i),
                        Name + ".xor"),
            ConstantInt::get(i64, (Salt ^ (0x9E3779B97F4A7C15ULL * (i + 1))) | 1ULL),
            Name + ".mix");
        B.CreateStore(mixed, Acc)->setVolatile(true);
    }
}

void emitDbiOverheadBranchSpan(IRBuilder<> &B, Module &M, AllocaInst *Acc,
                               std::uint64_t Salt, const Twine &Name) {
    LLVMContext &ctx = M.getContext();
    auto *i64 = Type::getInt64Ty(ctx);
    Function *fn = B.GetInsertBlock()->getParent();
    for (unsigned i = 0; i < 18; ++i) {
        auto *old = B.CreateLoad(i64, Acc, Name + ".load");
        old->setVolatile(true);
        Value *bit = B.CreateAnd(
            B.CreateXor(B.CreateLShr(old, ConstantInt::get(i64, (i % 13) + 1)),
                        old, Name + ".selector.mix"),
            ConstantInt::get(i64, 1), Name + ".selector.bit");
        auto *thenBB = BasicBlock::Create(ctx, (Name + ".then").str(), fn);
        auto *elseBB = BasicBlock::Create(ctx, (Name + ".else").str(), fn);
        auto *joinBB = BasicBlock::Create(ctx, (Name + ".join").str(), fn);
        B.CreateCondBr(B.CreateICmpNE(bit, ConstantInt::get(i64, 0),
                                      Name + ".take"),
                       thenBB, elseBB);

        IRBuilder<> TB(thenBB);
        Value *thenMix = TB.CreateAdd(
            TB.CreateMul(old,
                         ConstantInt::get(
                             i64, (Salt ^ (0xA0761D6478BD642FULL * (i + 1))) | 1ULL),
                         Name + ".then.mul"),
            ConstantInt::get(i64, Salt + 0xE7037ED1A0B428DBULL * (i + 3)),
            Name + ".then.mix");
        TB.CreateStore(thenMix, Acc)->setVolatile(true);
        TB.CreateBr(joinBB);

        IRBuilder<> EB(elseBB);
        Value *elseMix =
            EB.CreateXor(EB.CreateAdd(old,
                                      ConstantInt::get(
                                          i64, Salt ^ 0x8EBC6AF09C88C6E3ULL ^ i),
                                      Name + ".else.add"),
                         EB.CreateLShr(old, ConstantInt::get(i64, (i % 17) + 1)),
                         Name + ".else.mix");
        EB.CreateStore(elseMix, Acc)->setVolatile(true);
        EB.CreateBr(joinBB);

        B.SetInsertPoint(joinBB);
    }
}

Function *dbiOverheadProbe(Module &M, ir::IRRandom &rng, const Triple &TT) {
    if (!isX86Target(TT))
        return nullptr;
    if (Function *existing = M.getFunction("morok.antihook.dbi.overhead"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *i64 = Type::getInt64Ty(ctx);
    auto *fn = Function::Create(FunctionType::get(i64, false),
                                GlobalValue::PrivateLinkage,
                                "morok.antihook.dbi.overhead", &M);
    fn->addFnAttr(Attribute::NoInline);
    fn->setDSOLocal(true);

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *acc = B.CreateAlloca(i64, nullptr, "morok.antihook.dbi.overhead.acc");
    const std::uint64_t seed = rng.next();
    auto derive = [seed](std::uint64_t tag) {
        std::uint64_t x = seed + 0x9E3779B97F4A7C15ULL * (tag + 1);
        x ^= x >> 30;
        x *= 0xBF58476D1CE4E5B9ULL;
        x ^= x >> 27;
        x *= 0x94D049BB133111EBULL;
        return x ^ (x >> 31);
    };
    B.CreateStore(ConstantInt::get(i64, derive(0x10)), acc)->setVolatile(true);

    Value *anomalousSamples = ConstantInt::get(i32, 0);
    Value *mix = ConstantInt::get(i64, derive(0x20));
    const bool hasCycleClock = isX86Target(TT);
    const std::uint64_t branchFloor = hasCycleClock ? 50000ULL : 500000ULL;

    for (unsigned sample = 0; sample < 4; ++sample) {
        Value *linearStart = emitTimingPrimaryClock(
            B, M, TT, "morok.antihook.dbi.overhead.linear.start");
        emitDbiOverheadLinearSpan(
            B, acc, derive(0x100 + sample * 5),
            "morok.antihook.dbi.overhead.linear");
        Value *linearEnd = emitTimingPrimaryClock(
            B, M, TT, "morok.antihook.dbi.overhead.linear.end");
        emitDbiOverheadLinearSpan(
            B, acc, derive(0x101 + sample * 5),
            "morok.antihook.dbi.overhead.cooldown");
        Value *branchStart = emitTimingPrimaryClock(
            B, M, TT, "morok.antihook.dbi.overhead.branch.start");
        emitDbiOverheadBranchSpan(
            B, M, acc, derive(0x102 + sample * 5),
            "morok.antihook.dbi.overhead.branch");
        Value *branchEnd = emitTimingPrimaryClock(
            B, M, TT, "morok.antihook.dbi.overhead.branch.end");

        Value *linearDelta = B.CreateSub(
            linearEnd, linearStart, "morok.antihook.dbi.overhead.linear.delta");
        Value *branchDelta = B.CreateSub(
            branchEnd, branchStart, "morok.antihook.dbi.overhead.branch.delta");
        Value *ratioLimit = B.CreateAdd(
            B.CreateShl(linearDelta, ConstantInt::get(i64, 4),
                        "morok.antihook.dbi.overhead.linear.scaled"),
            ConstantInt::get(i64, branchFloor),
            "morok.antihook.dbi.overhead.branch.limit");
        Value *ratioSlow = B.CreateICmpUGT(
            branchDelta, ratioLimit, "morok.antihook.dbi.overhead.ratio.slow");
        Value *floorSlow = B.CreateICmpUGT(
            branchDelta, ConstantInt::get(i64, branchFloor),
            "morok.antihook.dbi.overhead.floor.slow");
        Value *sampleAnomaly = B.CreateAnd(
            ratioSlow, floorSlow, "morok.antihook.dbi.overhead.sample.anomaly");
        anomalousSamples =
            B.CreateAdd(anomalousSamples, B.CreateZExt(sampleAnomaly, i32),
                        "morok.antihook.dbi.overhead.anomalous.n");
        mix = B.CreateXor(
            B.CreateAdd(mix,
                        B.CreateMul(linearDelta,
                                    ConstantInt::get(
                                        i64, derive(0x103 + sample * 5) | 1ULL))),
            B.CreateMul(branchDelta,
                        ConstantInt::get(i64,
                                         derive(0x104 + sample * 5) | 1ULL)),
            "morok.antihook.dbi.overhead.mix");
    }

    Value *distribution = B.CreateICmpUGE(
        anomalousSamples, ConstantInt::get(i32, 2),
        "morok.antihook.dbi.overhead.distribution");
    Value *packed = B.CreateZExt(anomalousSamples, i64,
                                 "morok.antihook.dbi.overhead.count");
    packed = B.CreateOr(
        packed,
        B.CreateShl(B.CreateZExt(distribution, i64), ConstantInt::get(i64, 8),
                    "morok.antihook.dbi.overhead.distribution.bit"),
        "morok.antihook.dbi.overhead.pack.flags");
    Value *mixBits = B.CreateShl(
        B.CreateAnd(mix, ConstantInt::get(i64, 0x0000ffffffffffffULL),
                    "morok.antihook.dbi.overhead.mix.low"),
        ConstantInt::get(i64, 16), "morok.antihook.dbi.overhead.mix.pack");
    packed = B.CreateOr(packed, mixBits, "morok.antihook.dbi.overhead.pack");
    B.CreateRet(packed);
    return fn;
}

GlobalVariable *trapOracleState(Module &M, ir::IRRandom &rng) {
    if (auto *existing =
            M.getGlobalVariable("morok.trap.state", /*AllowInternal=*/true))
        return existing;
    auto *i64 = Type::getInt64Ty(M.getContext());
    auto *gv = new GlobalVariable(
        M, i64, /*isConstant=*/false, GlobalValue::PrivateLinkage,
        ConstantInt::get(i64, rng.next()), "morok.trap.state");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *trapHitCounter(Module &M) {
    if (auto *existing =
            M.getGlobalVariable("morok.trap.hits", /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(M, i32, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(i32, 0), "morok.trap.hits");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

GlobalVariable *trapTfPcCounter(Module &M) {
    if (auto *existing = M.getGlobalVariable("morok.trap.tf.pc.hits",
                                             /*AllowInternal=*/true))
        return existing;
    auto *i32 = Type::getInt32Ty(M.getContext());
    auto *gv = new GlobalVariable(M, i32, /*isConstant=*/false,
                                  GlobalValue::PrivateLinkage,
                                  ConstantInt::get(i32, 0),
                                  "morok.trap.tf.pc.hits");
    gv->setUnnamedAddr(GlobalValue::UnnamedAddr::Global);
    return gv;
}

