bool useLinuxX86SiginfoTrapHandler(const Triple &TT) {
    return TT.isOSLinux() && TT.getArch() == Triple::x86_64;
}

Function *trapSignalHandler(Module &M, GlobalVariable *Counter,
                            GlobalVariable *State, const Triple &TT) {
    if (Function *existing = M.getFunction("morok.trap.handler"))
        return existing;

    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    SmallVector<Type *, 3> args{i32, ptr, ptr};
    auto *fn = Function::Create(
        FunctionType::get(Type::getVoidTy(ctx), args, false),
        GlobalValue::PrivateLinkage, "morok.trap.handler", &M);
    fn->setDSOLocal(true);
    Argument *sig = fn->getArg(0);
    sig->setName("sig");
    Argument *info = fn->getArg(1);
    info->setName("info");
    Argument *uctx = fn->getArg(2);
    uctx->setName("uctx");

    auto *entry = BasicBlock::Create(ctx, "entry", fn);
    IRBuilder<> B(entry);
    auto *old = B.CreateLoad(i32, Counter, "morok.trap.hits.old");
    old->setVolatile(true);
    Value *next =
        B.CreateAdd(old, ConstantInt::get(i32, 1), "morok.trap.hits.next");
    auto *store = B.CreateStore(next, Counter);
    store->setVolatile(true);
    foldState(B, State, sig, 0xC286B9F2B77D6A41ULL, "morok.trap.signal");
    foldState(B, State, next, 0x4F3C2D1E9876A5B1ULL, "morok.trap.count");

    if (useLinuxX86SiginfoTrapHandler(TT)) {
        auto *ip = intPtrTy(M);
        auto *i8 = Type::getInt8Ty(ctx);
        auto *checkIllCtx = BasicBlock::Create(ctx, "morok.trap.ill.ctx", fn);
        auto *checkIllByte =
            BasicBlock::Create(ctx, "morok.trap.ill.byte", fn);
        auto *advanceIll =
            BasicBlock::Create(ctx, "morok.trap.ill.advance", fn);
        auto *checkTrapCtx = BasicBlock::Create(ctx, "morok.trap.tf.ctx", fn);
        auto *checkTrapByte =
            BasicBlock::Create(ctx, "morok.trap.tf.byte", fn);
        auto *recordTf = BasicBlock::Create(ctx, "morok.trap.tf.record", fn);
        auto *checkBusCtx = BasicBlock::Create(ctx, "morok.trap.ac.ctx", fn);
        auto *checkBusByte =
            BasicBlock::Create(ctx, "morok.trap.ac.byte", fn);
        auto *recordAc = BasicBlock::Create(ctx, "morok.trap.ac.record", fn);
        auto *done = BasicBlock::Create(ctx, "done", fn);

        Value *isIll =
            B.CreateICmpEQ(sig, ConstantInt::get(i32, 4), "morok.trap.ill");
        Value *isTrap =
            B.CreateICmpEQ(sig, ConstantInt::get(i32, 5), "morok.trap.sigtrap");
        Value *isBus =
            B.CreateICmpEQ(sig, ConstantInt::get(i32, 7), "morok.trap.sigbus");
        B.CreateCondBr(isIll, checkIllCtx, checkTrapCtx);

        IRBuilder<> CB(checkIllCtx);
        CB.CreateCondBr(CB.CreateICmpNE(uctx, ConstantPointerNull::get(ptr)),
                        checkIllByte, done);

        IRBuilder<> BB(checkIllByte);
        // Linux x86_64 ucontext_t: uc_mcontext.gregs[REG_RIP] at byte 168.
        // Orb reports ICEBP (0xf1) as SIGILL at the same PC, so advance only
        // when the trapped byte is exactly the ICEBP stimulus.
        Value *ripSlot = gepI8(BB, M, uctx, constIp(M, 168),
                               "morok.trap.rip.slot");
        Value *rip = BB.CreateLoad(ip, ripSlot, "morok.trap.rip");
        Value *pc = BB.CreateIntToPtr(rip, ptr, "morok.trap.pc");
        Value *byte = BB.CreateLoad(i8, pc, "morok.trap.icebp.byte");
        BB.CreateCondBr(
            BB.CreateICmpEQ(byte, ConstantInt::get(i8, 0xF1),
                            "morok.trap.icebp"),
            advanceIll, done);

        IRBuilder<> AB(advanceIll);
        AB.CreateStore(AB.CreateAdd(rip, ConstantInt::get(ip, 1)), ripSlot);
        AB.CreateBr(done);

        IRBuilder<> TB(checkTrapCtx);
        TB.CreateCondBr(
            isTrap, checkTrapByte,
            checkBusCtx);

        IRBuilder<> PB(checkTrapByte);
        PB.CreateCondBr(PB.CreateICmpNE(uctx, ConstantPointerNull::get(ptr),
                                        "morok.trap.tf.ctx.ready"),
                        recordTf, done);

        IRBuilder<> RB(recordTf);
        Value *tfRipSlot = gepI8(RB, M, uctx, constIp(M, 168),
                                 "morok.trap.tf.rip.slot");
        Value *tfRip = RB.CreateLoad(ip, tfRipSlot, "morok.trap.tf.rip");
        Value *prev = RB.CreateIntToPtr(
            RB.CreateSub(tfRip, ConstantInt::get(ip, 1),
                         "morok.trap.tf.prev.addr"),
            ptr, "morok.trap.tf.prev.ptr");
        auto *prevByte = RB.CreateLoad(i8, prev, "morok.trap.tf.prev.byte");
        prevByte->setVolatile(true);
        prevByte->setAlignment(Align(1));
        auto *tfOk = RB.CreateICmpEQ(prevByte, ConstantInt::get(i8, 0x90),
                                     "morok.trap.tf.pc.delta");
        auto *oldTf = RB.CreateLoad(i32, trapTfPcCounter(M),
                                    "morok.trap.tf.pc.old");
        oldTf->setVolatile(true);
        Value *tfNext = RB.CreateSelect(
            tfOk, RB.CreateAdd(oldTf, ConstantInt::get(i32, 1),
                               "morok.trap.tf.pc.next"),
            oldTf, "morok.trap.tf.pc.keep");
        auto *tfStore = RB.CreateStore(
            tfNext,
            trapTfPcCounter(M));
        tfStore->setVolatile(true);
        RB.CreateBr(done);

        IRBuilder<> BUS(checkBusCtx);
        BUS.CreateCondBr(BUS.CreateAnd(
                             isBus,
                             BUS.CreateICmpNE(uctx,
                                              ConstantPointerNull::get(ptr)),
                             "morok.trap.ac.ctx.ready"),
                         checkBusByte, done);

        IRBuilder<> ADB(checkBusByte);
        Value *acRipSlot = gepI8(ADB, M, uctx, constIp(M, 168),
                                 "morok.trap.ac.rip.slot");
        Value *acRip = ADB.CreateLoad(ip, acRipSlot, "morok.trap.ac.rip");
        Value *acPc = ADB.CreateIntToPtr(acRip, ptr, "morok.trap.ac.pc");
        auto *acOp0 = ADB.CreateLoad(i8, acPc, "morok.trap.ac.op0");
        acOp0->setVolatile(true);
        acOp0->setAlignment(Align(1));
        auto *acOp1 = ADB.CreateLoad(
            i8, gepI8(ADB, M, acPc, constIp(M, 1), "morok.trap.ac.op1.ptr"),
            "morok.trap.ac.op1");
        acOp1->setVolatile(true);
        acOp1->setAlignment(Align(1));
        auto *acOp2 = ADB.CreateLoad(
            i8, gepI8(ADB, M, acPc, constIp(M, 2), "morok.trap.ac.op2.ptr"),
            "morok.trap.ac.op2");
        acOp2->setVolatile(true);
        acOp2->setAlignment(Align(1));
        Value *acFault = ADB.CreateAnd(
            ADB.CreateAnd(ADB.CreateICmpEQ(acOp0, ConstantInt::get(i8, 0x8b)),
                          ADB.CreateICmpEQ(acOp1, ConstantInt::get(i8, 0x40))),
            ADB.CreateICmpEQ(acOp2, ConstantInt::get(i8, 0x01)),
            "morok.trap.ac.fault");
        ADB.CreateCondBr(acFault, recordAc, done);

        IRBuilder<> ACB(recordAc);
        auto *oldAc =
            ACB.CreateLoad(i32, trapAcCounter(M), "morok.trap.ac.old");
        oldAc->setVolatile(true);
        auto *acStore = ACB.CreateStore(
            ACB.CreateAdd(oldAc, ConstantInt::get(i32, 1),
                          "morok.trap.ac.next"),
            trapAcCounter(M));
        acStore->setVolatile(true);
        Value *eflSlot = gepI8(ACB, M, uctx, constIp(M, 176),
                               "morok.trap.ac.eflags.slot");
        auto *efl = ACB.CreateLoad(ip, eflSlot, "morok.trap.ac.eflags");
        efl->setAlignment(Align(1));
        auto *eflStore = ACB.CreateStore(
            ACB.CreateAnd(efl, ConstantInt::get(ip, ~0x40000ULL),
                          "morok.trap.ac.eflags.clear"),
            eflSlot);
        eflStore->setAlignment(Align(1));
        auto *ripStore = ACB.CreateStore(
            ACB.CreateAdd(acRip, ConstantInt::get(ip, 3),
                          "morok.trap.ac.rip.next"),
            acRipSlot);
        ripStore->setAlignment(Align(1));
        ACB.CreateBr(done);

        B.SetInsertPoint(done);
    }

    B.CreateRetVoid();
    return fn;
}

FunctionCallee sigactionDecl(Module &M) {
    LLVMContext &ctx = M.getContext();
    auto *i32 = Type::getInt32Ty(ctx);
    auto *ptr = PointerType::getUnqual(ctx);
    return M.getOrInsertFunction(
        "sigaction", FunctionType::get(i32, {i32, ptr, ptr}, false));
}

FunctionCallee raiseDecl(Module &M) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    return M.getOrInsertFunction("raise", FunctionType::get(i32, {i32}, false));
}

void zeroActionBytes(IRBuilder<> &B, Module &M, AllocaInst *Action,
                     std::uint64_t Bytes) {
    auto *i8 = Type::getInt8Ty(M.getContext());
    for (std::uint64_t i = 0; i < Bytes; ++i)
        B.CreateStore(ConstantInt::get(i8, 0),
                      gepI8(B, M, Action, constIp(M, i)));
}

struct TrapSigactionLayout {
    std::uint64_t sigactionSize = 0;
    std::uint64_t flagsOffset = 0;
    std::uint32_t saSiginfo = 0;
};

bool trapSigactionLayout(const Triple &TT, TrapSigactionLayout &L) {
    if (TT.isOSLinux() &&
        (TT.getArch() == Triple::x86_64 || TT.getArch() == Triple::aarch64 ||
         TT.getArch() == Triple::aarch64_be)) {
        L.sigactionSize = 152;
        L.flagsOffset = 136;
        L.saSiginfo = 4;
        return true;
    }
    if (TT.isOSDarwin() &&
        (TT.getArch() == Triple::x86_64 || TT.getArch() == Triple::aarch64)) {
        L.sigactionSize = 16;
        L.flagsOffset = 12;
        L.saSiginfo = 0x40;
        return true;
    }
    return false;
}

void storeTrapSiginfoAction(IRBuilder<> &B, Module &M, AllocaInst *Action,
                            Function *Handler,
                            const TrapSigactionLayout &Layout) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    zeroActionBytes(B, M, Action, Layout.sigactionSize);
    B.CreateStore(Handler, gepI8(B, M, Action, constIp(M, 0),
                                 "morok.trap.sa.handler"));
    B.CreateStore(ConstantInt::get(i32, Layout.saSiginfo),
                  gepI8(B, M, Action, constIp(M, Layout.flagsOffset),
                        "morok.trap.sa.flags"));
}

void emitTrapInlineAsm(IRBuilder<> &B, StringRef Asm, StringRef Constraints) {
    auto *asmTy = FunctionType::get(Type::getVoidTy(B.getContext()), false);
    InlineAsm *IA =
        InlineAsm::get(asmTy, Asm, Constraints, /*hasSideEffects=*/true);
    B.CreateCall(asmTy, IA);
}

unsigned emitTrapStimuli(IRBuilder<> &B, Module &M, const Triple &TT) {
    auto *i32 = Type::getInt32Ty(M.getContext());
    constexpr int kSigTrap = 5;
    if (useLinuxX86SiginfoTrapHandler(TT)) {
        emitTrapInlineAsm(B, "int3", "~{dirflag},~{fpsr},~{flags}");
        emitTrapInlineAsm(B, ".byte 0xf1", "~{dirflag},~{fpsr},~{flags}");
        emitTrapInlineAsm(B,
                          "pushfq\npopq %rax\norq $$256, %rax\npushq "
                          "%rax\npopfq\nnop\npushfq\npopq %rax\nandq "
                          "$$-257, %rax\npushq %rax\npopfq",
                          "~{rax},~{dirflag},~{fpsr},~{flags}");
        emitTrapInlineAsm(B,
                          "movq %rsp, %rax\npushfq\norq $$262144, "
                          "(%rsp)\npopfq\n.byte 0x8b,0x40,0x01\npushfq\n"
                          "andq $$-262145, (%rsp)\npopfq",
                          "~{rax},~{memory},~{dirflag},~{fpsr},~{flags}");
        return 4;
    }

    FunctionCallee raiseFn = raiseDecl(M);
    for (unsigned i = 0; i < 3; ++i)
        B.CreateCall(raiseFn, {ConstantInt::get(i32, kSigTrap)});
    return 3;
}

struct SchroFaultLayout {
    std::uint64_t sigactionSize = 0;
    std::uint64_t flagsOffset = 0;
    std::uint64_t siginfoAddrOffset = 0;
    std::uint64_t linuxPcSlotOffset = 0;
    std::uint64_t darwinMcontextOffset = 0;
    std::uint64_t darwinPcOffset = 0;
    std::uint32_t saSiginfo = 0;
    std::int32_t sigSegv = 11;
    std::int32_t sigBus = 7;
    bool darwinMcontext = false;
};

bool schroFaultLayout(const Triple &TT, SchroFaultLayout &L) {
    if (TT.isOSLinux() && TT.getArch() == Triple::x86_64) {
        L.sigactionSize = 152;
        L.flagsOffset = 136;
        L.siginfoAddrOffset = 16;
        L.linuxPcSlotOffset = 168;
        L.saSiginfo = 4;
        L.sigSegv = 11;
        L.sigBus = 7;
        return true;
    }
    if (TT.isOSDarwin() &&
        (TT.getArch() == Triple::x86_64 || TT.getArch() == Triple::aarch64 ||
         TT.getArch() == Triple::aarch64_32)) {
        L.sigactionSize = 16;
        L.flagsOffset = 12;
        L.siginfoAddrOffset = 24;
        L.darwinMcontextOffset = 48;
        L.darwinPcOffset = TT.getArch() == Triple::x86_64 ? 160 : 288;
        L.saSiginfo = 0x40;
        L.sigSegv = 11;
        L.sigBus = 10;
        L.darwinMcontext = true;
        return true;
    }
    return false;
}

